function buildWorkProgressSteps(
  labels: readonly string[],
  activeIndex: number
): WorkProgressStep[] {
  const isComplete = activeIndex >= labels.length;

  return labels.map((label, index) => ({
    label,
    state: isComplete || index < activeIndex ? 'complete' : index === activeIndex ? 'active' : 'pending'
  }));
}

function createDeterminateWorkProgress(
  label: string,
  detail: string,
  steps: readonly string[],
  activeIndex: number,
  percent: number
): WorkProgressState {
  const step = Math.min(Math.max(activeIndex + 1, 1), steps.length);

  return {
    detail,
    label,
    mode: 'determinate',
    percent: Math.max(0, Math.min(100, percent)),
    step,
    steps: buildWorkProgressSteps(steps, activeIndex),
    totalSteps: steps.length
  };
}

function createIndeterminateWorkProgress(
  label: string,
  detail: string,
  steps: readonly string[],
  activeIndex: number
): WorkProgressState {
  return {
    detail,
    label,
    mode: 'indeterminate',
    step: Math.min(activeIndex + 1, steps.length),
    steps: buildWorkProgressSteps(steps, activeIndex),
    totalSteps: steps.length
  };
}

type SupportSearchProgressPayload = {
  currentPath: string;
  currentRoot: string;
  searchedDirectories: number;
  searchedFiles: number;
};

function createSupportSearchWorkProgress(
  progress: SupportSearchProgressPayload | null
): WorkProgressState {
  const detail = progress
    ? `${progress.currentPath} · ${progress.searchedDirectories.toLocaleString()} folders · ${progress.searchedFiles.toLocaleString()} files`
    : 'Preparing local drive scan';

  return {
    detail,
    label: 'Finding oo2core_8_win64.dll',
    mode: 'indeterminate',
    step: progress ? 2 : 1,
    steps: buildWorkProgressSteps(
      ['Confirm search', 'Scan local drives', 'Set folder'],
      progress ? 1 : 0
    ),
    totalSteps: 3
  };
}
