  const handleUpdateEncounterSlotUpdates = async (updates: EncounterSlotFieldUpdate[]) => {
    const nonEmptyUpdates = updates.filter((update) => update.changes.length > 0);
    if (nonEmptyUpdates.length === 0) {
      return false;
    }

    setIsEncounterUpdating(true);
    setBridgeDiagnostics([]);
    setEditValidationDiagnostics([]);

    try {
      const totalChanges = nonEmptyUpdates.reduce(
        (total, update) => total + update.changes.length,
        0
      );
      const targetTableCount = new Set(nonEmptyUpdates.map((update) => update.tableId)).size;

      setWorkProgress(createDeterminateWorkProgress(
        'Applying Encounter Updates',
        `Preparing ${targetTableCount} encounter ${targetTableCount === 1 ? 'table' : 'tables'}`,
        encounterBatchUpdateProgressSteps,
        0,
        0
      ));

      setWorkProgress(createDeterminateWorkProgress(
        'Applying Encounter Updates',
        `Applying ${totalChanges} slot field updates`,
        encounterBatchUpdateProgressSteps,
        1,
        50
      ));

      const response = await runEditSessionMutation(
        (session) =>
          bridge.updateEncounterSlotFields({
            paths: createProjectPaths(draftPaths),
            session,
            updates: nonEmptyUpdates.flatMap((update) =>
              update.changes.map((change) => ({
                field: change.field,
                slot: update.slot,
                tableId: update.tableId,
                value: change.value
              }))
            )
          }),
        (updateResponse) => {
          setWorkProgress(createDeterminateWorkProgress(
            'Applying Encounter Updates',
            'Refreshing encounter tables',
            encounterBatchUpdateProgressSteps,
            2,
            100
          ));
          setEncountersWorkflow(updateResponse.workflow);
          setEditValidationDiagnostics(updateResponse.diagnostics);
        }
      );
      return (
        response !== null &&
        !response.diagnostics.some((diagnostic) => diagnostic.severity === 'error')
      );
    } catch (error) {
      setBridgeDiagnostics(toBridgeDiagnostics(error));
      return false;
    } finally {
      setIsEncounterUpdating(false);
      setWorkProgress(null);
    }
  };

