function VirtualTableBody<T>({
  getKey,
  items,
  renderRow
}: {
  getKey: (item: T, index: number) => string | number;
  items: T[];
  renderRow: (item: T) => ReactNode;
}) {
  const scrollParentRef = useRef<HTMLDivElement | null>(null);
  useVirtualTableHeaderScrollSync(scrollParentRef, items);
  const rowVirtualizer = useVirtualizer({
    count: items.length,
    estimateSize: () => virtualTableRowHeight,
    getItemKey: (index) => getKey(items[index]!, index),
    getScrollElement: () => scrollParentRef.current,
    initialRect: virtualTableInitialRect,
    overscan: virtualTableOverscan,
    ...(observeVirtualTableElementRect
      ? { observeElementRect: observeVirtualTableElementRect }
      : {})
  });

  return (
    <div className="virtual-table-body" ref={scrollParentRef} role="rowgroup">
      <div
        className="virtual-table-spacer"
        style={{ height: `${rowVirtualizer.getTotalSize()}px` }}
      >
        {rowVirtualizer.getVirtualItems().map((virtualRow) => {
          const item = items[virtualRow.index];

          if (item === undefined) {
            return null;
          }

          return (
            <div
              className="virtual-table-row"
              key={virtualRow.key}
              role="presentation"
              style={{
                height: `${virtualRow.size}px`,
                transform: `translateY(${virtualRow.start}px)`
              }}
            >
              {renderRow(item)}
            </div>
          );
        })}
      </div>
    </div>
  );
}

function useVirtualTableHeaderScrollSync<T>(
  scrollParentRef: RefObject<HTMLDivElement | null>,
  items: T[]
) {
  useLayoutEffect(() => {
    const scrollElement = scrollParentRef.current;
    const tableElement = scrollElement?.parentElement;

    if (!scrollElement || !tableElement) {
      return undefined;
    }

    const syncScrollState = () => {
      tableElement.style.setProperty(
        '--virtual-table-scroll-x',
        `${scrollElement.scrollLeft}px`
      );
      tableElement.style.setProperty(
        '--virtual-table-scroll-width',
        `${Math.max(scrollElement.scrollWidth, scrollElement.clientWidth)}px`
      );
    };

    syncScrollState();
    scrollElement.addEventListener('scroll', syncScrollState, { passive: true });

    const resizeObserver =
      typeof ResizeObserver === 'undefined' ? null : new ResizeObserver(syncScrollState);

    resizeObserver?.observe(scrollElement);
    const spacerElement = scrollElement.querySelector('.virtual-table-spacer');

    if (spacerElement instanceof HTMLElement) {
      resizeObserver?.observe(spacerElement);
    }

    return () => {
      scrollElement.removeEventListener('scroll', syncScrollState);
      resizeObserver?.disconnect();
      tableElement.style.removeProperty('--virtual-table-scroll-x');
      tableElement.style.removeProperty('--virtual-table-scroll-width');
    };
  }, [items, scrollParentRef]);
}

function HealthSection({
  bridgeDiagnostics,
  draftPaths,
  health,
  isBusy,
  isDesktopAvailable,
  isOutputRootCreating,
  isSvCacheWarming,
  isSupportSearchRunning,
  onChangeGame,
  onCreateOutputRootFolder,
  onOpenOutputRoot,
  onPickProjectPath,
  onRequestSupportSearch,
  onSetDraftPath,
  onValidateProject,
  pendingEditCount,
  projectStatus,
  selectedGame,
  svCacheStatus
}: {
  bridgeDiagnostics: ApiDiagnostic[];
  draftPaths: ProjectPathDraft;
  health: ProjectHealth | null;
  isBusy: boolean;
  isDesktopAvailable: boolean;
  isOutputRootCreating: boolean;
  isSvCacheWarming: boolean;
  isSupportSearchRunning: boolean;
  onChangeGame: () => void;
  onCreateOutputRootFolder: () => void;
  onOpenOutputRoot: () => void;
  onPickProjectPath: (pathField: ProjectPathField) => void;
  onRequestSupportSearch: () => void;
  onSetDraftPath: (field: ProjectPathFieldName, value: string) => void;
  onValidateProject: () => void;
  pendingEditCount: number;
  projectStatus: 'idle' | 'validating' | 'opening' | 'open';
  selectedGame: ProjectGame;
  svCacheStatus: TrinityCacheStatus | null;
}) {
  const outputRootPath = draftPaths.outputRootPath.trim();
  const gameDefinition = gameDefinitions[selectedGame];
  const GameIcon = gameDefinition.icon;
  const visiblePathFields = pathFields.filter((pathField) =>
    isProjectPathFieldVisible(pathField, selectedGame)
  );
  const canShowSvCacheProgress = Boolean(
    health &&
      isTrinityCacheGame(selectedGame) &&
      health.canOpenEditableWorkflows &&
      hasValidTrinitySupportFolder(selectedGame, health) &&
      svCacheStatus
  );
  const cacheTitle = getTrinityCacheTitle(selectedGame);

  return (
    <>
      <section aria-labelledby="project-gate-heading" className="panel project-gate">
        <div className="panel-heading">
          <FolderOpen aria-hidden="true" size={18} />
          <h2 id="project-gate-heading">Project Paths</h2>
        </div>

        <div className="selected-game-banner">
          <div className="selected-game-label">
            <GameIcon aria-hidden="true" size={22} />
            <span>{gameDefinition.title}</span>
          </div>
          <code>{gameDefinition.titleId}</code>
          <button
            className="secondary-button"
            disabled={isBusy || pendingEditCount > 0}
            onClick={onChangeGame}
            type="button"
          >
            <ArrowLeftRight aria-hidden="true" size={18} />
            <span>Change Game</span>
          </button>
        </div>

        <div className="path-form">
          {visiblePathFields.map((pathField) => {
            const pathValidation = health?.paths.find((path) => path.role === pathField.role);
            const inputId = `${pathField.field}-input`;

            return (
              <div className="path-field" key={pathField.field}>
                <label htmlFor={inputId}>{pathField.label}</label>
                <div className="path-input-row">
                  <input
                    aria-describedby={`${pathField.field}-status`}
                    id={inputId}
                    onChange={(event) => onSetDraftPath(pathField.field, event.target.value)}
                    placeholder="Not set"
                    value={draftPaths[pathField.field]}
                  />
                  <button
                    aria-label={`Browse for ${pathField.label}`}
                    className="secondary-button icon-button"
                    disabled={!isDesktopAvailable || isBusy}
                    onClick={() => onPickProjectPath(pathField)}
                    title={`Browse for ${pathField.label}`}
                    type="button"
                  >
                    {pathField.kind === 'file' ? (
                      <Save aria-hidden="true" size={18} />
                    ) : (
                      <FolderOpen aria-hidden="true" size={18} />
                    )}
                  </button>
                </div>
                <small
                  className={getPathStatusClassName(pathValidation)}
                  id={`${pathField.field}-status`}
                >
                  {pathValidation ? pathStatusLabels[pathValidation.status] : 'Not checked'}
                </small>
              </div>
            );
          })}
        </div>

        <div className="action-row">
          <button
            aria-busy={(projectStatus === 'validating') || undefined}
            className="secondary-button"
            disabled={isBusy}
            onClick={onValidateProject}
            type="button"
          >
            <BusyActionContent
              busyLabel="Validating"
              icon={<RefreshCw aria-hidden="true" size={18} />}
              isBusy={projectStatus === 'validating'}
              label="Validate Paths"
              size={18}
            />
          </button>
          <button
            className="secondary-button"
            disabled={!isDesktopAvailable || isBusy || outputRootPath.length === 0}
            onClick={onOpenOutputRoot}
            type="button"
          >
            <ExternalLink aria-hidden="true" size={18} />
            <span>Open Output Root</span>
          </button>
          <button
            aria-busy={isOutputRootCreating || undefined}
            className="secondary-button"
            disabled={
              !isDesktopAvailable ||
              isBusy ||
              isOutputRootCreating ||
              outputRootPath.length > 0
            }
            onClick={onCreateOutputRootFolder}
            type="button"
          >
            <BusyActionContent
              busyLabel="Creating Output Root Folder"
              icon={<Plus aria-hidden="true" size={18} />}
              isBusy={isOutputRootCreating}
              label="Create Output Root Folder"
              size={18}
            />
          </button>
          {isTrinityCacheGame(selectedGame) ? (
            <button
              aria-busy={isSupportSearchRunning || undefined}
              className="secondary-button"
              disabled={!isDesktopAvailable || isBusy || isSupportSearchRunning}
              onClick={onRequestSupportSearch}
              title="Search local drives for oo2core_8_win64.dll and fill the folder."
              type="button"
            >
              <BusyActionContent
                busyLabel="Finding oo2core_8_win64.dll"
                icon={<Search aria-hidden="true" size={18} />}
                isBusy={isSupportSearchRunning}
                label="Find oo2core_8_win64.dll"
                size={18}
              />
            </button>
          ) : null}
        </div>

        {canShowSvCacheProgress && svCacheStatus ? (
          <SvCacheProgressPanel
            cacheTitle={cacheTitle}
            isWarming={isSvCacheWarming}
            status={svCacheStatus}
          />
        ) : null}
      </section>

      <section aria-labelledby="health-heading" className="panel">
        <div className="panel-heading">
          <ShieldCheck aria-hidden="true" size={18} />
          <h2 id="health-heading">Health Summary</h2>
        </div>

        <div className="health-grid">
          <Metric label="State" value={health ? healthLabels[health.state] : 'No project'} />
          <Metric
            label="Read-only workflows"
            value={health?.canOpenReadOnlyWorkflows ? 'Enabled' : 'Disabled'}
          />
          <Metric
            label="Write workflows"
            value={health?.canOpenEditableWorkflows ? 'Enabled' : 'Disabled'}
          />
          <Metric label="Pending changes" value={pendingEditCount.toString()} />
        </div>
      </section>

      <DiagnosticsSection diagnostics={[...bridgeDiagnostics, ...(health?.diagnostics ?? [])]} />
    </>
  );
}

function SvCacheProgressPanel({
  cacheTitle,
  isWarming,
  status
}: {
  cacheTitle: string;
  isWarming: boolean;
  status: TrinityCacheStatus;
}) {
  const isMinimal = status.settings.mode === 'minimal';
  const percent = Math.max(0, Math.min(100, status.progressPercent));
  const phaseLabel = isMinimal
    ? 'Off'
    : isWarming
      ? 'Building'
      : percent >= 100
        ? 'Ready'
        : status.warmupCompleted > 0
          ? 'Partially built'
          : 'Ready to build';
  const message = isMinimal
    ? `Persistent ${cacheTitle} warmup is off in Minimal mode.`
    : status.message;

  return (
    <div className="sv-cache-progress-panel" role="status">
      <div className="sv-cache-progress-header">
        <div>
          <Layers aria-hidden="true" size={18} />
          <strong>{cacheTitle}</strong>
        </div>
        <span className="status-pill status-pill-info">{phaseLabel}</span>
      </div>
      {!isMinimal ? (
        <div
          aria-label={`${cacheTitle} build progress`}
          aria-valuemax={100}
          aria-valuemin={0}
          aria-valuenow={percent}
          className="work-progress-track"
          role="progressbar"
        >
          <div className="work-progress-fill" style={{ width: `${percent}%` }} />
        </div>
      ) : null}
      <dl className="work-progress-detail">
        <div>
          <dt>Mode</dt>
          <dd>{formatSvCacheModeLabel(status.settings.mode)}</dd>
        </div>
        {!isMinimal ? (
          <div>
            <dt>Progress</dt>
            <dd>
              {percent}% ({status.warmupCompleted} of {status.warmupTotal})
            </dd>
          </div>
        ) : null}
        <div>
          <dt>Cache size</dt>
          <dd>{formatByteSize(status.cacheSizeBytes)}</dd>
        </div>
      </dl>
      <p className="sv-cache-progress-message">{message}</p>
    </div>
  );
}

type ItemsSectionProps = {
  editSession: EditSession | null;
  editorFamily: EditorUiFamily;
  isEditStarting: boolean;
  isItemUpdating: boolean;
  onSearchChange: (searchText: string) => void;
  onSelectItem: (itemId: number | null) => void;
  onStartEditSession: () => void;
  onUpdateItemFields: (
    itemId: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  searchText: string;
  selectedItemId: number | null;
  workflow: ItemsWorkflow | null;
};

type ItemsSectionPublicProps = Omit<ItemsSectionProps, 'editorFamily'>;

function SwShItemsSection(props: ItemsSectionPublicProps) {
  return <ItemsSection {...props} editorFamily="swsh" />;
}

function SvItemsSection(props: ItemsSectionPublicProps) {
  return <ItemsSection {...props} editorFamily="sv" />;
}

function ZaItemsSection(props: ItemsSectionPublicProps) {
  return <ItemsSection {...props} editorFamily="za" />;
}

function ItemsSection({
  editSession,
  editorFamily,
  isEditStarting,
  isItemUpdating,
  onSearchChange,
  onSelectItem,
  onStartEditSession,
  onUpdateItemFields,
  searchText,
  selectedItemId,
  workflow
}: ItemsSectionProps) {
  const items = useMemo(
    () => (workflow?.items ?? []).filter((item) => item.itemId !== 0),
    [workflow?.items]
  );
  const filteredItems = useMemo(() => filterItems(items, searchText), [items, searchText]);
  const selectedItem = useMemo(
    () => filteredItems.find((item) => item.itemId === selectedItemId) ?? filteredItems[0] ?? null,
    [filteredItems, selectedItemId]
  );
  const canEditItems = workflow?.summary.availability === 'available';
  const pendingItemIds = useMemo(
    () => getPendingItemIds(editSession, items),
    [editSession, items]
  );
  const secondaryPriceLabels = getItemSecondaryPriceLabels(editorFamily);

  return (
    <>
      <section
        aria-labelledby="items-heading"
        className={`panel wide-panel ${editorFamily}-editor-surface ${editorFamily}-items-section`}
      >
        <div className="panel-heading">
          <Package aria-hidden="true" size={18} />
          <h2 id="items-heading">Items</h2>
        </div>

        <div className="items-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label="Search items"
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder="Search items"
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label="Loaded records"
            value={workflow ? workflow.stats.totalItemCount.toString() : '0'}
          />
          <Metric
            label="Pending changes"
            value={(editSession?.pendingEdits.length ?? 0).toString()}
          />
        </div>

        {workflow ? (
          <div className="items-layout">
            <div
              aria-colcount={8}
              aria-label="Items"
              aria-rowcount={filteredItems.length + 1}
              className="items-table"
              role="table"
            >
              <div className="items-row items-row-heading" role="row">
                <span role="columnheader">ID</span>
                <span role="columnheader">Name</span>
                <span role="columnheader">Category</span>
                <span role="columnheader">Buy</span>
                <span role="columnheader">Sell</span>
                <span role="columnheader">{secondaryPriceLabels.primary}</span>
                <span role="columnheader">{secondaryPriceLabels.secondary}</span>
                <span role="columnheader">Source</span>
              </div>
              <VirtualTableBody
                getKey={(item) => item.itemId}
                items={filteredItems}
                renderRow={(item) => (
                  <button
                    className={`items-row ${selectedItem?.itemId === item.itemId ? 'items-row-selected' : ''} ${
                      pendingItemIds.has(item.itemId) ? 'items-row-pending' : ''
                    }`}
                    onClick={() => onSelectItem(item.itemId)}
                    role="row"
                    type="button"
                  >
                    <span role="cell">{item.itemId}</span>
                    <span role="cell">{item.name}</span>
                    <span role="cell">{item.category}</span>
                    <span role="cell">{item.buyPrice}</span>
                    <span role="cell">{item.sellPrice}</span>
                    <span role="cell">{item.wattsPrice}</span>
                    <span role="cell">{item.alternatePrice}</span>
                    <span role="cell">{formatSourceLayer(item.provenance.sourceLayer)}</span>
                  </button>
                )}
              />
            </div>

            <SelectedItemPanel
              canEditItems={canEditItems}
              editSession={editSession}
              editorFamily={editorFamily}
              isEditStarting={isEditStarting}
              isItemUpdating={isItemUpdating}
              item={selectedItem}
              editableFields={workflow.editableFields}
              onStartEditSession={onStartEditSession}
              onUpdateItemFields={onUpdateItemFields}
            />
          </div>
        ) : (
          <p className="empty-copy">Open Items from Workflows to load backend item data.</p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
    </>
  );
}

function getItemSecondaryPriceLabels(editorFamily: EditorUiFamily) {
  switch (editorFamily) {
    case 'sv':
      return { primary: 'BP', secondary: 'Unused' };
    case 'za':
      return { primary: 'Mega Shards', secondary: 'Colorful Screws' };
    default:
      return { primary: 'Watts', secondary: 'Alt' };
  }
}

function SelectedItemPanel({
  canEditItems,
  editSession,
  editorFamily,
  editableFields,
  isEditStarting,
  isItemUpdating,
  item,
  onStartEditSession,
  onUpdateItemFields
}: {
  canEditItems: boolean;
  editSession: EditSession | null;
  editorFamily: EditorUiFamily;
  editableFields: ItemEditableField[];
  isEditStarting: boolean;
  isItemUpdating: boolean;
  item: ItemRecord | null;
  onStartEditSession: () => void;
  onUpdateItemFields: (
    itemId: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
}) {
  const [fieldDraftsByItemId, setFieldDraftsByItemId] = useState<
    Record<string, Record<string, string>>
  >({});
  const cancelActiveEditSession = useCancelActiveEditSession();
  const itemFieldGroups = useMemo(
    () => groupNumericEditableFields(editableFields, getItemEditableFieldGroup),
    [editableFields]
  );
  const itemDraftDefaults = useMemo(
    () =>
      item
        ? Object.fromEntries(
            editableFields.map((field) => [
              field.field,
              (getEditableItemFieldValue(item, field.field) ?? '').toString()
            ])
          )
        : {},
    [editableFields, item]
  );
  const itemDraftKey = item ? getItemStorageDraftKey(item) : null;
  const sparseFieldDrafts =
    itemDraftKey === null ? {} : (fieldDraftsByItemId[itemDraftKey] ?? {});
  const fieldDrafts = item ? { ...itemDraftDefaults, ...sparseFieldDrafts } : {};
  const writableItemFields = useMemo(
    () =>
      new Set(
        editableFields
          .filter((field) => getItemFieldDisabledReason(field, editorFamily, item) === null)
          .map((field) => field.field)
      ),
    [editableFields, editorFamily, item]
  );
  const itemDraftSummary = useMemo(
    () =>
      getTrainerDraftSummary(
        editableFields,
        fieldDrafts,
        item ? (field) => getEditableItemFieldValue(item, field) : null
      ),
    [editableFields, fieldDrafts, item]
  );
  const stagedItemChanges = useMemo(
    () => normalizeLinkedItemPriceChanges(itemDraftSummary.changedFields),
    [itemDraftSummary.changedFields]
  );
  useRegisterEditorDraftDirty('items', countFieldDraftRecords(fieldDraftsByItemId) > 0);
  const canSaveItemDrafts =
    item !== null &&
    editSession !== null &&
    canEditItems &&
    !isItemUpdating &&
    itemDraftSummary.changedFields.length > 0 &&
    itemDraftSummary.invalidFields.length === 0;

  useEffect(() => {
    if (!item) {
      return;
    }

    setFieldDraftsByItemId((currentDrafts) =>
      pruneSparseFieldDraftRecord(
        currentDrafts,
        getItemStorageDraftKey(item),
        itemDraftDefaults,
        writableItemFields
      )
    );
  }, [item, itemDraftDefaults, writableItemFields]);

  return (
    <aside aria-label="Selected item provenance" className="item-inspector">
      <div className="panel-heading">
        <ShieldCheck aria-hidden="true" size={18} />
        <h3>Selected Item</h3>
      </div>

      {item ? (
        <>
          <dl className="item-provenance-list">
            <div>
              <dt>Name</dt>
              <dd>{item.name}</dd>
            </div>
            <div>
              <dt>Source file</dt>
              <dd>{item.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>Layer</dt>
              <dd>{formatSourceLayer(item.provenance.sourceLayer)}</dd>
            </div>
            <div>
              <dt>File state</dt>
              <dd>{formatFileState(item.provenance.fileState)}</dd>
            </div>
            <div>
              <dt>Shared row</dt>
              <dd>{formatSharedItemIds(item)}</dd>
            </div>
          </dl>

          <div className="item-edit-form">
            {editSession ? (
              <div className="draft-action-row">
                <button
                  aria-busy={isItemUpdating || undefined}
                  className="primary-button"
                  disabled={!canSaveItemDrafts}
                  onClick={async () => {
                    const didSave = await onUpdateItemFields(
                      item.itemId,
                      stagedItemChanges.map((change) => ({
                        field: change.field,
                        value: change.value
                      }))
                    );
                    if (didSave) {
                      setFieldDraftsByItemId((currentDrafts) =>
                        deleteFieldDraftRecord(
                          currentDrafts,
                          getItemStorageDraftKey(item)
                        )
                      );
                    }
                  }}
                  type="button"
                >
                  <BusyActionContent
                    busyLabel="Staging"
                    icon={<Save aria-hidden="true" size={16} />}
                    isBusy={isItemUpdating}
                    label="Stage"
                  />
                </button>
                <button
                  className="danger-button"
                  disabled={isItemUpdating}
                  onClick={() =>
                    cancelActiveEditSession(() =>
                      setFieldDraftsByItemId({})
                    )
                  }
                  type="button"
                >
                  <X aria-hidden="true" size={16} />
                  <span>Cancel</span>
                </button>
                <span className="draft-action-summary">{formatDraftSummary(itemDraftSummary)}</span>
              </div>
            ) : (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditItems || isEditStarting}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            )}

            <div className="editable-field-groups">
              {itemFieldGroups.map((group) => (
                <fieldset className="editable-field-group" key={group.group}>
                  <legend>{group.group}</legend>
                  <div className="editable-field-grid">
                    {group.fields.map((field) => {
                      const currentValue = getEditableItemFieldValue(item, field.field);
                      const draftValue = fieldDrafts[field.field] ?? '';
                      const draftState = getTrainerFieldDraftState(
                        draftValue,
                        currentValue,
                        field
                      );
                      const disabledReason = getItemFieldDisabledReason(field, editorFamily, item);

                      return (
                        <GiftPokemonDraftField
                          currentValue={currentValue}
                          disabled={
                            !canEditItems ||
                            editSession === null ||
                            isItemUpdating ||
                            disabledReason !== null
                          }
                          disabledReason={disabledReason ?? undefined}
                          draftState={draftState}
                          draftValue={draftValue}
                          field={field}
                          idPrefix="item-field"
                          key={field.field}
                          onChange={(value) => {
                            const nextDrafts = synchronizeLinkedItemPriceDrafts(
                              field.field,
                              value,
                              {
                                ...fieldDrafts,
                                [field.field]: value
                              },
                              itemDraftDefaults
                            );
                            setFieldDraftsByItemId((currentDrafts) =>
                              setSparseFieldDraftRecord(
                                currentDrafts,
                                getItemStorageDraftKey(item),
                                nextDrafts,
                                itemDraftDefaults
                              )
                            );
                          }}
                        />
                      );
                    })}
                  </div>
                </fieldset>
              ))}
            </div>
          </div>

          {item.detailGroups.map((group) => (
            <section className="inspector-block" key={group.label}>
              <h4>{group.label}</h4>
              <dl className="item-provenance-list compact-dl">
                {group.details.map((detail) => (
                  <div key={`${group.label}:${detail.label}`}>
                    <dt>{detail.label}</dt>
                    <dd>{detail.value}</dd>
                  </div>
                ))}
              </dl>
            </section>
          ))}
        </>
      ) : (
        <p className="empty-copy">No item selected.</p>
      )}
    </aside>
  );
}

function isPlaceholderPokemonRecord(pokemon: Pick<PokemonRecord, 'name' | 'personalId'>) {
  return Number(pokemon.personalId) === 0 || pokemon.name.trim().toLowerCase() === 'egg';
}

type PokemonSectionProps = {
  editSession: EditSession | null;
  editorFamily: EditorUiFamily;
  isEditStarting: boolean;
  isPokemonUpdating: boolean;
  onSearchChange: (searchText: string) => void;
  onSelectPokemon: (personalId: number | null) => void;
  onStartEditSession: () => void;
  onUpdatePokemonField: (personalId: number, field: string, value: string) => void;
  onUpdatePokemonFields: (
    personalId: number,
    changes: Array<{ field: string; value: string }>,
    evolutionChanges?: PokemonEvolutionDraftChange[],
    learnsetChanges?: PokemonLearnsetDraftChange[]
  ) => Promise<boolean>;
  onUpdatePokemonEvolution: (
    personalId: number,
    action: string,
    slot: number | null,
    method: number | null,
    argument: number | null,
    species: number | null,
    form: number | null,
    level: number | null
  ) => Promise<boolean>;
  onUpdatePokemonLearnset: (
    personalId: number,
    action: string,
    slot: number | null,
    moveId: number | null,
    level: number | null
  ) => Promise<boolean>;
  searchText: string;
  selectedPokemonPersonalId: number | null;
  workflow: PokemonWorkflow | null;
};

type PokemonSectionPublicProps = Omit<PokemonSectionProps, 'editorFamily'>;

function SwShPokemonSection(props: PokemonSectionPublicProps) {
  return <PokemonSection {...props} editorFamily="swsh" />;
}

function SvPokemonSection(props: PokemonSectionPublicProps) {
  return <PokemonSection {...props} editorFamily="sv" />;
}

function ZaPokemonSection(props: PokemonSectionPublicProps) {
  return <PokemonSection {...props} editorFamily="za" />;
}

function PokemonSection({
  editSession,
  editorFamily,
  isEditStarting,
  isPokemonUpdating,
  onSearchChange,
  onSelectPokemon,
  onStartEditSession,
  onUpdatePokemonField,
  onUpdatePokemonFields,
  onUpdatePokemonEvolution,
  onUpdatePokemonLearnset,
  searchText,
  selectedPokemonPersonalId,
  workflow
}: PokemonSectionProps) {
  const pokemon = workflow?.pokemon ?? [];
  const filteredPokemon = useMemo(
    () => filterPokemon(pokemon, searchText, editorFamily),
    [editorFamily, pokemon, searchText]
  );
  const selectedPokemon = useMemo(
    () => {
      const selectedPokemonId =
        selectedPokemonPersonalId === null ? null : Number(selectedPokemonPersonalId);
      const explicitlySelectedPokemon =
        selectedPokemonId === null || selectedPokemonId === 0
          ? null
          : filteredPokemon.find(
              (candidate) =>
                Number(candidate.personalId) === selectedPokemonId &&
                !isPlaceholderPokemonRecord(candidate)
            );

      return (
        explicitlySelectedPokemon ??
        filteredPokemon.find((candidate) => !isPlaceholderPokemonRecord(candidate)) ??
        filteredPokemon[0] ??
        null
      );
    },
    [filteredPokemon, selectedPokemonPersonalId]
  );

  useEffect(() => {
    if (
      selectedPokemon !== null &&
      (selectedPokemonPersonalId === null ||
        Number(selectedPokemon.personalId) !== Number(selectedPokemonPersonalId))
    ) {
      onSelectPokemon(selectedPokemon.personalId);
    }
  }, [onSelectPokemon, selectedPokemon, selectedPokemonPersonalId]);

  const canEditPokemon = workflow?.summary.availability === 'available';
  const pendingPokemonIds = useMemo(() => getPendingPokemonIds(editSession), [editSession]);
  const canBulkUpdatePokemonYield = workflow !== null && canEditPokemon && !isPokemonUpdating;
  const [expYieldConfirmation, setExpYieldConfirmation] =
    useState<PokemonYieldConfirmationState>(null);
  const [evYieldConfirmation, setEvYieldConfirmation] =
    useState<PokemonYieldConfirmationState>(null);
  const handleConfirmExpYieldAction = useCallback(() => {
    if (expYieldConfirmation === 'remove') {
      onUpdatePokemonField(0, pokemonGlobalExpYieldFieldName, pokemonRemoveEvYieldValue);
    } else if (expYieldConfirmation === 'restore') {
      onUpdatePokemonField(0, pokemonGlobalExpYieldFieldName, pokemonRestoreEvYieldValue);
    }

    setExpYieldConfirmation(null);
  }, [expYieldConfirmation, onUpdatePokemonField]);
  const handleConfirmEvYieldAction = useCallback(() => {
    if (evYieldConfirmation === 'remove') {
      onUpdatePokemonField(0, pokemonGlobalEvYieldFieldName, pokemonRemoveEvYieldValue);
    } else if (evYieldConfirmation === 'restore') {
      onUpdatePokemonField(0, pokemonGlobalEvYieldFieldName, pokemonRestoreEvYieldValue);
    }

    setEvYieldConfirmation(null);
  }, [evYieldConfirmation, onUpdatePokemonField]);
  const pokemonDiagnostics =
    workflow && selectedPokemon ? (
      <div className={`${editorFamily}-pokemon-diagnostics-row`}>
        <DiagnosticsSection diagnostics={workflow.diagnostics} />
        <SelectedPokemonSummaryCard
          editorFamily={editorFamily}
          pokemon={selectedPokemon}
          variant="context"
        />
      </div>
    ) : (
      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
    );

  return (
    <>
      <section
        aria-labelledby="pokemon-heading"
        className={`panel wide-panel ${editorFamily}-editor-surface ${editorFamily}-pokemon-section`}
      >
        <div className="panel-heading">
          <Dna aria-hidden="true" size={18} />
          <h2 id="pokemon-heading">Pokemon</h2>
        </div>

        <div className="items-toolbar pokemon-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label="Search Pokemon"
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder="Search Pokemon"
              type="search"
              value={searchText}
            />
          </label>
          <div className="pokemon-toolbar-side">
            <div className="pokemon-toolbar-metrics">
              <Metric
                label="Loaded records"
                value={workflow ? workflow.stats.totalPokemonCount.toString() : '0'}
              />
              <Metric
                label="Present"
                value={workflow ? workflow.stats.presentPokemonCount.toString() : '0'}
              />
              <Metric
                label="Learnset moves"
                value={workflow ? workflow.stats.totalLearnsetMoveCount.toString() : '0'}
              />
            </div>
            {editorFamily !== 'za' ? (
            <div className="pokemon-toolbar-actions">
              <button
                className="primary-button compact-button"
                disabled={!canBulkUpdatePokemonYield}
                onClick={() => setExpYieldConfirmation('remove')}
                type="button"
              >
                <Trash2 aria-hidden="true" size={14} />
                <span>Remove EXP Yield</span>
              </button>
              <button
                className="primary-button compact-button"
                disabled={!canBulkUpdatePokemonYield}
                onClick={() => setExpYieldConfirmation('restore')}
                type="button"
              >
                <RefreshCw aria-hidden="true" size={14} />
                <span>Restore EXP Yield</span>
              </button>
              <button
                className="primary-button compact-button"
                disabled={!canBulkUpdatePokemonYield}
                onClick={() => setEvYieldConfirmation('remove')}
                type="button"
              >
                <Trash2 aria-hidden="true" size={14} />
                <span>Remove EV Yield</span>
              </button>
              <button
                className="primary-button compact-button"
                disabled={!canBulkUpdatePokemonYield}
                onClick={() => setEvYieldConfirmation('restore')}
                type="button"
              >
                <RefreshCw aria-hidden="true" size={14} />
                <span>Restore EV Yield</span>
              </button>
            </div>
            ) : null}
          </div>
        </div>

        {workflow ? (
          <div className={`items-layout ${editorFamily}-pokemon-layout`}>
            <SelectedPokemonPanel
              canEditPokemon={canEditPokemon}
              editSession={editSession}
              editorFamily={editorFamily}
              editableFields={workflow.editableFields}
              evolutionMethodOptions={workflow.evolutionMethodOptions}
              isEditStarting={isEditStarting}
              isPokemonUpdating={isPokemonUpdating}
              learnsetMoveOptions={workflow.learnsetMoveOptions}
              onStartEditSession={onStartEditSession}
              pokemonTable={
                <div
                  aria-colcount={3}
                  aria-label="Pokemon"
                  aria-rowcount={filteredPokemon.length + 1}
                  className="items-table pokemon-table"
                  role="table"
                >
                  <div className="items-row items-row-heading" role="row">
                    <span role="columnheader">ID</span>
                    <span role="columnheader">Name</span>
                    <span role="columnheader">Types</span>
                  </div>
                  <VirtualTableBody
                    getKey={(record) => record.personalId}
                    items={filteredPokemon}
                    renderRow={(record) => {
                      return (
                        <button
                          className={`items-row ${
                            selectedPokemon?.personalId === record.personalId
                              ? 'items-row-selected'
                              : ''
                          } ${pendingPokemonIds.has(record.personalId) ? 'moves-row-pending' : ''}`}
                          onClick={() => onSelectPokemon(record.personalId)}
                          role="row"
                          type="button"
                        >
                          <span role="cell">{record.personalId}</span>
                          <span data-localization-ignore="true" role="cell">
                            {formatPokemonRecordName(record, editorFamily)}
                          </span>
                          <span data-localization-ignore="true" role="cell">
                            {formatPokemonTypes(record)}
                          </span>
                        </button>
                      );
                    }}
                  />
                </div>
              }
              onUpdatePokemonField={onUpdatePokemonField}
              onUpdatePokemonFields={onUpdatePokemonFields}
              onUpdatePokemonEvolution={onUpdatePokemonEvolution}
              onUpdatePokemonLearnset={onUpdatePokemonLearnset}
              pokemon={selectedPokemon}
              pokemonRecords={pokemon}
            />
          </div>
        ) : (
          <p className="empty-copy">Open Pokemon from the sidebar to load backend Pokemon data.</p>
        )}
      </section>

      {pokemonDiagnostics}
      {expYieldConfirmation ? (
        <PokemonYieldConfirmationModal
          action={expYieldConfirmation}
          kind="exp"
          onCancel={() => setExpYieldConfirmation(null)}
          onConfirm={handleConfirmExpYieldAction}
        />
      ) : null}
      {evYieldConfirmation ? (
        <PokemonYieldConfirmationModal
          action={evYieldConfirmation}
          kind="ev"
          onCancel={() => setEvYieldConfirmation(null)}
          onConfirm={handleConfirmEvYieldAction}
        />
      ) : null}
    </>
  );
}

function SelectedPokemonSummaryCard({
  editorFamily,
  pokemon,
  variant = 'detailed'
}: {
  editorFamily: EditorUiFamily;
  pokemon: PokemonRecord;
  variant?: 'context' | 'detailed';
}) {
  const isContext = variant === 'context';
  const pokemonLabel = formatPokemonRecordName(pokemon, editorFamily);
  const pokemonFormLabel = formatSpeciesFormOptionLabel(pokemon.form, {
    gameFamily: editorFamily,
    species: pokemon.name,
    speciesId: pokemon.speciesId
  });

  return (
    <div
      className={`${editorFamily}-pokemon-summary-card pokemon-summary-card ${
        isContext ? 'pokemon-summary-card-context' : 'pokemon-summary-card-detailed'
      }`}
    >
      <PokemonSprite
        className="pokemon-summary-sprite"
        editorFamily={editorFamily}
        form={pokemon.form}
        name={pokemonLabel}
        speciesId={pokemon.speciesId}
        spriteName={pokemon.spriteName}
      />
      <div className="pokemon-summary-main">
        <strong data-localization-ignore="true">{pokemonLabel}</strong>
        <span data-localization-ignore="true">
          {pokemon.speciesId} / {pokemonFormLabel}
        </span>
      </div>
      <dl className="item-provenance-list pokemon-summary-metadata">
        <div>
          <dt>Personal ID</dt>
          <dd>{pokemon.personalId}</dd>
        </div>
        <div>
          <dt>Types</dt>
          <dd data-localization-ignore="true">{formatPokemonTypes(pokemon)}</dd>
        </div>
        <div>
          <dt>Dex</dt>
          <dd>{formatPokemonDexPresence(pokemon)}</dd>
        </div>
        {!isContext ? (
          <>
            <div>
              <dt>Source file</dt>
              <dd>{pokemon.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>Layer</dt>
              <dd>{formatSourceLayer(pokemon.provenance.sourceLayer)}</dd>
            </div>
            <div>
              <dt>File state</dt>
              <dd>{formatFileState(pokemon.provenance.fileState)}</dd>
            </div>
          </>
        ) : null}
      </dl>
    </div>
  );
}

function formatPokemonRecordName(pokemon: PokemonRecord, editorFamily: EditorUiFamily) {
  return formatSpeciesFormLabel(pokemon.name, pokemon.form, pokemon.speciesId, editorFamily);
}

function getPokemonSpriteNameForSpecies(
  pokemonRecords: PokemonRecord[],
  speciesId: number,
  form: number,
  editorFamily: EditorUiFamily,
  fallback: string
) {
  const matchingForm = pokemonRecords.find(
    (record) => record.speciesId === speciesId && record.form === form
  );
  const matchingSpriteName = getPokemonRecordSpriteName(matchingForm);
  if (matchingSpriteName) {
    return formatSpeciesFormLabel(matchingSpriteName, form, speciesId, editorFamily);
  }

  const baseRecord = pokemonRecords.find(
    (record) => record.speciesId === speciesId && record.form === 0
  );
  const baseSpriteName = getPokemonRecordSpriteName(baseRecord);
  if (baseSpriteName) {
    return formatSpeciesFormLabel(baseSpriteName, form, speciesId, editorFamily);
  }

  return matchingForm?.name ?? baseRecord?.name ?? fallback;
}

function getPokemonRecordSpriteName(pokemon?: PokemonRecord | null) {
  return pokemon?.spriteName && pokemon.spriteName.trim().length > 0
    ? pokemon.spriteName
    : null;
}

function SelectedPokemonPanel({
  canEditPokemon,
  editSession,
  editorFamily,
  editableFields,
  evolutionMethodOptions,
  isEditStarting,
  isPokemonUpdating,
  learnsetMoveOptions,
  onStartEditSession,
  pokemonTable,
  onUpdatePokemonField,
  onUpdatePokemonFields,
  onUpdatePokemonEvolution,
  onUpdatePokemonLearnset,
  pokemon,
  pokemonRecords
}: {
  canEditPokemon: boolean;
  editSession: EditSession | null;
  editorFamily: EditorUiFamily;
  editableFields: PokemonEditableField[];
  evolutionMethodOptions: PokemonEvolutionMethodOption[];
  isEditStarting: boolean;
  isPokemonUpdating: boolean;
  learnsetMoveOptions: PokemonEditableFieldOption[];
  onStartEditSession: () => void;
  pokemonTable: ReactNode;
  onUpdatePokemonField: (personalId: number, field: string, value: string) => void;
  onUpdatePokemonFields: (
    personalId: number,
    changes: Array<{ field: string; value: string }>,
    evolutionChanges?: PokemonEvolutionDraftChange[],
    learnsetChanges?: PokemonLearnsetDraftChange[]
  ) => Promise<boolean>;
  onUpdatePokemonEvolution: (
    personalId: number,
    action: string,
    slot: number | null,
    method: number | null,
    argument: number | null,
    species: number | null,
    form: number | null,
    level: number | null
  ) => Promise<boolean>;
  onUpdatePokemonLearnset: (
    personalId: number,
    action: string,
    slot: number | null,
    moveId: number | null,
    level: number | null
  ) => Promise<boolean>;
  pokemon: PokemonRecord | null;
  pokemonRecords: PokemonRecord[];
}) {
  const personalDraftDefaults = useMemo(
    () => createPokemonPersonalDrafts(pokemon, editableFields),
    [editableFields, pokemon]
  );
  const [personalDraftsByPokemonId, setPersonalDraftsByPokemonId] = useState<
    Record<string, Record<string, string>>
  >({});
  const sparsePersonalDrafts = pokemon
    ? personalDraftsByPokemonId[pokemon.personalId.toString()] ?? {}
    : {};
  const personalDrafts = pokemon
    ? { ...personalDraftDefaults, ...sparsePersonalDrafts }
    : {};
  const writablePersonalFields = useMemo(
    () =>
      new Set(
        pokemon
          ? editableFields
              .filter(
                (field) =>
                  getEditablePersonalFieldValue(pokemon, field.field) !== null &&
                  !(field.field === formFieldName && pokemon.personal.formCount <= 1)
              )
              .map((field) => field.field)
          : []
      ),
    [editableFields, pokemon]
  );
  const cancelActiveEditSession = useCancelActiveEditSession();
  const [selectedCompatibilityGroupId, setSelectedCompatibilityGroupId] = useState(
    pokemon?.compatibility[0]?.groupId ?? ''
  );
  const [compatibilitySearchText, setCompatibilitySearchText] = useState('');
  const orderedEvolutions = useMemo(
    () => [...(pokemon?.evolutions ?? [])].sort((left, right) => left.slot - right.slot),
    [pokemon]
  );
  const [selectedEvolutionSlot, setSelectedEvolutionSlot] = useState(
    orderedEvolutions[0]?.slot ?? 0
  );
  const selectedEvolution =
    orderedEvolutions.find((evolution) => evolution.slot === selectedEvolutionSlot) ??
    orderedEvolutions[0] ??
    null;
  const selectedEvolutionIndex =
    selectedEvolution
      ? orderedEvolutions.findIndex((evolution) => evolution.slot === selectedEvolution.slot)
      : -1;
  const previousEvolutionSlot =
    selectedEvolutionIndex > 0
      ? (orderedEvolutions[selectedEvolutionIndex - 1]?.slot ?? null)
      : null;
  const nextEvolutionSlot =
    selectedEvolutionIndex >= 0 && selectedEvolutionIndex < orderedEvolutions.length - 1
      ? (orderedEvolutions[selectedEvolutionIndex + 1]?.slot ?? null)
      : null;
  const [evolutionDraftsByPokemonId, setEvolutionDraftsByPokemonId] = useState<
    Record<string, Record<number, PokemonEvolutionDraftFields>>
  >({});
  const [learnsetDraftsByPokemonId, setLearnsetDraftsByPokemonId] = useState<
    Record<string, Record<number, PokemonLearnsetDraftFields>>
  >({});
  const evolutionDraftsBySlot = pokemon
    ? evolutionDraftsByPokemonId[pokemon.personalId.toString()] ?? {}
    : {};
  const learnsetDraftsBySlot = pokemon
    ? learnsetDraftsByPokemonId[pokemon.personalId.toString()] ?? {}
    : {};
  const pokemonSpeciesOptions = useMemo(
    () => {
      const fieldOptions =
        editableFields.find((field) => field.field === 'hatchedSpecies')?.options ?? [];
      return fieldOptions.length > 0 ? fieldOptions : createPokemonSpeciesOptions(pokemonRecords);
    },
    [editableFields, pokemonRecords]
  );
  const pokemonSpeciesLabels = useMemo(
    () => createPokemonSpeciesLabelMap(pokemonSpeciesOptions, pokemonRecords),
    [pokemonSpeciesOptions, pokemonRecords]
  );
  const [evolutionMethodDraft, setEvolutionMethodDraft] = useState(
    selectedEvolution?.method.toString() ?? ''
  );
  const [evolutionArgumentDraft, setEvolutionArgumentDraft] = useState(
    selectedEvolution?.argument.toString() ?? ''
  );
  const [evolutionSpeciesDraft, setEvolutionSpeciesDraft] = useState(
    selectedEvolution?.species.toString() ?? ''
  );
  const [evolutionFormDraft, setEvolutionFormDraft] = useState(
    selectedEvolution?.form.toString() ?? ''
  );
  const [evolutionLevelDraft, setEvolutionLevelDraft] = useState(
    selectedEvolution?.level.toString() ?? ''
  );
  const [newEvolutionMethodDraft, setNewEvolutionMethodDraft] = useState('');
  const [newEvolutionArgumentDraft, setNewEvolutionArgumentDraft] = useState('0');
  const [newEvolutionSpeciesDraft, setNewEvolutionSpeciesDraft] = useState('');
  const [newEvolutionFormDraft, setNewEvolutionFormDraft] = useState('0');
  const [newEvolutionLevelDraft, setNewEvolutionLevelDraft] = useState('');
  const selectedEvolutionMethodOptions = useMemo(
    () => addCurrentEvolutionMethodOption(evolutionMethodOptions, evolutionMethodDraft),
    [evolutionMethodOptions, evolutionMethodDraft]
  );
  const selectedEvolutionMethodOption = useMemo(
    () => findEvolutionMethodOption(selectedEvolutionMethodOptions, evolutionMethodDraft),
    [evolutionMethodDraft, selectedEvolutionMethodOptions]
  );
  const selectedEvolutionArgumentOptions = useMemo(
    () => addCurrentPokemonFieldOption(
      selectedEvolutionMethodOption?.argumentOptions ?? [],
      evolutionArgumentDraft,
      selectedEvolutionMethodOption?.argumentLabel ?? 'Argument'
    ),
    [
      evolutionArgumentDraft,
      selectedEvolutionMethodOption?.argumentLabel,
      selectedEvolutionMethodOption?.argumentOptions
    ]
  );
  const newEvolutionMethodOptions = useMemo(
    () => addCurrentEvolutionMethodOption(evolutionMethodOptions, newEvolutionMethodDraft),
    [evolutionMethodOptions, newEvolutionMethodDraft]
  );
  const newEvolutionMethodOption = useMemo(
    () => findEvolutionMethodOption(newEvolutionMethodOptions, newEvolutionMethodDraft),
    [newEvolutionMethodDraft, newEvolutionMethodOptions]
  );
  const newEvolutionArgumentOptions = useMemo(
    () => addCurrentPokemonFieldOption(
      newEvolutionMethodOption?.argumentOptions ?? [],
      newEvolutionArgumentDraft,
      newEvolutionMethodOption?.argumentLabel ?? 'Argument'
    ),
    [
      newEvolutionArgumentDraft,
      newEvolutionMethodOption?.argumentLabel,
      newEvolutionMethodOption?.argumentOptions
    ]
  );
  const [selectedLearnsetSlot, setSelectedLearnsetSlot] = useState(
    pokemon?.learnset[0]?.slot ?? 0
  );
  const selectedLearnsetMove =
    pokemon?.learnset.find((move) => move.slot === selectedLearnsetSlot) ??
    pokemon?.learnset[0] ??
    null;
  const [learnsetMoveIdDraft, setLearnsetMoveIdDraft] = useState(
    selectedLearnsetMove?.moveId.toString() ?? ''
  );
  const [learnsetLevelDraft, setLearnsetLevelDraft] = useState(
    selectedLearnsetMove?.level.toString() ?? ''
  );
  const [newLearnsetMoveIdDraft, setNewLearnsetMoveIdDraft] = useState('');
  const [newLearnsetLevelDraft, setNewLearnsetLevelDraft] = useState('');
  const [draggedLearnsetSlot, setDraggedLearnsetSlot] = useState<number | null>(null);
  const [dragOverLearnsetSlot, setDragOverLearnsetSlot] = useState<number | null>(null);
  const learnsetMoveOptionsForDraft = useMemo(
    () => addCurrentPokemonFieldOption(learnsetMoveOptions, learnsetMoveIdDraft, 'Move'),
    [learnsetMoveIdDraft, learnsetMoveOptions]
  );
  const newLearnsetMoveOptions = useMemo(
    () => addCurrentPokemonFieldOption(learnsetMoveOptions, newLearnsetMoveIdDraft, 'Move'),
    [learnsetMoveOptions, newLearnsetMoveIdDraft]
  );

  useRegisterEditorDraftDirty(
    'pokemon',
    countFieldDraftRecords(personalDraftsByPokemonId) > 0 ||
      Object.keys(evolutionDraftsByPokemonId).length > 0 ||
      Object.keys(learnsetDraftsByPokemonId).length > 0
  );

  useEffect(() => {
    if (!pokemon) {
      return;
    }

    setPersonalDraftsByPokemonId((currentDrafts) =>
      pruneSparseFieldDraftRecord(
        currentDrafts,
        pokemon.personalId,
        personalDraftDefaults,
        writablePersonalFields
      )
    );
  }, [personalDraftDefaults, pokemon, writablePersonalFields]);

  useEffect(() => {
    if (!pokemon) {
      return;
    }

    setEvolutionDraftsByPokemonId((currentDrafts) => {
      const pokemonKey = pokemon.personalId.toString();
      const currentPokemonDrafts = currentDrafts[pokemonKey];
      if (!currentPokemonDrafts) {
        return currentDrafts;
      }

      const review = reviewPokemonEvolutionDrafts(
        pokemon,
        currentPokemonDrafts,
        evolutionMethodOptions,
        pokemonSpeciesOptions,
        pokemonSpeciesLabels,
        editorFamily
      );
      if (review.changes.length > 0 || review.invalidCount > 0) {
        return currentDrafts;
      }

      const nextDrafts = { ...currentDrafts };
      delete nextDrafts[pokemonKey];
      return nextDrafts;
    });
  }, [editorFamily, evolutionMethodOptions, pokemon, pokemonSpeciesLabels, pokemonSpeciesOptions]);

  useEffect(() => {
    if (!pokemon) {
      return;
    }

    setLearnsetDraftsByPokemonId((currentDrafts) => {
      const pokemonKey = pokemon.personalId.toString();
      const currentPokemonDrafts = currentDrafts[pokemonKey];
      if (!currentPokemonDrafts) {
        return currentDrafts;
      }

      const review = reviewPokemonLearnsetDrafts(
        pokemon,
        currentPokemonDrafts,
        learnsetMoveOptions,
        editorFamily
      );
      if (review.changes.length > 0 || review.invalidCount > 0) {
        return currentDrafts;
      }

      const nextDrafts = { ...currentDrafts };
      delete nextDrafts[pokemonKey];
      return nextDrafts;
    });
  }, [editorFamily, learnsetMoveOptions, pokemon]);

  useEffect(() => {
    if (!pokemon) {
      setSelectedCompatibilityGroupId('');
      return;
    }

    if (
      pokemon.compatibility.length > 0 &&
      !pokemon.compatibility.some((group) => group.groupId === selectedCompatibilityGroupId)
    ) {
      setSelectedCompatibilityGroupId(pokemon.compatibility[0].groupId);
    }
  }, [pokemon, selectedCompatibilityGroupId]);

  useEffect(() => {
    if (!pokemon || pokemon.learnset.length === 0) {
      setSelectedLearnsetSlot(0);
      return;
    }

    if (!pokemon.learnset.some((move) => move.slot === selectedLearnsetSlot)) {
      setSelectedLearnsetSlot(pokemon.learnset[0].slot);
    }
  }, [pokemon, selectedLearnsetSlot]);

  useEffect(() => {
    if (orderedEvolutions.length === 0) {
      setSelectedEvolutionSlot(0);
      return;
    }

    if (!orderedEvolutions.some((evolution) => evolution.slot === selectedEvolutionSlot)) {
      setSelectedEvolutionSlot(orderedEvolutions[0]!.slot);
    }
  }, [orderedEvolutions, selectedEvolutionSlot]);

  useEffect(() => {
    const localDraft =
      selectedLearnsetMove === null
        ? null
        : learnsetDraftsBySlot[selectedLearnsetMove.slot] ?? null;
    setLearnsetMoveIdDraft(
      localDraft?.moveId ?? selectedLearnsetMove?.moveId.toString() ?? ''
    );
    setLearnsetLevelDraft(
      localDraft?.level ?? selectedLearnsetMove?.level.toString() ?? ''
    );
  }, [
    learnsetDraftsBySlot,
    selectedLearnsetMove?.level,
    selectedLearnsetMove?.moveId,
    selectedLearnsetMove?.slot
  ]);

  useEffect(() => {
    const localDraft =
      selectedEvolution === null ? null : evolutionDraftsBySlot[selectedEvolution.slot] ?? null;
    setEvolutionMethodDraft(
      localDraft?.method ?? selectedEvolution?.method.toString() ?? ''
    );
    setEvolutionArgumentDraft(
      localDraft?.argument ?? selectedEvolution?.argument.toString() ?? ''
    );
    setEvolutionSpeciesDraft(
      localDraft?.species ?? selectedEvolution?.species.toString() ?? ''
    );
    setEvolutionFormDraft(
      localDraft?.form ?? selectedEvolution?.form.toString() ?? ''
    );
    setEvolutionLevelDraft(
      localDraft?.level ?? selectedEvolution?.level.toString() ?? ''
    );
  }, [
    evolutionDraftsBySlot,
    selectedEvolution?.argument,
    selectedEvolution?.form,
    selectedEvolution?.level,
    selectedEvolution?.method,
    selectedEvolution?.slot,
    selectedEvolution?.species
  ]);

  const personalFieldGroups = useMemo(
    () => groupPokemonEditableFields(editableFields),
    [editableFields]
  );
  const updateSelectedEvolutionDraft = useCallback(
    (patch: Partial<PokemonEvolutionDraftFields>) => {
      if (!pokemon || !selectedEvolution) {
        return;
      }

      setEvolutionDraftsByPokemonId((currentDraftsByPokemonId) => {
        const pokemonKey = pokemon.personalId.toString();
        const currentPokemonDrafts = currentDraftsByPokemonId[pokemonKey] ?? {};
        const currentDraft =
          currentPokemonDrafts[selectedEvolution.slot] ??
          createPokemonEvolutionDraftFields(selectedEvolution);
        const nextDraft = { ...currentDraft, ...patch };
        const nextPokemonDrafts = { ...currentPokemonDrafts };

        if (pokemonEvolutionDraftEqualsRecord(nextDraft, selectedEvolution)) {
          delete nextPokemonDrafts[selectedEvolution.slot];
        } else {
          nextPokemonDrafts[selectedEvolution.slot] = nextDraft;
        }

        const nextDraftsByPokemonId = { ...currentDraftsByPokemonId };
        if (Object.keys(nextPokemonDrafts).length === 0) {
          delete nextDraftsByPokemonId[pokemonKey];
        } else {
          nextDraftsByPokemonId[pokemonKey] = nextPokemonDrafts;
        }

        return nextDraftsByPokemonId;
      });
    },
    [pokemon, selectedEvolution]
  );
  const updateSelectedLearnsetDraft = useCallback(
    (patch: Partial<PokemonLearnsetDraftFields>) => {
      if (!pokemon || !selectedLearnsetMove) {
        return;
      }

      setLearnsetDraftsByPokemonId((currentDraftsByPokemonId) => {
        const pokemonKey = pokemon.personalId.toString();
        const currentPokemonDrafts = currentDraftsByPokemonId[pokemonKey] ?? {};
        const currentDraft =
          currentPokemonDrafts[selectedLearnsetMove.slot] ??
          createPokemonLearnsetDraftFields(selectedLearnsetMove);
        const nextDraft = { ...currentDraft, ...patch };
        const nextPokemonDrafts = { ...currentPokemonDrafts };

        if (pokemonLearnsetDraftEqualsRecord(nextDraft, selectedLearnsetMove)) {
          delete nextPokemonDrafts[selectedLearnsetMove.slot];
        } else {
          nextPokemonDrafts[selectedLearnsetMove.slot] = nextDraft;
        }

        const nextDraftsByPokemonId = { ...currentDraftsByPokemonId };
        if (Object.keys(nextPokemonDrafts).length === 0) {
          delete nextDraftsByPokemonId[pokemonKey];
        } else {
          nextDraftsByPokemonId[pokemonKey] = nextPokemonDrafts;
        }

        return nextDraftsByPokemonId;
      });
    },
    [pokemon, selectedLearnsetMove]
  );
  const personalDraftSummary = useMemo(
    () => getPokemonPersonalDraftSummary(pokemon, editableFields, personalDrafts),
    [editableFields, personalDrafts, pokemon]
  );
  const selectedCompatibilityGroup =
    pokemon?.compatibility.find((group) => group.groupId === selectedCompatibilityGroupId) ??
    pokemon?.compatibility[0] ??
    null;
  const filteredCompatibilityEntries = useMemo(
    () =>
      selectedCompatibilityGroup
        ? filterPokemonCompatibilityEntries(selectedCompatibilityGroup, compatibilitySearchText)
        : [],
    [compatibilitySearchText, selectedCompatibilityGroup]
  );
  const canToggleCompatibility = canEditPokemon && editSession !== null && !isPokemonUpdating;
  const canEditEvolution = canEditPokemon && editSession !== null && !isPokemonUpdating;
  const canEditLearnset = canEditPokemon && editSession !== null && !isPokemonUpdating;
  const learnsetMaximumLevel = getPokemonLearnsetMaximumLevel(editorFamily);
  const evolutionMaximumForm = getPokemonEvolutionMaximumForm(editorFamily);
  const evolutionMaximumLevel = getPokemonEvolutionMaximumLevel(editorFamily);
  const hasEvolutionDrafts = Object.keys(evolutionDraftsBySlot).length > 0;
  const hasLearnsetDrafts = Object.keys(learnsetDraftsBySlot).length > 0;
  const canModifyEvolutionStructure = canEditEvolution && !hasEvolutionDrafts;
  const canModifyLearnsetStructure = canEditLearnset && !hasLearnsetDrafts;
  const parsedEvolutionSpecies = parseEditableIntegerDraft(
    evolutionSpeciesDraft,
    pokemonSpeciesOptions
  );
  const selectedEvolutionFormOptions = useMemo(
    () =>
      createEvolutionFormOptions(
        parsedEvolutionSpecies,
        pokemonSpeciesLabels,
        evolutionFormDraft,
        editorFamily
      ),
    [editorFamily, evolutionFormDraft, parsedEvolutionSpecies, pokemonSpeciesLabels]
  );
  const parsedNewEvolutionMethod = parseEditableIntegerDraft(
    newEvolutionMethodDraft,
    newEvolutionMethodOptions
  );
  const parsedNewEvolutionArgument = parseEditableIntegerDraft(
    newEvolutionArgumentDraft,
    newEvolutionArgumentOptions
  );
  const parsedNewEvolutionSpecies = parseEditableIntegerDraft(
    newEvolutionSpeciesDraft,
    pokemonSpeciesOptions
  );
  const newEvolutionFormOptions = useMemo(
    () =>
      createEvolutionFormOptions(
        parsedNewEvolutionSpecies,
        pokemonSpeciesLabels,
        newEvolutionFormDraft,
        editorFamily
      ),
    [editorFamily, newEvolutionFormDraft, parsedNewEvolutionSpecies, pokemonSpeciesLabels]
  );
  const parsedNewEvolutionForm = parseEditableIntegerDraft(
    newEvolutionFormDraft,
    newEvolutionFormOptions
  );
  const parsedNewEvolutionLevel = parseEditableIntegerDraft(newEvolutionLevelDraft);
  const parsedNewLearnsetMoveId = parseEditableIntegerDraft(
    newLearnsetMoveIdDraft,
    newLearnsetMoveOptions
  );
  const parsedNewLearnsetLevel = parseEditableIntegerDraft(newLearnsetLevelDraft);
  const canAddLearnsetMove =
    canModifyLearnsetStructure &&
    (editorFamily !== 'swsh' || (pokemon?.learnset.length ?? 0) < swshPokemonMaximumLearnsetRows) &&
    isIntegerInRange(parsedNewLearnsetMoveId, 0, pokemonMaximumUshortValue) &&
    isIntegerInRange(parsedNewLearnsetLevel, 0, learnsetMaximumLevel) &&
    (editorFamily !== 'swsh' ||
      isValidSwShLearnsetMove(parsedNewLearnsetMoveId, learnsetMoveOptions));
  const handleDropLearnsetMove = useCallback(
    async (targetSlot: number, sourceSlot = draggedLearnsetSlot) => {
      if (
        !canModifyLearnsetStructure ||
        !pokemon ||
        sourceSlot === null ||
        !Number.isInteger(sourceSlot) ||
        sourceSlot === targetSlot
      ) {
        setDraggedLearnsetSlot(null);
        setDragOverLearnsetSlot(null);
        return;
      }

      const didMove = await onUpdatePokemonLearnset(
        pokemon.personalId,
        'moveTo',
        sourceSlot,
        targetSlot,
        null
      );
      if (didMove) {
        setSelectedLearnsetSlot(targetSlot);
      }
      setDraggedLearnsetSlot(null);
      setDragOverLearnsetSlot(null);
    },
    [
      canModifyLearnsetStructure,
      draggedLearnsetSlot,
      onUpdatePokemonLearnset,
      pokemon
    ]
  );
  const evolutionDraftReview = useMemo(
    () =>
      reviewPokemonEvolutionDrafts(
        pokemon,
        evolutionDraftsBySlot,
        evolutionMethodOptions,
        pokemonSpeciesOptions,
        pokemonSpeciesLabels,
        editorFamily
      ),
    [
      editorFamily,
      evolutionDraftsBySlot,
      evolutionMethodOptions,
      pokemon,
      pokemonSpeciesLabels,
      pokemonSpeciesOptions
    ]
  );
  const learnsetDraftReview = useMemo(
    () =>
      reviewPokemonLearnsetDrafts(
        pokemon,
        learnsetDraftsBySlot,
        learnsetMoveOptions,
        editorFamily
      ),
    [editorFamily, learnsetDraftsBySlot, learnsetMoveOptions, pokemon]
  );
  const pokemonDraftInvalidCount =
    personalDraftSummary.invalidFields.length +
    (editSession !== null
      ? evolutionDraftReview.invalidCount + learnsetDraftReview.invalidCount
      : 0);
  const pokemonDraftChangedCount =
    personalDraftSummary.changedFields.length +
    evolutionDraftReview.changes.length +
    learnsetDraftReview.changes.length;
  const canSavePokemonDrafts =
    pokemon !== null &&
    editSession !== null &&
    canEditPokemon &&
    !isPokemonUpdating &&
    pokemonDraftChangedCount > 0 &&
    pokemonDraftInvalidCount === 0;
  const canAddEvolution =
    canModifyEvolutionStructure &&
    (editorFamily !== 'swsh' || orderedEvolutions.length < swshPokemonMaximumEvolutionRows) &&
    isIntegerInRange(parsedNewEvolutionMethod, 0, pokemonMaximumUshortValue) &&
    isIntegerInRange(parsedNewEvolutionArgument, 0, pokemonMaximumUshortValue) &&
    isIntegerInRange(parsedNewEvolutionSpecies, 0, pokemonMaximumUshortValue) &&
    isIntegerInRange(parsedNewEvolutionForm, 0, evolutionMaximumForm) &&
    isIntegerInRange(parsedNewEvolutionLevel, 0, evolutionMaximumLevel) &&
    (editorFamily !== 'swsh' ||
      isValidSwShEvolutionAddition(
        parsedNewEvolutionMethod,
        parsedNewEvolutionArgument,
        parsedNewEvolutionSpecies,
        evolutionMethodOptions,
        pokemonSpeciesOptions
      ));

  return (
    <aside
      aria-label="Selected Pokemon provenance"
      className={`item-inspector ${editorFamily}-pokemon-inspector`}
    >
      <div className={`${editorFamily}-pokemon-selected-stack`}>
        <div className="panel-heading">
          <ShieldCheck aria-hidden="true" size={18} />
          <h3>Selected Pokemon</h3>
        </div>

        {pokemon ? (
          <>
          <SelectedPokemonSummaryCard editorFamily={editorFamily} pokemon={pokemon} />

          <div className={`inspector-block ${editorFamily}-pokemon-stats-block`}>
            <h4>Base Stats</h4>
            <dl className="item-provenance-list compact-dl">
              <div>
                <dt>HP</dt>
                <dd>{pokemon.baseStats.hp}</dd>
              </div>
              <div>
                <dt>Attack</dt>
                <dd>{pokemon.baseStats.attack}</dd>
              </div>
              <div>
                <dt>Defense</dt>
                <dd>{pokemon.baseStats.defense}</dd>
              </div>
              <div>
                <dt>Sp. Atk</dt>
                <dd>{pokemon.baseStats.specialAttack}</dd>
              </div>
              <div>
                <dt>Sp. Def</dt>
                <dd>{pokemon.baseStats.specialDefense}</dd>
              </div>
              <div>
                <dt>Speed</dt>
                <dd>{pokemon.baseStats.speed}</dd>
              </div>
              <div>
                <dt>Total</dt>
                <dd>{pokemon.baseStats.total}</dd>
              </div>
            </dl>
          </div>

          <div className={`inspector-block ${editorFamily}-pokemon-traits-block`}>
            <h4>Traits</h4>
            <dl className="item-provenance-list compact-dl">
              <div>
                <dt>Ability 1</dt>
                <dd data-localization-ignore="true">{pokemon.abilities.ability1Label}</dd>
              </div>
              <div>
                <dt>Ability 2</dt>
                <dd data-localization-ignore="true">{pokemon.abilities.ability2Label}</dd>
              </div>
              <div>
                <dt>Hidden</dt>
                <dd data-localization-ignore="true">{pokemon.abilities.hiddenAbilityLabel}</dd>
              </div>
              <div>
                <dt>Catch rate</dt>
                <dd>{pokemon.catchRate}</dd>
              </div>
              <div>
                <dt>Base EXP</dt>
                <dd>{pokemon.baseExperience}</dd>
              </div>
              <div>
                <dt>Gender</dt>
                <dd>{pokemon.genderRatioLabel}</dd>
              </div>
              <div>
                <dt>Height / weight</dt>
                <dd>
                  {pokemon.height} / {pokemon.weight}
                </dd>
              </div>
            </dl>
          </div>

          <div className={`inspector-block ${editorFamily}-pokemon-personal-edit-block`}>
            <h4>Personal Edit</h4>
            <div className="editable-field-groups">
              {personalFieldGroups.map((group) => (
                <fieldset className="editable-field-group" key={group.group}>
                  <legend>{group.group}</legend>
                  <div className="editable-field-grid">
                    {group.fields.map((field) => {
                      const currentValue = pokemon
                        ? getEditablePersonalFieldValue(pokemon, field.field)
                        : null;
                      const draftValue = personalDrafts[field.field] ?? '';
                      const draftState = getPokemonPersonalFieldDraftState(
                        draftValue,
                        currentValue,
                        field
                      );

                      return (
                        <PokemonPersonalFieldInput
                          currentValue={currentValue}
                          disabled={
                            !canEditPokemon ||
                            editSession === null ||
                            isPokemonUpdating ||
                            (field.field === formFieldName && pokemon.personal.formCount <= 1)
                          }
                          disabledReason={
                            field.field === formFieldName && pokemon.personal.formCount <= 1
                              ? 'No alternate forms available for this Pokemon.'
                              : undefined
                          }
                          draftState={draftState}
                          draftValue={draftValue}
                          field={field}
                          formOptionContext={{
                            gameFamily: editorFamily,
                            species: pokemon.name,
                            speciesId: pokemon.speciesId
                          }}
                          key={field.field}
                          onChange={(value) => {
                            const nextDrafts = {
                              ...personalDrafts,
                              [field.field]: value
                            };
                            setPersonalDraftsByPokemonId((currentDrafts) =>
                              setSparseFieldDraftRecord(
                                currentDrafts,
                                pokemon.personalId,
                                nextDrafts,
                                personalDraftDefaults
                              )
                            );
                          }}
                        />
                      );
                    })}
                  </div>
                </fieldset>
              ))}
            </div>
            {editSession ? (
              <div className="draft-action-row">
                <button
                  aria-busy={isPokemonUpdating || undefined}
                  className="primary-button"
                  disabled={!canSavePokemonDrafts}
                  onClick={async () => {
                    if (pokemon) {
                      const didSave = await onUpdatePokemonFields(
                        pokemon.personalId,
                        personalDraftSummary.changedFields.map((change) => ({
                          field: change.field,
                          value: change.value
                        })),
                        evolutionDraftReview.changes,
                        learnsetDraftReview.changes
                      );
                      if (didSave) {
                        setPersonalDraftsByPokemonId((currentDrafts) =>
                          deleteFieldDraftRecord(currentDrafts, pokemon.personalId)
                        );
                        setEvolutionDraftsByPokemonId((currentDrafts) =>
                          deleteFieldDraftRecord(currentDrafts, pokemon.personalId)
                        );
                        setLearnsetDraftsByPokemonId((currentDrafts) =>
                          deleteFieldDraftRecord(currentDrafts, pokemon.personalId)
                        );
                      }
                    }
                  }}
                  type="button"
                >
                  <BusyActionContent
                    busyLabel="Staging"
                    icon={<Save aria-hidden="true" size={16} />}
                    isBusy={isPokemonUpdating}
                    label="Stage"
                  />
                </button>
                <button
                  className="danger-button"
                  disabled={isPokemonUpdating}
                  onClick={() =>
                    cancelActiveEditSession(() => {
                      setPersonalDraftsByPokemonId({});
                      setEvolutionDraftsByPokemonId({});
                      setLearnsetDraftsByPokemonId({});
                    })
                  }
                  type="button"
                >
                  <X aria-hidden="true" size={16} />
                  <span>Cancel</span>
                </button>
                <span className="draft-action-summary">
                  {pokemonDraftInvalidCount > 0
                    ? `${pokemonDraftInvalidCount} field${
                        pokemonDraftInvalidCount === 1 ? '' : 's'
                      } need valid values`
                    : `${pokemonDraftChangedCount} changed`}
                </span>
              </div>
            ) : null}
            {canEditPokemon && editSession === null ? (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={isEditStarting}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            ) : null}
          </div>
          </>
        ) : (
          <p className="empty-copy">No Pokemon selected.</p>
        )}
      </div>

      <div className={`${editorFamily}-pokemon-left-stack`}>
        {pokemonTable}
      {pokemon ? (
        <>
          <div className={`inspector-block ${editorFamily}-pokemon-learnset-block`}>
            <h4>Learnset</h4>
            <div className="learnset-editor">
              {pokemon.learnset.length > 0 ? (
                <ul className="learnset-list">
                  {pokemon.learnset.map((move) => {
                    const isSelected = selectedLearnsetMove?.slot === move.slot;
                    const localDraft = learnsetDraftsBySlot[move.slot] ?? null;
                    const displayMove = getPokemonLearnsetDraftDisplay(
                      move,
                      localDraft,
                      learnsetMoveOptions,
                      editorFamily
                    );

                    return (
                      <li
                        className={`learnset-list-item ${
                          draggedLearnsetSlot === move.slot ? 'learnset-dragging' : ''
                        } ${
                          dragOverLearnsetSlot === move.slot ? 'learnset-drop-target' : ''
                        }`}
                        draggable={canModifyLearnsetStructure}
                        key={move.slot}
                        onDragEnd={() => {
                          setDraggedLearnsetSlot(null);
                          setDragOverLearnsetSlot(null);
                        }}
                        onDragLeave={() => {
                          setDragOverLearnsetSlot((currentSlot) =>
                            currentSlot === move.slot ? null : currentSlot
                          );
                        }}
                        onDragOver={(event) => {
                          const transferredSlot = Number.parseInt(
                            event.dataTransfer.getData('text/plain'),
                            10
                          );
                          const sourceSlot =
                            draggedLearnsetSlot ??
                            (Number.isInteger(transferredSlot) ? transferredSlot : null);
                          if (
                            !canModifyLearnsetStructure ||
                            sourceSlot === null ||
                            sourceSlot === move.slot
                          ) {
                            return;
                          }

                          event.preventDefault();
                          event.dataTransfer.dropEffect = 'move';
                          setDragOverLearnsetSlot(move.slot);
                        }}
                        onDragStart={(event) => {
                          if (!canModifyLearnsetStructure) {
                            event.preventDefault();
                            return;
                          }

                          event.dataTransfer.effectAllowed = 'move';
                          event.dataTransfer.setData('text/plain', move.slot.toString());
                          setDraggedLearnsetSlot(move.slot);
                          setDragOverLearnsetSlot(null);
                          setSelectedLearnsetSlot(move.slot);
                        }}
                        onDrop={(event) => {
                          const transferredSlot = Number.parseInt(
                            event.dataTransfer.getData('text/plain'),
                            10
                          );
                          const sourceSlot =
                            draggedLearnsetSlot ??
                            (Number.isInteger(transferredSlot) ? transferredSlot : null);
                          event.preventDefault();
                          void handleDropLearnsetMove(move.slot, sourceSlot);
                        }}
                      >
                        {isSelected && editSession !== null ? (
                          <div className="learnset-row learnset-inline-row">
                            <span className="learnset-drag-cell" aria-hidden="true">
                              <GripVertical size={15} />
                            </span>
                            <span className="learnset-slot-cell">#{move.slot + 1}</span>
                            <label className="path-field learnset-inline-field learnset-move-field">
                              <span>Move</span>
                              {learnsetMoveOptionsForDraft.length > 0 ? (
                                <SearchableOptionInput
                                  ariaLabel="Move"
                                  disabled={!canEditLearnset}
                                  onChange={(value) => {
                                    setLearnsetMoveIdDraft(value);
                                    updateSelectedLearnsetDraft({ moveId: value });
                                  }}
                                  options={learnsetMoveOptionsForDraft}
                                  value={learnsetMoveIdDraft}
                                />
                              ) : (
                                <input
                                  disabled={!canEditLearnset}
                                  max={pokemonMaximumUshortValue}
                                  min={0}
                                  onChange={(event) => {
                                    setLearnsetMoveIdDraft(event.target.value);
                                    updateSelectedLearnsetDraft({ moveId: event.target.value });
                                  }}
                                  type="number"
                                  value={learnsetMoveIdDraft}
                                />
                              )}
                            </label>
                            <label className="path-field learnset-inline-field learnset-level-field">
                              <span>Level</span>
                              <input
                                disabled={!canEditLearnset}
                                max={learnsetMaximumLevel}
                                min={0}
                                onChange={(event) => {
                                  setLearnsetLevelDraft(event.target.value);
                                  updateSelectedLearnsetDraft({ level: event.target.value });
                                }}
                                type="number"
                                value={learnsetLevelDraft}
                              />
                            </label>
                            <span
                              className="learnset-inline-metadata"
                              data-localization-ignore="true"
                            >
                              {displayMove.masteryLabel ?? ''}
                            </span>
                            <div className="learnset-inline-actions">
                              <button
                                aria-label="Move learnset row up"
                                className="secondary-button icon-button"
                                disabled={!canModifyLearnsetStructure || move.slot === 0}
                                onClick={async () => {
                                  const didMove = await onUpdatePokemonLearnset(
                                    pokemon.personalId,
                                    'moveUp',
                                    move.slot,
                                    null,
                                    null
                                  );
                                  if (didMove) {
                                    setSelectedLearnsetSlot(move.slot - 1);
                                  }
                                }}
                                title="Move learnset row up"
                                type="button"
                              >
                                <ArrowUp aria-hidden="true" size={16} />
                              </button>
                              <button
                                aria-label="Move learnset row down"
                                className="secondary-button icon-button"
                                disabled={
                                  !canModifyLearnsetStructure ||
                                  move.slot >= pokemon.learnset.length - 1
                                }
                                onClick={async () => {
                                  const didMove = await onUpdatePokemonLearnset(
                                    pokemon.personalId,
                                    'moveDown',
                                    move.slot,
                                    null,
                                    null
                                  );
                                  if (didMove) {
                                    setSelectedLearnsetSlot(move.slot + 1);
                                  }
                                }}
                                title="Move learnset row down"
                                type="button"
                              >
                                <ArrowDown aria-hidden="true" size={16} />
                              </button>
                              <button
                                aria-label="Remove learnset row"
                                className="secondary-button icon-button danger-icon-button"
                                disabled={!canModifyLearnsetStructure}
                                onClick={() => {
                                  void onUpdatePokemonLearnset(
                                    pokemon.personalId,
                                    'remove',
                                    move.slot,
                                    null,
                                    null
                                  );
                                }}
                                title="Remove learnset row"
                                type="button"
                              >
                                <Trash2 aria-hidden="true" size={16} />
                              </button>
                            </div>
                          </div>
                        ) : (
                          <button
                            className={`learnset-row ${
                              isSelected ? 'learnset-row-selected' : ''
                            }`}
                            onClick={() => setSelectedLearnsetSlot(move.slot)}
                            type="button"
                          >
                            <span className="learnset-drag-cell" aria-hidden="true">
                              <GripVertical size={15} />
                            </span>
                            <span className="learnset-slot-cell">#{move.slot + 1}</span>
                            <span
                              className="learnset-level-cell"
                              data-localization-ignore="true"
                            >
                              {displayMove.levelLabel ?? `Lv. ${displayMove.level}`}
                            </span>
                            {displayMove.masteryLabel ? (
                              <span
                                className="learnset-mastery-cell"
                                data-localization-ignore="true"
                              >
                                {displayMove.masteryLabel}
                              </span>
                            ) : (
                              <span aria-hidden="true" className="learnset-mastery-cell" />
                            )}
                            <strong
                              className="learnset-move-name"
                              data-localization-ignore="true"
                            >
                              {displayMove.moveName}
                            </strong>
                            <span>{displayMove.moveId}</span>
                          </button>
                        )}
                      </li>
                    );
                  })}
                </ul>
              ) : (
                <p className="empty-copy">No level-up moves.</p>
              )}

              <div className="learnset-edit-grid">
                <label className="path-field">
                  <span>New move</span>
                  {newLearnsetMoveOptions.length > 0 ? (
                    <SearchableOptionInput
                      ariaLabel="New move"
                      disabled={!canEditLearnset}
                      onChange={setNewLearnsetMoveIdDraft}
                      options={newLearnsetMoveOptions}
                      value={newLearnsetMoveIdDraft}
                    />
                  ) : (
                    <input
                      disabled={!canEditLearnset}
                      max={pokemonMaximumUshortValue}
                      min={0}
                      onChange={(event) => setNewLearnsetMoveIdDraft(event.target.value)}
                      type="number"
                      value={newLearnsetMoveIdDraft}
                    />
                  )}
                </label>
                <label className="path-field">
                  <span>New level</span>
                  <input
                    disabled={!canEditLearnset}
                    max={learnsetMaximumLevel}
                    min={0}
                    onChange={(event) => setNewLearnsetLevelDraft(event.target.value)}
                    type="number"
                    value={newLearnsetLevelDraft}
                  />
                </label>
                <button
                  aria-label="Add learnset row"
                  className="secondary-button learnset-add-button"
                  disabled={!canAddLearnsetMove}
                  onClick={async () => {
                    const didAdd = await onUpdatePokemonLearnset(
                      pokemon.personalId,
                      'add',
                      null,
                      parsedNewLearnsetMoveId,
                      parsedNewLearnsetLevel
                    );
                    if (didAdd) {
                      setNewLearnsetMoveIdDraft('');
                      setNewLearnsetLevelDraft('');
                    }
                  }}
                  type="button"
                >
                  <Plus aria-hidden="true" size={16} />
                  <span>Add Row</span>
                </button>
              </div>
            </div>
          </div>

          <div className={`inspector-block ${editorFamily}-pokemon-compatibility-block`}>
            <h4>Compatibility</h4>
            {pokemon.compatibility.length > 0 ? (
              <div className="compatibility-editor">
                <div className="compatibility-controls">
                  <label className="path-field">
                    <span>Compatibility group</span>
                    <select
                      onChange={(event) => setSelectedCompatibilityGroupId(event.target.value)}
                      value={selectedCompatibilityGroup?.groupId ?? ''}
                    >
                      {pokemon.compatibility.map((group) => (
                        <option key={group.groupId} value={group.groupId}>
                          {group.label} ({group.enabledCount}/{group.entries.length})
                        </option>
                      ))}
                    </select>
                  </label>
                  <label className="search-box compatibility-search">
                    <Search aria-hidden="true" size={16} />
                    <input
                      aria-label="Search compatibility"
                      onChange={(event) => setCompatibilitySearchText(event.target.value)}
                      placeholder="Search compatibility"
                      type="search"
                      value={compatibilitySearchText}
                    />
                  </label>
                </div>
                <ul className="compatibility-list">
                  {filteredCompatibilityEntries.map((entry) => (
                    <li key={`${selectedCompatibilityGroup?.groupId}-${entry.slot}`}>
                      <label className="compatibility-toggle">
                        <input
                          checked={entry.canLearn}
                          disabled={!canToggleCompatibility}
                          onChange={(event) => {
                            if (pokemon && selectedCompatibilityGroup) {
                              onUpdatePokemonField(
                                pokemon.personalId,
                                createPokemonCompatibilityFieldName(
                                  selectedCompatibilityGroup.groupId,
                                  entry.slot
                                ),
                                event.target.checked ? '1' : '0'
                              );
                            }
                          }}
                          type="checkbox"
                        />
                        <span data-localization-ignore="true">{entry.label}</span>
                        <small>{entry.moveId}</small>
                      </label>
                    </li>
                  ))}
                </ul>
                {filteredCompatibilityEntries.length === 0 ? (
                  <p className="empty-copy">No compatibility entries matched.</p>
                ) : null}
              </div>
            ) : (
              <p className="empty-copy">No compatibility data.</p>
            )}
          </div>

          <div className={`inspector-block ${editorFamily}-pokemon-evolutions-block`}>
            <h4>Evolutions</h4>
            <div className="learnset-editor">
              {orderedEvolutions.length > 0 ? (
                <ul className="learnset-list">
                  {orderedEvolutions.map((evolution) => {
                    const evolutionSpeciesLabel = formatReferenceLabel(
                      pokemonSpeciesLabels,
                      evolution.species,
                      'Species'
                    );
                    const evolutionFormLabel = formatEvolutionFormReference(
                      pokemonSpeciesLabels,
                      evolution.species,
                      evolution.form,
                      editorFamily
                    );
                    const evolutionSpriteName = getPokemonSpriteNameForSpecies(
                      pokemonRecords,
                      evolution.species,
                      evolution.form,
                      editorFamily,
                      evolutionSpeciesLabel
                    );

                    return (
                      <li key={evolution.slot}>
                        <button
                          className={`learnset-row evolution-row ${
                            selectedEvolution?.slot === evolution.slot
                              ? 'learnset-row-selected'
                              : ''
                          }`}
                          onClick={() => setSelectedEvolutionSlot(evolution.slot)}
                          type="button"
                        >
                          <PokemonSprite
                            className="pokemon-row-sprite"
                            name={getReferenceSpriteName(evolutionSpriteName)}
                            preferStatic
                          />
                          <span title={`Slot ${evolution.slot + 1}`}>#{evolution.slot + 1}</span>
                          <span
                            data-localization-ignore="true"
                            title={formatEvolutionMethodSummary(evolution)}
                          >
                            {formatEvolutionMethodSummary(evolution)}
                          </span>
                          <strong data-localization-ignore="true" title={evolutionSpeciesLabel}>
                            {evolutionSpeciesLabel}
                          </strong>
                          <span data-localization-ignore="true" title={evolutionFormLabel}>
                            {evolutionFormLabel}
                          </span>
                          <span>Lv. {evolution.level}</span>
                          <span
                            data-localization-ignore="true"
                            title={formatEvolutionArgumentSummary(evolution)}
                          >
                            {formatEvolutionArgumentSummary(evolution)}
                          </span>
                        </button>
                      </li>
                    );
                  })}
                </ul>
              ) : (
                <p className="empty-copy">No evolution entries.</p>
              )}

              {selectedEvolution ? (
                <div className="learnset-edit-grid evolution-edit-grid">
                  <label className="path-field">
                    <span>Method</span>
                    <SearchableOptionInput
                      ariaLabel="Method"
                      disabled={!canEditEvolution}
                      onChange={(nextMethod) => {
                        const nextOption = findEvolutionMethodOption(
                          selectedEvolutionMethodOptions,
                          nextMethod
                        );
                        const nextArgument = getDefaultEvolutionArgumentDraft(nextOption);
                        setEvolutionMethodDraft(nextMethod);
                        setEvolutionArgumentDraft(nextArgument);
                        updateSelectedEvolutionDraft({
                          argument: nextArgument,
                          method: nextMethod
                        });
                      }}
                      options={selectedEvolutionMethodOptions}
                      value={evolutionMethodDraft}
                    />
                  </label>
                  <label className="path-field">
                    <span>{selectedEvolutionMethodOption?.argumentLabel ?? 'Argument'}</span>
                    {usesEvolutionArgumentSelector(selectedEvolutionMethodOption) &&
                    selectedEvolutionArgumentOptions.length > 0 ? (
                      <SearchableOptionInput
                        ariaLabel={selectedEvolutionMethodOption?.argumentLabel ?? 'Argument'}
                        disabled={!canEditEvolution}
                        onChange={(value) => {
                          setEvolutionArgumentDraft(value);
                          updateSelectedEvolutionDraft({ argument: value });
                        }}
                        options={selectedEvolutionArgumentOptions}
                        value={evolutionArgumentDraft}
                      />
                    ) : (
                      <input
                        disabled={
                          !canEditEvolution ||
                          !usesEvolutionArgumentNumberInput(selectedEvolutionMethodOption)
                        }
                        max={65535}
                        min={0}
                        onChange={(event) => {
                          setEvolutionArgumentDraft(event.target.value);
                          updateSelectedEvolutionDraft({ argument: event.target.value });
                        }}
                        type="number"
                        value={evolutionArgumentDraft}
                      />
                    )}
                  </label>
                  <label className="path-field">
                    <span>Species</span>
                    {pokemonSpeciesOptions.length > 0 ? (
                      <SearchableOptionInput
                        ariaLabel="Species"
                        disabled={!canEditEvolution}
                        onChange={(value) => {
                          setEvolutionSpeciesDraft(value);
                          updateSelectedEvolutionDraft({ species: value });
                        }}
                        options={addCurrentPokemonFieldOption(
                          pokemonSpeciesOptions,
                          evolutionSpeciesDraft,
                          'Species',
                          pokemonSpeciesLabels
                        )}
                        value={evolutionSpeciesDraft}
                      />
                    ) : (
                      <input
                        disabled={!canEditEvolution}
                        max={65535}
                        min={0}
                        onChange={(event) => {
                          setEvolutionSpeciesDraft(event.target.value);
                          updateSelectedEvolutionDraft({ species: event.target.value });
                        }}
                        type="number"
                        value={evolutionSpeciesDraft}
                      />
                    )}
                  </label>
                  <label className="path-field">
                    <span>Form</span>
                    <SearchableOptionInput
                      ariaLabel="Form"
                      disabled={!canEditEvolution}
                      onChange={(value) => {
                        setEvolutionFormDraft(value);
                        updateSelectedEvolutionDraft({ form: value });
                      }}
                      options={selectedEvolutionFormOptions}
                      value={evolutionFormDraft}
                    />
                  </label>
                  <label className="path-field">
                    <span>Level</span>
                    <input
                      disabled={!canEditEvolution}
                      max={evolutionMaximumLevel}
                      min={0}
                      onChange={(event) => {
                        setEvolutionLevelDraft(event.target.value);
                        updateSelectedEvolutionDraft({ level: event.target.value });
                      }}
                      type="number"
                      value={evolutionLevelDraft}
                    />
                  </label>
                  <div className="learnset-button-row">
                    <button
                      aria-label="Move evolution row up"
                      className="secondary-button icon-button"
                      disabled={!canModifyEvolutionStructure || previousEvolutionSlot === null}
                      onClick={async () => {
                        if (previousEvolutionSlot === null) {
                          return;
                        }

                        const didMove = await onUpdatePokemonEvolution(
                          pokemon.personalId,
                          'moveUp',
                          selectedEvolution.slot,
                          null,
                          null,
                          null,
                          null,
                          null
                        );
                        if (didMove) {
                          setSelectedEvolutionSlot(previousEvolutionSlot);
                        }
                      }}
                      title="Move evolution row up"
                      type="button"
                    >
                      <ArrowUp aria-hidden="true" size={16} />
                    </button>
                    <button
                      aria-label="Move evolution row down"
                      className="secondary-button icon-button"
                      disabled={
                        !canModifyEvolutionStructure || nextEvolutionSlot === null
                      }
                      onClick={async () => {
                        if (nextEvolutionSlot === null) {
                          return;
                        }

                        const didMove = await onUpdatePokemonEvolution(
                          pokemon.personalId,
                          'moveDown',
                          selectedEvolution.slot,
                          null,
                          null,
                          null,
                          null,
                          null
                        );
                        if (didMove) {
                          setSelectedEvolutionSlot(nextEvolutionSlot);
                        }
                      }}
                      title="Move evolution row down"
                      type="button"
                    >
                      <ArrowDown aria-hidden="true" size={16} />
                    </button>
                    <button
                      aria-label="Remove evolution row"
                      className="secondary-button icon-button danger-icon-button"
                      disabled={!canModifyEvolutionStructure}
                      onClick={() =>
                        void onUpdatePokemonEvolution(
                          pokemon.personalId,
                          'remove',
                          selectedEvolution.slot,
                          null,
                          null,
                          null,
                          null,
                          null
                        )
                      }
                      title="Remove evolution row"
                      type="button"
                    >
                      <Trash2 aria-hidden="true" size={16} />
                    </button>
                  </div>
                </div>
              ) : null}

              <div className="learnset-edit-grid evolution-edit-grid">
                <label className="path-field">
                  <span>New method</span>
                  <SearchableOptionInput
                    ariaLabel="New method"
                    disabled={!canEditEvolution}
                    onChange={(nextMethod) => {
                      const nextOption = findEvolutionMethodOption(
                        newEvolutionMethodOptions,
                        nextMethod
                      );
                      setNewEvolutionMethodDraft(nextMethod);
                      setNewEvolutionArgumentDraft(getDefaultEvolutionArgumentDraft(nextOption));
                    }}
                    options={newEvolutionMethodOptions}
                    value={newEvolutionMethodDraft}
                  />
                </label>
                <label className="path-field">
                  <span>{newEvolutionMethodOption?.argumentLabel ?? 'New argument'}</span>
                  {usesEvolutionArgumentSelector(newEvolutionMethodOption) &&
                  newEvolutionArgumentOptions.length > 0 ? (
                    <SearchableOptionInput
                      ariaLabel={newEvolutionMethodOption?.argumentLabel ?? 'New argument'}
                      disabled={!canEditEvolution}
                      onChange={setNewEvolutionArgumentDraft}
                      options={newEvolutionArgumentOptions}
                      value={newEvolutionArgumentDraft}
                    />
                  ) : (
                    <input
                      disabled={
                        !canEditEvolution ||
                        !usesEvolutionArgumentNumberInput(newEvolutionMethodOption)
                      }
                      max={65535}
                      min={0}
                      onChange={(event) => setNewEvolutionArgumentDraft(event.target.value)}
                      type="number"
                      value={newEvolutionArgumentDraft}
                    />
                  )}
                </label>
                <label className="path-field">
                  <span>New species</span>
                  {pokemonSpeciesOptions.length > 0 ? (
                    <SearchableOptionInput
                      ariaLabel="New species"
                      disabled={!canEditEvolution}
                      onChange={setNewEvolutionSpeciesDraft}
                      options={addCurrentPokemonFieldOption(
                        pokemonSpeciesOptions,
                        newEvolutionSpeciesDraft,
                        'Species',
                        pokemonSpeciesLabels
                      )}
                      value={newEvolutionSpeciesDraft}
                    />
                  ) : (
                    <input
                      disabled={!canEditEvolution}
                      max={65535}
                      min={0}
                      onChange={(event) => setNewEvolutionSpeciesDraft(event.target.value)}
                      type="number"
                      value={newEvolutionSpeciesDraft}
                    />
                  )}
                </label>
                <label className="path-field">
                  <span>New form</span>
                  <SearchableOptionInput
                    ariaLabel="New form"
                    disabled={!canEditEvolution}
                    onChange={setNewEvolutionFormDraft}
                    options={newEvolutionFormOptions}
                    value={newEvolutionFormDraft}
                  />
                </label>
                <label className="path-field">
                  <span>New level</span>
                  <input
                    disabled={!canEditEvolution}
                    max={evolutionMaximumLevel}
                    min={0}
                    onChange={(event) => setNewEvolutionLevelDraft(event.target.value)}
                    type="number"
                    value={newEvolutionLevelDraft}
                  />
                </label>
                <button
                  aria-label="Add evolution row"
                  className="secondary-button learnset-add-button"
                  disabled={!canAddEvolution}
                  onClick={async () => {
                    const didAdd = await onUpdatePokemonEvolution(
                      pokemon.personalId,
                      'add',
                      null,
                      parsedNewEvolutionMethod,
                      parsedNewEvolutionArgument,
                      parsedNewEvolutionSpecies,
                      parsedNewEvolutionForm,
                      parsedNewEvolutionLevel
                    );
                    if (didAdd) {
                      setNewEvolutionMethodDraft('');
                      setNewEvolutionArgumentDraft('0');
                      setNewEvolutionSpeciesDraft('');
                      setNewEvolutionFormDraft('0');
                      setNewEvolutionLevelDraft('');
                    }
                  }}
                  type="button"
                >
                  <Plus aria-hidden="true" size={16} />
                  <span>Add Row</span>
                </button>
              </div>
            </div>
          </div>
        </>
      ) : null}
      </div>
    </aside>
  );
}

type MoveBaselineValuesByMoveId = Record<string, Record<string, number | null>>;

function MovesSection({
  baselineValuesByMoveId,
  editSession,
  isEditStarting,
  isMoveUpdating,
  onSearchChange,
  onSelectMove,
  onStartEditSession,
  onUpdateMoveFields,
  searchText,
  selectedMoveId,
  workflow
}: {
  baselineValuesByMoveId: MoveBaselineValuesByMoveId;
  editSession: EditSession | null;
  isEditStarting: boolean;
  isMoveUpdating: boolean;
  onSearchChange: (searchText: string) => void;
  onSelectMove: (moveId: number | null) => void;
  onStartEditSession: () => void;
  onUpdateMoveFields: (
    moveId: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  searchText: string;
  selectedMoveId: number | null;
  workflow: MovesWorkflow | null;
}) {
  const { translateLiteral } = useLocalization();
  const moves = workflow?.moves ?? [];
  const filteredMoves = useMemo(() => filterMoves(moves, searchText), [moves, searchText]);
  const selectedMove = useMemo(
    () =>
      filteredMoves.find((candidate) => candidate.moveId === selectedMoveId) ??
      filteredMoves[0] ??
      null,
    [filteredMoves, selectedMoveId]
  );
  const canEditMoves = workflow?.summary.availability === 'available';
  const pendingMoveIds = useMemo(() => getPendingMoveIds(editSession), [editSession]);

  return (
    <>
      <section aria-labelledby="moves-heading" className="panel wide-panel">
        <div className="panel-heading">
          <Zap aria-hidden="true" size={18} />
          <h2 id="moves-heading">Moves</h2>
        </div>

        <div className="items-toolbar moves-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label="Search moves"
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder="Search moves"
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label="Loaded records"
            value={workflow ? workflow.stats.totalMoveCount.toString() : '0'}
          />
          <Metric
            label="Enabled"
            value={workflow ? workflow.stats.enabledMoveCount.toString() : '0'}
          />
          <Metric
            label="Active flags"
            value={workflow ? workflow.stats.activeFlagCount.toString() : '0'}
          />
        </div>

        {workflow ? (
          <div className="items-layout moves-layout">
            <div
              aria-colcount={8}
              aria-label="Moves"
              aria-rowcount={filteredMoves.length + 1}
              className="moves-table"
              role="table"
            >
              <div className="moves-row moves-row-heading" role="row">
                <span role="columnheader">ID</span>
                <span role="columnheader">Move</span>
                <span role="columnheader">Type</span>
                <span role="columnheader">Category</span>
                <span role="columnheader">Power</span>
                <span role="columnheader">Acc</span>
                <span role="columnheader">PP</span>
                <span role="columnheader">Flags</span>
              </div>
              <VirtualTableBody
                getKey={(move) => move.moveId}
                items={filteredMoves}
                renderRow={(move) => (
                  <button
                    className={`moves-row ${
                      selectedMove?.moveId === move.moveId ? 'moves-row-selected' : ''
                    } ${
                      pendingMoveIds.has(move.moveId) ? 'moves-row-pending' : ''
                    }`}
                    onClick={() => onSelectMove(move.moveId)}
                    role="row"
                    type="button"
                  >
                    <span role="cell">{move.moveId}</span>
                    <span role="cell">{move.name}</span>
                    <span role="cell">{move.typeName}</span>
                    <span role="cell">{move.categoryName}</span>
                    <span role="cell">{formatMovePower(move.power)}</span>
                    <span role="cell">{translateLiteral(formatMoveAccuracy(move.accuracy))}</span>
                    <span role="cell">{move.pp}</span>
                    <span role="cell">{formatMoveActiveFlags(move)}</span>
                  </button>
                )}
              />
            </div>

            <SelectedMovePanel
              baselineValues={
                selectedMove
                  ? (baselineValuesByMoveId[selectedMove.moveId.toString()] ?? null)
                  : null
              }
              canEditMoves={canEditMoves}
              editSession={editSession}
              editableFields={workflow.editableFields}
              isEditStarting={isEditStarting}
              isMoveUpdating={isMoveUpdating}
              move={selectedMove}
              onStartEditSession={onStartEditSession}
              onUpdateMoveFields={onUpdateMoveFields}
            />
          </div>
        ) : (
          <p className="empty-copy">Open Moves from the sidebar to load backend move data.</p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
    </>
  );
}

function SelectedMovePanel({
  baselineValues,
  canEditMoves,
  editSession,
  editableFields,
  isEditStarting,
  isMoveUpdating,
  move,
  onStartEditSession,
  onUpdateMoveFields
}: {
  baselineValues: Record<string, number | null> | null;
  canEditMoves: boolean;
  editSession: EditSession | null;
  editableFields: MoveEditableField[];
  isEditStarting: boolean;
  isMoveUpdating: boolean;
  move: MoveRecord | null;
  onStartEditSession: () => void;
  onUpdateMoveFields: (
    moveId: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
}) {
  const [moveDraftsByMoveId, setMoveDraftsByMoveId] = useState<
    Record<string, Record<string, string>>
  >({});
  const cancelActiveEditSession = useCancelActiveEditSession();
  const { translateLiteral } = useLocalization();
  const moveFields = useMemo(
    () => editableFields.map((field) => toNumericEditableField(field)),
    [editableFields]
  );
  const moveFieldGroups = useMemo(
    () =>
      orderMoveEditableFieldGroups(
        groupNumericEditableFields(moveFields, getMoveEditableFieldGroup)
      ),
    [moveFields]
  );
  const moveDraftDefaults = useMemo(
    () =>
      move
        ? createTrainerDrafts(moveFields, (field) => getEditableMoveFieldValue(move, field))
        : {},
    [move, moveFields]
  );
  const moveDrafts = move ? moveDraftsByMoveId[move.moveId.toString()] ?? moveDraftDefaults : {};
  const moveDraftContext = useMemo<DraftStateContext | undefined>(
    () =>
      move
        ? {
            drafts: moveDrafts,
            fields: moveFields,
            getValue: (field) => getEditableMoveFieldValue(move, field),
            preservedValues: baselineValues ?? undefined
          }
        : undefined,
    [baselineValues, move, moveDrafts, moveFields]
  );
  const moveDraftSummary = useMemo(
    () =>
      getTrainerDraftSummary(
        moveFields,
        moveDrafts,
        move ? (field) => getEditableMoveFieldValue(move, field) : null,
        { preservedValues: baselineValues ?? undefined }
      ),
    [baselineValues, move, moveDrafts, moveFields]
  );
  useRegisterEditorDraftDirty('moves', countFieldDraftRecords(moveDraftsByMoveId) > 0);
  const activeFlags = move?.flags.filter((flag) => flag.enabled) ?? [];
  const qualityField = moveFields.find((field) => field.field === 'quality');
  const mappedQualityLabel = move
    ? (qualityField?.options.find((option) => option.value === move.quality)?.label ?? null)
    : null;
  const visibleStatChanges =
    move?.statChanges.filter(
      (statChange) =>
        statChange.stat > 0 ||
        (statChange.stat === 0 && (statChange.stage !== 0 || statChange.percent !== 0))
    ) ?? [];
  const canSaveMoveDrafts =
    move !== null &&
    editSession !== null &&
    canEditMoves &&
    !isMoveUpdating &&
    moveDraftSummary.changedFields.length > 0 &&
    moveDraftSummary.invalidFields.length === 0;

  useEffect(() => {
    if (!move) {
      return;
    }

    setMoveDraftsByMoveId((currentDrafts) =>
      pruneFieldDraftRecord(currentDrafts, move.moveId, moveDraftDefaults)
    );
  }, [move, moveDraftDefaults]);

  return (
    <aside aria-label="Selected move details" className="item-inspector">
      <div className="panel-heading">
        <ShieldCheck aria-hidden="true" size={18} />
        <h3>Selected Move</h3>
      </div>

      {move ? (
        <>
          <dl className="item-provenance-list">
            <div>
              <dt>Name</dt>
              <dd>{move.name}</dd>
            </div>
            <div>
              <dt>Move ID</dt>
              <dd>{move.moveId}</dd>
            </div>
            <div>
              <dt>Status</dt>
              <dd>{move.canUseMove ? 'Enabled' : 'Disabled'}</dd>
            </div>
            <div>
              <dt>Type / category</dt>
              <dd>
                {move.typeName} / {move.categoryName}
              </dd>
            </div>
            <div>
              <dt>Description</dt>
              <dd>{move.description ?? 'No description text.'}</dd>
            </div>
            <div>
              <dt>Source file</dt>
              <dd>{move.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>Layer</dt>
              <dd>{formatSourceLayer(move.provenance.sourceLayer)}</dd>
            </div>
            <div>
              <dt>File state</dt>
              <dd>{formatFileState(move.provenance.fileState)}</dd>
            </div>
          </dl>

          <div className="item-edit-form move-edit-form">
            {!editSession ? (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditMoves || isEditStarting}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            ) : null}

            <div className="editable-field-groups">
              <fieldset className="editable-field-group">
                <legend>Read-only</legend>
                <div className="editable-field-grid">
                  <label className="path-field editable-field-control editable-field-disabled">
                    <span>Move ID</span>
                    <input disabled readOnly value={move.moveId} />
                  </label>
                  <label className="path-field editable-field-control editable-field-disabled">
                    <span>Version</span>
                    <input disabled readOnly value={move.version} />
                  </label>
                </div>
              </fieldset>
              {moveFieldGroups.map((group) => {
                const isFlagsGroup = group.group === 'Flags';
                return (
                  <fieldset
                    className={`editable-field-group${isFlagsGroup ? ' move-flags-field-group' : ''}`}
                    key={group.group}
                  >
                    <legend>{translateLiteral(group.group)}</legend>
                    <div
                      className={`editable-field-grid${isFlagsGroup ? ' move-flags-field-grid' : ''}`}
                    >
                      {group.fields.map((field) => {
                        const currentValue = getEditableMoveFieldValue(move, field.field);
                        const draftValue = moveDrafts[field.field] ?? '';
                        const draftState = getTrainerFieldDraftState(
                          draftValue,
                          currentValue,
                          field,
                          moveDraftContext
                        );

                        return (
                          <GiftPokemonDraftField
                            currentValue={currentValue}
                            disabled={!canEditMoves || editSession === null || isMoveUpdating}
                            draftState={draftState}
                            draftValue={draftValue}
                            field={field}
                            idPrefix="move-field"
                            key={field.field}
                            onChange={(value) => {
                              const nextDrafts = {
                                ...moveDrafts,
                                [field.field]: value
                              };
                              setMoveDraftsByMoveId((currentDrafts) =>
                                setFieldDraftRecord(
                                  currentDrafts,
                                  move.moveId,
                                  nextDrafts,
                                  moveDraftDefaults
                                )
                              );
                            }}
                            preservedValue={baselineValues?.[field.field] ?? null}
                          />
                        );
                      })}
                    </div>
                  </fieldset>
                );
              })}
            </div>

            {editSession ? (
              <div className="draft-action-row">
                <button
                  aria-busy={isMoveUpdating || undefined}
                  className="primary-button"
                  disabled={!canSaveMoveDrafts}
                  onClick={async () => {
                    const didSave = await onUpdateMoveFields(
                      move.moveId,
                      moveDraftSummary.changedFields.map((change) => ({
                        field: change.field,
                        value: change.value
                      }))
                    );
                    if (didSave) {
                      setMoveDraftsByMoveId((currentDrafts) =>
                        deleteFieldDraftRecord(currentDrafts, move.moveId)
                      );
                    }
                  }}
                  type="button"
                >
                  <BusyActionContent
                    busyLabel="Staging"
                    icon={<Save aria-hidden="true" size={16} />}
                    isBusy={isMoveUpdating}
                    label="Stage"
                  />
                </button>
                <button
                  className="danger-button"
                  disabled={isMoveUpdating}
                  onClick={() =>
                    cancelActiveEditSession(() =>
                      setMoveDraftsByMoveId({})
                    )
                  }
                  type="button"
                >
                  <X aria-hidden="true" size={16} />
                  <span>Cancel</span>
                </button>
                <span className="draft-action-summary">{formatDraftSummary(moveDraftSummary)}</span>
              </div>
            ) : null}
          </div>

          <div className="inspector-block">
            <h4>Core Stats</h4>
            <dl className="item-provenance-list compact-dl">
              <div>
                <dt>Power</dt>
                <dd>{formatMovePower(move.power)}</dd>
              </div>
              <div>
                <dt>Accuracy</dt>
                <dd>{translateLiteral(formatMoveAccuracy(move.accuracy))}</dd>
              </div>
              <div>
                <dt>PP</dt>
                <dd>{move.pp}</dd>
              </div>
              <div>
                <dt>Priority</dt>
                <dd>{move.priority}</dd>
              </div>
              <div>
                <dt>Crit stage</dt>
                <dd>{move.critStage}</dd>
              </div>
              <div>
                <dt>Max move</dt>
                <dd>{move.maxMovePower}</dd>
              </div>
            </dl>
          </div>

          <div className="inspector-block">
            <h4>Targeting</h4>
            <dl className="item-provenance-list compact-dl">
              <div>
                <dt>Target</dt>
                <dd>{move.targetName}</dd>
              </div>
              <div>
                <dt>{translateLiteral('Hits')}</dt>
                <dd>{translateLiteral(formatMoveHitRange(move.hitMin, move.hitMax))}</dd>
              </div>
            </dl>
          </div>

          <div className="inspector-block">
            <h4>Secondary Effects</h4>
            <dl className="item-provenance-list compact-dl">
              <div>
                <dt>Inflict</dt>
                <dd>{move.inflictName}</dd>
              </div>
              <div>
                <dt>{translateLiteral('Inflict chance')}</dt>
                <dd>
                  {translateLiteral(
                    formatMoveEffectChance(move.inflictPercent, move.inflict !== 0)
                  )}
                </dd>
              </div>
              <div>
                <dt>Inflict duration</dt>
                <dd>{formatMoveInflictDuration(move.rawInflictCount)}</dd>
              </div>
              <div>
                <dt>{translateLiteral('Inflicted-effect turns')}</dt>
                <dd>
                  {translateLiteral(formatMoveInflictedEffectTurns(move.turnMin, move.turnMax))}
                </dd>
              </div>
              {mappedQualityLabel ? (
                <div>
                  <dt>{translateLiteral('Effect quality')}</dt>
                  <dd>{translateLiteral(mappedQualityLabel)}</dd>
                </div>
              ) : null}
              <div>
                <dt>Flinch chance</dt>
                <dd>{move.flinch}%</dd>
              </div>
              <div>
                <dt>{translateLiteral('Drain (+) / recoil (-)')}</dt>
                <dd>{translateLiteral(formatMoveRecoilValue(move.recoil))}</dd>
              </div>
            </dl>
          </div>

          <div className="inspector-block">
            <h4>Stat Changes</h4>
            {visibleStatChanges.length > 0 ? (
              <ul className="inspector-list">
                {visibleStatChanges.map((statChange) => (
                  <li key={statChange.slot}>
                    {statChange.statName}: {statChange.stage} stage,{' '}
                    {translateLiteral(formatMoveEffectChance(statChange.percent, true))}
                  </li>
                ))}
              </ul>
            ) : (
              <p className="empty-copy">No stat change effects.</p>
            )}
          </div>

          <div className="inspector-block">
            <h4>{translateLiteral('Advanced / Raw')}</h4>
            <dl className="item-provenance-list compact-dl">
              {!mappedQualityLabel ? (
                <div>
                  <dt>{translateLiteral('Quality (raw)')}</dt>
                  <dd>{move.quality}</dd>
                </div>
              ) : null}
              <div>
                <dt>Effect sequence ID</dt>
                <dd>{move.effectSequence}</dd>
              </div>
              <div>
                <dt>{translateLiteral('HP recovery / cost (raw)')}</dt>
                <dd>{translateLiteral(formatMoveHealingValue(move.rawHealing))}</dd>
              </div>
            </dl>
          </div>

          <div className="inspector-block">
            <h4>Active Flags</h4>
            {activeFlags.length > 0 ? (
              <ul className="inspector-list">
                {activeFlags.map((flag) => (
                  <li key={flag.field}>{flag.label}</li>
                ))}
              </ul>
            ) : (
              <p className="empty-copy">No active flags.</p>
            )}
          </div>
        </>
      ) : (
        <p className="empty-copy">No move selected.</p>
      )}
    </aside>
  );
}

function TextSection({
  editSession,
  isEditStarting,
  isPagedResultWindow,
  isTextUpdating,
  onSearchChange,
  onSelectTextEntry,
  onStartEditSession,
  onUpdateTextEntry,
  searchText,
  selectedTextKey,
  workflow
}: {
  editSession: EditSession | null;
  isEditStarting: boolean;
  isPagedResultWindow: boolean;
  isTextUpdating: boolean;
  onSearchChange: (searchText: string) => void;
  onSelectTextEntry: (textKey: string | null) => void;
  onStartEditSession: () => void;
  onUpdateTextEntry: (textKey: string, value: string) => Promise<boolean>;
  searchText: string;
  selectedTextKey: string | null;
  workflow: TextWorkflow | null;
}) {
  const entries = workflow?.entries ?? [];
  const filteredEntries = useMemo(
    () => filterTextEntries(entries, searchText),
    [entries, searchText]
  );
  const selectedEntry = useMemo(
    () =>
      filteredEntries.find((entry) => entry.textKey === selectedTextKey) ??
      filteredEntries[0] ??
      null,
    [filteredEntries, selectedTextKey]
  );
  const canEditText = workflow?.summary.availability === 'available';
  const pendingTextKeys = useMemo(() => getPendingTextKeys(editSession), [editSession]);

  return (
    <>
      <section aria-labelledby="text-heading" className="panel wide-panel">
        <div className="panel-heading">
          <ListChecks aria-hidden="true" size={18} />
          <h2 id="text-heading">Text and Dialogue Map</h2>
        </div>

        <div className="items-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label="Search text entries"
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder="Search text"
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label={isPagedResultWindow ? 'Loaded results' : 'Loaded entries'}
            value={workflow ? workflow.stats.totalTextEntryCount.toString() : '0'}
          />
          <Metric
            label="Source files"
            value={workflow ? workflow.stats.sourceFileCount.toString() : '0'}
          />
          <Metric
            label="Pending changes"
            value={(editSession?.pendingEdits.length ?? 0).toString()}
          />
        </div>

        {workflow ? (
          <div className="text-layout">
            <div
              aria-colcount={5}
              aria-label="Text entries"
              aria-rowcount={filteredEntries.length + 1}
              className="text-table"
              role="table"
            >
              <div className="text-row text-row-heading" role="row">
                <span role="columnheader">Index</span>
                <span role="columnheader">File</span>
                <span role="columnheader">Line</span>
                <span role="columnheader">Value</span>
                <span role="columnheader">Source</span>
              </div>
              <VirtualTableBody
                getKey={(entry) => entry.textKey}
                items={filteredEntries}
                renderRow={(entry) => (
                  <button
                    className={`text-row ${selectedEntry?.textKey === entry.textKey ? 'text-row-selected' : ''} ${
                      pendingTextKeys.has(entry.textKey) ? 'text-row-pending' : ''
                    }`}
                    onClick={() => onSelectTextEntry(entry.textKey)}
                    role="row"
                    type="button"
                  >
                    <span role="cell">{entry.textId}</span>
                    <span role="cell">{entry.sourceFile}</span>
                    <span role="cell">{entry.lineIndex}</span>
                    <span data-localization-ignore="true" role="cell">{entry.value}</span>
                    <span role="cell">{formatSourceLayer(entry.provenance.sourceLayer)}</span>
                  </button>
                )}
              />
            </div>

            <SelectedTextPanel
              canEditText={canEditText}
              editSession={editSession}
              editableFields={workflow.editableFields}
              entry={selectedEntry}
              isEditStarting={isEditStarting}
              isTextUpdating={isTextUpdating}
              onStartEditSession={onStartEditSession}
              onUpdateTextEntry={onUpdateTextEntry}
            />
          </div>
        ) : (
          <p className="empty-copy">Open Text from Editors to load backend message tables.</p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
    </>
  );
}

function SelectedTextPanel({
  canEditText,
  editSession,
  editableFields,
  entry,
  isEditStarting,
  isTextUpdating,
  onStartEditSession,
  onUpdateTextEntry
}: {
  canEditText: boolean;
  editSession: EditSession | null;
  editableFields: TextEditableField[];
  entry: TextEntryRecord | null;
  isEditStarting: boolean;
  isTextUpdating: boolean;
  onStartEditSession: () => void;
  onUpdateTextEntry: (textKey: string, value: string) => Promise<boolean>;
}) {
  const [draftsByTextKey, setDraftsByTextKey] = useState<Record<string, string>>({});
  const textValueTextareaRef = useRef<HTMLTextAreaElement | null>(null);
  const valueField = editableFields.find((field) => field.field === 'value');
  const draftValue = entry ? draftsByTextKey[entry.textKey] ?? entry.value : '';
  const isTextDraftDirty =
    entry !== null && (draftsByTextKey[entry.textKey] ?? entry.value) !== entry.value;
  const isTextInputDisabled =
    entry === null || !canEditText || editSession === null || isTextUpdating || !entry.canEdit;
  useRegisterEditorDraftDirty(
    'text',
    Object.entries(draftsByTextKey).some(([textKey, value]) => {
      const sourceEntry = textKey === entry?.textKey ? entry : null;
      return sourceEntry ? value !== sourceEntry.value : true;
    })
  );

  useEffect(() => {
    if (!entry || !isTextDraftDirty) {
      return;
    }

    setDraftsByTextKey((currentDrafts) => {
      if (currentDrafts[entry.textKey] !== entry.value) {
        return currentDrafts;
      }

      const nextDrafts = { ...currentDrafts };
      delete nextDrafts[entry.textKey];
      return nextDrafts;
    });
  }, [entry, isTextDraftDirty]);

  const updateTextDraft = useCallback(
    (nextValue: string) => {
      if (!entry) {
        return;
      }

      setDraftsByTextKey((currentDrafts) => {
        if (nextValue === entry.value) {
          const nextDrafts = { ...currentDrafts };
          delete nextDrafts[entry.textKey];
          return nextDrafts;
        }

        return {
          ...currentDrafts,
          [entry.textKey]: nextValue
        };
      });
    },
    [entry]
  );

  const insertTextControlToken = useCallback(
    (token: string) => {
      if (!entry || isTextInputDisabled) {
        return;
      }

      const textarea = textValueTextareaRef.current;
      const shouldUseTextareaSelection = textarea !== null && document.activeElement === textarea;
      const selectionStart = shouldUseTextareaSelection
        ? textarea.selectionStart
        : draftValue.length;
      const selectionEnd = shouldUseTextareaSelection ? textarea.selectionEnd : draftValue.length;
      const nextValue = `${draftValue.slice(0, selectionStart)}${token}${draftValue.slice(selectionEnd)}`;
      const nextCursorPosition = selectionStart + token.length;
      updateTextDraft(nextValue);

      window.requestAnimationFrame(() => {
        textarea?.focus();
        textarea?.setSelectionRange(nextCursorPosition, nextCursorPosition);
      });
    },
    [draftValue, entry, isTextInputDisabled, updateTextDraft]
  );

  const draftState = getTextDraftState(draftValue, entry, valueField);
  const canSubmit = editSession !== null && draftState.canSubmit;

  return (
    <aside aria-label="Selected text provenance" className="text-inspector">
      <div className="panel-heading">
        <ShieldCheck aria-hidden="true" size={18} />
        <h3>Selected Text</h3>
      </div>

      {entry ? (
        <>
          <dl className="item-provenance-list">
            <div>
              <dt>Label</dt>
              <dd data-localization-ignore="true">{entry.label}</dd>
            </div>
            <div className="text-source-file-detail">
              <dt>Source file</dt>
              <dd data-localization-ignore="true">{entry.sourceFile}</dd>
            </div>
            <div>
              <dt>Line</dt>
              <dd>{entry.lineIndex}</dd>
            </div>
            <div>
              <dt>Layer</dt>
              <dd>{formatSourceLayer(entry.provenance.sourceLayer)}</dd>
            </div>
            <div>
              <dt>File state</dt>
              <dd>{formatFileState(entry.provenance.fileState)}</dd>
            </div>
          </dl>

          <div className="text-edit-form">
            <div className="path-field">
              <span>{valueField?.label ?? 'Text value'}</span>
              <div aria-label="Insert text controls" className="text-token-toolbar" role="toolbar">
                {textControlInserts.map((token) => (
                  <button
                    aria-label={`Insert ${token.label} ${token.display}`}
                    className="text-token-button"
                    disabled={isTextInputDisabled}
                    key={token.value}
                    onClick={() => insertTextControlToken(token.value)}
                    title={token.title}
                    type="button"
                  >
                    <span>{token.label}</span>
                    <code>{token.display}</code>
                  </button>
                ))}
              </div>
              <textarea
                aria-label={valueField?.label ?? 'Text value'}
                disabled={isTextInputDisabled}
                maxLength={valueField?.maximumLength ?? undefined}
                onChange={(event) => updateTextDraft(event.target.value)}
                ref={textValueTextareaRef}
                rows={8}
                value={draftValue}
              />
            </div>

            {!entry.canEdit ? (
              <p className="empty-copy">{entry.editBlockedReason ?? 'This text line is read-only.'}</p>
            ) : null}

            {editSession ? (
              <button
                aria-busy={isTextUpdating || undefined}
                className="primary-button"
                disabled={!canSubmit || isTextUpdating}
                onClick={async () => {
                  const didSave = await onUpdateTextEntry(entry.textKey, draftValue);
                  if (didSave) {
                    setDraftsByTextKey((currentDrafts) =>
                      deleteFieldDraftRecord(currentDrafts, entry.textKey)
                    );
                  }
                }}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Staging"
                  icon={<Save aria-hidden="true" size={16} />}
                  isBusy={isTextUpdating}
                  label="Stage"
                />
              </button>
            ) : (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditText || isEditStarting || !entry.canEdit}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            )}
          </div>
        </>
      ) : (
        <p className="empty-copy">No text entry selected.</p>
      )}
    </aside>
  );
}

type TrainersSectionProps = {
  editSession: EditSession | null;
  editorFamily: EditorUiFamily;
  isEditStarting: boolean;
  isTrainerUpdating: boolean;
  isScarletVioletProject: boolean;
  onSearchChange: (searchText: string) => void;
  onSelectTrainer: (trainerId: number | null) => void;
  onStartEditSession: () => void;
  onUpdateTrainerField: (
    trainerId: number,
    slot: number | null,
    field: string,
    value: string
  ) => void;
  onUpdateTrainerFields: (
    trainerId: number,
    slot: number | null,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  pokemonWorkflow: PokemonWorkflow | null;
  searchText: string;
  selectedTrainerId: number | null;
  workflow: TrainersWorkflow | null;
};

type TrainersSectionPublicProps = Omit<
  TrainersSectionProps,
  'editorFamily' | 'isScarletVioletProject'
>;

function SwShTrainersSection(props: TrainersSectionPublicProps) {
  return <TrainersSection {...props} editorFamily="swsh" isScarletVioletProject={false} />;
}

function SvTrainersSection(props: TrainersSectionPublicProps) {
  return <TrainersSection {...props} editorFamily="sv" isScarletVioletProject />;
}

function ZaTrainersSection(props: TrainersSectionPublicProps) {
  return <TrainersSection {...props} editorFamily="za" isScarletVioletProject={false} />;
}

function TrainersSection({
  editSession,
  editorFamily,
  isEditStarting,
  isTrainerUpdating,
  isScarletVioletProject,
  onSearchChange,
  onSelectTrainer,
  onStartEditSession,
  onUpdateTrainerField,
  onUpdateTrainerFields,
  pokemonWorkflow,
  searchText,
  selectedTrainerId,
  workflow
}: TrainersSectionProps) {
  const [selectedSlot, setSelectedSlot] = useState<number | null>(null);
  const [selectedTrainerCategoryId, setSelectedTrainerCategoryId] = useState('all');
  const trainers = workflow?.trainers ?? [];
  const searchFilteredTrainers = useMemo(
    () => filterTrainers(trainers, searchText),
    [searchText, trainers]
  );
  const trainerCategories = useMemo(
    () => (editorFamily === 'za' ? buildZaTrainerCategories(searchFilteredTrainers) : []),
    [editorFamily, searchFilteredTrainers]
  );
  const supportsTrainerCategories = trainerCategories.length > 1;
  const activeTrainerCategoryId =
    supportsTrainerCategories &&
    trainerCategories.some((category) => category.id === selectedTrainerCategoryId)
      ? selectedTrainerCategoryId
      : 'all';
  const filteredTrainers = useMemo(
    () =>
      supportsTrainerCategories && activeTrainerCategoryId !== 'all'
        ? searchFilteredTrainers.filter(
            (trainer) => getZaTrainerCategoryId(trainer) === activeTrainerCategoryId
          )
        : searchFilteredTrainers,
    [activeTrainerCategoryId, searchFilteredTrainers, supportsTrainerCategories]
  );
  const selectedTrainer = useMemo(
    () =>
      filteredTrainers.find((trainer) => trainer.trainerId === selectedTrainerId) ??
      filteredTrainers[0] ??
      null,
    [filteredTrainers, selectedTrainerId]
  );
  const selectedPokemon =
    selectedTrainer?.team.find((pokemon) => pokemon.slot === selectedSlot) ??
    selectedTrainer?.team[0] ??
    null;
  const canEditTrainers = workflow?.summary.availability === 'available';
  const pendingTrainerIds = useMemo(
    () => getPendingTrainerIds(editSession, trainers),
    [editSession, trainers]
  );

  useEffect(() => {
    if (!selectedTrainer) {
      setSelectedSlot(null);
      return;
    }

    const hasSelectedSlot = selectedTrainer.team.some((pokemon) => pokemon.slot === selectedSlot);
    if (!hasSelectedSlot) {
      setSelectedSlot(selectedTrainer.team[0]?.slot ?? null);
    }
  }, [selectedSlot, selectedTrainer?.trainerId, selectedTrainer?.team]);

  useEffect(() => {
    if (
      selectedTrainerCategoryId !== 'all' &&
      !trainerCategories.some((category) => category.id === selectedTrainerCategoryId)
    ) {
      setSelectedTrainerCategoryId('all');
    }
  }, [selectedTrainerCategoryId, trainerCategories]);

  return (
    <>
      <section
        aria-labelledby="trainers-heading"
        className={`panel wide-panel ${editorFamily}-editor-surface ${editorFamily}-trainers-section`}
      >
        <div className="panel-heading">
          <Activity aria-hidden="true" size={18} />
          <h2 id="trainers-heading">Trainers</h2>
        </div>

        <div className="items-toolbar trainers-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label="Search trainers"
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder="Search trainers"
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label="Loaded trainers"
            value={workflow ? workflow.stats.totalTrainerCount.toString() : '0'}
          />
          <Metric
            label="Party Pokemon"
            value={workflow ? workflow.stats.totalPokemonCount.toString() : '0'}
          />
          <Metric
            label="Pending changes"
            value={(editSession?.pendingEdits.length ?? 0).toString()}
          />
        </div>

        {workflow ? (
          <>
            {supportsTrainerCategories ? (
              <div
                aria-label="Trainer categories"
                className="condition-tabs trainer-category-tabs"
                role="tablist"
              >
                {trainerCategories.map((category) => (
                  <button
                    aria-selected={category.id === activeTrainerCategoryId}
                    className="condition-tab-button trainer-category-tab"
                    key={category.id}
                    onClick={() => {
                      setSelectedTrainerCategoryId(category.id);
                      const nextTrainer =
                        category.id === 'all'
                          ? searchFilteredTrainers[0]
                          : searchFilteredTrainers.find(
                              (trainer) => getZaTrainerCategoryId(trainer) === category.id
                            );
                      onSelectTrainer(nextTrainer?.trainerId ?? null);
                    }}
                    role="tab"
                    title={category.description}
                    type="button"
                  >
                    <span>{category.label}</span>
                    <small>{category.count}</small>
                  </button>
                ))}
              </div>
            ) : null}

            <div className="trainers-layout">
              <div
                aria-colcount={6}
                aria-label="Trainers"
                aria-rowcount={filteredTrainers.length + 1}
                className="trainers-table"
                role="table"
              >
                <div className="trainers-row trainers-row-heading" role="row">
                  <span role="columnheader">ID</span>
                  <span role="columnheader">Name</span>
                  <span role="columnheader">Class</span>
                  <span role="columnheader">Battle</span>
                  <span role="columnheader">Team</span>
                  <span role="columnheader">Source</span>
                </div>
                <VirtualTableBody
                  getKey={(trainer) => trainer.trainerId}
                  items={filteredTrainers}
                  renderRow={(trainer) => (
                    <button
                      className={`trainers-row ${
                        selectedTrainer?.trainerId === trainer.trainerId
                          ? 'trainers-row-selected'
                          : ''
                      } ${pendingTrainerIds.has(trainer.trainerId) ? 'trainers-row-pending' : ''}`}
                      onClick={() => onSelectTrainer(trainer.trainerId)}
                      role="row"
                      type="button"
                    >
                      <span role="cell">{trainer.trainerId}</span>
                      <span data-localization-ignore="true" role="cell">
                        {trainer.name}
                      </span>
                      <span data-localization-ignore="true" role="cell">
                        {trainer.trainerClass}
                      </span>
                      <span data-localization-ignore="true" role="cell">
                        {trainer.battleType}
                      </span>
                      <span role="cell">{getOccupiedTrainerPokemonCount(trainer)}</span>
                      <span role="cell">{formatSourceLayer(trainer.provenance.sourceLayer)}</span>
                    </button>
                  )}
                />
              </div>

              <SelectedTrainerPanel
                canEditTrainers={canEditTrainers}
                editSession={editSession}
                editorFamily={editorFamily}
                editableFields={workflow.editableFields}
                isEditStarting={isEditStarting}
                isTrainerUpdating={isTrainerUpdating}
                isScarletVioletProject={isScarletVioletProject}
                onSelectSlot={setSelectedSlot}
                onStartEditSession={onStartEditSession}
                onUpdateTrainerField={onUpdateTrainerField}
                onUpdateTrainerFields={onUpdateTrainerFields}
                pokemonWorkflow={pokemonWorkflow}
                selectedPokemon={selectedPokemon}
                selectedSlot={selectedSlot}
                trainer={selectedTrainer}
              />
            </div>
          </>
        ) : (
          <p className="empty-copy">Open Trainers from Workflows to load backend trainer data.</p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
    </>
  );
}

function SelectedTrainerPanel({
  canEditTrainers,
  editSession,
  editorFamily,
  editableFields,
  isEditStarting,
  isTrainerUpdating,
  isScarletVioletProject,
  onSelectSlot,
  onStartEditSession,
  onUpdateTrainerField,
  onUpdateTrainerFields,
  pokemonWorkflow,
  selectedPokemon,
  selectedSlot,
  trainer
}: {
  canEditTrainers: boolean;
  editSession: EditSession | null;
  editorFamily: EditorUiFamily;
  editableFields: TrainerEditableField[];
  isEditStarting: boolean;
  isTrainerUpdating: boolean;
  isScarletVioletProject: boolean;
  onSelectSlot: (slot: number | null) => void;
  onStartEditSession: () => void;
  onUpdateTrainerField: (
    trainerId: number,
    slot: number | null,
    field: string,
    value: string
  ) => void;
  onUpdateTrainerFields: (
    trainerId: number,
    slot: number | null,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  pokemonWorkflow: PokemonWorkflow | null;
  selectedPokemon: TrainerPokemonRecord | null;
  selectedSlot: number | null;
  trainer: TrainerRecord | null;
}) {
  const [trainerDraftsByTrainerId, setTrainerDraftsByTrainerId] = useState<
    Record<string, Record<string, string>>
  >({});
  const [pokemonDraftsByTrainerSlot, setPokemonDraftsByTrainerSlot] = useState<
    Record<string, Record<string, string>>
  >({});
  const cancelActiveEditSession = useCancelActiveEditSession();
  const trainerFields = useMemo(
    () =>
      editableFields.filter((field) =>
        trainerDataFieldNames.includes(field.field as (typeof trainerDataFieldNames)[number])
      ),
    [editableFields]
  );
  const pokemonFields = useMemo(
    () =>
      editableFields.filter((field) =>
        trainerPokemonFieldNames.includes(field.field as (typeof trainerPokemonFieldNames)[number])
      ),
    [editableFields]
  );
  const defaultContextualPokemonFields = useMemo(
    () =>
      pokemonFields.map((field) => {
        const options = getContextualFieldOptions(
          field,
          selectedPokemon
            ? {
                abilityOptions: selectedPokemon.abilityOptions,
                species: selectedPokemon.species,
                speciesId: selectedPokemon.speciesId
              }
            : undefined
        );

        return options === field.options ? field : { ...field, options };
      }),
    [pokemonFields, selectedPokemon]
  );
  const trainerDraftDefaults = useMemo(
    () =>
      trainer
        ? createTrainerDrafts(trainerFields, (field) =>
            getEditableTrainerFieldValue(trainer, field)
          )
        : {},
    [trainer, trainerFields]
  );
  const pokemonDraftDefaults = useMemo(
    () =>
      selectedPokemon
        ? createTrainerDrafts(defaultContextualPokemonFields, (field) =>
            getEditablePokemonFieldValue(selectedPokemon, field)
          )
        : {},
    [defaultContextualPokemonFields, selectedPokemon]
  );
  const selectedPokemonDraftKey =
    trainer && selectedPokemon ? `${trainer.trainerId}:${selectedPokemon.slot}` : null;
  const trainerDrafts = trainer
    ? trainerDraftsByTrainerId[trainer.trainerId.toString()] ?? trainerDraftDefaults
    : {};
  const pokemonDrafts = selectedPokemonDraftKey
    ? pokemonDraftsByTrainerSlot[selectedPokemonDraftKey] ?? pokemonDraftDefaults
    : {};
  const selectedPokemonFormOptionContext = useMemo(
    () => {
      if (!selectedPokemon) {
        return undefined;
      }

      const context = createDraftSpeciesFormOptionContext(
            defaultContextualPokemonFields.find(
              (field) => field.field === speciesIdFieldName
            ) ?? null,
            pokemonDrafts[speciesIdFieldName],
            selectedPokemon.species,
            selectedPokemon.speciesId,
            selectedPokemon.abilityOptions,
            editorFamily
          );
      const draftedForm = Number.parseInt(
        pokemonDrafts[formFieldName] ?? selectedPokemon.form.toString(),
        10
      );
      const referencePokemon = pokemonWorkflow?.pokemon.find(
        (pokemon) =>
          pokemon.speciesId === context.speciesId &&
          pokemon.form === (Number.isInteger(draftedForm) ? draftedForm : selectedPokemon.form)
      );
      const usesCurrentIdentity =
        context.speciesId === selectedPokemon.speciesId &&
        draftedForm === selectedPokemon.form;

      return {
        ...context,
        abilityOptions: referencePokemon
          ? createTrainerPokemonAbilityOptions(referencePokemon)
          : usesCurrentIdentity
            ? selectedPokemon.abilityOptions
            : []
      };
    },
    [
      defaultContextualPokemonFields,
      editorFamily,
      pokemonDrafts,
      pokemonWorkflow,
      selectedPokemon
    ]
  );
  const contextualPokemonFields = useMemo(
    () =>
      pokemonFields.map((field) => {
        const options = getContextualFieldOptions(field, selectedPokemonFormOptionContext);
        return options === field.options ? field : { ...field, options };
      }),
    [pokemonFields, selectedPokemonFormOptionContext]
  );
  const projectedTrainerHighestLevel = useMemo(
    () => getProjectedTrainerHighestLevel(trainer, selectedSlot, pokemonDrafts),
    [pokemonDrafts, selectedSlot, trainer]
  );
  const contextualTrainerFields = useMemo(
    () =>
      trainerFields.map((field) =>
        field.field === moneyFieldName
          ? {
              ...field,
              label:
                editorFamily === 'swsh'
                  ? 'Prize money rate'
                  : editorFamily === 'za'
                    ? field.label
                    : 'Prize money',
              options:
                editorFamily === 'swsh' || editorFamily === 'za'
                  ? field.options
                  : createTrainerPrizeMoneyOptions(projectedTrainerHighestLevel)
            }
          : field
      ),
    [editorFamily, projectedTrainerHighestLevel, trainerFields]
  );
  const aiFlagsField = editableFields.find((field) => field.field === aiFlagsFieldName) ?? null;
  const canToggleAiFlags =
    canEditTrainers && editSession !== null && !isTrainerUpdating && aiFlagsField !== null;
  const aiFlagsMaskLabel = trainer
    ? `0x${trainer.aiFlags.toString(16).padStart(4, '0').toLocaleUpperCase()}`
    : '0x0000';
  const showTerastallizationDetails =
    isScarletVioletProject &&
    contextualTrainerFields.some((field) => field.field === trainerCanTerastallizeFieldName);
  const trainerFieldGroups = useMemo(
    () => groupTrainerEditableFields(contextualTrainerFields, getTrainerDataFieldGroup),
    [contextualTrainerFields]
  );
  const pokemonFieldGroups = useMemo(
    () =>
      groupTrainerEditableFields(contextualPokemonFields, getTrainerPokemonFieldGroup).map(
        sortTrainerPokemonFieldGroup
      ),
    [contextualPokemonFields]
  );
  const pokemonNatureEffects = useMemo(() => {
    if (!selectedPokemon) {
      return null;
    }

    const natureField =
      contextualPokemonFields.find((field) => field.field === natureFieldName) ?? null;
    const natureDraftValue = pokemonDrafts[natureFieldName] ?? selectedPokemon.nature.toString();
    return getNatureStatEffects(
      parseEditableIntegerDraft(natureDraftValue, natureField?.options),
      editorFamily
    );
  }, [contextualPokemonFields, editorFamily, pokemonDrafts, selectedPokemon]);
  const projectedPokemonStats = useMemo(
    () =>
      selectedPokemon
        ? getProjectedTrainerPokemonStats(
            selectedPokemon,
            contextualPokemonFields,
            pokemonDrafts,
            pokemonWorkflow,
            editorFamily
          )
        : null,
    [contextualPokemonFields, editorFamily, pokemonDrafts, pokemonWorkflow, selectedPokemon]
  );
  const selectedPokemonCanDynamax = useMemo(() => {
    if (!selectedPokemon) {
      return true;
    }

    const pokemonCanDynamaxField =
      contextualPokemonFields.find((field) => field.field === canDynamaxFieldName) ?? null;
    if (!pokemonCanDynamaxField) {
      return true;
    }

    const currentValue = getEditablePokemonFieldValue(selectedPokemon, canDynamaxFieldName);
    const draftValue =
      pokemonDrafts[canDynamaxFieldName] ?? currentValue?.toString() ?? '';
    const draftState = getTrainerFieldDraftState(
      draftValue,
      currentValue,
      pokemonCanDynamaxField
    );

    if (!draftState.isValid || draftState.normalizedValue === null) {
      return currentValue === 1;
    }

    return draftState.normalizedValue === '1';
  }, [contextualPokemonFields, pokemonDrafts, selectedPokemon]);
  const selectedPokemonBlockedByPreviousSlot = useMemo(() => {
    if (!trainer || !selectedPokemon) {
      return false;
    }

    return trainer.team.some(
      (pokemon) => pokemon.slot < selectedPokemon.slot && pokemon.speciesId === 0
    );
  }, [selectedPokemon, trainer]);
  const trainerDraftSummary = useMemo(
    () =>
      getTrainerDraftSummary(
        contextualTrainerFields,
        trainerDrafts,
        trainer ? (field) => getEditableTrainerFieldValue(trainer, field) : null
      ),
    [contextualTrainerFields, trainer, trainerDrafts]
  );
  const pokemonDraftSummary = useMemo(
    () =>
      getTrainerDraftSummary(
        contextualPokemonFields,
        pokemonDrafts,
        selectedPokemon ? (field) => getEditablePokemonFieldValue(selectedPokemon, field) : null
      ),
    [contextualPokemonFields, pokemonDrafts, selectedPokemon]
  );
  const canSaveTrainerDrafts =
    trainer !== null &&
    editSession !== null &&
    canEditTrainers &&
    !isTrainerUpdating &&
    trainerDraftSummary.changedFields.length > 0 &&
    trainerDraftSummary.invalidFields.length === 0;
  const canSavePokemonDrafts =
    trainer !== null &&
    selectedPokemon !== null &&
    editSession !== null &&
    canEditTrainers &&
    !isTrainerUpdating &&
    pokemonDraftSummary.changedFields.length > 0 &&
    pokemonDraftSummary.invalidFields.length === 0;
  useRegisterEditorDraftDirty(
    'trainers',
    countFieldDraftRecords(trainerDraftsByTrainerId) > 0 ||
      countFieldDraftRecords(pokemonDraftsByTrainerSlot) > 0
  );

  useEffect(() => {
    if (!trainer) {
      return;
    }

    setTrainerDraftsByTrainerId((currentDrafts) =>
      pruneFieldDraftRecord(currentDrafts, trainer.trainerId, trainerDraftDefaults)
    );
  }, [trainer, trainerDraftDefaults]);

  useEffect(() => {
    if (!selectedPokemonDraftKey) {
      return;
    }

    setPokemonDraftsByTrainerSlot((currentDrafts) =>
      pruneFieldDraftRecord(currentDrafts, selectedPokemonDraftKey, pokemonDraftDefaults)
    );
  }, [pokemonDraftDefaults, selectedPokemonDraftKey]);

  return (
    <aside aria-label="Selected trainer provenance" className="trainer-inspector">
      <div className="panel-heading">
        <ShieldCheck aria-hidden="true" size={18} />
        <h3>Selected Trainer</h3>
      </div>

      {trainer ? (
        <>
          <dl className="item-provenance-list">
            <div>
              <dt>Name</dt>
              <dd data-localization-ignore="true">{trainer.name}</dd>
            </div>
            <div>
              <dt>Data file</dt>
              <dd>{trainer.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>Party file</dt>
              <dd>{trainer.provenance.teamSourceFile}</dd>
            </div>
            <div>
              <dt>Class file</dt>
              <dd>{trainer.provenance.classSourceFile ?? 'Not loaded'}</dd>
            </div>
            <div>
              <dt>Class ball scope</dt>
              <dd>{trainer.classBallScope}</dd>
            </div>
            {showTerastallizationDetails ? (
              <>
                <div>
                  <dt>Can Terastallize</dt>
                  <dd>{trainer.canTerastallize === true ? 'Yes' : 'No'}</dd>
                </div>
                <div>
                  <dt>Tera behavior</dt>
                  <dd>{trainer.teraTarget ?? 'Disabled'}</dd>
                </div>
              </>
            ) : null}
            <div>
              <dt>Data layer</dt>
              <dd>{formatSourceLayer(trainer.provenance.sourceLayer)}</dd>
            </div>
            <div>
              <dt>Party layer</dt>
              <dd>{formatSourceLayer(trainer.provenance.teamSourceLayer)}</dd>
            </div>
            <div>
              <dt>Class layer</dt>
              <dd>
                {trainer.provenance.classSourceLayer
                  ? formatSourceLayer(trainer.provenance.classSourceLayer)
                  : 'Not loaded'}
              </dd>
            </div>
          </dl>

          <div className="trainer-edit-form">
            {trainer.aiFlagStates.length > 0 ? (
              <div className="trainer-ai-flags-panel">
                <div className="trainer-ai-flags-header">
                  <strong>AI Flags</strong>
                  <span>{aiFlagsMaskLabel}</span>
                </div>
                <div className="trainer-ai-flags-grid">
                  {trainer.aiFlagStates.map((flag) => {
                    const isReserved = flag.label.toLocaleLowerCase().startsWith('unused');

                    return (
                      <label
                        className={`trainer-ai-flag ${
                          isReserved ? 'trainer-ai-flag-disabled' : ''
                        }`}
                        key={flag.bit}
                        title={isReserved ? 'Reserved for later research.' : flag.description}
                      >
                        <input
                          checked={flag.enabled}
                          disabled={!canToggleAiFlags || isReserved}
                          onChange={(event) => {
                            const nextValue = event.target.checked
                              ? trainer.aiFlags | flag.mask
                              : trainer.aiFlags & ~flag.mask;
                            onUpdateTrainerField(
                              trainer.trainerId,
                              null,
                              aiFlagsFieldName,
                              nextValue.toString()
                            );
                          }}
                          type="checkbox"
                        />
                        <span>
                          <strong>{flag.label}</strong>
                          <small>{isReserved ? 'Reserved and locked.' : flag.description}</small>
                        </span>
                      </label>
                    );
                  })}
                </div>
              </div>
            ) : null}

            <div className="editable-field-groups">
              {trainerFieldGroups.map((group) => (
                <fieldset className="editable-field-group" key={group.group}>
                  <legend>{group.group}</legend>
                  <div className="editable-field-grid">
                    {group.fields.map((field) => {
                      const currentValue = getEditableTrainerFieldValue(trainer, field.field);
                      const draftValue = trainerDrafts[field.field] ?? '';
                      const draftState = getTrainerFieldDraftState(draftValue, currentValue, field);
                      const isFieldBlocked =
                        field.field === classBallIdFieldName && !trainer.canEditClassBall;
                      const disabledReason =
                        editorFamily === 'swsh' && field.field === giftFieldName
                          ? 'This unknown trainer header value is preserved as raw read-only data.'
                          : editorFamily === 'swsh' && field.field === healFieldName
                            ? 'This unknown trainer header flag is preserved as raw read-only data.'
                          : isFieldBlocked
                          ? 'Class ball is locked for this trainer class.'
                          : undefined;

                      return (
                        <TrainerDraftField
                          currentValue={currentValue}
                          disabled={
                            disabledReason !== undefined ||
                            !canEditTrainers ||
                            editSession === null ||
                            isTrainerUpdating
                          }
                          disabledReason={disabledReason}
                          draftState={draftState}
                          draftValue={draftValue}
                          field={field}
                          key={field.field}
                          onChange={(value) => {
                            const nextDrafts = {
                              ...trainerDrafts,
                              [field.field]: value
                            };
                            setTrainerDraftsByTrainerId((currentDrafts) =>
                              setFieldDraftRecord(
                                currentDrafts,
                                trainer.trainerId,
                                nextDrafts,
                                trainerDraftDefaults
                              )
                            );
                          }}
                        />
                      );
                    })}
                  </div>
                </fieldset>
              ))}
            </div>
            {editSession ? (
              <div className="draft-action-row">
                <button
                  aria-busy={isTrainerUpdating || undefined}
                  className="primary-button"
                  disabled={!canSaveTrainerDrafts}
                  onClick={async () => {
                    const didSave = await onUpdateTrainerFields(
                      trainer.trainerId,
                      null,
                      trainerDraftSummary.changedFields.map((change) => ({
                        field: change.field,
                        value: change.value
                      }))
                    );
                    if (didSave) {
                      setTrainerDraftsByTrainerId((currentDrafts) =>
                        deleteFieldDraftRecord(currentDrafts, trainer.trainerId)
                      );
                    }
                  }}
                  type="button"
                >
                  <BusyActionContent
                    busyLabel="Staging"
                    icon={<Save aria-hidden="true" size={16} />}
                    isBusy={isTrainerUpdating}
                    label="Stage"
                  />
                </button>
                <button
                  className="danger-button"
                  disabled={isTrainerUpdating}
                  onClick={() =>
                    cancelActiveEditSession(() => {
                      setTrainerDraftsByTrainerId({});
                      setPokemonDraftsByTrainerSlot({});
                    })
                  }
                  type="button"
                >
                  <X aria-hidden="true" size={16} />
                  <span>Cancel</span>
                </button>
                <span className="draft-action-summary">
                  {formatDraftSummary(trainerDraftSummary)}
                </span>
              </div>
            ) : null}

            <div className="trainer-party-header">
              <strong>Party</strong>
            </div>

            {trainer.team.length > 0 ? (
              <div className="trainer-party-card-grid" aria-label="Trainer party Pokemon">
                {trainer.team.map((pokemon) => {
                  const isEmptySlot = pokemon.speciesId === 0;
                  const pokemonLabel = isEmptySlot
                    ? 'Empty slot'
                    : formatSpeciesFormLabel(
                        pokemon.species,
                        pokemon.form,
                        pokemon.speciesId,
                        editorFamily
                      );
                  const pokemonSpriteLabel = isEmptySlot
                    ? 'None'
                    : formatSpeciesFormLabel(
                        pokemon.spriteName ?? pokemon.species,
                        pokemon.form,
                        pokemon.speciesId,
                        editorFamily
                      );
                  const slotLabel = `Slot ${formatTrainerSlotNumber(pokemon.slot, editorFamily)}`;

                  return (
                    <button
                      aria-pressed={selectedSlot === pokemon.slot}
                      className="trainer-party-card"
                      key={pokemon.slot}
                      onClick={() => onSelectSlot(pokemon.slot)}
                      type="button"
                    >
                      <PokemonSprite
                        editorFamily={editorFamily}
                        className="trainer-party-sprite"
                        form={pokemon.form}
                        name={pokemonLabel}
                        speciesId={pokemon.speciesId}
                        spriteName={pokemon.spriteName ?? pokemonSpriteLabel}
                      />
                      <strong data-localization-ignore="true">
                        {isEmptySlot ? slotLabel : pokemonLabel}
                      </strong>
                      <span>{isEmptySlot ? 'None' : `Lv. ${pokemon.level}`}</span>
                    </button>
                  );
                })}
              </div>
            ) : null}

            {selectedPokemon ? (
              <div className="trainer-party-edit-stack">
                <div className="editable-field-groups">
                  {pokemonFieldGroups.map((group) => (
                    <fieldset className="editable-field-group" key={group.group}>
                      <legend>{group.group}</legend>
                      <div className="editable-field-grid">
                        {group.fields.map((field) => {
                          const currentValue = getEditablePokemonFieldValue(
                            selectedPokemon,
                            field.field
                          );
                          const draftValue = pokemonDrafts[field.field] ?? '';
                          const draftState = getTrainerFieldDraftState(
                            draftValue,
                            currentValue,
                            field
                          );
                          const isDynamaxDependentField = dynamaxDependentFieldNames.includes(
                            field.field as (typeof dynamaxDependentFieldNames)[number]
                          );
                          const selectedPokemonSlotIsEmpty = selectedPokemon.speciesId === 0;
                          const disabledReason =
                            selectedPokemonBlockedByPreviousSlot
                              ? 'Fill the previous party slot first.'
                              : selectedPokemonSlotIsEmpty && field.field !== speciesIdFieldName
                              ? 'Set species before editing this slot.'
                              : isDynamaxDependentField && !selectedPokemonCanDynamax
                              ? 'Set Can Dynamax to Yes to edit this field.'
                              : undefined;

                          return (
                            <TrainerDraftField
                              currentValue={currentValue}
                              disabled={
                                disabledReason !== undefined ||
                                !canEditTrainers ||
                                editSession === null ||
                                isTrainerUpdating
                              }
                              disabledReason={disabledReason}
                              draftState={draftState}
                              draftValue={draftValue}
                              field={field}
                              formOptionContext={selectedPokemonFormOptionContext}
                              key={field.field}
                              labelAdornment={getNatureStatAdornment(
                                field.field,
                                pokemonNatureEffects
                              )}
                              onChange={(value) => {
                                if (!selectedPokemonDraftKey) {
                                  return;
                                }

                                const nextDrafts = {
                                  ...pokemonDrafts,
                                  [field.field]: value
                                };
                                if (field.field === canDynamaxFieldName && value === '0') {
                                  for (const dependentField of dynamaxDependentFieldNames) {
                                    nextDrafts[dependentField] =
                                      pokemonDraftDefaults[dependentField] ?? '';
                                  }
                                }
                                setPokemonDraftsByTrainerSlot((currentDrafts) =>
                                  setFieldDraftRecord(
                                    currentDrafts,
                                    selectedPokemonDraftKey,
                                    nextDrafts,
                                    pokemonDraftDefaults
                                  )
                                );
                              }}
                            />
                          );
                        })}
                      </div>
                    </fieldset>
                  ))}
                </div>
                <TrainerPokemonProjectedStatsPanel projectedStats={projectedPokemonStats} />
                {editSession ? (
                  <div className="draft-action-row">
                    <button
                      aria-busy={isTrainerUpdating || undefined}
                      className="primary-button"
                      disabled={!canSavePokemonDrafts}
                      onClick={async () => {
                        const didSave = await onUpdateTrainerFields(
                          trainer.trainerId,
                          selectedPokemon.slot,
                          pokemonDraftSummary.changedFields.map((change) => ({
                            field: change.field,
                            value: change.value
                          }))
                        );
                        if (didSave && selectedPokemonDraftKey) {
                          setPokemonDraftsByTrainerSlot((currentDrafts) =>
                            deleteFieldDraftRecord(currentDrafts, selectedPokemonDraftKey)
                          );
                        }
                      }}
                      type="button"
                    >
                      <BusyActionContent
                        busyLabel="Staging"
                        icon={<Save aria-hidden="true" size={16} />}
                        isBusy={isTrainerUpdating}
                        label="Stage"
                      />
                    </button>
                    <button
                      className="danger-button"
                      disabled={isTrainerUpdating}
                      onClick={() =>
                        cancelActiveEditSession(() => {
                          setTrainerDraftsByTrainerId({});
                          setPokemonDraftsByTrainerSlot({});
                        })
                      }
                      type="button"
                    >
                      <X aria-hidden="true" size={16} />
                      <span>Cancel</span>
                    </button>
                    <span className="draft-action-summary">
                      {formatDraftSummary(pokemonDraftSummary)}
                    </span>
                  </div>
                ) : null}
              </div>
            ) : (
              <p className="empty-copy">No party Pokemon selected.</p>
            )}

            {!editSession ? (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditTrainers || isEditStarting}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            ) : null}
          </div>
        </>
      ) : (
        <p className="empty-copy">No trainer selected.</p>
      )}
    </aside>
  );
}

type TrainerDraftState = {
  error: string | null;
  isChanged: boolean;
  isValid: boolean;
  normalizedValue: string | null;
};

type TrainerDraftChange = {
  field: string;
  label: string;
  value: string;
};

type ProjectedTrainerPokemonStats = {
  baseStats: NonNullable<TrainerPokemonRecord['baseStats']>;
  stats: TrainerPokemonRecord['evs'];
};

function TrainerPokemonProjectedStatsPanel({
  projectedStats
}: {
  projectedStats: ProjectedTrainerPokemonStats | null;
}) {
  const { translateLiteral } = useLocalization();

  if (!projectedStats) {
    return null;
  }

  return (
    <section aria-label="Projected stats" className="trainer-projected-stats-panel">
      <div className="trainer-projected-stats-header">
        <strong>{translateLiteral('Projected Stats')}</strong>
      </div>
      <dl className="trainer-projected-stats-grid">
        {trainerProjectedStatRows.map((row) => (
          <div className="trainer-projected-stat" key={row.key}>
            <dt>{translateLiteral(row.label)}</dt>
            <dd aria-label={`${row.label} projected stat`}>
              {projectedStats.stats[row.key]}
            </dd>
          </div>
        ))}
      </dl>
    </section>
  );
}
type DynamaxAdventureEditableFieldName = DynamaxAdventureEditableField['field'];
type DynamaxAdventureEntryChangeGroup = {
  entryIndex: number;
  changes: Array<{ field: DynamaxAdventureEditableFieldName; value: string }>;
};
type DynamaxAdventureDraftFieldOptions = Record<string, EditableFieldOption[]>;

type DraftStateContext = {
  clampIvStats?: boolean;
  drafts: Record<string, string>;
  enforcePokemonEvLimits?: boolean;
  fields: NumericEditableField[];
  getValue: (field: string) => number | null;
  preservedValues?: Readonly<Record<string, number | null>>;
};

type NumericEditableField = {
  field: string;
  label: string;
  maximumValue: number | null;
  minimumValue: number | null;
  options: Array<{ label: string; value: number }>;
  valueKind: string;
};

function TrainerDraftField({
  currentValue,
  disabled,
  disabledReason,
  draftState,
  draftValue,
  field,
  formOptionContext,
  idPrefix = 'trainer-field',
  labelAdornment,
  onChange
}: {
  currentValue: number | null;
  disabled: boolean;
  disabledReason?: string;
  draftState: TrainerDraftState;
  draftValue: string;
  field: NumericEditableField;
  formOptionContext?: SpeciesFormOptionContext;
  idPrefix?: string;
  labelAdornment?: ReactNode;
  onChange: (value: string) => void;
}) {
  const inputId = `${idPrefix}-${field.field}`;
  const { contextualFormOptionContext, knownFormCount, options } =
    useContextualSpeciesFormOptions(field, formOptionContext, currentValue);
  const formDisabledReason = getFormFieldDisabledReason(
    field,
    contextualFormOptionContext,
    currentValue,
    knownFormCount
  );
  const effectiveDisabledReason = disabledReason ?? formDisabledReason ?? undefined;
  const effectiveDisabled = disabled || Boolean(effectiveDisabledReason);
  const statusText = draftState.error ?? (draftState.isChanged ? 'Changed' : null);
  const { translateLiteral } = useLocalization();
  const localizedFieldLabel = translateLiteral(field.label);
  const localizedFieldHelpText = translateLiteral(
    effectiveDisabledReason ?? getEditableFieldHelp(field)
  );

  return (
    <label
      className={`path-field editable-field-control ${
        draftState.isChanged ? 'editable-field-changed' : ''
      } ${!draftState.isValid ? 'editable-field-invalid' : ''} ${
        effectiveDisabledReason ? 'editable-field-disabled' : ''
      }`}
      htmlFor={inputId}
      title={localizedFieldHelpText}
    >
      <span className="editable-field-label-row">
        <span>{localizedFieldLabel}</span>
        {labelAdornment}
      </span>
      {field.valueKind === 'boolean' ? (
        <select
          aria-label={localizedFieldLabel}
          disabled={effectiveDisabled}
          id={inputId}
          onChange={(event) => onChange(event.target.value)}
          title={localizedFieldHelpText}
          value={draftValue === '1' ? '1' : '0'}
        >
          <option value="1">{translateLiteral('Yes')}</option>
          <option value="0">{translateLiteral('No')}</option>
        </select>
      ) : options.length > 0 ? (
        <SearchableOptionInput
          ariaLabel={field.label}
          disabled={effectiveDisabled}
          id={inputId}
          onChange={onChange}
          options={options}
          title={localizedFieldHelpText}
          value={draftValue}
        />
      ) : (
        <input
          aria-label={localizedFieldLabel}
          disabled={effectiveDisabled}
          id={inputId}
          max={field.maximumValue ?? undefined}
          min={field.minimumValue ?? undefined}
          onChange={(event) => onChange(event.target.value)}
          title={localizedFieldHelpText}
          type="number"
          value={draftValue}
        />
      )}
      {effectiveDisabledReason ? (
        <small className="editable-field-status">{translateLiteral(effectiveDisabledReason)}</small>
      ) : statusText ? (
        <small className={draftState.error ? 'editable-field-error' : 'editable-field-status'}>
          {translateLiteral(statusText)}
        </small>
      ) : null}
    </label>
  );
}

function createTrainerDrafts(
  fields: NumericEditableField[],
  getValue: (field: string) => number | null
) {
  return Object.fromEntries(
    fields.map((field) => [field.field, (getValue(field.field) ?? '').toString()])
  );
}

function createPokemonInstanceDrafts(
  fields: NumericEditableField[],
  getValue: (field: string) => number | null
) {
  return Object.fromEntries(
    fields.map((field) => {
      const value = getValue(field.field);
      return [
        field.field,
        value === null && isPokemonInstanceIvPresetField(field.field)
          ? ivPresetCustomOptionValue.toString()
          : (value ?? '').toString()
      ];
    })
  );
}

function withPokemonInstanceIvPresetOptions<T extends NumericEditableField>(field: T): T {
  if (!isPokemonInstanceIvPresetField(field.field)) {
    return field;
  }

  if (field.options.some((option) => option.value === ivPresetCustomOptionValue)) {
    return field;
  }

  return {
    ...field,
    options: [...field.options, ivPresetCustomOption]
  };
}

function withDynamaxAdventureSpeciesOptions<T extends NumericEditableField>(
  field: T,
  encounter: DynamaxAdventureRecord | null,
  safeNormalSpeciesOptions: EditableFieldOption[],
  fieldOptions: DynamaxAdventureDraftFieldOptions
): T {
  const overrideOptions = fieldOptions[field.field];
  if (overrideOptions !== undefined) {
    return { ...field, options: overrideOptions };
  }

  if (
    encounter !== null &&
    staticEncounterMoveFieldNames.includes(
      field.field as (typeof staticEncounterMoveFieldNames)[number]
    )
  ) {
    return { ...field, options: encounter.moveOptions };
  }

  if (field.field === abilityFieldName && encounter !== null) {
    return { ...field, options: encounter.abilityOptions };
  }

  if (field.field === dynamaxAdventureGigantamaxStateFieldName && encounter !== null) {
    return { ...field, options: encounter.gigantamaxOptions };
  }

  if (field.field !== giftSpeciesFieldName || encounter === null) {
    return field;
  }

  if (safeNormalSpeciesOptions.length === 0) {
    return { ...field, options: [] };
  }

  const options = [...safeNormalSpeciesOptions];
  const selectedIdentityOptions = [
    {
      label: `${encounter.speciesId.toString().padStart(3, '0')} ${encounter.species}`,
      value: encounter.speciesId
    },
    ...(encounter.vanillaPokemon
      ? [
          {
            label: `${encounter.vanillaPokemon.speciesId.toString().padStart(3, '0')} ${encounter.vanillaPokemon.species}`,
            value: encounter.vanillaPokemon.speciesId
          }
        ]
      : [])
  ];
  for (const option of selectedIdentityOptions) {
    if (!options.some((candidate) => candidate.value === option.value)) {
      options.push(option);
    }
  }
  options.sort((left, right) => left.value - right.value);
  return { ...field, options };
}

function isPokemonInstanceIvPresetField(fieldName: string) {
  return (
    fieldName === giftFlawlessIvCountFieldName ||
    fieldName === rentalFixedIvPresetFieldName ||
    fieldName === dynamaxAdventureGuaranteedPerfectIvsFieldName
  );
}

function isPokemonInstanceIvStatField(fieldName: string) {
  return (
    ivFieldNames.includes(fieldName as (typeof ivFieldNames)[number]) ||
    dynamaxAdventureIvFieldNames.includes(
      fieldName as (typeof dynamaxAdventureIvFieldNames)[number]
    )
  );
}

function getPokemonInstanceIvPresetFieldName(fields: NumericEditableField[]) {
  return (
    fields.find((field) => isPokemonInstanceIvPresetField(field.field))?.field ?? null
  );
}

function isPokemonInstanceIvCustomSelected(
  fields: NumericEditableField[],
  drafts: Record<string, string>
) {
  const presetFieldName = getPokemonInstanceIvPresetFieldName(fields);
  return (
    presetFieldName !== null &&
    parseEditableIntegerDraft(drafts[presetFieldName] ?? '', [
      ivPresetCustomOption
    ]) === ivPresetCustomOptionValue
  );
}

function getActivePokemonInstanceFields(
  fields: NumericEditableField[],
  drafts: Record<string, string>
) {
  if (isPokemonInstanceIvCustomSelected(fields, drafts)) {
    return fields;
  }

  return fields.filter((field) => !isPokemonInstanceIvStatField(field.field));
}

function getPokemonInstanceIvStatDisabledReason(
  fieldName: string,
  fields: NumericEditableField[],
  drafts: Record<string, string>
) {
  if (!isPokemonInstanceIvStatField(fieldName)) {
    return null;
  }

  if (getPokemonInstanceIvPresetFieldName(fields) === null) {
    return null;
  }

  return isPokemonInstanceIvCustomSelected(fields, drafts)
    ? null
    : 'Select Custom in IV preset to edit individual IVs.';
}

function normalizePokemonStatDraftValue(
  fieldName: string,
  value: number,
  context?: DraftStateContext
) {
  if (context?.clampIvStats && isPokemonIvStatField(fieldName)) {
    if (
      value === -1 &&
      dynamaxAdventureIvFieldNames.includes(
        fieldName as (typeof dynamaxAdventureIvFieldNames)[number]
      )
    ) {
      return value;
    }

    return clampInteger(value, 0, maximumPokemonIvValue);
  }

  if (context?.enforcePokemonEvLimits && isPokemonEvStatField(fieldName)) {
    return clampPokemonEvDraftValue(fieldName, value, context);
  }

  return value;
}

function clampPokemonEvDraftValue(
  fieldName: string,
  value: number,
  context: DraftStateContext
) {
  const otherEvTotal = evFieldNames
    .filter((candidate) => candidate !== fieldName)
    .reduce((total, otherFieldName) => {
      const otherField = context.fields.find((field) => field.field === otherFieldName);
      const parsedDraft =
        otherField === undefined
          ? null
          : parseEditableIntegerDraft(context.drafts[otherFieldName] ?? '', otherField.options);
      const fallbackValue = context.getValue(otherFieldName) ?? 0;
      const effectiveValue = parsedDraft ?? fallbackValue;
      return total + clampInteger(effectiveValue, 0, maximumPokemonEvValue);
    }, 0);
  const remainingBudget = Math.max(0, maximumPokemonEvTotal - otherEvTotal);

  return Math.min(clampInteger(value, 0, maximumPokemonEvValue), remainingBudget);
}

function isPokemonIvStatField(fieldName: string) {
  return (
    ivFieldNames.includes(fieldName as (typeof ivFieldNames)[number]) ||
    dynamaxAdventureIvFieldNames.includes(
      fieldName as (typeof dynamaxAdventureIvFieldNames)[number]
    )
  );
}

function isPokemonEvStatField(fieldName: string) {
  return evFieldNames.includes(fieldName as (typeof evFieldNames)[number]);
}

function clampInteger(value: number, minimum: number, maximum: number) {
  return Math.min(Math.max(value, minimum), maximum);
}

function getProjectedTrainerHighestLevel(
  trainer: TrainerRecord | null,
  selectedSlot: number | null,
  pokemonDrafts: Record<string, string>
) {
  if (!trainer || trainer.team.length === 0) {
    return 0;
  }

  return Math.max(
    ...trainer.team.map((pokemon) => {
      if (pokemon.slot !== selectedSlot) {
        return pokemon.level;
      }

      const draftedLevel = Number.parseInt(pokemonDrafts[levelFieldName] ?? '', 10);
      return Number.isInteger(draftedLevel) ? draftedLevel : pokemon.level;
    })
  );
}

function getOccupiedTrainerPokemonCount(trainer: TrainerRecord) {
  return trainer.team.filter((pokemon) => pokemon.speciesId > 0).length;
}

function formatTrainerSlotNumber(slot: number, editorFamily: EditorUiFamily) {
  return editorFamily === 'swsh' ? slot : slot + 1;
}

function createTrainerPrizeMoneyOptions(highestLevel: number): EditableFieldOption[] {
  const normalizedHighestLevel = Math.max(0, highestLevel);

  return Array.from({ length: 256 }, (_, rate) => {
    const payout = getTrainerPrizeMoney(normalizedHighestLevel, rate);

    return {
      label: `$${payout.toLocaleString()} (rate ${rate})`,
      value: rate
    };
  });
}

function getTrainerPrizeMoney(highestLevel: number, rate: number) {
  return highestLevel * rate * 4;
}

type NumericEditableFieldSource = EditableFieldWithOptions & {
  field: string;
  valueKind: string;
};

function toNumericEditableControlField(
  field: NumericEditableFieldSource,
  optionsOverride?: EditableFieldOption[]
): NumericEditableField {
  return {
    field: field.field,
    label: field.label,
    maximumValue: field.maximumValue ?? null,
    minimumValue: field.minimumValue ?? null,
    options: optionsOverride ?? field.options ?? [],
    valueKind: field.valueKind
  };
}

function groupTrainerEditableFields(
  fields: TrainerEditableField[],
  getGroup: (field: TrainerEditableField) => string
) {
  const groups: Array<{ group: string; fields: TrainerEditableField[] }> = [];

  for (const field of fields) {
    const groupName = getGroup(field);
    let group = groups.find((candidate) => candidate.group === groupName);
    if (!group) {
      group = { group: groupName, fields: [] };
      groups.push(group);
    }

    group.fields.push(field);
  }

  return groups;
}

function sortTrainerPokemonFieldGroup(group: {
  group: string;
  fields: TrainerEditableField[];
}) {
  if (group.group !== 'Traits') {
    return group;
  }

  const traitOrder = new Map(
    [
      genderFieldName,
      abilityFieldName,
      natureFieldName,
      trainerTeraTypeFieldName,
      canDynamaxFieldName,
      dynamaxLevelFieldName,
      canGigantamaxFieldName,
      shinyFieldName
    ].map((fieldName, index) => [fieldName, index])
  );

  return {
    ...group,
    fields: [...group.fields].sort(
      (left, right) =>
        (traitOrder.get(left.field) ?? Number.MAX_SAFE_INTEGER) -
        (traitOrder.get(right.field) ?? Number.MAX_SAFE_INTEGER)
    )
  };
}

type NatureStatKey = keyof typeof natureStatLabels;

type NatureStatEffects = {
  down: NatureStatKey | null;
  up: NatureStatKey | null;
};

function getNatureStatEffects(
  nature: number | null,
  editorFamily: EditorUiFamily = 'swsh'
): NatureStatEffects | null {
  const effects: Record<number, NatureStatEffects> = {
    1: { up: 'attack', down: 'defense' },
    2: { up: 'attack', down: 'speed' },
    3: { up: 'attack', down: 'specialAttack' },
    4: { up: 'attack', down: 'specialDefense' },
    5: { up: 'defense', down: 'attack' },
    7: { up: 'defense', down: 'speed' },
    8: { up: 'defense', down: 'specialAttack' },
    9: { up: 'defense', down: 'specialDefense' },
    10: { up: 'speed', down: 'attack' },
    11: { up: 'speed', down: 'defense' },
    13: { up: 'speed', down: 'specialAttack' },
    14: { up: 'speed', down: 'specialDefense' },
    15: { up: 'specialAttack', down: 'attack' },
    16: { up: 'specialAttack', down: 'defense' },
    17: { up: 'specialAttack', down: 'speed' },
    19: { up: 'specialAttack', down: 'specialDefense' },
    20: { up: 'specialDefense', down: 'attack' },
    21: { up: 'specialDefense', down: 'defense' },
    22: { up: 'specialDefense', down: 'speed' },
    23: { up: 'specialDefense', down: 'specialAttack' }
  };

  if (nature === null) {
    return null;
  }

  const normalizedNature =
    (editorFamily === 'sv' || editorFamily === 'za') && nature > 0 ? nature - 1 : nature;
  return effects[normalizedNature] ?? { up: null, down: null };
}

function getProjectedTrainerPokemonStats(
  pokemon: TrainerPokemonRecord,
  fields: TrainerEditableField[],
  drafts: Record<string, string>,
  pokemonWorkflow: PokemonWorkflow | null,
  editorFamily: EditorUiFamily
): ProjectedTrainerPokemonStats | null {
  const speciesId =
    getProjectedTrainerPokemonFieldValue(pokemon, fields, drafts, speciesIdFieldName) ??
    pokemon.speciesId;
  const form =
    getProjectedTrainerPokemonFieldValue(pokemon, fields, drafts, formFieldName) ?? pokemon.form;
  const fallbackBaseStats =
    speciesId === pokemon.speciesId && form === pokemon.form ? pokemon.baseStats ?? null : null;
  const baseStats =
    resolveProjectedTrainerPokemonBaseStats(pokemonWorkflow, speciesId, form) ??
    fallbackBaseStats;

  if (speciesId <= 0 || !baseStats) {
    return null;
  }

  const level = clampInteger(
    getProjectedTrainerPokemonFieldValue(pokemon, fields, drafts, levelFieldName) ??
      pokemon.level,
    1,
    100
  );
  const nature =
    getProjectedTrainerPokemonFieldValue(pokemon, fields, drafts, natureFieldName) ??
    pokemon.nature;
  const effects = getNatureStatEffects(nature, editorFamily);
  const evs = getProjectedTrainerPokemonStatValues(pokemon, fields, drafts, evFieldNames);
  const ivs = getProjectedTrainerPokemonStatValues(pokemon, fields, drafts, ivFieldNames);

  return {
    baseStats,
    stats: {
      hp: calculateProjectedTrainerPokemonStat(
        'hp',
        baseStats.hp,
        normalizeProjectedTrainerEv(evs.hp),
        normalizeProjectedTrainerIv(ivs.hp),
        level,
        effects
      ),
      attack: calculateProjectedTrainerPokemonStat(
        'attack',
        baseStats.attack,
        normalizeProjectedTrainerEv(evs.attack),
        normalizeProjectedTrainerIv(ivs.attack),
        level,
        effects
      ),
      defense: calculateProjectedTrainerPokemonStat(
        'defense',
        baseStats.defense,
        normalizeProjectedTrainerEv(evs.defense),
        normalizeProjectedTrainerIv(ivs.defense),
        level,
        effects
      ),
      specialAttack: calculateProjectedTrainerPokemonStat(
        'specialAttack',
        baseStats.specialAttack,
        normalizeProjectedTrainerEv(evs.specialAttack),
        normalizeProjectedTrainerIv(ivs.specialAttack),
        level,
        effects
      ),
      specialDefense: calculateProjectedTrainerPokemonStat(
        'specialDefense',
        baseStats.specialDefense,
        normalizeProjectedTrainerEv(evs.specialDefense),
        normalizeProjectedTrainerIv(ivs.specialDefense),
        level,
        effects
      ),
      speed: calculateProjectedTrainerPokemonStat(
        'speed',
        baseStats.speed,
        normalizeProjectedTrainerEv(evs.speed),
        normalizeProjectedTrainerIv(ivs.speed),
        level,
        effects
      )
    }
  };
}

function getProjectedTrainerPokemonStatValues(
  pokemon: TrainerPokemonRecord,
  fields: TrainerEditableField[],
  drafts: Record<string, string>,
  fieldNames: typeof evFieldNames | typeof ivFieldNames
): TrainerPokemonRecord['evs'] {
  return {
    hp:
      getProjectedTrainerPokemonFieldValue(pokemon, fields, drafts, fieldNames[0]) ??
      getEditablePokemonFieldValue(pokemon, fieldNames[0]) ??
      0,
    attack:
      getProjectedTrainerPokemonFieldValue(pokemon, fields, drafts, fieldNames[1]) ??
      getEditablePokemonFieldValue(pokemon, fieldNames[1]) ??
      0,
    defense:
      getProjectedTrainerPokemonFieldValue(pokemon, fields, drafts, fieldNames[2]) ??
      getEditablePokemonFieldValue(pokemon, fieldNames[2]) ??
      0,
    specialAttack:
      getProjectedTrainerPokemonFieldValue(pokemon, fields, drafts, fieldNames[3]) ??
      getEditablePokemonFieldValue(pokemon, fieldNames[3]) ??
      0,
    specialDefense:
      getProjectedTrainerPokemonFieldValue(pokemon, fields, drafts, fieldNames[4]) ??
      getEditablePokemonFieldValue(pokemon, fieldNames[4]) ??
      0,
    speed:
      getProjectedTrainerPokemonFieldValue(pokemon, fields, drafts, fieldNames[5]) ??
      getEditablePokemonFieldValue(pokemon, fieldNames[5]) ??
      0
  };
}

function getProjectedTrainerPokemonFieldValue(
  pokemon: TrainerPokemonRecord,
  fields: TrainerEditableField[],
  drafts: Record<string, string>,
  fieldName: string
) {
  const currentValue = getEditablePokemonFieldValue(pokemon, fieldName);
  const field = fields.find((candidate) => candidate.field === fieldName);
  if (!field || currentValue === null) {
    return currentValue;
  }

  const draftValue = drafts[fieldName] ?? currentValue.toString();
  const normalizedDraftValue = draftValue.trim();
  if (normalizedDraftValue.length === 0) {
    return currentValue;
  }

  const parsedValue =
    field.valueKind === 'number'
      ? Number(normalizedDraftValue)
      : parseEditableIntegerDraft(normalizedDraftValue, field.options);

  if (parsedValue === null || !Number.isFinite(parsedValue)) {
    return currentValue;
  }

  const minimumValue = field.minimumValue ?? null;
  const maximumValue = field.maximumValue ?? null;
  if (
    (minimumValue !== null && parsedValue < minimumValue) ||
    (maximumValue !== null && parsedValue > maximumValue)
  ) {
    return currentValue;
  }

  if (
    field.options.length > 0 &&
    !isSpeciesFormField(field.field) &&
    !field.options.some((option) => option.value === parsedValue)
  ) {
    return currentValue;
  }

  return parsedValue;
}

function resolveProjectedTrainerPokemonBaseStats(
  pokemonWorkflow: PokemonWorkflow | null,
  speciesId: number,
  form: number
): TrainerPokemonRecord['baseStats'] | null {
  if (!pokemonWorkflow || speciesId <= 0) {
    return null;
  }

  return (
    pokemonWorkflow.pokemon.find(
      (candidate) => candidate.speciesId === speciesId && candidate.form === form
    )?.baseStats ??
    pokemonWorkflow.pokemon.find(
      (candidate) => candidate.speciesId === speciesId && candidate.form === 0
    )?.baseStats ??
    null
  );
}

function calculateProjectedTrainerPokemonStat(
  statKey: keyof TrainerPokemonRecord['evs'],
  baseStat: number,
  ev: number,
  iv: number,
  level: number,
  effects: NatureStatEffects | null
) {
  if (statKey === 'hp') {
    return baseStat === 1
      ? 1
      : Math.floor(((2 * baseStat + iv + Math.floor(ev / 4)) * level) / 100) + level + 10;
  }

  const neutralStat = Math.floor(((2 * baseStat + iv + Math.floor(ev / 4)) * level) / 100) + 5;
  const natureMultiplier =
    effects?.up === statKey ? 1.1 : effects?.down === statKey ? 0.9 : 1;
  return Math.floor(neutralStat * natureMultiplier);
}

function normalizeProjectedTrainerEv(value: number) {
  return clampInteger(value, 0, maximumPokemonEvValue);
}

function normalizeProjectedTrainerIv(value: number) {
  return clampInteger(value, 0, maximumPokemonIvValue);
}

function getNatureStatAdornment(fieldName: string, effects: NatureStatEffects | null) {
  if (!effects) {
    return null;
  }

  const stat = statFieldKeysByEditableField[
    fieldName as keyof typeof statFieldKeysByEditableField
  ] as NatureStatKey | 'hp' | undefined;
  if (!stat || stat === 'hp') {
    return null;
  }

  if (effects.up === stat) {
    return (
      <span
        className="nature-stat-arrow nature-stat-arrow-up"
        title={`Nature raises ${natureStatLabels[stat]}.`}
      >
        <ArrowUp aria-hidden="true" size={14} />
      </span>
    );
  }

  if (effects.down === stat) {
    return (
      <span
        className="nature-stat-arrow nature-stat-arrow-down"
        title={`Nature lowers ${natureStatLabels[stat]}.`}
      >
        <ArrowDown aria-hidden="true" size={14} />
      </span>
    );
  }

  return null;
}

function getTrainerDataFieldGroup(field: TrainerEditableField) {
  if (
    field.field === trainerClassIdFieldName ||
    field.field === classBallIdFieldName ||
    field.field === battleTypeFieldName ||
    field.field === zaRankFieldName ||
    field.field === zaMegaEvolutionFieldName ||
    field.field === zaLastHandFieldName
  ) {
    return 'Trainer Setup';
  }

  if (field.field === trainerCanTerastallizeFieldName) {
    return 'Terastallization';
  }

  if (trainerItemFieldNames.includes(field.field as (typeof trainerItemFieldNames)[number])) {
    return 'Battle Items';
  }

  if (
    field.field === healFieldName ||
    field.field === moneyFieldName ||
    field.field === giftFieldName
  ) {
    return 'Battle Rewards';
  }

  return 'Trainer Data';
}

function getTrainerPokemonFieldGroup(field: TrainerEditableField) {
  if (
    field.field === speciesIdFieldName ||
    field.field === formFieldName ||
    field.field === levelFieldName ||
    field.field === heldItemIdFieldName
  ) {
    return 'Pokemon';
  }

  if (moveFieldNames.includes(field.field as (typeof moveFieldNames)[number])) {
    return 'Moves';
  }

  if (
    field.field === genderFieldName ||
    field.field === abilityFieldName ||
    field.field === natureFieldName ||
    field.field === dynamaxLevelFieldName ||
    field.field === canGigantamaxFieldName ||
    field.field === shinyFieldName ||
    field.field === trainerTeraTypeFieldName ||
    field.field === canDynamaxFieldName
  ) {
    return 'Traits';
  }

  if (evFieldNames.includes(field.field as (typeof evFieldNames)[number])) {
    return 'Stats - EVs';
  }

  if (ivFieldNames.includes(field.field as (typeof ivFieldNames)[number])) {
    return 'Stats - IVs';
  }

  return 'Pokemon';
}

function getTrainerDraftSummary(
  fields: NumericEditableField[],
  drafts: Record<string, string>,
  getValue: ((field: string) => number | null) | null,
  options: {
    clampIvStats?: boolean;
    enforcePokemonEvLimits?: boolean;
    preservedValues?: Readonly<Record<string, number | null>>;
  } = {}
): { changedFields: TrainerDraftChange[]; dirtyFieldCount: number; invalidFields: TrainerDraftChange[] } {
  const changedFields: TrainerDraftChange[] = [];
  const invalidFields: TrainerDraftChange[] = [];
  let dirtyFieldCount = 0;

  if (!getValue) {
    return { changedFields, dirtyFieldCount, invalidFields };
  }

  const draftContext: DraftStateContext = {
    clampIvStats: options.clampIvStats,
    drafts,
    enforcePokemonEvLimits: options.enforcePokemonEvLimits,
    fields,
    getValue,
    preservedValues: options.preservedValues
  };

  for (const field of fields) {
    const currentValue = getValue(field.field);
    const draftValue = drafts[field.field] ?? '';
    const draftState = getTrainerFieldDraftState(draftValue, currentValue, field, draftContext);

    if (draftState.isChanged || !draftState.isValid) {
      dirtyFieldCount += 1;
    }

    if (!draftState.isValid) {
      invalidFields.push({ field: field.field, label: field.label, value: draftValue });
      continue;
    }

    if (draftState.isChanged && draftState.normalizedValue !== null) {
      changedFields.push({
        field: field.field,
        label: field.label,
        value: draftState.normalizedValue
      });
    }
  }

  return { changedFields, dirtyFieldCount, invalidFields };
}

function getTrainerFieldDraftState(
  draftValue: string,
  currentValue: number | null,
  field: NumericEditableField,
  context?: DraftStateContext
): TrainerDraftState {
  const normalizedValue = draftValue.trim();

  if (currentValue === null && normalizedValue === '') {
    return {
      error: null,
      isChanged: false,
      isValid: true,
      normalizedValue: null
    };
  }

  const currentText = currentValue?.toString() ?? '';

  if (field.valueKind === 'boolean') {
    if (normalizedValue !== '0' && normalizedValue !== '1') {
      return {
        error: 'Choose Yes or No.',
        isChanged: normalizedValue !== currentText,
        isValid: false,
        normalizedValue: null
      };
    }

    return {
      error: null,
      isChanged: normalizedValue !== currentText,
      isValid: true,
      normalizedValue
    };
  }

  if (
    isPokemonInstanceIvPresetField(field.field) &&
    parseEditableIntegerDraft(normalizedValue, [
      ...field.options,
      ivPresetCustomOption
    ]) === ivPresetCustomOptionValue
  ) {
    return {
      error: null,
      isChanged: false,
      isValid: true,
      normalizedValue: null
    };
  }

  if (field.valueKind === 'number') {
    const parsedValue = Number(normalizedValue);
    const minimumValue = field.minimumValue ?? null;
    const maximumValue = field.maximumValue ?? null;

    if (!Number.isFinite(parsedValue)) {
      return {
        error: getIntegerDraftError(normalizedValue),
        isChanged: normalizedValue !== currentText,
        isValid: false,
        normalizedValue: null
      };
    }

    const matchesCurrentValue = currentValue !== null && parsedValue === currentValue;
    const matchesPreservedValue = parsedValue === context?.preservedValues?.[field.field];
    const isAllowedExistingValue = matchesCurrentValue || matchesPreservedValue;

    if (minimumValue !== null && parsedValue < minimumValue && !isAllowedExistingValue) {
      return {
        error: `Minimum value is ${minimumValue}.`,
        isChanged: currentValue === null || parsedValue !== currentValue,
        isValid: false,
        normalizedValue: null
      };
    }

    if (maximumValue !== null && parsedValue > maximumValue && !isAllowedExistingValue) {
      return {
        error: `Maximum value is ${maximumValue}.`,
        isChanged: currentValue === null || parsedValue !== currentValue,
        isValid: false,
        normalizedValue: null
      };
    }

    return {
      error: null,
      isChanged: currentValue === null || Math.abs(parsedValue - currentValue) > Number.EPSILON,
      isValid: true,
      normalizedValue: parsedValue.toString()
    };
  }

  let parsedValue = parseEditableIntegerDraft(normalizedValue, field.options);

  if (parsedValue === null) {
    return {
      error: getIntegerDraftError(normalizedValue),
      isChanged: normalizedValue !== currentText,
      isValid: false,
      normalizedValue: null
    };
  }

  parsedValue = normalizePokemonStatDraftValue(field.field, parsedValue, context);
  const minimumValue = field.minimumValue ?? null;
  const maximumValue = field.maximumValue ?? null;

  const matchesCurrentValue = currentValue !== null && parsedValue === currentValue;
  const matchesPreservedValue = parsedValue === context?.preservedValues?.[field.field];
  const isAllowedExistingValue = matchesCurrentValue || matchesPreservedValue;

  if (minimumValue !== null && parsedValue < minimumValue && !isAllowedExistingValue) {
    return {
      error: `Minimum value is ${minimumValue}.`,
      isChanged: currentValue === null || parsedValue !== currentValue,
      isValid: false,
      normalizedValue: null
    };
  }

  if (maximumValue !== null && parsedValue > maximumValue && !isAllowedExistingValue) {
    return {
      error: `Maximum value is ${maximumValue}.`,
      isChanged: currentValue === null || parsedValue !== currentValue,
      isValid: false,
      normalizedValue: null
    };
  }

  if (
    field.options.length > 0 &&
    !isSpeciesFormField(field.field) &&
    !isAllowedExistingValue &&
    !field.options.some((option) => option.value === parsedValue)
  ) {
    return {
      error: 'Choose one of the available options.',
      isChanged: true,
      isValid: false,
      normalizedValue: null
    };
  }

  return {
    error: null,
    isChanged: currentValue === null || parsedValue !== currentValue,
    isValid: true,
    normalizedValue: parsedValue.toString()
  };
}

function getRentalPokemonDraftSummary(
  rental: RentalPokemonRecord | null,
  fields: NumericEditableField[],
  drafts: Record<string, string>
) {
  const summary = getTrainerDraftSummary(
    fields,
    drafts,
    rental ? (field) => getEditableRentalPokemonFieldValue(rental, field) : null
  );
  if (!rental) {
    return summary;
  }

  const evIssue = getRentalPokemonEvTotalIssue(rental, fields, drafts);
  if (evIssue === null) {
    return summary;
  }

  const invalidFieldNames = new Set(summary.invalidFields.map((field) => field.field));
  const evFieldNamesWithErrors = new Set(evIssue.changedFields);
  const invalidFields = [
    ...summary.invalidFields,
    ...evIssue.changedFields
      .filter((fieldName) => !invalidFieldNames.has(fieldName))
      .map((fieldName) => {
        const field = fields.find((candidate) => candidate.field === fieldName)!;
        return { field: fieldName, label: field.label, value: drafts[fieldName] ?? '' };
      })
  ];

  return {
    ...summary,
    changedFields: summary.changedFields.filter(
      (change) => !evFieldNamesWithErrors.has(change.field)
    ),
    invalidFields
  };
}

function getRentalPokemonFieldDraftState(
  rental: RentalPokemonRecord,
  draftValue: string,
  currentValue: number | null,
  field: NumericEditableField,
  fields: NumericEditableField[],
  drafts: Record<string, string>
) {
  const draftState = getTrainerFieldDraftState(draftValue, currentValue, field, {
    drafts,
    fields,
    getValue: (fieldName) => getEditableRentalPokemonFieldValue(rental, fieldName)
  });
  if (!draftState.isValid) {
    return draftState;
  }

  const evIssue = getRentalPokemonEvTotalIssue(rental, fields, drafts);
  if (
    evIssue !== null &&
    draftState.isChanged &&
    evIssue.changedFields.includes(field.field)
  ) {
    return {
      error: `EV total is ${evIssue.total}. Maximum total is ${maximumPokemonEvTotal}.`,
      isChanged: true,
      isValid: false,
      normalizedValue: null
    };
  }

  return draftState;
}

function getRentalPokemonEvTotalIssue(
  rental: RentalPokemonRecord,
  fields: NumericEditableField[],
  drafts: Record<string, string>
) {
  let total = 0;
  const changedFields: string[] = [];

  for (const fieldName of evFieldNames) {
    const field = fields.find((candidate) => candidate.field === fieldName);
    if (!field) {
      continue;
    }

    const currentValue = getEditableRentalPokemonFieldValue(rental, fieldName);
    const draftValue = drafts[fieldName] ?? currentValue?.toString() ?? '';
    const parsedValue = parseEditableIntegerDraft(draftValue, field.options);
    if (parsedValue === null) {
      return null;
    }

    const draftState = getTrainerFieldDraftState(draftValue, currentValue, field);
    if (!draftState.isValid) {
      return null;
    }

    total += parsedValue;
    if (draftState.isChanged) {
      changedFields.push(fieldName);
    }
  }

  return total > maximumPokemonEvTotal && changedFields.length > 0
    ? { changedFields, total }
    : null;
}

function getStaticEncounterDraftSummary(
  encounter: StaticEncounterRecord | null,
  fields: NumericEditableField[],
  drafts: Record<string, string>,
  allFields: StaticEncounterEditableField[]
) {
  const changedFields: TrainerDraftChange[] = [];
  const invalidFields: TrainerDraftChange[] = [];
  let dirtyFieldCount = 0;

  if (!encounter) {
    return { changedFields, dirtyFieldCount, invalidFields };
  }

  for (const field of fields) {
    if (allFields.find((candidate) => candidate.field === field.field)?.isReadOnly) {
      continue;
    }

    const currentValue = getEditableStaticEncounterFieldValue(encounter, field.field);
    const draftValue = drafts[field.field] ?? '';
    const draftState = getStaticEncounterFieldDraftState(
      encounter,
      draftValue,
      currentValue,
      field,
      allFields,
      drafts
    );

    if (draftState.isChanged || !draftState.isValid) {
      dirtyFieldCount += 1;
    }

    if (!draftState.isValid) {
      invalidFields.push({ field: field.field, label: field.label, value: draftValue });
    } else if (draftState.isChanged && draftState.normalizedValue !== null) {
      changedFields.push({
        field: field.field,
        label: field.label,
        value: draftState.normalizedValue
      });
    }
  }

  return { changedFields, dirtyFieldCount, invalidFields };
}

function getStaticEncounterFieldDraftState(
  encounter: StaticEncounterRecord,
  draftValue: string,
  currentValue: number | null,
  field: NumericEditableField,
  fields: NumericEditableField[],
  drafts: Record<string, string>
): TrainerDraftState {
  const isCustomIvSelected = isPokemonInstanceIvCustomSelected(fields, drafts);
  const draftState = getTrainerFieldDraftState(draftValue, currentValue, field, {
    clampIvStats: encounter.editorFamily !== 'swsh' && isCustomIvSelected,
    drafts,
    fields,
    getValue: (fieldName) => getEditableStaticEncounterFieldValue(encounter, fieldName)
  });

  if (!draftState.isValid) {
    return draftState;
  }

  if (
    encounter.editorFamily === 'swsh' &&
    isCustomIvSelected &&
    isPokemonIvStatField(field.field) &&
    draftState.normalizedValue !== null
  ) {
    const value = Number.parseInt(draftState.normalizedValue, 10);
    const isSupportedSentinel =
      value === -1 || (field.field === ivFieldNames[0] && value === -4);
    if (value < 0 && !isSupportedSentinel) {
      return {
        error:
          field.field === ivFieldNames[0]
            ? 'Use -1 for a random IV, -4 for the 3 perfect IV preset, or 0 through 31.'
            : 'Use -1 for a random IV or 0 through 31.',
        isChanged: draftState.isChanged,
        isValid: false,
        normalizedValue: null
      };
    }
  }

  const ivSentinelIssue = getStaticEncounterIvSentinelIssue(encounter, drafts);
  if (
    ivSentinelIssue !== null &&
    ivSentinelIssue.changedFields.includes(field.field) &&
    draftState.isChanged
  ) {
    return {
      error: 'HP IV -4 requires every other IV to be -1.',
      isChanged: true,
      isValid: false,
      normalizedValue: null
    };
  }

  const evIssue = getStaticEncounterEvTotalIssue(encounter, fields, drafts);
  if (
    evIssue !== null &&
    evIssue.changedFields.includes(field.field) &&
    draftState.isChanged
  ) {
    return {
      error: `EV total is ${evIssue.total}. Maximum total is ${maximumPokemonEvTotal}.`,
      isChanged: true,
      isValid: false,
      normalizedValue: null
    };
  }

  return draftState;
}

function getStaticEncounterIvSentinelIssue(
  encounter: StaticEncounterRecord,
  drafts: Record<string, string>
) {
  if (encounter.editorFamily !== 'swsh') {
    return null;
  }

  const values = Object.fromEntries(
    ivFieldNames.map((fieldName) => {
      const currentValue = getEditableStaticEncounterFieldValue(encounter, fieldName);
      const draftValue = drafts[fieldName];
      const parsedValue =
        draftValue === undefined || draftValue.trim().length === 0
          ? currentValue
          : Number(draftValue.trim());
      return [fieldName, Number.isInteger(parsedValue) ? parsedValue : null];
    })
  ) as Record<(typeof ivFieldNames)[number], number | null>;

  if (values[ivFieldNames[0]] !== -4) {
    return null;
  }

  const hasInvalidNonHpIv = ivFieldNames
    .slice(1)
    .some((fieldName) => values[fieldName] !== -1);
  if (!hasInvalidNonHpIv) {
    return null;
  }

  const changedFields: string[] = ivFieldNames.filter((fieldName) => {
    const currentValue = getEditableStaticEncounterFieldValue(encounter, fieldName);
    return values[fieldName] !== currentValue;
  });

  return changedFields.length > 0 ? { changedFields } : null;
}

function getStaticEncounterEvTotalIssue(
  encounter: StaticEncounterRecord,
  fields: NumericEditableField[],
  drafts: Record<string, string>
) {
  let total = 0;
  const changedFields: string[] = [];

  for (const fieldName of evFieldNames) {
    const field = fields.find((candidate) => candidate.field === fieldName);
    if (!field) {
      continue;
    }

    const currentValue = getEditableStaticEncounterFieldValue(encounter, fieldName);
    const draftValue = drafts[fieldName] ?? currentValue?.toString() ?? '';
    const parsedValue = parseEditableIntegerDraft(draftValue, field.options);
    if (parsedValue === null) {
      return null;
    }

    const draftState = getTrainerFieldDraftState(draftValue, currentValue, field);
    if (!draftState.isValid) {
      return null;
    }

    total += parsedValue;
    if (draftState.isChanged) {
      changedFields.push(fieldName);
    }
  }

  return total > maximumPokemonEvTotal && changedFields.length > 0
    ? { changedFields, total }
    : null;
}

function formatDraftSummary(summary: {
  changedFields: unknown[];
  dirtyFieldCount: number;
  invalidFields: unknown[];
}) {
  if (summary.invalidFields.length > 0) {
    return `${summary.invalidFields.length} field${
      summary.invalidFields.length === 1 ? '' : 's'
    } need valid values`;
  }

  return `${summary.changedFields.length} changed`;
}

