function createPendingEditDisplayDetails(
  edit: PendingEdit,
  overrides: Partial<Omit<PendingEditDisplayDetails, 'fieldKey' | 'recordKey' | 'sourceLabel'>>
): PendingEditDisplayDetails {
  const fieldKey = edit.field ?? 'n/a';
  const recordKey = edit.recordId ?? 'n/a';

  return {
    editorLabel: overrides.editorLabel ?? formatPendingEditDomain(edit.domain),
    fieldKey,
    fieldLabel: overrides.fieldLabel ?? humanizePendingEditKey(fieldKey),
    newValueLabel: overrides.newValueLabel ?? formatPendingEditValue(edit.newValue),
    recordKey,
    recordLabel: overrides.recordLabel ?? recordKey,
    sourceLabel: formatPendingEditSources(edit)
  };
}

function formatCatchCapPendingValue(value: string | null | undefined) {
  if (!value) {
    return undefined;
  }

  const parts = value
    .split(';')
    .map((part) => part.trim())
    .filter(Boolean)
    .map((part) => {
      const [badgeCount, levelCap] = part.split('=');
      return badgeCount !== undefined && levelCap !== undefined
        ? `${badgeCount} badges: Lv. ${levelCap}`
        : part;
    });

  return parts.length > 0 ? parts.join(', ') : undefined;
}

function formatCatchCapProjectGame(
  game: ProjectGame | null,
  translateLiteral: (literal: string) => string
) {
  switch (game) {
    case 'sword':
      return translateLiteral('Pokemon Sword');
    case 'shield':
      return translateLiteral('Pokemon Shield');
    default:
      return translateLiteral('Unknown');
  }
}

function formatHyperTrainingPendingValue(value: string | null | undefined) {
  if (!value) {
    return undefined;
  }

  const minimumLevel = parseHyperTrainingLevelInput(value);
  return minimumLevel !== null && minimumLevel >= 1 && minimumLevel <= 100
    ? `Lv. ${minimumLevel}`
    : value;
}

const hyperTrainingScriptPath = 'romfs/bin/script/amx/hyper_training.amx';
const hyperTrainingDialoguePath = 'romfs/bin/message/English/script/sub_event_007.dat';
const hyperTrainingMainPath = 'exefs/main';
const hyperTrainingPendingPayloadPattern =
  /^pending\/hyper-training\/minimum-level\/[A-F0-9]{64}$/;

function getCanonicalHyperTrainingPendingMinimumLevel(editSession: EditSession | null) {
  if (editSession?.pendingEdits.length !== 1) {
    return null;
  }

  const edit = editSession.pendingEdits[0];
  if (
    edit?.domain !== 'workflow.hyperTraining' ||
    edit.recordId !== 'hyper-training-minimum-level' ||
    edit.field !== 'minimumLevel'
  ) {
    return null;
  }

  const minimumLevel = parseHyperTrainingLevelInput(edit.newValue ?? '');
  if (
    minimumLevel === null ||
    minimumLevel < 1 ||
    minimumLevel > 100 ||
    edit.newValue !== minimumLevel.toString() ||
    edit.summary !== `Stage Hyper Training minimum level Lv.${minimumLevel}.` ||
    !hasCanonicalHyperTrainingPendingSources(edit.sources)
  ) {
    return null;
  }

  return minimumLevel;
}

function hasCanonicalHyperTrainingPendingSources(
  sources: EditSession['pendingEdits'][number]['sources']
) {
  const sourceKeys = sources.map((source) => `${source.layer}:${source.relativePath}`);
  if (sources.length < 3 || new Set(sourceKeys).size !== sources.length) {
    return false;
  }

  if (
    !sourceKeys.includes(`base:${hyperTrainingScriptPath}`) ||
    !sourceKeys.includes(`base:${hyperTrainingMainPath}`)
  ) {
    return false;
  }

  let pendingPayloadCount = 0;
  for (const source of sources) {
    if (source.layer === 'pending') {
      if (!hyperTrainingPendingPayloadPattern.test(source.relativePath)) {
        return false;
      }
      pendingPayloadCount += 1;
      continue;
    }

    if (
      (source.layer !== 'base' && source.layer !== 'layered') ||
      ![
        hyperTrainingScriptPath,
        hyperTrainingDialoguePath,
        hyperTrainingMainPath
      ].includes(source.relativePath)
    ) {
      return false;
    }
  }

  if (pendingPayloadCount !== 1) {
    return false;
  }

  const layerOrder: Record<(typeof sources)[number]['layer'], number> = {
    base: 0,
    layered: 1,
    pending: 2,
    generated: 3
  };
  return sources.every((source, index) => {
    if (index === 0) {
      return true;
    }

    const previous = sources[index - 1]!;
    const layerDifference = layerOrder[previous.layer] - layerOrder[source.layer];
    return (
      layerDifference < 0 ||
      (layerDifference === 0 && previous.relativePath < source.relativePath)
    );
  });
}

function formatTypeChartPendingValue(
  value: string | null | undefined,
  context: PendingEditContext
) {
  const values = decodeTypeChartPendingValues(value);
  if (!values) {
    return undefined;
  }

  const currentValues = getTypeChartWorkflowValues(context.typeChartWorkflow);
  const changedCount = currentValues
    ? values.filter((effectiveness, index) => effectiveness !== currentValues[index]).length
    : values.length;

  return `${changedCount} changed matchup${changedCount === 1 ? '' : 's'}`;
}

function formatFairyGymBoostsPendingValue(value: string | null | undefined) {
  const outcomeCount =
    value
      ?.split(';')
      .map((part) => part.trim())
      .filter(Boolean).length ?? 0;

  return outcomeCount > 0
    ? `${outcomeCount} answer outcome${outcomeCount === 1 ? '' : 's'}`
    : undefined;
}

function formatStartingItemsPendingValue(
  value: string | null | undefined,
  context: PendingEditContext
) {
  if (!value) {
    return 'Clear slots 2-20';
  }

  const itemLookup = new Map(
    (context.startingItemsWorkflow?.itemOptions ?? []).map((option) => [option.itemId, option.name])
  );
  const parts = value
    .split(';')
    .map((part) => part.trim())
    .filter(Boolean)
    .map((part) => {
      const [slot, itemIdText, quantity] = part.split(':');
      const itemId = parseCanonicalPositiveInteger(itemIdText ?? '');
      const itemName = itemId === null ? null : itemLookup.get(itemId);
      return slot && itemIdText && quantity
        ? `slot ${slot}: ${itemName ?? `item ${itemIdText}`} x${quantity}`
        : part;
    });

  return parts.length > 0 ? parts.join(', ') : undefined;
}

function parseStartingItemsPendingGrantInputs(value: string | null | undefined) {
  const grants = new Map<number, { itemId: string; quantity: string }>();
  if (!value) {
    return grants;
  }

  for (const part of value.split(';')) {
    const [slotText, itemIdText, quantityText] = part.split(':');
    const slot = parseCanonicalPositiveInteger(slotText ?? '');
    if (
      slot === null ||
      slot < 2 ||
      slot > 20 ||
      itemIdText === undefined ||
      quantityText === undefined
    ) {
      continue;
    }

    grants.set(slot, {
      itemId: itemIdText === '0' ? '' : itemIdText,
      quantity: quantityText
    });
  }

  return grants;
}

function parseRoyalCandyPendingLevelCapInputs(value: string | null | undefined) {
  const levelCaps = new Map<number, string>();
  if (!value?.startsWith('storyLimits|')) {
    return levelCaps;
  }

  for (const part of value.slice('storyLimits|'.length).split(';')) {
    const [slotText, levelCapText] = part.split('=');
    const slot = Number.parseInt(slotText ?? '', 10);
    if (!Number.isInteger(slot) || levelCapText === undefined) {
      continue;
    }

    levelCaps.set(slot, levelCapText);
  }

  return levelCaps;
}

function getPokemonPendingEditDisplayDetails(
  edit: PendingEdit,
  context: PendingEditContext,
  editorLabel: string
) {
  const pokemon = context.pokemonWorkflow?.pokemon.find(
    (candidate) => candidate.personalId === parseOptionalInteger(edit.recordId)
  );
  const fieldKey = edit.field ?? '';

  if (fieldKey.startsWith('learnset:')) {
    const details = parsePokemonGroupedEditField(fieldKey);
    return createPendingEditDisplayDetails(edit, {
      editorLabel,
      fieldLabel: details
        ? `Learnset slot #${details.slot + 1} ${formatPendingAction(details.action)}`
        : 'Learnset',
      newValueLabel: formatPokemonLearnsetPendingValue(edit.newValue, details, context),
      recordLabel: pokemon ? `${pokemon.name} (#${pokemon.personalId})` : undefined
    });
  }

  if (fieldKey.startsWith('evolution:')) {
    const details = parsePokemonGroupedEditField(fieldKey);
    return createPendingEditDisplayDetails(edit, {
      editorLabel,
      fieldLabel: details
        ? `Evolution slot #${details.slot + 1} ${formatPendingAction(details.action)}`
        : 'Evolution',
      newValueLabel: formatPokemonEvolutionPendingValue(edit.newValue, details, {
        itemsWorkflow: context.itemsWorkflow,
        pokemon,
        pokemonWorkflow: context.pokemonWorkflow
      }),
      recordLabel: pokemon ? `${pokemon.name} (#${pokemon.personalId})` : undefined
    });
  }

  if (fieldKey.startsWith('compatibility:')) {
    const label = getPokemonCompatibilityPendingFieldLabel(fieldKey, pokemon);
    return createPendingEditDisplayDetails(edit, {
      editorLabel,
      fieldLabel: label,
      newValueLabel: edit.newValue === '1' ? 'Enabled' : 'Disabled',
      recordLabel: pokemon ? `${pokemon.name} (#${pokemon.personalId})` : undefined
    });
  }

  const field = findPendingEditableField(context.pokemonWorkflow?.editableFields, edit.field);

  return createPendingEditDisplayDetails(edit, {
    editorLabel,
    fieldLabel: field?.label,
    newValueLabel: formatPendingEditValue(edit.newValue, field),
    recordLabel: pokemon ? `${pokemon.name} (#${pokemon.personalId})` : undefined
  });
}

function getTrainerPendingEditDisplayDetails(
  edit: PendingEdit,
  context: PendingEditContext,
  editorLabel: string
) {
  const editorFamily: EditorUiFamily = isPokemonLegendsZAGame(context.selectedGame)
    ? 'za'
    : isScarletVioletGame(context.selectedGame)
      ? 'sv'
      : 'swsh';
  const [trainerIdText, slotText] = (edit.recordId ?? '').split(':');
  const trainerId = parseOptionalInteger(trainerIdText);
  const slot = parseOptionalInteger(slotText);
  const trainer = context.trainersWorkflow?.trainers.find(
    (candidate) => candidate.trainerId === trainerId
  );
  const trainerClass =
    edit.field === classBallIdFieldName
      ? context.trainersWorkflow?.trainers.find(
          (candidate) => candidate.trainerClassId === trainerId
        )
      : null;
  const trainerPokemon = slot === null ? null : trainer?.team.find((pokemon) => pokemon.slot === slot);
  const field = findPendingEditableField(context.trainersWorkflow?.editableFields, edit.field);
  const recordLabel =
    trainerClass
      ? `${trainerClass.trainerClass} class (#${trainerClass.trainerClassId})`
      : edit.field === classBallIdFieldName && trainerId !== null
        ? `Trainer class #${trainerId}`
        : trainer && trainerPokemon
      ? `${trainer.name} (#${trainer.trainerId}) party slot #${formatTrainerSlotNumber(
          trainerPokemon.slot,
          editorFamily
        )}: ${trainerPokemon.species}`
      : trainer
        ? `${trainer.name} (#${trainer.trainerId})`
        : undefined;

  return createPendingEditDisplayDetails(edit, {
    editorLabel,
    fieldLabel: field?.label,
    newValueLabel: formatPendingEditValue(edit.newValue, field),
    recordLabel
  });
}

function getShopPendingEditDisplayDetails(
  edit: PendingEdit,
  context: PendingEditContext,
  editorLabel: string
) {
  const [shopId, slotText] = (edit.recordId ?? '').split('#');
  const slot = parseOptionalInteger(slotText);
  const shop = context.shopsWorkflow?.shops.find((candidate) => candidate.shopId === shopId);
  const field = findPendingEditableField(context.shopsWorkflow?.editableFields, edit.field);
  const slotItem = slot === null ? null : shop?.inventory.find((item) => item.slot === slot);

  return createPendingEditDisplayDetails(edit, {
    editorLabel,
    fieldLabel: edit.field === shopSetInventoryFieldName ? 'Inventory order' : field?.label,
    newValueLabel:
      edit.field === shopSetInventoryFieldName
        ? formatShopInventoryOrderValue(edit.newValue, context)
        : formatPendingEditValue(edit.newValue, field),
    recordLabel: shop
      ? `${shop.name} (${shop.location})${
          slotItem ? ` slot #${slotItem.slot}: ${slotItem.itemName}` : ''
        }`
      : undefined
  });
}

function getEncounterPendingEditDisplayDetails(
  edit: PendingEdit,
  context: PendingEditContext,
  editorLabel: string
) {
  const workflow = context.encountersWorkflow;
  const [tableId, slotText] = (edit.recordId ?? '').split('#');
  const slot = parseOptionalInteger(slotText);
  let table = workflow?.tables.find((candidate) => candidate.tableId === tableId);
  let slotRecord = slot === null ? null : table?.slots.find((candidate) => candidate.slot === slot);
  if (!slotRecord && edit.recordId) {
    for (const candidateTable of workflow?.tables ?? []) {
      const candidateSlot = candidateTable.slots.find(
        (candidate) => candidate.encounterRecordId === edit.recordId
      );
      if (candidateSlot) {
        table = candidateTable;
        slotRecord = candidateSlot;
        break;
      }
    }
  }

  const sharedSpawnerCount = edit.recordId
    ? new Set(
        (workflow?.tables ?? [])
          .filter((candidateTable) =>
            candidateTable.slots.some(
              (candidateSlot) => candidateSlot.encounterRecordId === edit.recordId
            )
          )
          .map((candidateTable) => candidateTable.tableId)
      ).size
    : 0;
  const field = findPendingEditableField(context.encountersWorkflow?.editableFields, edit.field);

  return createPendingEditDisplayDetails(edit, {
    editorLabel,
    fieldLabel: field?.label,
    newValueLabel: formatPendingEditValue(edit.newValue, field),
    recordLabel:
      table && slotRecord
        ? `${table.location} ${table.encounterType} ${table.gameVersion} ${slotRecord.weather} slot #${slotRecord.slot}: ${slotRecord.species}${
            sharedSpawnerCount > 1 ? `, shared by ${formatZaEncounterSpawnerCount(sharedSpawnerCount)}` : ''
          }`
        : table
          ? `${table.location} ${table.encounterType} ${table.gameVersion}`
          : undefined
  });
}

function getRaidBattlePendingEditDisplayDetails(
  edit: PendingEdit,
  context: PendingEditContext,
  editorLabel: string
) {
  const [tableId, slotText] = (edit.recordId ?? '').split('#');
  const slot = parseOptionalInteger(slotText);
  const table = context.raidBattlesWorkflow?.tables.find((candidate) => candidate.tableId === tableId);
  const slotRecord = slot === null ? null : table?.slots.find((candidate) => candidate.slot === slot);
  const field = findPendingEditableField(context.raidBattlesWorkflow?.editableFields, edit.field);

  return createPendingEditDisplayDetails(edit, {
    editorLabel,
    fieldLabel: field?.label,
    newValueLabel: formatPendingEditValue(edit.newValue, field),
    recordLabel:
      table && slotRecord
        ? `${table.displayName} slot #${slotRecord.slot}: ${slotRecord.species}`
        : table?.displayName
  });
}

function getTeraRaidPendingEditDisplayDetails(
  edit: PendingEdit,
  context: PendingEditContext,
  editorLabel: string
) {
  const field = findPendingEditableField(context.teraRaidsWorkflow?.editableFields, edit.field);
  const recordId = edit.recordId ?? '';
  const [kind] = recordId.split(':');

  if (kind === 'raid') {
    const raid = context.teraRaidsWorkflow?.raids.find(
      (candidate) => candidate.recordId === recordId
    );

    return createPendingEditDisplayDetails(edit, {
      editorLabel,
      fieldLabel: field?.label,
      newValueLabel: formatPendingEditValue(edit.newValue, field),
      recordLabel: raid
        ? `${raid.region} ${raid.starLabel}: ${formatSpeciesFormLabel(
            raid.species,
            raid.form,
            raid.speciesId
          )}`
        : undefined
    });
  }

  const rewardTables =
    kind === 'fixed'
      ? context.teraRaidsWorkflow?.fixedRewardTables
      : kind === 'lottery'
        ? context.teraRaidsWorkflow?.lotteryRewardTables
        : undefined;
  const reward = rewardTables
    ?.flatMap((table) => table.rewards)
    .find((candidate) => candidate.recordId === recordId);

  return createPendingEditDisplayDetails(edit, {
    editorLabel,
    fieldLabel: field?.label,
    newValueLabel: formatPendingEditValue(edit.newValue, field),
    recordLabel: reward
      ? `${reward.rewardKindLabel} table ${reward.tableIndex} slot #${reward.slot}: ${reward.itemName}`
      : undefined
  });
}

function getRaidRewardPendingEditDisplayDetails(
  edit: PendingEdit,
  workflow: RaidRewardsWorkflow | null,
  editorLabel: string
) {
  const [tableId, slotText] = (edit.recordId ?? '').split('#');
  const slot = parseOptionalInteger(slotText);
  const table = workflow?.tables.find((candidate) => candidate.tableId === tableId);
  const reward = slot === null ? null : table?.rewards.find((candidate) => candidate.slot === slot);
  const field = findPendingEditableField(workflow?.editableFields, edit.field);

  return createPendingEditDisplayDetails(edit, {
    editorLabel,
    fieldLabel: field?.label,
    newValueLabel: formatPendingEditValue(edit.newValue, field),
    recordLabel:
      table && reward
        ? `${table.displayName} slot #${reward.slot}: ${reward.itemName}`
        : table
          ? table.displayName
          : undefined
  });
}

function findPendingEditableField(
  fields: readonly PendingEditableField[] | undefined,
  fieldKey: string | null | undefined
) {
  return fields?.find((field) => field.field === fieldKey) ?? null;
}

function formatPendingEditValue(
  value: string | null | undefined,
  field?: PendingEditableField | null
) {
  if (value === null || value === undefined || value.length === 0) {
    return 'n/a';
  }

  const option = findPendingEditableOption(field?.options, value);
  if (option) {
    return option.label;
  }

  if (field?.valueKind === 'boolean') {
    return value === '1' ? 'Enabled' : 'Disabled';
  }

  return value;
}

function findPendingEditableOption(
  options: readonly PendingEditableOption[] | undefined,
  value: string
) {
  const exactOption = options?.find((option) => option.value.toString() === value);
  if (exactOption) {
    return exactOption;
  }

  const parsedValue = Number.parseInt(value, 10);
  if (!Number.isFinite(parsedValue)) {
    return null;
  }

  return options?.find((option) => option.value === parsedValue) ?? null;
}

function parsePokemonGroupedEditField(fieldKey: string) {
  const [, action, slotText] = fieldKey.split(':');
  const slot = parseOptionalInteger(slotText);

  return action && slot !== null ? { action, slot } : null;
}

function formatPokemonLearnsetPendingValue(
  value: string | null | undefined,
  details: { action: string; slot: number } | null,
  context: PendingEditContext
) {
  if (!details) {
    return formatPendingEditValue(value);
  }

  switch (details.action) {
    case 'upsert': {
      const [moveText, levelText] = splitPokemonOperationValue(value);
      const move = formatPendingOptionValue(moveText, context.pokemonWorkflow?.learnsetMoveOptions);
      const level = formatPokemonLearnsetLevelText(levelText);
      return level ? `${level} ${move}` : move;
    }
    case 'moveUp':
      return `Move slot #${details.slot + 1} up`;
    case 'moveDown':
      return `Move slot #${details.slot + 1} down`;
    case 'moveTo': {
      const targetSlot = parseOptionalInteger(value);
      return targetSlot === null ? 'Move to new slot' : `Move to slot #${targetSlot + 1}`;
    }
    case 'remove':
      return `Remove slot #${details.slot + 1}`;
    default:
      return formatPendingEditValue(value);
  }
}

function splitPokemonOperationValue(value: string | null | undefined) {
  const text = value ?? '';
  return text.includes('|') ? text.split('|') : text.split(':');
}

function formatPokemonLearnsetLevelText(levelText: string | undefined) {
  if (!levelText) {
    return null;
  }

  return parseOptionalInteger(levelText) === 253 ? 'Evolution' : `Lv. ${levelText}`;
}

function getPokemonCompatibilityPendingFieldLabel(
  fieldKey: string,
  pokemon: PokemonRecord | undefined
) {
  const [, groupId, slotText] = fieldKey.split(':');
  const slot = parseOptionalInteger(slotText);
  const group = pokemon?.compatibility.find((candidate) => candidate.groupId === groupId);
  const entry = slot === null ? null : group?.entries.find((candidate) => candidate.slot === slot);

  return entry ? `${group?.label ?? groupId} compatibility: ${entry.label}` : 'Compatibility';
}

function formatShopInventoryOrderValue(value: string | null | undefined, context: PendingEditContext) {
  const itemIds = parseShopInventoryUpdateItemIds(value);

  if (itemIds.length === 0) {
    return 'n/a';
  }

  return itemIds
    .map((itemId, index) => {
      const item = context.itemsWorkflow?.items.find((candidate) => candidate.itemId === itemId);
      return `#${index + 1} ${item?.name ?? `Item ${itemId}`}`;
    })
    .join(' / ');
}

function formatPendingOptionValue(
  value: string | null | undefined,
  options: readonly PendingEditableOption[] | undefined
) {
  if (value === null || value === undefined || value.length === 0) {
    return 'n/a';
  }

  return findPendingEditableOption(options, value)?.label ?? value;
}

function formatPendingAction(action: string) {
  const labels: Record<string, string> = {
    add: 'Add',
    moveDown: 'Move Down',
    moveTo: 'Move To',
    moveUp: 'Move Up',
    remove: 'Remove',
    upsert: 'Update'
  };

  return labels[action] ?? humanizePendingEditKey(action);
}

function formatPendingEditSources(edit: PendingEdit) {
  if (edit.sources.length === 0) {
    return 'n/a';
  }

  return edit.sources
    .map((source) => `${source.relativePath} (${formatProjectFileLayer(source.layer)})`)
    .join(', ');
}

function humanizePendingEditKey(value: string) {
  if (value === 'n/a') {
    return value;
  }

  return value
    .replace(/[:.#_-]+/g, ' ')
    .replace(/([a-z])([A-Z])/g, '$1 $2')
    .replace(/\b\w/g, (match) => match.toLocaleUpperCase());
}

function quotePendingEditValue(value: string) {
  return `"${value}"`;
}

function parsePrefixedRecordId(recordId: string | null | undefined, prefix: string) {
  if (!recordId) {
    return null;
  }

  const [recordPrefix, value] = recordId.split(':');
  return recordPrefix === prefix ? parseOptionalInteger(value) : null;
}

function parseDynamaxAdventureRecordId(recordId: string | null | undefined) {
  const match = /^dynamaxAdventure:(0|[1-9]\d*)$/.exec(recordId ?? '');
  if (!match) {
    return null;
  }

  const entryIndex = Number(match[1]);
  return Number.isSafeInteger(entryIndex) ? entryIndex : null;
}

function parseOptionalInteger(value: string | null | undefined) {
  if (value === null || value === undefined || value.trim().length === 0) {
    return null;
  }

  const parsedValue = Number.parseInt(value, 10);
  return Number.isFinite(parsedValue) ? parsedValue : null;
}

function groupNumericEditableFields<TField extends NumericEditableField>(
  fields: TField[],
  getGroup: (field: TField) => string
) {
  const groups: Array<{ group: string; fields: TField[] }> = [];

  for (const field of fields) {
    const groupName = getGroup(field);
    let group = groups.find((candidate) => candidate.group === groupName);
    if (!group) {
      group = { group: groupName, fields: [] };
      groups.push(group);
    }

    group.fields.push(field);
  }

  return groups;
}

function getItemEditableFieldGroup(field: ItemEditableField) {
  const fieldName = field.field.toLocaleLowerCase();

  if (
    field.field === 'buyPrice' ||
    field.field === 'sellPrice' ||
    field.field === 'wattsPrice' ||
    field.field === 'alternatePrice'
  ) {
    return 'Prices';
  }

  if (
    field.field === 'pouch' ||
    fieldName.includes('sort') ||
    fieldName.includes('category')
  ) {
    return 'Bag Metadata';
  }

  if (field.valueKind === 'boolean') {
    return 'Use Flags';
  }

  if (
    fieldName.includes('heal') ||
    fieldName.startsWith('ev') ||
    fieldName.includes('friendship') ||
    fieldName.includes('pp')
  ) {
    return 'Use Effects';
  }

  return 'Item Data';
}

function toNumericEditableField(field: MoveEditableField): NumericEditableField {
  return {
    field: field.field,
    label: getMoveEditableFieldLabel(field),
    maximumValue: field.maximumValue,
    minimumValue: field.minimumValue,
    options: field.options,
    valueKind: field.valueKind
  };
}

function orderMoveEditableFieldGroups<TField extends NumericEditableField>(
  groups: Array<{ group: string; fields: TField[] }>
) {
  return [
    ...groups.filter((group) => group.group !== 'Flags'),
    ...groups.filter((group) => group.group === 'Flags')
  ];
}

function getEncounterEditableFieldGroup(field: NumericEditableField) {
  if (field.field === raidBattleSpeciesFieldName || field.field === encounterFormFieldName) {
    return 'Pokemon';
  }

  if (field.field === encounterLevelMinFieldName || field.field === encounterLevelMaxFieldName) {
    return 'Levels';
  }

  if (field.field === encounterProbabilityFieldName) {
    return 'Probability';
  }

  if (
    field.field === zaEncounterAlphaChanceFieldName ||
    field.field === zaEncounterAlphaLevelBonusFieldName
  ) {
    return 'Shared Alpha Settings';
  }

  return 'Encounter Data';
}

function contextualizeZaEncounterField(
  field: NumericEditableField,
  slot: EncounterSlotRecord | null,
  editorFamily: EditorUiFamily
) {
  if (
    editorFamily !== 'za' ||
    !slot ||
    field.field !== zaEncounterAlphaChanceFieldName ||
    isZaGuaranteedAlphaSlot(slot)
  ) {
    return field;
  }

  return {
    ...field,
    maximumValue: Math.min(field.maximumValue ?? 99, 99)
  };
}

function getRaidBattleEditableFieldGroup(field: NumericEditableField) {
  if (field.field === raidBattleSpeciesFieldName || field.field === raidBattleFormFieldName) {
    return 'Pokemon';
  }

  if (
    field.field === raidBattleAbilityFieldName ||
    field.field === raidBattleGenderFieldName ||
    field.field === raidBattleIsGigantamaxFieldName ||
    field.field === raidBattleFlawlessIvsFieldName
  ) {
    return 'Traits';
  }

  if (
    raidBattleProbabilityFieldNames.includes(
      field.field as (typeof raidBattleProbabilityFieldNames)[number]
    )
  ) {
    return 'Star Odds';
  }

  return 'Battle Data';
}

function getRaidRewardEditableFieldGroup(field: NumericEditableField) {
  if (field.field === raidRewardItemIdFieldName) {
    return 'Reward Item';
  }

  if (
    raidRewardValueFieldNames.includes(
      field.field as (typeof raidRewardValueFieldNames)[number]
    )
  ) {
    return field.label.includes('drop chance') ? 'Drop Chances' : 'Quantities';
  }

  return 'Reward Data';
}

function getPokemonInstanceFieldGroup(field: NumericEditableField) {
  if (
    field.field === giftSpeciesFieldName ||
    field.field === formFieldName ||
    field.field === levelFieldName ||
    field.field === heldItemIdFieldName ||
    field.field === giftBallItemIdFieldName ||
    field.field === dynamaxAdventureBallItemIdFieldName ||
    field.field === giftScaleModeFieldName ||
    field.field === giftScaleValueFieldName
  ) {
    return 'Pokemon';
  }

  if (
    moveFieldNames.includes(field.field as (typeof moveFieldNames)[number]) ||
    staticEncounterMoveFieldNames.includes(
      field.field as (typeof staticEncounterMoveFieldNames)[number]
    ) ||
    tradeRelearnMoveFieldNames.includes(field.field as (typeof tradeRelearnMoveFieldNames)[number]) ||
    giftMoveFieldNames.includes(field.field as (typeof giftMoveFieldNames)[number]) ||
    field.field === giftSpecialMoveIdFieldName
  ) {
    return 'Moves';
  }

  if (evFieldNames.includes(field.field as (typeof evFieldNames)[number])) {
    return 'Stats - EVs';
  }

  if (
    ivFieldNames.includes(field.field as (typeof ivFieldNames)[number]) ||
    dynamaxAdventureIvFieldNames.includes(
      field.field as (typeof dynamaxAdventureIvFieldNames)[number]
    ) ||
    field.field === giftFlawlessIvCountFieldName ||
    field.field === rentalFixedIvPresetFieldName ||
    field.field === dynamaxAdventureGuaranteedPerfectIvsFieldName
  ) {
    return 'Stats - IVs';
  }

  if (
    field.field === abilityFieldName ||
    field.field === natureFieldName ||
    field.field === genderFieldName ||
    field.field === giftShinyLockFieldName ||
    field.field === giftTeraTypeFieldName ||
    field.field === dynamaxLevelFieldName ||
    field.field === canGigantamaxFieldName ||
    field.field === dynamaxAdventureGigantamaxStateFieldName ||
    field.field === dynamaxAdventureShinyRollFieldName ||
    field.field === dynamaxAdventureOtGenderFieldName ||
    field.field === dynamaxAdventureIsSingleCaptureFieldName ||
    field.field === dynamaxAdventureIsStoryProgressGatedFieldName
  ) {
    return 'Traits';
  }

  if (
    field.field === tradeRequiredSpeciesFieldName ||
    field.field === tradeRequiredFormFieldName ||
    field.field === tradeRequiredNatureFieldName ||
    field.field === tradeUnknownRequirementFieldName
  ) {
    return 'Trade Request';
  }

  if (
    field.field === tradeTrainerIdFieldName ||
    field.field === tradeOtGenderFieldName ||
    field.field === tradeMemoryCodeFieldName ||
    field.field === tradeMemoryTextVariableFieldName ||
    field.field === tradeMemoryFeelFieldName ||
    field.field === tradeMemoryIntensityFieldName
  ) {
    return 'Trade Memory';
  }

  if (
    field.field === tradeField03FieldName ||
    field.field === staticEncounterScenarioFieldName ||
    field.field === dynamaxAdventureVersionFieldName
  ) {
    return 'Advanced';
  }

  return 'Details';
}

function getStaticEncounterFieldGroup(field: StaticEncounterEditableField) {
  return field.group ?? getPokemonInstanceFieldGroup(field);
}

function isStaticEncounterFieldVisible(
  field: StaticEncounterEditableField,
  encounter: StaticEncounterRecord | null
) {
  if (!encounter) {
    return false;
  }

  if (encounter?.supportedFields.length) {
    return encounter.supportedFields.includes(field.field);
  }

  return (
    encounter.editorFamily === 'swsh' &&
    staticEncounterFieldNames.includes(
      field.field as (typeof staticEncounterFieldNames)[number]
    )
  );
}

function withStaticEncounterFieldState(
  field: StaticEncounterEditableField,
  encounter: StaticEncounterRecord | null
) {
  if (!encounter) {
    return field;
  }

  return {
    ...field,
    options:
      field.field === genderFieldName && encounter.genderOptions?.length
        ? encounter.genderOptions
        : field.options,
    isReadOnly: field.isReadOnly || encounter.fieldReadOnly[field.field] === true
  };
}

function getTradeFieldDisabledReason(fieldName: string) {
  return lockedTradeFieldNames.includes(fieldName as (typeof lockedTradeFieldNames)[number])
    ? 'Locked until this field has a confirmed editor-safe meaning.'
    : null;
}

function getItemFieldDisabledReason(
  field: ItemEditableField,
  editorFamily: EditorUiFamily,
  item?: ItemRecord | null
) {
  const fieldName = field.field;
  if (field.isReadOnly) {
    return field.readOnlyReason ?? 'This field is read-only.';
  }

  if (editorFamily === 'za' && fieldName === itemCanUseOnPokemonFieldName) {
    return 'Derived from item effects. Edit healing, revive, EV, form change, or Evolution Item instead.';
  }

  if (fieldName === itemFieldFlagsFieldName) {
    return 'This legacy raw field is visible for compatibility. Use Battle pouch instead.';
  }

  if (fieldName === itemCureStatusFlagsFieldName) {
    return 'Raw cure status flags are visible for reference. Edit the named cure controls instead.';
  }

  if (fieldName === itemUseFlags1FieldName) {
    return 'Raw use flags 1 is visible for research and locked. Edit the decoded known flags instead.';
  }

  if (fieldName === itemUseFlags2FieldName) {
    return 'Raw use flags 2 includes unknown bits 5-7. Edit the decoded known flags instead.';
  }

  if (fieldName === itemMachineMoveIdFieldName) {
    if (!item || item.metadata.machineSlot === null) {
      return 'Only TM and TR item records can edit the taught move.';
    }

    if (item.metadata.machineMoveId === null) {
      return 'This item table does not expose a writable TM or TR move entry.';
    }
  }

  return null;
}

function getDynamaxAdventureFieldDisabledReason(
  field: NumericEditableField,
  encounter: DynamaxAdventureRecord
) {
  if (
    !encounter.layoutWritableFields.includes(
      field.field as DynamaxAdventureEditableFieldName
    )
  ) {
    return 'Read-only';
  }

  if (field.field === formFieldName) {
    return 'Read-only';
  }

  if (
    (field.field === giftSpeciesFieldName ||
      field.field === abilityFieldName ||
      field.field === dynamaxAdventureGigantamaxStateFieldName ||
      staticEncounterMoveFieldNames.includes(
        field.field as (typeof staticEncounterMoveFieldNames)[number]
      )) &&
    field.options.length === 0
  ) {
    return 'Unavailable';
  }

  if (
    field.field === dynamaxAdventureGigantamaxStateFieldName &&
    field.options.length <= 1
  ) {
    return 'Selected Pokemon does not have a Gigantamax form.';
  }

  return null;
}

function GiftPokemonDraftField({
  currentValue,
  disabled,
  disabledReason,
  draftState,
  draftValue,
  field,
  formOptionContext,
  idPrefix = 'pokemon-instance',
  onChange,
  preservedValue
}: {
  currentValue: number | null;
  disabled: boolean;
  disabledReason?: string;
  draftState: TrainerDraftState;
  draftValue: string;
  field: NumericEditableField;
  formOptionContext?: SpeciesFormOptionContext;
  idPrefix?: string;
  onChange: (value: string) => void;
  preservedValue?: number | null;
}) {
  const inputId = `${idPrefix}-${field.field}`;
  const { contextualFormOptionContext, knownFormCount, options } =
    useContextualSpeciesFormOptions(field, formOptionContext, currentValue);
  const formDisabledReason = getFormFieldDisabledReason(
    field,
    contextualFormOptionContext,
    currentValue,
    knownFormCount
  );
  const effectiveDisabledReason = disabledReason ?? formDisabledReason ?? undefined;
  const effectiveDisabled = disabled || Boolean(effectiveDisabledReason);
  const statusText = draftState.error ?? (draftState.isChanged ? 'Changed' : null);
  const { translateLiteral } = useLocalization();
  const localizedFieldLabel = translateLiteral(field.label);
  const localizedFieldHelpText = translateLiteral(
    effectiveDisabledReason ?? getEditableFieldHelp(field)
  );
  const optionsWithPreservedValue =
    preservedValue === null || preservedValue === undefined
      ? options
      : addCurrentPokemonFieldOption(
          options,
          preservedValue.toString(),
          field.label
        );

  return (
    <label
      className={`path-field editable-field-control ${
        draftState.isChanged ? 'editable-field-changed' : ''
      } ${!draftState.isValid ? 'editable-field-invalid' : ''} ${
        effectiveDisabledReason ? 'editable-field-disabled' : ''
      }`}
      htmlFor={inputId}
      title={localizedFieldHelpText}
    >
      <span>{localizedFieldLabel}</span>
      {field.valueKind === 'boolean' ? (
        <select
          aria-label={localizedFieldLabel}
          disabled={effectiveDisabled}
          id={inputId}
          onChange={(event) => onChange(event.target.value)}
          title={localizedFieldHelpText}
          value={draftValue === '1' ? '1' : '0'}
        >
          <option value="1">{translateLiteral('Yes')}</option>
          <option value="0">{translateLiteral('No')}</option>
        </select>
      ) : options.length > 0 ? (
        <SearchableOptionInput
          ariaLabel={localizedFieldLabel}
          disabled={effectiveDisabled}
          id={inputId}
          onChange={onChange}
          options={addCurrentPokemonFieldOption(
            optionsWithPreservedValue,
            draftValue,
            field.label
          )}
          title={localizedFieldHelpText}
          value={draftValue}
        />
      ) : (
        <input
          aria-label={localizedFieldLabel}
          disabled={effectiveDisabled}
          id={inputId}
          max={field.maximumValue ?? undefined}
          min={field.minimumValue ?? undefined}
          onChange={(event) => onChange(event.target.value)}
          title={localizedFieldHelpText}
          type="number"
          value={draftValue}
        />
      )}
      {effectiveDisabledReason ? (
        <small className="editable-field-status">{translateLiteral(effectiveDisabledReason)}</small>
      ) : statusText ? (
        <small className={draftState.error ? 'editable-field-error' : 'editable-field-status'}>
          {translateLiteral(statusText)}
        </small>
      ) : null}
    </label>
  );
}

function ShinyLockRemovalConfirmationModal({
  affectedCount,
  isApplying,
  label,
  onCancel,
  onConfirm,
  recordLabel,
  recordLabelPlural,
  targetLabel = 'Random'
}: {
  affectedCount: number;
  isApplying: boolean;
  label: string;
  onCancel: () => void;
  onConfirm: () => Promise<void>;
  recordLabel: string;
  recordLabelPlural: string;
  targetLabel?: string;
}) {
  const dialogRef = useModalDialog<HTMLDivElement>({
    canClose: !isApplying,
    onClose: onCancel
  });
  const affectedLabel = affectedCount === 1 ? recordLabel : recordLabelPlural;

  return (
    <div
      aria-labelledby="shiny-lock-removal-heading"
      aria-modal="true"
      className="modal-backdrop"
      ref={dialogRef}
      role="dialog"
      tabIndex={-1}
    >
      <section className="modal-panel">
        <div className="panel-heading">
          <ShieldCheck aria-hidden="true" size={18} />
          <h2 id="shiny-lock-removal-heading">Remove {label} Shiny Lock?</h2>
        </div>
        <p className="modal-copy">
          This will stage shiny lock edits for {affectedCount} {affectedLabel}. Their shiny lock
          value will be set to {targetLabel}, which lets the game use its normal shiny behavior.
        </p>
        <p className="modal-copy modal-copy-muted">
          Records that are already {targetLabel} are skipped. This still uses the normal review and apply
          flow, so files are not written until you approve the change plan.
        </p>
        <div className="modal-actions">
          <button className="secondary-button" disabled={isApplying} onClick={onCancel} type="button">
            <X aria-hidden="true" size={16} />
            <span>Cancel</span>
          </button>
          <button
            aria-busy={isApplying || undefined}
            className="primary-button"
            disabled={isApplying}
            onClick={onConfirm}
            type="button"
          >
            <BusyActionContent
              busyLabel="Removing"
              icon={<ShieldCheck aria-hidden="true" size={16} />}
              isBusy={isApplying}
              label={`Remove ${label} Shiny Lock`}
            />
          </button>
        </div>
      </section>
    </div>
  );
}

function GiftPokemonSection({
  editSession,
  isEditStarting,
  isGiftPokemonUpdating,
  onSearchChange,
  onSelectGift,
  onStartEditSession,
  onRemoveGiftPokemonShinyLocks,
  onUpdateGiftPokemonFields,
  pokemonWorkflow,
  searchText,
  selectedGiftIndex,
  workflow
}: {
  editSession: EditSession | null;
  isEditStarting: boolean;
  isGiftPokemonUpdating: boolean;
  onSearchChange: (searchText: string) => void;
  onSelectGift: (giftIndex: number | null) => void;
  onStartEditSession: () => void;
  onRemoveGiftPokemonShinyLocks: (
    giftIndexes: number[],
    resetValue: string
  ) => Promise<boolean>;
  onUpdateGiftPokemonFields: (
    giftIndex: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  pokemonWorkflow: PokemonWorkflow | null;
  searchText: string;
  selectedGiftIndex: number | null;
  workflow: GiftPokemonWorkflow | null;
}) {
  const [isShinyLockConfirmationOpen, setIsShinyLockConfirmationOpen] = useState(false);
  const gifts = workflow?.gifts ?? [];
  const filteredGifts = useMemo(
    () => filterGiftPokemon(gifts, searchText),
    [gifts, searchText]
  );
  const selectedGift = useMemo(
    () =>
      filteredGifts.find((gift) => gift.giftIndex === selectedGiftIndex) ??
      filteredGifts[0] ??
      null,
    [filteredGifts, selectedGiftIndex]
  );
  const canEditGifts = workflow?.summary.availability === 'available';
  const editorFamily: EditorUiFamily =
    workflow?.editorFamily === 'za' ? 'za' : workflow?.editorFamily === 'sv' ? 'sv' : 'swsh';
  const pendingGiftIndexes = useMemo(() => getPendingGiftPokemonIndexes(editSession), [editSession]);
  const shinyReset = useMemo(() => getGiftPokemonShinyReset(workflow), [workflow]);
  const lockedGiftIndexes = useMemo(
    () =>
      gifts
        .filter((gift) => gift.shinyLock !== shinyReset.value)
        .map((gift) => gift.giftIndex),
    [gifts, shinyReset.value]
  );
  const canRemoveGiftShinyLocks =
    canEditGifts &&
    editSession !== null &&
    !isGiftPokemonUpdating &&
    lockedGiftIndexes.length > 0;
  const removeGiftShinyLockTitle =
    editSession === null
      ? 'Start editing before removing gift shiny locks.'
      : lockedGiftIndexes.length === 0
      ? 'No gift shiny locks are currently set.'
      : `Set every locked gift Pokemon shiny lock to ${shinyReset.label}.`;

  return (
    <>
      <section aria-labelledby="gift-pokemon-heading" className="panel wide-panel">
        <div className="panel-heading">
          <Dna aria-hidden="true" size={18} />
          <h2 id="gift-pokemon-heading">Gift Pokemon</h2>
        </div>

        <div className="items-toolbar trainers-toolbar shiny-lock-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label="Search gift Pokemon"
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder="Search gift Pokemon"
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label="Loaded gifts"
            value={workflow ? workflow.stats.totalGiftCount.toString() : '0'}
          />
          <Metric
            label="Egg gifts"
            value={workflow ? workflow.stats.eggGiftCount.toString() : '0'}
          />
          <Metric
            label="Fixed IV rows"
            value={workflow ? workflow.stats.fixedIvGiftCount.toString() : '0'}
          />
          <button
            className="primary-button compact-button"
            disabled={!canRemoveGiftShinyLocks}
            onClick={() => setIsShinyLockConfirmationOpen(true)}
            title={removeGiftShinyLockTitle}
            type="button"
          >
            <ShieldCheck aria-hidden="true" size={14} />
            <span>Remove Gift Shiny Lock</span>
          </button>
        </div>

        {workflow ? (
          <div className="trainers-layout">
            <div
              aria-colcount={5}
              aria-label="Gift Pokemon"
              aria-rowcount={filteredGifts.length + 1}
              className="trainers-table"
              role="table"
            >
              <div className="trainers-row gift-pokemon-row trainers-row-heading" role="row">
                <span role="columnheader">Gift #</span>
                <span role="columnheader">Species</span>
                <span role="columnheader">Level</span>
                <span role="columnheader">IVs</span>
                <span role="columnheader">Source</span>
              </div>
              <VirtualTableBody
                getKey={(gift) => gift.giftIndex}
                items={filteredGifts}
                renderRow={(gift) => (
                  <button
                    className={`trainers-row gift-pokemon-row ${
                      selectedGift?.giftIndex === gift.giftIndex ? 'trainers-row-selected' : ''
                    } ${pendingGiftIndexes.has(gift.giftIndex) ? 'trainers-row-pending' : ''}`}
                    onClick={() => onSelectGift(gift.giftIndex)}
                    role="row"
                    type="button"
                  >
                    <span role="cell">#{gift.giftIndex + 1}</span>
                    <span role="cell">
                      {formatSpeciesFormLabel(gift.species, gift.form, gift.speciesId, editorFamily)}
                    </span>
                    <span role="cell">{formatGiftPokemonLevel(gift, editorFamily)}</span>
                    <span role="cell">{gift.ivSummary}</span>
                    <span role="cell">{formatSourceLayer(gift.provenance.sourceLayer)}</span>
                  </button>
                )}
              />
            </div>

            <SelectedGiftPokemonPanel
              canEditGifts={canEditGifts}
              editSession={editSession}
              editableFields={workflow.editableFields}
              editorFamily={editorFamily}
              gift={selectedGift}
              isEditStarting={isEditStarting}
              isGiftPokemonUpdating={isGiftPokemonUpdating}
              onStartEditSession={onStartEditSession}
              onUpdateGiftPokemonFields={onUpdateGiftPokemonFields}
              pokemonWorkflow={pokemonWorkflow}
            />
          </div>
        ) : (
          <p className="empty-copy">Open Gift Pokemon from Workflows to load backend gift data.</p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
      {isShinyLockConfirmationOpen ? (
        <ShinyLockRemovalConfirmationModal
          affectedCount={lockedGiftIndexes.length}
          isApplying={isGiftPokemonUpdating}
          label="Gift"
          recordLabel="gift Pokemon"
          recordLabelPlural="gift Pokemon"
          targetLabel={shinyReset.label}
          onCancel={() => setIsShinyLockConfirmationOpen(false)}
          onConfirm={async () => {
            const didSave = await onRemoveGiftPokemonShinyLocks(
              lockedGiftIndexes,
              shinyReset.value.toString()
            );
            if (didSave) {
              setIsShinyLockConfirmationOpen(false);
            }
          }}
        />
      ) : null}
    </>
  );
}

function SelectedGiftPokemonPanel({
  canEditGifts,
  editSession,
  editableFields,
  editorFamily,
  gift,
  isEditStarting,
  isGiftPokemonUpdating,
  onStartEditSession,
  onUpdateGiftPokemonFields,
  pokemonWorkflow
}: {
  canEditGifts: boolean;
  editSession: EditSession | null;
  editableFields: GiftPokemonEditableField[];
  editorFamily: EditorUiFamily;
  gift: GiftPokemonRecord | null;
  isEditStarting: boolean;
  isGiftPokemonUpdating: boolean;
  onStartEditSession: () => void;
  onUpdateGiftPokemonFields: (
    giftIndex: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  pokemonWorkflow: PokemonWorkflow | null;
}) {
  const [giftDraftsByIndex, setGiftDraftsByIndex] = useState<
    Record<string, Record<string, string>>
  >({});
  const cancelActiveEditSession = useCancelActiveEditSession();
  const giftFields = useMemo(
    () =>
      editableFields
        .filter((field) =>
          giftPokemonFieldNames.includes(field.field as (typeof giftPokemonFieldNames)[number])
        )
        .map(withPokemonInstanceIvPresetOptions),
    [editableFields]
  );
  const defaultContextualGiftFields = useMemo(
    () =>
      giftFields.map((field) => {
        const options = getContextualFieldOptions(
          field,
          gift
            ? {
                abilityOptions: gift.abilityOptions,
                gameFamily: editorFamily,
                genderOptions: gift.genderOptions,
                species: gift.species,
                speciesId: gift.speciesId
              }
            : undefined
        );

        return options === field.options ? field : { ...field, options };
      }),
    [editorFamily, gift, giftFields]
  );
  const giftDraftDefaults = useMemo(
    () =>
      gift
        ? createPokemonInstanceDrafts(defaultContextualGiftFields, (field) =>
            getEditableGiftPokemonFieldValue(gift, field)
          )
        : {},
    [defaultContextualGiftFields, gift]
  );
  const giftDrafts = gift ? giftDraftsByIndex[gift.giftIndex.toString()] ?? giftDraftDefaults : {};
  const giftFormOptionContext = useMemo(() => {
    if (!gift) {
      return undefined;
    }

    const context = createDraftSpeciesFormOptionContext(
      defaultContextualGiftFields.find((field) => field.field === giftSpeciesFieldName),
      giftDrafts[giftSpeciesFieldName],
      gift.species,
      gift.speciesId,
      gift.abilityOptions,
      editorFamily,
      gift.genderOptions
    );
    const draftedForm = Number.parseInt(
      giftDrafts[formFieldName] ?? gift.form.toString(),
      10
    );
    const normalizedDraftedForm = Number.isInteger(draftedForm) ? draftedForm : gift.form;
    const usesCurrentIdentity =
      context.speciesId === gift.speciesId && normalizedDraftedForm === gift.form;
    const referencePokemon =
      editorFamily === 'swsh'
        ? pokemonWorkflow?.pokemon.find(
            (pokemon) =>
              pokemon.speciesId === context.speciesId && pokemon.form === normalizedDraftedForm
          )
        : undefined;
    const fallbackAbilityOptions =
      giftFields.find((field) => field.field === abilityFieldName)?.options ?? [];
    const fallbackGenderOptions =
      giftFields.find((field) => field.field === genderFieldName)?.options ?? [];

    return {
      ...context,
      abilityOptions: referencePokemon
        ? createTrainerPokemonAbilityOptions(referencePokemon)
        : usesCurrentIdentity
          ? gift.abilityOptions
          : fallbackAbilityOptions,
      genderOptions: referencePokemon
        ? createGiftPokemonGenderOptions(referencePokemon)
        : usesCurrentIdentity
          ? gift.genderOptions
          : fallbackGenderOptions
    };
  }, [
    defaultContextualGiftFields,
    editorFamily,
    gift,
    giftDrafts,
    giftFields,
    pokemonWorkflow
  ]);
  const contextualGiftFields = useMemo(
    () =>
      giftFields.map((field) => {
        const options = getContextualFieldOptions(field, giftFormOptionContext);
        return options === field.options ? field : { ...field, options };
      }),
    [giftFields, giftFormOptionContext]
  );
  const giftFieldGroups = useMemo(
    () => groupNumericEditableFields(contextualGiftFields, getPokemonInstanceFieldGroup),
    [contextualGiftFields]
  );
  const giftDraftSummary = useMemo(
    () =>
      getTrainerDraftSummary(
        getActivePokemonInstanceFields(contextualGiftFields, giftDrafts),
        giftDrafts,
        gift ? (field) => getEditableGiftPokemonFieldValue(gift, field) : null
      ),
    [contextualGiftFields, gift, giftDrafts]
  );
  useRegisterEditorDraftDirty('giftPokemon', countFieldDraftRecords(giftDraftsByIndex) > 0);
  const canSaveGiftDrafts =
    gift !== null &&
    editSession !== null &&
    canEditGifts &&
    !isGiftPokemonUpdating &&
    giftDraftSummary.changedFields.length > 0 &&
    giftDraftSummary.invalidFields.length === 0;

  useEffect(() => {
    if (!gift) {
      return;
    }

    setGiftDraftsByIndex((currentDrafts) =>
      pruneFieldDraftRecord(currentDrafts, gift.giftIndex, giftDraftDefaults)
    );
  }, [gift, giftDraftDefaults]);

  return (
    <aside aria-label="Selected gift Pokemon provenance" className="trainer-inspector">
      <div className="panel-heading">
        <ShieldCheck aria-hidden="true" size={18} />
        <h3>Selected Gift</h3>
      </div>

      {gift ? (
        <>
          <PokemonSummaryCard
            editorFamily={editorFamily}
            form={gift.form}
            name={formatSpeciesFormLabel(gift.species, gift.form, gift.speciesId, editorFamily)}
            speciesId={gift.speciesId}
            subtitle={`Gift #${gift.giftIndex + 1} | ${formatGiftPokemonLevelSummary(gift, editorFamily)}`}
            title={formatSpeciesFormLabel(gift.species, gift.form, gift.speciesId, editorFamily)}
          />

          <dl className="item-provenance-list">
            <div>
              <dt>Gift</dt>
              <dd>{gift.label}</dd>
            </div>
            {editorFamily !== 'swsh' && gift.eventLabel ? (
              <div>
                <dt>Event label</dt>
                <dd>{gift.eventLabel}</dd>
              </div>
            ) : null}
            <div>
              <dt>Data file</dt>
              <dd>{gift.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>Layer</dt>
              <dd>{formatSourceLayer(gift.provenance.sourceLayer)}</dd>
            </div>
            <div>
              <dt>File state</dt>
              <dd>{formatFileState(gift.provenance.fileState)}</dd>
            </div>
            <div>
              <dt>Ball</dt>
              <dd>{gift.ballItem}</dd>
            </div>
            <div>
              <dt>Held item</dt>
              <dd>{gift.heldItem ?? 'None'}</dd>
            </div>
            {editorFamily === 'sv' || editorFamily === 'za' ? (
              <>
                <div>
                  <dt>Moves</dt>
                  <dd>{formatGiftPokemonMoves(gift)}</dd>
                </div>
                {gift.teraTypeLabel !== null ? (
                  <div>
                    <dt>Tera type</dt>
                    <dd>{gift.teraTypeLabel}</dd>
                  </div>
                ) : null}
                {gift.scaleModeLabel !== null ? (
                  <div>
                    <dt>Scale</dt>
                    <dd>{formatGiftPokemonScale(gift)}</dd>
                  </div>
                ) : null}
              </>
            ) : (
              <div>
                <dt>Special Move</dt>
                <dd>{gift.specialMove ?? 'None'}</dd>
              </div>
            )}
            <div>
              <dt>IV detail</dt>
              <dd>{formatGiftPokemonIvs(gift)}</dd>
            </div>
          </dl>

          <div className="trainer-edit-form">
            <div className="editable-field-groups">
              {giftFieldGroups.map((group) => (
                <fieldset className="editable-field-group" key={group.group}>
                  <legend>{group.group}</legend>
                  <div className="editable-field-grid">
                    {group.fields.map((field) => {
                      const currentValue = getEditableGiftPokemonFieldValue(gift, field.field);
                      const draftValue = giftDrafts[field.field] ?? '';
                      const draftState = getTrainerFieldDraftState(
                        draftValue,
                        currentValue,
                        field,
                        {
                          drafts: giftDrafts,
                          fields: contextualGiftFields,
                          getValue: (fieldName) =>
                            getEditableGiftPokemonFieldValue(gift, fieldName)
                        }
                      );

                      return (
                        <GiftPokemonDraftField
                          currentValue={currentValue}
                          disabled={!canEditGifts || editSession === null || isGiftPokemonUpdating}
                          disabledReason={
                            getPokemonInstanceIvStatDisabledReason(
                              field.field,
                              contextualGiftFields,
                              giftDrafts
                            ) ?? undefined
                          }
                          draftState={draftState}
                          draftValue={draftValue}
                          field={field}
                          formOptionContext={giftFormOptionContext}
                          key={field.field}
                          onChange={(value) => {
                            const nextDrafts = {
                              ...giftDrafts,
                              [field.field]: value
                            };
                            const speciesField = contextualGiftFields.find(
                              (candidate) => candidate.field === giftSpeciesFieldName
                            );
                            const formField = contextualGiftFields.find(
                              (candidate) => candidate.field === formFieldName
                            );
                            const previousSpeciesId =
                              parseEditableIntegerDraft(
                                giftDrafts[giftSpeciesFieldName] ?? gift.speciesId.toString(),
                                speciesField?.options
                              ) ?? gift.speciesId;
                            const previousForm =
                              parseEditableIntegerDraft(
                                giftDrafts[formFieldName] ?? gift.form.toString(),
                                formField?.options
                              ) ?? gift.form;
                            let nextSpeciesId = previousSpeciesId;
                            let nextForm = previousForm;
                            let identityChanged = false;

                            if (field.field === giftSpeciesFieldName) {
                              const parsedSpeciesId = parseEditableIntegerDraft(
                                value,
                                field.options
                              );
                              if (
                                parsedSpeciesId !== null &&
                                parsedSpeciesId !== previousSpeciesId
                              ) {
                                nextSpeciesId = parsedSpeciesId;
                                nextForm = 0;
                                identityChanged = true;
                                if (formField) {
                                  nextDrafts[formFieldName] = '0';
                                }
                              }
                            } else if (field.field === formFieldName) {
                              const parsedForm = parseEditableIntegerDraft(value, field.options);
                              if (parsedForm !== null && parsedForm !== previousForm) {
                                nextForm = parsedForm;
                                identityChanged = true;
                              }
                            }

                            if (identityChanged) {
                              if (editorFamily === 'swsh') {
                                const referencePokemon = pokemonWorkflow?.pokemon.find(
                                  (pokemon) =>
                                    pokemon.speciesId === nextSpeciesId &&
                                    pokemon.form === nextForm
                                );
                                if (referencePokemon) {
                                  preserveValidGiftDependencyOrReset(
                                    nextDrafts,
                                    contextualGiftFields,
                                    abilityFieldName,
                                    gift.ability,
                                    createTrainerPokemonAbilityOptions(referencePokemon)
                                  );
                                  preserveValidGiftDependencyOrReset(
                                    nextDrafts,
                                    contextualGiftFields,
                                    genderFieldName,
                                    gift.gender,
                                    createGiftPokemonGenderOptions(referencePokemon)
                                  );
                                }
                              } else {
                                const abilityField = contextualGiftFields.find(
                                  (candidate) => candidate.field === abilityFieldName
                                );
                                if (abilityField?.options.some((option) => option.value === 0)) {
                                  nextDrafts[abilityFieldName] = '0';
                                }
                              }
                            }
                            setGiftDraftsByIndex((currentDrafts) =>
                              setFieldDraftRecord(
                                currentDrafts,
                                gift.giftIndex,
                                nextDrafts,
                                giftDraftDefaults
                              )
                            );
                          }}
                        />
                      );
                    })}
                  </div>
                </fieldset>
              ))}
            </div>
            {editSession ? (
              <div className="draft-action-row">
                <button
                  aria-busy={isGiftPokemonUpdating || undefined}
                  className="primary-button"
                  disabled={!canSaveGiftDrafts}
                  onClick={async () => {
                    const didSave = await onUpdateGiftPokemonFields(
                      gift.giftIndex,
                      giftDraftSummary.changedFields.map((change) => ({
                        field: change.field,
                        value: change.value
                      }))
                    );
                    if (didSave) {
                      setGiftDraftsByIndex((currentDrafts) =>
                        deleteFieldDraftRecord(currentDrafts, gift.giftIndex)
                      );
                    }
                  }}
                  type="button"
                >
                  <BusyActionContent
                    busyLabel="Staging"
                    icon={<Save aria-hidden="true" size={16} />}
                    isBusy={isGiftPokemonUpdating}
                    label="Stage"
                  />
                </button>
                <button
                  className="danger-button"
                  disabled={isGiftPokemonUpdating}
                  onClick={() => cancelActiveEditSession(() => setGiftDraftsByIndex({}))}
                  type="button"
                >
                  <X aria-hidden="true" size={16} />
                  <span>Cancel</span>
                </button>
                <span className="draft-action-summary">{formatDraftSummary(giftDraftSummary)}</span>
              </div>
            ) : null}

            {!editSession ? (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditGifts || isEditStarting}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            ) : null}
          </div>
        </>
      ) : (
        <p className="empty-copy">No gift selected.</p>
      )}
    </aside>
  );
}

function TradePokemonSection({
  editSession,
  isEditStarting,
  isTradePokemonUpdating,
  onSearchChange,
  onSelectTrade,
  onStartEditSession,
  onRemoveTradePokemonShinyLocks,
  onUpdateTradePokemonFields,
  pokemonWorkflow,
  searchText,
  selectedTradeIndex,
  workflow
}: {
  editSession: EditSession | null;
  isEditStarting: boolean;
  isTradePokemonUpdating: boolean;
  onSearchChange: (searchText: string) => void;
  onSelectTrade: (tradeIndex: number | null) => void;
  onStartEditSession: () => void;
  onRemoveTradePokemonShinyLocks: (
    tradeIndexes: number[],
    resetValue: string
  ) => Promise<boolean>;
  onUpdateTradePokemonFields: (
    tradeIndex: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  pokemonWorkflow: PokemonWorkflow | null;
  searchText: string;
  selectedTradeIndex: number | null;
  workflow: TradePokemonWorkflow | null;
}) {
  const [isShinyLockConfirmationOpen, setIsShinyLockConfirmationOpen] = useState(false);
  const trades = workflow?.trades ?? [];
  const editorFamily: EditorUiFamily =
    workflow?.editorFamily === 'za' ? 'za' : workflow?.editorFamily === 'sv' ? 'sv' : 'swsh';
  const isZaTradeWorkflow = editorFamily === 'za';
  const filteredTrades = useMemo(
    () => filterTradePokemon(trades, searchText),
    [searchText, trades]
  );
  const selectedTrade = useMemo(
    () =>
      filteredTrades.find((trade) => trade.tradeIndex === selectedTradeIndex) ??
      filteredTrades[0] ??
      null,
    [filteredTrades, selectedTradeIndex]
  );
  const canEditTrades = workflow?.summary.availability === 'available';
  const pendingTradeIndexes = useMemo(
    () => getPendingTradePokemonIndexes(editSession),
    [editSession]
  );
  const shinyReset = useMemo(() => getTradePokemonShinyReset(workflow), [workflow]);
  const lockedTradeIndexes = useMemo(
    () =>
      trades
        .filter((trade) => trade.shinyLock !== shinyReset.value)
        .map((trade) => trade.tradeIndex),
    [shinyReset.value, trades]
  );
  const canRemoveTradeShinyLocks =
    canEditTrades &&
    editSession !== null &&
    !isTradePokemonUpdating &&
    lockedTradeIndexes.length > 0;
  const removeTradeShinyLockTitle =
    editSession === null
      ? 'Start editing before removing trade shiny locks.'
      : lockedTradeIndexes.length === 0
      ? 'No trade shiny locks are currently set.'
      : `Set every locked trade Pokemon shiny lock to ${shinyReset.label}.`;

  return (
    <>
      <section aria-labelledby="trade-pokemon-heading" className="panel wide-panel">
        <div className="panel-heading">
          <ArrowLeftRight aria-hidden="true" size={18} />
          <h2 id="trade-pokemon-heading">Trade Pokemon</h2>
        </div>

        <div className="items-toolbar trainers-toolbar shiny-lock-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label="Search trade Pokemon"
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder="Search trade Pokemon"
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label="Loaded trades"
            value={workflow ? workflow.stats.totalTradeCount.toString() : '0'}
          />
          <Metric
            label="Fixed IV rows"
            value={workflow ? workflow.stats.fixedIvTradeCount.toString() : '0'}
          />
          <Metric
            label="Sources"
            value={workflow ? workflow.stats.sourceFileCount.toString() : '0'}
          />
          <button
            className="primary-button compact-button"
            disabled={!canRemoveTradeShinyLocks}
            onClick={() => setIsShinyLockConfirmationOpen(true)}
            title={removeTradeShinyLockTitle}
            type="button"
          >
            <ShieldCheck aria-hidden="true" size={14} />
            <span>Remove Trade Shiny Lock</span>
          </button>
        </div>

        {workflow ? (
          <div className="trainers-layout">
            <div
              aria-colcount={7}
              aria-label="Trade Pokemon"
              aria-rowcount={filteredTrades.length + 1}
              className="trainers-table"
              role="table"
            >
              <div className="trainers-row trade-pokemon-row trainers-row-heading" role="row">
                <span role="columnheader">Index</span>
                <span role="columnheader">{isZaTradeWorkflow ? 'Request' : 'Requested'}</span>
                <span role="columnheader">Received</span>
                <span role="columnheader">Level</span>
                <span role="columnheader">IVs</span>
                <span role="columnheader">Moves</span>
                <span role="columnheader">Source</span>
              </div>
              <VirtualTableBody
                getKey={(trade) => trade.tradeIndex}
                items={filteredTrades}
                renderRow={(trade) => (
                  <button
                    className={`trainers-row trade-pokemon-row ${
                      selectedTrade?.tradeIndex === trade.tradeIndex
                        ? 'trainers-row-selected'
                        : ''
                    } ${
                      pendingTradeIndexes.has(trade.tradeIndex) ? 'trainers-row-pending' : ''
                    }`}
                    onClick={() => onSelectTrade(trade.tradeIndex)}
                    role="row"
                    type="button"
                  >
                    <span role="cell">{trade.tradeIndex + 1}</span>
                    <span role="cell">
                      {formatTradePokemonRequestLabel(trade, editorFamily)}
                    </span>
                    <span role="cell">
                      {formatSpeciesFormLabel(trade.species, trade.form, trade.speciesId, editorFamily)}
                    </span>
                    <span role="cell">{trade.level}</span>
                    <span role="cell">{trade.ivSummary}</span>
                    <span role="cell">{formatTradePokemonRelearnMoves(trade)}</span>
                    <span role="cell">{formatSourceLayer(trade.provenance.sourceLayer)}</span>
                  </button>
                )}
              />
            </div>

            <SelectedTradePokemonPanel
              canEditTrades={canEditTrades}
              editSession={editSession}
              editableFields={workflow.editableFields}
              editorFamily={editorFamily}
              isEditStarting={isEditStarting}
              isTradePokemonUpdating={isTradePokemonUpdating}
              isZaTradeWorkflow={isZaTradeWorkflow}
              onStartEditSession={onStartEditSession}
              onUpdateTradePokemonFields={onUpdateTradePokemonFields}
              pokemonWorkflow={pokemonWorkflow}
              trade={selectedTrade}
            />
          </div>
        ) : (
          <p className="empty-copy">Open Trade Pokemon from Workflows to load backend trade data.</p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
      {isShinyLockConfirmationOpen ? (
        <ShinyLockRemovalConfirmationModal
          affectedCount={lockedTradeIndexes.length}
          isApplying={isTradePokemonUpdating}
          label="Trade"
          recordLabel="trade Pokemon"
          recordLabelPlural="trade Pokemon"
          targetLabel={shinyReset.label}
          onCancel={() => setIsShinyLockConfirmationOpen(false)}
          onConfirm={async () => {
            const didSave = await onRemoveTradePokemonShinyLocks(
              lockedTradeIndexes,
              shinyReset.value.toString()
            );
            if (didSave) {
              setIsShinyLockConfirmationOpen(false);
            }
          }}
        />
      ) : null}
    </>
  );
}

function SelectedTradePokemonPanel({
  canEditTrades,
  editSession,
  editableFields,
  editorFamily,
  isEditStarting,
  isTradePokemonUpdating,
  isZaTradeWorkflow,
  onStartEditSession,
  onUpdateTradePokemonFields,
  pokemonWorkflow,
  trade
}: {
  canEditTrades: boolean;
  editSession: EditSession | null;
  editableFields: TradePokemonEditableField[];
  editorFamily: EditorUiFamily;
  isEditStarting: boolean;
  isTradePokemonUpdating: boolean;
  isZaTradeWorkflow: boolean;
  onStartEditSession: () => void;
  onUpdateTradePokemonFields: (
    tradeIndex: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  pokemonWorkflow: PokemonWorkflow | null;
  trade: TradePokemonRecord | null;
}) {
  const [tradeDraftsByIndex, setTradeDraftsByIndex] = useState<
    Record<string, Record<string, string>>
  >({});
  const cancelActiveEditSession = useCancelActiveEditSession();
  const tradeFields = useMemo(
    () =>
      editableFields
        .filter((field) =>
          tradePokemonFieldNames.includes(field.field as (typeof tradePokemonFieldNames)[number])
        )
        .map(withPokemonInstanceIvPresetOptions),
    [editableFields]
  );
  const defaultReceivedTradeContext = useMemo(
    () =>
      trade
        ? {
            abilityOptions: trade.abilityOptions,
            gameFamily: editorFamily,
            genderOptions: trade.genderOptions,
            species: trade.species,
            speciesId: trade.speciesId
          }
        : undefined,
    [editorFamily, trade]
  );
  const defaultRequestedTradeContext = useMemo(
    () =>
      trade
        ? {
            gameFamily: editorFamily,
            species: trade.requiredSpecies,
            speciesId: trade.requiredSpeciesId
          }
        : undefined,
    [editorFamily, trade]
  );
  const defaultContextualTradeFields = useMemo(
    () =>
      tradeFields.map((field) => {
        const options = getContextualFieldOptions(
          field,
          field.field === tradeRequiredFormFieldName
            ? defaultRequestedTradeContext
            : defaultReceivedTradeContext
        );
        return options === field.options ? field : { ...field, options };
      }),
    [defaultReceivedTradeContext, defaultRequestedTradeContext, tradeFields]
  );
  const tradeDraftDefaults = useMemo(
    () =>
      trade
        ? createPokemonInstanceDrafts(defaultContextualTradeFields, (field) =>
            getEditableTradePokemonFieldValue(trade, field)
          )
        : {},
    [defaultContextualTradeFields, trade]
  );
  const tradeDrafts = trade
    ? tradeDraftsByIndex[trade.tradeIndex.toString()] ?? tradeDraftDefaults
    : {};
  const receivedTradeFormOptionContext = useMemo(() => {
    if (!trade) {
      return undefined;
    }

    const context = createDraftSpeciesFormOptionContext(
      defaultContextualTradeFields.find((field) => field.field === giftSpeciesFieldName),
      tradeDrafts[giftSpeciesFieldName],
      trade.species,
      trade.speciesId,
      trade.abilityOptions,
      editorFamily,
      trade.genderOptions
    );
    const draftedForm = Number.parseInt(tradeDrafts[formFieldName] ?? trade.form.toString(), 10);
    const normalizedDraftedForm = Number.isInteger(draftedForm) ? draftedForm : trade.form;
    const usesCurrentIdentity =
      context.speciesId === trade.speciesId && normalizedDraftedForm === trade.form;
    const referencePokemon =
      editorFamily === 'swsh'
        ? pokemonWorkflow?.pokemon.find(
            (pokemon) =>
              pokemon.speciesId === context.speciesId && pokemon.form === normalizedDraftedForm
          )
        : undefined;
    const fallbackAbilityOptions =
      tradeFields.find((field) => field.field === abilityFieldName)?.options ?? [];
    const fallbackGenderOptions =
      tradeFields.find((field) => field.field === genderFieldName)?.options ?? [];

    return {
      ...context,
      abilityOptions: referencePokemon
        ? createTrainerPokemonAbilityOptions(referencePokemon)
        : usesCurrentIdentity
          ? trade.abilityOptions
          : fallbackAbilityOptions,
      genderOptions: referencePokemon
        ? createGiftPokemonGenderOptions(referencePokemon)
        : usesCurrentIdentity
          ? trade.genderOptions
          : fallbackGenderOptions
    };
  }, [
    defaultContextualTradeFields,
    editorFamily,
    pokemonWorkflow,
    trade,
    tradeDrafts,
    tradeFields
  ]);
  const requestedTradeFormOptionContext = useMemo(() => {
    if (!trade) {
      return undefined;
    }

    return createDraftSpeciesFormOptionContext(
      defaultContextualTradeFields.find(
        (field) => field.field === tradeRequiredSpeciesFieldName
      ),
      tradeDrafts[tradeRequiredSpeciesFieldName],
      trade.requiredSpecies,
      trade.requiredSpeciesId,
      undefined,
      editorFamily
    );
  }, [defaultContextualTradeFields, editorFamily, trade, tradeDrafts]);
  const contextualTradeFields = useMemo(
    () =>
      tradeFields.map((field) => {
        const options = getContextualFieldOptions(
          field,
          field.field === tradeRequiredFormFieldName
            ? requestedTradeFormOptionContext
            : receivedTradeFormOptionContext
        );
        return options === field.options ? field : { ...field, options };
      }),
    [receivedTradeFormOptionContext, requestedTradeFormOptionContext, tradeFields]
  );
  const tradeFieldGroups = useMemo(
    () => groupNumericEditableFields(contextualTradeFields, getPokemonInstanceFieldGroup),
    [contextualTradeFields]
  );
  const tradeDraftSummary = useMemo(
    () =>
      getTrainerDraftSummary(
        getActivePokemonInstanceFields(contextualTradeFields, tradeDrafts),
        tradeDrafts,
        trade ? (field) => getEditableTradePokemonFieldValue(trade, field) : null
      ),
    [contextualTradeFields, trade, tradeDrafts]
  );
  useRegisterEditorDraftDirty('tradePokemon', countFieldDraftRecords(tradeDraftsByIndex) > 0);
  const canSaveTradeDrafts =
    trade !== null &&
    editSession !== null &&
    canEditTrades &&
    !isTradePokemonUpdating &&
    tradeDraftSummary.changedFields.length > 0 &&
    tradeDraftSummary.invalidFields.length === 0;

  useEffect(() => {
    if (!trade) {
      return;
    }

    setTradeDraftsByIndex((currentDrafts) =>
      pruneFieldDraftRecord(currentDrafts, trade.tradeIndex, tradeDraftDefaults)
    );
  }, [trade, tradeDraftDefaults]);

  return (
    <aside aria-label="Selected trade Pokemon provenance" className="trainer-inspector">
      <div className="panel-heading">
        <ShieldCheck aria-hidden="true" size={18} />
        <h3>Selected Trade</h3>
      </div>

      {trade ? (
        <>
          <div className="pokemon-summary-grid">
            {!isZaTradeWorkflow ? (
              <PokemonSummaryCard
                name={formatTradePokemonRequestLabel(trade, editorFamily)}
                subtitle="Requested"
                title={formatTradePokemonRequestLabel(trade, editorFamily)}
              />
            ) : null}
            <PokemonSummaryCard
              name={formatSpeciesFormLabel(trade.species, trade.form, trade.speciesId, editorFamily)}
              subtitle={`Received | Lv. ${trade.level}`}
              title={formatSpeciesFormLabel(trade.species, trade.form, trade.speciesId, editorFamily)}
            />
          </div>

          <dl className="item-provenance-list">
            <div>
              <dt>Trade</dt>
              <dd>{trade.label}</dd>
            </div>
            <div>
              <dt>Data file</dt>
              <dd>{trade.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>Layer</dt>
              <dd>{formatSourceLayer(trade.provenance.sourceLayer)}</dd>
            </div>
            <div>
              <dt>File state</dt>
              <dd>{formatFileState(trade.provenance.fileState)}</dd>
            </div>
            <div>
              <dt>{isZaTradeWorkflow ? 'Request source' : 'Requested'}</dt>
              <dd>{formatTradePokemonRequestLabel(trade, editorFamily)}</dd>
            </div>
            <div>
              <dt>Received</dt>
              <dd>{`${formatSpeciesFormLabel(trade.species, trade.form, trade.speciesId, editorFamily)} Lv. ${trade.level}`}</dd>
            </div>
            <div>
              <dt>Ball</dt>
              <dd>{trade.ballItem}</dd>
            </div>
            <div>
              <dt>Held item</dt>
              <dd>{trade.heldItem ?? 'None'}</dd>
            </div>
            <div>
              <dt>{editorFamily === 'sv' || editorFamily === 'za' ? 'Moves' : 'Relearn moves'}</dt>
              <dd>{formatTradePokemonRelearnMoves(trade)}</dd>
            </div>
            {editorFamily === 'sv' || editorFamily === 'za' ? (
              <>
                <div>
                  <dt>Event label</dt>
                  <dd>{trade.eventLabel ?? 'None'}</dd>
                </div>
                {trade.teraTypeLabel !== null ? (
                  <div>
                    <dt>Tera type</dt>
                    <dd>{trade.teraTypeLabel}</dd>
                  </div>
                ) : null}
                {trade.scaleModeLabel !== null ? (
                  <div>
                    <dt>Scale</dt>
                    <dd>{formatTradePokemonScale(trade)}</dd>
                  </div>
                ) : null}
              </>
            ) : (
              <>
                <div>
                  <dt>Memory</dt>
                  <dd>{formatTradePokemonMemory(trade)}</dd>
                </div>
                <div>
                  <dt>Identifiers</dt>
                  <dd>{`${trade.hash0} / ${trade.hash1} / ${trade.hash2}`}</dd>
                </div>
              </>
            )}
            <div>
              <dt>IV detail</dt>
              <dd>{formatTradePokemonIvs(trade)}</dd>
            </div>
          </dl>

          <div className="trainer-edit-form">
            <div className="editable-field-groups">
              {tradeFieldGroups.map((group) => (
                <fieldset className="editable-field-group" key={group.group}>
                  <legend>{group.group}</legend>
                  <div className="editable-field-grid">
                    {group.fields.map((field) => {
                      const currentValue = getEditableTradePokemonFieldValue(trade, field.field);
                      const draftValue = tradeDrafts[field.field] ?? '';
                      const draftState = getTrainerFieldDraftState(
                        draftValue,
                        currentValue,
                        field,
                        {
                          drafts: tradeDrafts,
                          fields: contextualTradeFields,
                          getValue: (fieldName) =>
                            getEditableTradePokemonFieldValue(trade, fieldName)
                        }
                      );
                      const disabledReason =
                        getTradeFieldDisabledReason(field.field) ??
                          getPokemonInstanceIvStatDisabledReason(
                            field.field,
                            contextualTradeFields,
                            tradeDrafts
                          );

                      return (
                        <GiftPokemonDraftField
                          currentValue={currentValue}
                          disabled={
                            !canEditTrades ||
                            editSession === null ||
                            isTradePokemonUpdating ||
                            disabledReason !== null
                          }
                          disabledReason={disabledReason ?? undefined}
                          draftState={draftState}
                          draftValue={draftValue}
                          field={field}
                          formOptionContext={
                            field.field === tradeRequiredFormFieldName
                              ? requestedTradeFormOptionContext
                              : receivedTradeFormOptionContext
                          }
                          key={field.field}
                          onChange={(value) => {
                            const nextDrafts = {
                              ...tradeDrafts,
                              [field.field]: value
                            };
                            const speciesField = contextualTradeFields.find(
                              (candidate) => candidate.field === giftSpeciesFieldName
                            );
                            const formField = contextualTradeFields.find(
                              (candidate) => candidate.field === formFieldName
                            );
                            const requestedSpeciesField = contextualTradeFields.find(
                              (candidate) => candidate.field === tradeRequiredSpeciesFieldName
                            );
                            const requestedFormField = contextualTradeFields.find(
                              (candidate) => candidate.field === tradeRequiredFormFieldName
                            );
                            const previousSpeciesId =
                              parseEditableIntegerDraft(
                                tradeDrafts[giftSpeciesFieldName] ?? trade.speciesId.toString(),
                                speciesField?.options
                              ) ?? trade.speciesId;
                            const previousForm =
                              parseEditableIntegerDraft(
                                tradeDrafts[formFieldName] ?? trade.form.toString(),
                                formField?.options
                              ) ?? trade.form;
                            let nextSpeciesId = previousSpeciesId;
                            let nextForm = previousForm;
                            let identityChanged = false;

                            if (field.field === giftSpeciesFieldName) {
                              const parsedSpeciesId = parseEditableIntegerDraft(
                                value,
                                field.options
                              );
                              if (
                                parsedSpeciesId !== null &&
                                parsedSpeciesId !== previousSpeciesId
                              ) {
                                nextSpeciesId = parsedSpeciesId;
                                nextForm = 0;
                                identityChanged = true;
                                if (formField) {
                                  nextDrafts[formFieldName] = '0';
                                }
                              }
                            } else if (field.field === formFieldName) {
                              const parsedForm = parseEditableIntegerDraft(value, field.options);
                              if (parsedForm !== null && parsedForm !== previousForm) {
                                nextForm = parsedForm;
                                identityChanged = true;
                              }
                            } else if (field.field === tradeRequiredSpeciesFieldName) {
                              const previousRequestedSpeciesId =
                                parseEditableIntegerDraft(
                                  tradeDrafts[tradeRequiredSpeciesFieldName] ??
                                    trade.requiredSpeciesId.toString(),
                                  requestedSpeciesField?.options
                                ) ?? trade.requiredSpeciesId;
                              const parsedRequestedSpeciesId = parseEditableIntegerDraft(
                                value,
                                field.options
                              );
                              if (
                                parsedRequestedSpeciesId !== null &&
                                parsedRequestedSpeciesId !== previousRequestedSpeciesId &&
                                requestedFormField
                              ) {
                                nextDrafts[tradeRequiredFormFieldName] = '0';
                              }
                            }

                            if (identityChanged) {
                              if (editorFamily === 'swsh') {
                                const referencePokemon = pokemonWorkflow?.pokemon.find(
                                  (pokemon) =>
                                    pokemon.speciesId === nextSpeciesId &&
                                    pokemon.form === nextForm
                                );
                                if (referencePokemon) {
                                  preserveValidGiftDependencyOrReset(
                                    nextDrafts,
                                    contextualTradeFields,
                                    abilityFieldName,
                                    trade.ability,
                                    createTrainerPokemonAbilityOptions(referencePokemon)
                                  );
                                  preserveValidGiftDependencyOrReset(
                                    nextDrafts,
                                    contextualTradeFields,
                                    genderFieldName,
                                    trade.gender,
                                    createGiftPokemonGenderOptions(referencePokemon)
                                  );
                                }
                              } else {
                                const abilityField = contextualTradeFields.find(
                                  (candidate) => candidate.field === abilityFieldName
                                );
                                if (abilityField?.options.some((option) => option.value === 0)) {
                                  nextDrafts[abilityFieldName] = '0';
                                }
                              }
                            }
                            setTradeDraftsByIndex((currentDrafts) =>
                              setFieldDraftRecord(
                                currentDrafts,
                                trade.tradeIndex,
                                nextDrafts,
                                tradeDraftDefaults
                              )
                            );
                          }}
                        />
                      );
                    })}
                  </div>
                </fieldset>
              ))}
            </div>
            {editSession ? (
              <div className="draft-action-row">
                <button
                  aria-busy={isTradePokemonUpdating || undefined}
                  className="primary-button"
                  disabled={!canSaveTradeDrafts}
                  onClick={async () => {
                    const didSave = await onUpdateTradePokemonFields(
                      trade.tradeIndex,
                      tradeDraftSummary.changedFields.map((change) => ({
                        field: change.field,
                        value: change.value
                      }))
                    );
                    if (didSave) {
                      setTradeDraftsByIndex((currentDrafts) =>
                        deleteFieldDraftRecord(currentDrafts, trade.tradeIndex)
                      );
                    }
                  }}
                  type="button"
                >
                  <BusyActionContent
                    busyLabel="Staging"
                    icon={<Save aria-hidden="true" size={16} />}
                    isBusy={isTradePokemonUpdating}
                    label="Stage"
                  />
                </button>
                <button
                  className="danger-button"
                  disabled={isTradePokemonUpdating}
                  onClick={() => cancelActiveEditSession(() => setTradeDraftsByIndex({}))}
                  type="button"
                >
                  <X aria-hidden="true" size={16} />
                  <span>Cancel</span>
                </button>
                <span className="draft-action-summary">{formatDraftSummary(tradeDraftSummary)}</span>
              </div>
            ) : null}

            {!editSession ? (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditTrades || isEditStarting}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            ) : null}
          </div>
        </>
      ) : (
        <p className="empty-copy">No trade selected.</p>
      )}
    </aside>
  );
}

function RentalPokemonSection({
  editSession,
  isEditStarting,
  isRentalPokemonUpdating,
  onSearchChange,
  onSelectRental,
  onStartEditSession,
  onUpdateRentalPokemonFields,
  pokemonWorkflow,
  searchText,
  selectedRentalIndex,
  workflow
}: {
  editSession: EditSession | null;
  isEditStarting: boolean;
  isRentalPokemonUpdating: boolean;
  onSearchChange: (searchText: string) => void;
  onSelectRental: (rentalIndex: number | null) => void;
  onStartEditSession: () => void;
  onUpdateRentalPokemonFields: (
    rentalIndex: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  pokemonWorkflow: PokemonWorkflow | null;
  searchText: string;
  selectedRentalIndex: number | null;
  workflow: RentalPokemonWorkflow | null;
}) {
  const rentals = workflow?.rentals ?? [];
  const filteredRentals = useMemo(
    () => filterRentalPokemon(rentals, searchText),
    [rentals, searchText]
  );
  const selectedRental = useMemo(
    () =>
      filteredRentals.find((rental) => rental.rentalIndex === selectedRentalIndex) ??
      filteredRentals[0] ??
      null,
    [filteredRentals, selectedRentalIndex]
  );
  const canEditRentals = workflow?.summary.availability === 'available';
  const pendingRentalIndexes = useMemo(
    () => getPendingRentalPokemonIndexes(editSession),
    [editSession]
  );

  return (
    <>
      <section aria-labelledby="rental-pokemon-heading" className="panel wide-panel">
        <div className="panel-heading">
          <Dna aria-hidden="true" size={18} />
          <h2 id="rental-pokemon-heading">Rental Pokemon</h2>
        </div>

        <div className="items-toolbar trainers-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label="Search rental Pokemon"
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder="Search rental Pokemon"
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label="Loaded rentals"
            value={workflow ? workflow.stats.totalRentalCount.toString() : '0'}
          />
          <Metric
            label="Perfect IV rows"
            value={workflow ? workflow.stats.perfectIvRentalCount.toString() : '0'}
          />
          <Metric
            label="Sources"
            value={workflow ? workflow.stats.sourceFileCount.toString() : '0'}
          />
        </div>

        {workflow ? (
          <div className="trainers-layout">
            <div
              aria-colcount={7}
              aria-label="Rental Pokemon"
              aria-rowcount={filteredRentals.length + 1}
              className="trainers-table"
              role="table"
            >
              <div className="trainers-row rental-pokemon-row trainers-row-heading" role="row">
                <span role="columnheader">Index</span>
                <span role="columnheader">Pokemon</span>
                <span role="columnheader">Level</span>
                <span role="columnheader">IVs</span>
                <span role="columnheader">EVs</span>
                <span role="columnheader">Moves</span>
                <span role="columnheader">Source</span>
              </div>
              <VirtualTableBody
                getKey={(rental) => rental.rentalIndex}
                items={filteredRentals}
                renderRow={(rental) => (
                  <button
                    className={`trainers-row rental-pokemon-row ${
                      selectedRental?.rentalIndex === rental.rentalIndex
                        ? 'trainers-row-selected'
                        : ''
                    } ${
                      pendingRentalIndexes.has(rental.rentalIndex) ? 'trainers-row-pending' : ''
                    }`}
                    onClick={() => onSelectRental(rental.rentalIndex)}
                    role="row"
                    type="button"
                  >
                    <span role="cell">{rental.rentalIndex + 1}</span>
                    <span role="cell">
                      {formatSpeciesFormLabel(rental.species, rental.form, rental.speciesId)}
                    </span>
                    <span role="cell">{rental.level}</span>
                    <span role="cell">{rental.ivSummary}</span>
                    <span role="cell">{formatRentalPokemonStats(rental.evs)}</span>
                    <span role="cell">{formatRentalPokemonMoves(rental)}</span>
                    <span role="cell">{formatSourceLayer(rental.provenance.sourceLayer)}</span>
                  </button>
                )}
              />
            </div>

            <SelectedRentalPokemonPanel
              canEditRentals={canEditRentals}
              editSession={editSession}
              editableFields={workflow.editableFields}
              isEditStarting={isEditStarting}
              isRentalPokemonUpdating={isRentalPokemonUpdating}
              onStartEditSession={onStartEditSession}
              onUpdateRentalPokemonFields={onUpdateRentalPokemonFields}
              pokemonWorkflow={pokemonWorkflow}
              rental={selectedRental}
            />
          </div>
        ) : (
          <p className="empty-copy">Open Rental Pokemon from Workflows to load backend rental data.</p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
    </>
  );
}

function SelectedRentalPokemonPanel({
  canEditRentals,
  editSession,
  editableFields,
  isEditStarting,
  isRentalPokemonUpdating,
  onStartEditSession,
  onUpdateRentalPokemonFields,
  pokemonWorkflow,
  rental
}: {
  canEditRentals: boolean;
  editSession: EditSession | null;
  editableFields: RentalPokemonEditableField[];
  isEditStarting: boolean;
  isRentalPokemonUpdating: boolean;
  onStartEditSession: () => void;
  onUpdateRentalPokemonFields: (
    rentalIndex: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  pokemonWorkflow: PokemonWorkflow | null;
  rental: RentalPokemonRecord | null;
}) {
  const [rentalDraftsByIndex, setRentalDraftsByIndex] = useState<
    Record<string, Record<string, string>>
  >({});
  const cancelActiveEditSession = useCancelActiveEditSession();
  const rentalFields = useMemo(
    () =>
      editableFields
        .filter((field) =>
          rentalPokemonFieldNames.includes(field.field as (typeof rentalPokemonFieldNames)[number])
        )
        .map(withPokemonInstanceIvPresetOptions),
    [editableFields]
  );
  const defaultRentalFormOptionContext = useMemo(
    () =>
      rental
        ? {
            abilityOptions: rental.abilityOptions,
            gameFamily: 'swsh' as const,
            genderOptions: rental.genderOptions,
            species: rental.species,
            speciesId: rental.speciesId
          }
        : undefined,
    [rental]
  );
  const defaultContextualRentalFields = useMemo(
    () =>
      rentalFields.map((field) => {
        const options = getContextualFieldOptions(field, defaultRentalFormOptionContext);
        return options === field.options ? field : { ...field, options };
      }),
    [defaultRentalFormOptionContext, rentalFields]
  );
  const rentalDraftDefaults = useMemo(
    () =>
      rental
        ? createPokemonInstanceDrafts(defaultContextualRentalFields, (field) =>
            getEditableRentalPokemonFieldValue(rental, field)
          )
        : {},
    [defaultContextualRentalFields, rental]
  );
  const rentalDrafts = rental
    ? rentalDraftsByIndex[rental.rentalIndex.toString()] ?? rentalDraftDefaults
    : {};
  const rentalFormOptionContext = useMemo(() => {
    if (!rental) {
      return undefined;
    }

    const context = createDraftSpeciesFormOptionContext(
      defaultContextualRentalFields.find((field) => field.field === giftSpeciesFieldName),
      rentalDrafts[giftSpeciesFieldName],
      rental.species,
      rental.speciesId,
      rental.abilityOptions,
      'swsh',
      rental.genderOptions
    );
    const draftedForm = Number.parseInt(rentalDrafts[formFieldName] ?? rental.form.toString(), 10);
    const normalizedDraftedForm = Number.isInteger(draftedForm) ? draftedForm : rental.form;
    const usesCurrentIdentity =
      context.speciesId === rental.speciesId && normalizedDraftedForm === rental.form;
    const referencePokemon = pokemonWorkflow?.pokemon.find(
      (pokemon) =>
        pokemon.speciesId === context.speciesId && pokemon.form === normalizedDraftedForm
    );
    const fallbackAbilityOptions =
      rentalFields.find((field) => field.field === abilityFieldName)?.options ?? [];
    const fallbackGenderOptions =
      rentalFields.find((field) => field.field === genderFieldName)?.options ?? [];

    return {
      ...context,
      abilityOptions: referencePokemon
        ? createRentalPokemonAbilityOptions(referencePokemon)
        : usesCurrentIdentity
          ? rental.abilityOptions
          : fallbackAbilityOptions,
      genderOptions: referencePokemon
        ? createGiftPokemonGenderOptions(referencePokemon)
        : usesCurrentIdentity
          ? rental.genderOptions
          : fallbackGenderOptions
    };
  }, [defaultContextualRentalFields, pokemonWorkflow, rental, rentalDrafts, rentalFields]);
  const contextualRentalFields = useMemo(
    () =>
      rentalFields.map((field) => {
        const options = getContextualFieldOptions(field, rentalFormOptionContext);
        return options === field.options ? field : { ...field, options };
      }),
    [rentalFields, rentalFormOptionContext]
  );
  const rentalFieldGroups = useMemo(
    () => groupNumericEditableFields(contextualRentalFields, getPokemonInstanceFieldGroup),
    [contextualRentalFields]
  );
  const rentalDraftSummary = useMemo(
    () =>
      getRentalPokemonDraftSummary(
        rental,
        getActivePokemonInstanceFields(contextualRentalFields, rentalDrafts),
        rentalDrafts
      ),
    [contextualRentalFields, rental, rentalDrafts]
  );
  useRegisterEditorDraftDirty('rentalPokemon', countFieldDraftRecords(rentalDraftsByIndex) > 0);
  const canSaveRentalDrafts =
    rental !== null &&
    editSession !== null &&
    canEditRentals &&
    !isRentalPokemonUpdating &&
    rentalDraftSummary.changedFields.length > 0 &&
    rentalDraftSummary.invalidFields.length === 0;

  useEffect(() => {
    if (!rental) {
      return;
    }

    setRentalDraftsByIndex((currentDrafts) =>
      pruneFieldDraftRecord(currentDrafts, rental.rentalIndex, rentalDraftDefaults)
    );
  }, [rental, rentalDraftDefaults]);

  return (
    <aside aria-label="Selected rental Pokemon provenance" className="trainer-inspector">
      <div className="panel-heading">
        <ShieldCheck aria-hidden="true" size={18} />
        <h3>Selected Rental</h3>
      </div>

      {rental ? (
        <>
          <PokemonSummaryCard
            name={formatSpeciesFormLabel(rental.species, rental.form, rental.speciesId)}
            subtitle={`Rental #${rental.rentalIndex + 1} | Lv. ${rental.level}`}
            title={formatSpeciesFormLabel(rental.species, rental.form, rental.speciesId)}
          />

          <dl className="item-provenance-list">
            <div>
              <dt>Rental</dt>
              <dd>{rental.label}</dd>
            </div>
            <div>
              <dt>Data file</dt>
              <dd>{rental.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>Layer</dt>
              <dd>{formatSourceLayer(rental.provenance.sourceLayer)}</dd>
            </div>
            <div>
              <dt>File state</dt>
              <dd>{formatFileState(rental.provenance.fileState)}</dd>
            </div>
            <div>
              <dt>Pokemon</dt>
              <dd>{`${formatSpeciesFormLabel(rental.species, rental.form, rental.speciesId)} Lv. ${rental.level}`}</dd>
            </div>
            <div>
              <dt>Ball</dt>
              <dd>{rental.ballItem}</dd>
            </div>
            <div>
              <dt>Held item</dt>
              <dd>{rental.heldItem ?? 'None'}</dd>
            </div>
            <div>
              <dt>Ability</dt>
              <dd>{rental.abilityLabel}</dd>
            </div>
            <div>
              <dt>Nature / Gender</dt>
              <dd>{`${rental.natureLabel} / ${rental.genderLabel}`}</dd>
            </div>
            <div>
              <dt>Trainer ID</dt>
              <dd>{rental.trainerId}</dd>
            </div>
            <div>
              <dt>Identifiers</dt>
              <dd>{`${rental.hash1} / ${rental.hash2}`}</dd>
            </div>
            <div>
              <dt>Moves</dt>
              <dd>{formatRentalPokemonMoves(rental)}</dd>
            </div>
            <div>
              <dt>EV detail</dt>
              <dd>{formatRentalPokemonStats(rental.evs)}</dd>
            </div>
            <div>
              <dt>IV detail</dt>
              <dd>{formatRentalPokemonIvs(rental)}</dd>
            </div>
          </dl>

          <div className="trainer-edit-form">
            <div className="editable-field-groups">
              {rentalFieldGroups.map((group) => (
                <fieldset className="editable-field-group" key={group.group}>
                  <legend>{group.group}</legend>
                  <div className="editable-field-grid">
                    {group.fields.map((field) => {
                      const currentValue = getEditableRentalPokemonFieldValue(
                        rental,
                        field.field
                      );
                      const draftValue = rentalDrafts[field.field] ?? '';
                      const draftState = getRentalPokemonFieldDraftState(
                        rental,
                        draftValue,
                        currentValue,
                        field,
                        contextualRentalFields,
                        rentalDrafts
                      );

                      return (
                        <GiftPokemonDraftField
                          currentValue={currentValue}
                          disabled={
                            !canEditRentals || editSession === null || isRentalPokemonUpdating
                          }
                          disabledReason={
                            getPokemonInstanceIvStatDisabledReason(
                              field.field,
                              contextualRentalFields,
                              rentalDrafts
                            ) ?? undefined
                          }
                          draftState={draftState}
                          draftValue={draftValue}
                          field={field}
                          formOptionContext={rentalFormOptionContext}
                          key={field.field}
                          onChange={(value) => {
                            const nextDrafts = {
                              ...rentalDrafts,
                              [field.field]: value
                            };
                            const speciesField = contextualRentalFields.find(
                              (candidate) => candidate.field === giftSpeciesFieldName
                            );
                            const formField = contextualRentalFields.find(
                              (candidate) => candidate.field === formFieldName
                            );
                            const previousSpeciesId =
                              parseEditableIntegerDraft(
                                rentalDrafts[giftSpeciesFieldName] ??
                                  rental.speciesId.toString(),
                                speciesField?.options
                              ) ?? rental.speciesId;
                            const previousForm =
                              parseEditableIntegerDraft(
                                rentalDrafts[formFieldName] ?? rental.form.toString(),
                                formField?.options
                              ) ?? rental.form;
                            let nextSpeciesId = previousSpeciesId;
                            let nextForm = previousForm;
                            let identityChanged = false;

                            if (field.field === giftSpeciesFieldName) {
                              const parsedSpeciesId = parseEditableIntegerDraft(
                                value,
                                field.options
                              );
                              if (
                                parsedSpeciesId !== null &&
                                parsedSpeciesId !== previousSpeciesId
                              ) {
                                nextSpeciesId = parsedSpeciesId;
                                nextForm = 0;
                                identityChanged = true;
                                if (formField) {
                                  nextDrafts[formFieldName] = '0';
                                }
                              }
                            } else if (field.field === formFieldName) {
                              const parsedForm = parseEditableIntegerDraft(value, field.options);
                              if (parsedForm !== null && parsedForm !== previousForm) {
                                nextForm = parsedForm;
                                identityChanged = true;
                              }
                            }

                            if (identityChanged) {
                              const referencePokemon = pokemonWorkflow?.pokemon.find(
                                (pokemon) =>
                                  pokemon.speciesId === nextSpeciesId &&
                                  pokemon.form === nextForm
                              );
                              if (referencePokemon) {
                                preserveValidGiftDependencyOrReset(
                                  nextDrafts,
                                  contextualRentalFields,
                                  abilityFieldName,
                                  rental.ability,
                                  createRentalPokemonAbilityOptions(referencePokemon)
                                );
                                preserveValidGiftDependencyOrReset(
                                  nextDrafts,
                                  contextualRentalFields,
                                  genderFieldName,
                                  rental.gender,
                                  createGiftPokemonGenderOptions(referencePokemon)
                                );
                              }
                            }
                            setRentalDraftsByIndex((currentDrafts) =>
                              setFieldDraftRecord(
                                currentDrafts,
                                rental.rentalIndex,
                                nextDrafts,
                                rentalDraftDefaults
                              )
                            );
                          }}
                        />
                      );
                    })}
                  </div>
                </fieldset>
              ))}
            </div>
            {editSession ? (
              <div className="draft-action-row">
                <button
                  aria-busy={isRentalPokemonUpdating || undefined}
                  className="primary-button"
                  disabled={!canSaveRentalDrafts}
                  onClick={async () => {
                    const didSave = await onUpdateRentalPokemonFields(
                      rental.rentalIndex,
                      rentalDraftSummary.changedFields.map((change) => ({
                        field: change.field,
                        value: change.value
                      }))
                    );
                    if (didSave) {
                      setRentalDraftsByIndex((currentDrafts) =>
                        deleteFieldDraftRecord(currentDrafts, rental.rentalIndex)
                      );
                    }
                  }}
                  type="button"
                >
                  <BusyActionContent
                    busyLabel="Staging"
                    icon={<Save aria-hidden="true" size={16} />}
                    isBusy={isRentalPokemonUpdating}
                    label="Stage"
                  />
                </button>
                <button
                  className="danger-button"
                  disabled={isRentalPokemonUpdating}
                  onClick={() => cancelActiveEditSession(() => setRentalDraftsByIndex({}))}
                  type="button"
                >
                  <X aria-hidden="true" size={16} />
                  <span>Cancel</span>
                </button>
                <span className="draft-action-summary">
                  {formatDraftSummary(rentalDraftSummary)}
                </span>
              </div>
            ) : null}

            {!editSession ? (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditRentals || isEditStarting}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            ) : null}
          </div>
        </>
      ) : (
        <p className="empty-copy">No rental selected.</p>
      )}
    </aside>
  );
}

function DynamaxAdventuresSection({
  actionDiagnostics,
  applyResult,
  changePlan,
  editSession,
  isChangePlanApplying,
  isChangePlanCreating,
  isDynamaxAdventureUpdating,
  onApplyChangePlan,
  onCancelDynamaxAdventurePreview,
  onCreateChangePlan,
  onPreviewDynamaxAdventureDefaults,
  onSearchChange,
  onSelectAdventure,
  onStageRepair,
  onStageTableRestore,
  onUpdateDynamaxAdventureEntryChanges,
  onUpdateDynamaxAdventureFields,
  searchText,
  selectedEntryIndex,
  workflow
}: {
  actionDiagnostics: ApiDiagnostic[];
  applyResult: ApplyResult | null;
  changePlan: ChangePlan | null;
  editSession: EditSession | null;
  isChangePlanApplying: boolean;
  isChangePlanCreating: boolean;
  isDynamaxAdventureUpdating: boolean;
  onApplyChangePlan: () => void;
  onCancelDynamaxAdventurePreview: () => void;
  onCreateChangePlan: () => void;
  onPreviewDynamaxAdventureDefaults: (entryIndex: number, species: number, form: number, level: number) => Promise<PreviewDynamaxAdventureDefaultsResponse | null>;
  onSearchChange: (searchText: string) => void;
  onSelectAdventure: (entryIndex: number | null) => void;
  onStageRepair: () => Promise<boolean>;
  onStageTableRestore: () => Promise<boolean>;
  onUpdateDynamaxAdventureEntryChanges: (groups: DynamaxAdventureEntryChangeGroup[]) => Promise<boolean>;
  onUpdateDynamaxAdventureFields: (entryIndex: number, changes: Array<{ field: DynamaxAdventureEditableFieldName; value: string }>) => Promise<boolean>;
  searchText: string;
  selectedEntryIndex: number | null;
  workflow: DynamaxAdventuresWorkflow | null;
}) {
  const { translateLiteral } = useLocalization();
  const encounters = workflow?.encounters ?? [];
  const editableEncounters = useMemo(() => encounters.filter((encounter) => encounter.isEditable), [encounters]);
  const pendingEntryIndexes = useMemo(
    () => getPendingDynamaxAdventureIndexes(editSession),
    [editSession]
  );
  const filteredEncounters = useMemo(
    () => {
      const matches = filterDynamaxAdventures(encounters, searchText);
      const pinnedPendingEncounters = encounters.filter((encounter) =>
        pendingEntryIndexes.has(encounter.entryIndex)
      );
      return [
        ...pinnedPendingEncounters,
        ...matches.filter((encounter) => !pendingEntryIndexes.has(encounter.entryIndex))
      ];
    },
    [encounters, pendingEntryIndexes, searchText]
  );
  const selectedEncounter = useMemo(
    () =>
      encounters.find((encounter) => encounter.entryIndex === selectedEntryIndex) ??
      filteredEncounters[0] ??
      null,
    [encounters, filteredEncounters, selectedEntryIndex]
  );
  const canUseDynamaxAdventuresWorkflow =
    workflow?.summary.availability === 'available' &&
    !workflow.usesVanillaRecoveryProjection;
  const canEditDynamaxAdventures =
    canUseDynamaxAdventuresWorkflow && !workflow?.hasLegacyBossTargetPatch;
  const dynamaxAdventureEditDisabledReason = workflow?.hasLegacyBossTargetPatch
    ? 'Stage Repair or a full vanilla table restore must remove the unsupported legacy final-boss target remap before this field can be edited.'
    : undefined;
  const combinedDiagnostics = [
    ...(workflow?.diagnostics ?? []),
    ...actionDiagnostics,
    ...(changePlan?.diagnostics ?? []),
    ...(applyResult?.diagnostics ?? [])
  ];

  return (
    <>
      <section aria-labelledby="dynamax-adventures-heading" className="panel wide-panel">
        <div className="panel-heading">
          <ShieldCheck aria-hidden="true" size={18} />
          <h2 id="dynamax-adventures-heading">Dynamax Adventures</h2>
        </div>

        <div className="items-toolbar trainers-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label="Search Dynamax Adventures"
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder="Search Dynamax Adventures"
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label="Editable rows"
            value={workflow ? editableEncounters.length.toString() : '0'}
          />
          <Metric
            label="Source files"
            value={workflow ? workflow.stats.sourceFileCount.toString() : '0'}
          />
          <Metric
            label="Guaranteed IV rows"
            value={
              workflow ? workflow.stats.guaranteedPerfectIvEncounterCount.toString() : '0'
            }
          />
        </div>

        {workflow ? (
          <>
            <div
              className="dynamax-adventure-integrity-notice dynamax-adventure-install-status"
              role="note"
            >
              <ShieldCheck aria-hidden="true" size={16} />
              <div className="dynamax-adventure-install-status-content">
                <dl className="item-provenance-list dynamax-adventure-status-summary">
                  <div>
                    <dt>Install status</dt>
                    <dd>{humanizePendingEditKey(workflow.installStatus)}</dd>
                  </div>
                  <div>
                    <dt>Detected game</dt>
                    <dd>
                      {workflow.detectedGame
                        ? gameDefinitions[workflow.detectedGame].label
                        : 'Unknown'}
                    </dd>
                  </div>
                  <div>
                    <dt>Reserved regions</dt>
                    <dd data-localization-ignore="true">
                      {workflow.reservedRegions.length}
                    </dd>
                  </div>
                </dl>
                <p data-localization-ignore="true">{workflow.installMessage}</p>
                {workflow.canRestoreVanillaTable ? (
                  <div className="dynamax-adventure-table-restore">
                    <p data-localization-ignore="true">
                      {workflow.restoreVanillaTableMessage}
                    </p>
                    <p>
                      {translateLiteral(
                        'Restoring the vanilla table removes all layered Dynamax Adventures table changes.'
                      )}
                    </p>
                    <div className="draft-action-row">
                      <button
                        aria-busy={isDynamaxAdventureUpdating || undefined}
                        className="danger-button"
                        disabled={
                          isDynamaxAdventureUpdating ||
                          isChangePlanCreating ||
                          isChangePlanApplying ||
                          editSession?.hasPendingChanges === true ||
                          (editSession?.pendingEdits.length ?? 0) > 0
                        }
                        onClick={() => void onStageTableRestore()}
                        type="button"
                      >
                        <BusyActionContent
                          busyLabel="Staging"
                          icon={<RotateCcw aria-hidden="true" size={16} />}
                          isBusy={isDynamaxAdventureUpdating}
                          label="Stage Table Restore"
                        />
                      </button>
                    </div>
                  </div>
                ) : null}
                {workflow.installStatus === 'repairable' &&
                canUseDynamaxAdventuresWorkflow &&
                !workflow.canRestoreVanillaTable &&
                !workflow.usesVanillaRecoveryProjection ? (
                  <button
                    aria-busy={isDynamaxAdventureUpdating || undefined}
                    className="secondary-button"
                    disabled={
                      isDynamaxAdventureUpdating ||
                      isChangePlanCreating ||
                      isChangePlanApplying ||
                      editSession?.hasPendingChanges === true ||
                      (editSession?.pendingEdits.length ?? 0) > 0
                    }
                    onClick={() => void onStageRepair()}
                    type="button"
                  >
                    <BusyActionContent
                      busyLabel="Staging"
                      icon={<Wrench aria-hidden="true" size={16} />}
                      isBusy={isDynamaxAdventureUpdating}
                      label="Stage Repair"
                    />
                  </button>
                ) : null}
                <details className="dynamax-adventure-technical-details">
                  <summary>{translateLiteral('Technical details')}</summary>
                  <dl className="item-provenance-list dynamax-adventure-build-details">
                    <div>
                      <dt>Build ID</dt>
                      <dd data-localization-ignore="true">{workflow.buildId}</dd>
                    </div>
                  </dl>
                  {workflow.reservedRegions.length > 0 ? (
                    <ul className="dynamax-adventure-region-list">
                      {workflow.reservedRegions.map((region) => (
                        <li key={`${region.area}:${region.offset}`}>
                          <span data-localization-ignore="true">{region.label}</span>{' '}
                          <code data-localization-ignore="true">
                            {region.area} {region.offset}
                          </code>
                        </li>
                      ))}
                    </ul>
                  ) : null}
                </details>
              </div>
            </div>
            {workflow.hasLegacyBossTargetPatch ? (
              <div className="dynamax-adventure-recovery-projection" role="note">
                <AlertTriangle aria-hidden="true" size={16} />
                <p>
                  {translateLiteral(
                    'Unsupported legacy final-boss target remap detected. Ordinary row editing and default previews are disabled. Stage Repair or a full vanilla table restore removes it.'
                  )}
                </p>
              </div>
            ) : null}
            {workflow.usesVanillaRecoveryProjection ? (
              <div className="dynamax-adventure-recovery-projection" role="note">
                <RotateCcw aria-hidden="true" size={16} />
                <p>
                  {translateLiteral(
                    'Recovery view: the rows below show verified vanilla target values. Current layered values that require recovery are hidden and cannot be edited.'
                  )}
                </p>
              </div>
            ) : null}
            <div className="trainers-layout dynamax-adventures-layout">
            <div
              aria-colcount={6}
              aria-label="Dynamax Adventure encounters"
              aria-rowcount={filteredEncounters.length + 1}
              className="trainers-table dynamax-adventures-table"
              role="table"
            >
              <div className="trainers-row dynamax-adventures-row trainers-row-heading" role="row">
                <span role="columnheader">Index</span>
                <span role="columnheader">Pokemon</span>
                <span role="columnheader">Level</span>
                <span role="columnheader">IVs</span>
                <span role="columnheader">Moves</span>
                <span role="columnheader">Source</span>
              </div>
              <VirtualTableBody
                getKey={(encounter) => encounter.entryIndex}
                items={filteredEncounters}
                renderRow={(encounter) => (
                  <button
                    className={`trainers-row dynamax-adventures-row ${
                      selectedEncounter?.entryIndex === encounter.entryIndex
                        ? 'trainers-row-selected'
                        : ''
                    } ${
                      pendingEntryIndexes.has(encounter.entryIndex)
                        ? 'trainers-row-pending'
                        : ''
                    } ${
                      encounter.isEditable ? '' : 'trainers-row-read-only'
                    }`}
                    onClick={() => onSelectAdventure(encounter.entryIndex)}
                    role="row"
                    type="button"
                  >
                    <span data-localization-ignore="true" role="cell">
                      {encounter.entryIndex}
                    </span>
                    <span data-localization-ignore="true" role="cell">
                      {formatSpeciesFormLabel(
                        encounter.species,
                        encounter.form,
                        encounter.speciesId
                      )}
                    </span>
                    <span data-localization-ignore="true" role="cell">{encounter.level}</span>
                    <span data-localization-ignore="true" role="cell">{encounter.ivSummary}</span>
                    <span data-localization-ignore="true" role="cell">
                      {formatDynamaxAdventureMoves(encounter)}
                    </span>
                    <span role="cell">
                      {formatSourceLayer(encounter.provenance.sourceLayer)}
                    </span>
                  </button>
                )}
              />
            </div>

            <SelectedDynamaxAdventurePanel
              canEditDynamaxAdventures={canEditDynamaxAdventures}
              changePlan={changePlan}
              editDisabledReason={dynamaxAdventureEditDisabledReason}
              editSession={editSession}
              editableFields={workflow.editableFields}
              encounter={selectedEncounter}
              isChangePlanApplying={isChangePlanApplying}
              isChangePlanCreating={isChangePlanCreating}
              isDynamaxAdventureUpdating={isDynamaxAdventureUpdating}
              onApplyChangePlan={onApplyChangePlan}
              onCancelDynamaxAdventurePreview={onCancelDynamaxAdventurePreview}
              onCreateChangePlan={onCreateChangePlan}
              onPreviewDynamaxAdventureDefaults={onPreviewDynamaxAdventureDefaults}
              onUpdateDynamaxAdventureEntryChanges={onUpdateDynamaxAdventureEntryChanges}
              onUpdateDynamaxAdventureFields={onUpdateDynamaxAdventureFields}
              safeNormalSpeciesOptions={workflow.safeNormalSpeciesOptions}
            />
            </div>
          </>
        ) : (
          <p className="empty-copy">
            Open Dynamax Adventures from Advanced Editors to load backend encounter data.
          </p>
        )}
      </section>

      {changePlan ? <ChangePlanSection changePlan={changePlan} /> : null}
      {applyResult ? <ApplyResultSection applyResult={applyResult} /> : null}
      <DiagnosticsSection diagnostics={combinedDiagnostics} />
    </>
  );
}

function SelectedDynamaxAdventurePanel({
  canEditDynamaxAdventures,
  changePlan,
  editDisabledReason,
  editSession,
  editableFields,
  encounter,
  isChangePlanApplying,
  isChangePlanCreating,
  isDynamaxAdventureUpdating,
  onApplyChangePlan,
  onCancelDynamaxAdventurePreview,
  onCreateChangePlan,
  onPreviewDynamaxAdventureDefaults,
  onUpdateDynamaxAdventureEntryChanges,
  onUpdateDynamaxAdventureFields,
  safeNormalSpeciesOptions
}: {
  canEditDynamaxAdventures: boolean;
  changePlan: ChangePlan | null;
  editDisabledReason?: string;
  editSession: EditSession | null;
  editableFields: DynamaxAdventureEditableField[];
  encounter: DynamaxAdventureRecord | null;
  isChangePlanApplying: boolean;
  isChangePlanCreating: boolean;
  isDynamaxAdventureUpdating: boolean;
  onApplyChangePlan: () => void;
  onCancelDynamaxAdventurePreview: () => void;
  onCreateChangePlan: () => void;
  onPreviewDynamaxAdventureDefaults: (entryIndex: number, species: number, form: number, level: number) => Promise<PreviewDynamaxAdventureDefaultsResponse | null>;
  onUpdateDynamaxAdventureEntryChanges: (groups: DynamaxAdventureEntryChangeGroup[]) => Promise<boolean>;
  onUpdateDynamaxAdventureFields: (entryIndex: number, changes: Array<{ field: DynamaxAdventureEditableFieldName; value: string }>) => Promise<boolean>;
  safeNormalSpeciesOptions: EditableFieldOption[];
}) {
  const { translateLiteral } = useLocalization();
  const [draftsByEntryIndex, setDraftsByEntryIndex] = useState<
    Record<string, Record<string, string>>
  >({});
  const [draftFieldOptionsByEntryIndex, setDraftFieldOptionsByEntryIndex] = useState<
    Record<string, DynamaxAdventureDraftFieldOptions>
  >({});
  const previewRunRef = useRef(0);
  const previewRequestKeyRef = useRef<string | null>(null);
  const encounterDraftKey = encounter?.entryIndex.toString() ?? null;
  const adventureFieldOptions =
    encounter && encounterDraftKey
      ? draftFieldOptionsByEntryIndex[encounterDraftKey] ?? {}
      : {};
  const adventureAbilityOptions = adventureFieldOptions[abilityFieldName] ?? encounter?.abilityOptions ?? [];
  const adventureFields = useMemo(
    () =>
      editableFields
        .filter((field) =>
          dynamaxAdventureFieldNames.includes(
            field.field as (typeof dynamaxAdventureFieldNames)[number]
          )
        )
        .map((field) => withDynamaxAdventureSpeciesOptions(withPokemonInstanceIvPresetOptions(field), encounter, safeNormalSpeciesOptions, adventureFieldOptions)),
    [editableFields, encounter, safeNormalSpeciesOptions, adventureFieldOptions]
  );
  const adventureFieldGroups = useMemo(
    () => groupNumericEditableFields(adventureFields, getPokemonInstanceFieldGroup),
    [adventureFields]
  );
  const adventureDraftDefaults = useMemo(
    () =>
      encounter
        ? createPokemonInstanceDrafts(adventureFields, (field) =>
            getEditableDynamaxAdventureFieldValue(encounter, field)
          )
        : {},
    [adventureFields, encounter]
  );
  const drafts = encounter
    ? draftsByEntryIndex[encounter.entryIndex.toString()] ?? adventureDraftDefaults
    : {};
  const adventureDraftSummary = useMemo(
    () =>
      getTrainerDraftSummary(
        getActivePokemonInstanceFields(adventureFields, drafts),
        drafts,
        encounter ? (field) => getEditableDynamaxAdventureFieldValue(encounter, field) : null,
        { clampIvStats: isPokemonInstanceIvCustomSelected(adventureFields, drafts) }
      ),
    [adventureFields, drafts, encounter]
  );
  useRegisterEditorDraftDirty(
    'dynamaxAdventures',
    countFieldDraftRecords(draftsByEntryIndex) > 0
  );
  const canEditSelectedAdventure =
    canEditDynamaxAdventures && encounter?.isEditable === true;
  const pendingOwnerEntryIndex = useMemo(
    () => getPendingDynamaxAdventureOwner(editSession),
    [editSession]
  );
  const hasPendingSessionChanges = (editSession?.pendingEdits.length ?? 0) > 0;
  const hasPendingTableRestore =
    editSession?.pendingEdits.some(
      (edit) =>
        edit.domain === 'workflow.dynamaxAdventures' &&
        edit.summary === 'Restore the vanilla Dynamax Adventures table.'
    ) ?? false;
  const ownsSolePendingAdventure =
    encounter !== null && pendingOwnerEntryIndex === encounter.entryIndex;
  const hasPendingDifferentAdventure =
    hasPendingSessionChanges && !ownsSolePendingAdventure;
  const canSaveAdventureDrafts =
    encounter !== null &&
    canEditSelectedAdventure &&
    !hasPendingDifferentAdventure &&
    !isDynamaxAdventureUpdating &&
    !isChangePlanCreating &&
    !isChangePlanApplying &&
    adventureDraftSummary.changedFields.length > 0 &&
    adventureDraftSummary.invalidFields.length === 0;
  const hasPendingDynamaxAdventureChange =
    editSession?.pendingEdits.some((edit) => edit.domain === 'workflow.dynamaxAdventures') ??
    false;
  const canReviewPlan =
    hasPendingDynamaxAdventureChange &&
    ownsSolePendingAdventure &&
    !isDynamaxAdventureUpdating &&
    !isChangePlanCreating &&
    !isChangePlanApplying;
  const canApplyPlan =
    hasPendingDynamaxAdventureChange &&
    ownsSolePendingAdventure &&
    changePlan !== null &&
    changePlan.canApply &&
    changePlan.writes.length > 0 &&
    !isDynamaxAdventureUpdating &&
    !isChangePlanApplying;
  const vanillaRestoreChanges = useMemo(
    () => (encounter ? getDynamaxAdventureVanillaRestoreChanges(encounter) : []),
    [encounter]
  );
  const canRestoreVanilla =
    canEditSelectedAdventure &&
    !hasPendingDifferentAdventure &&
    !isDynamaxAdventureUpdating &&
    !isChangePlanCreating &&
    !isChangePlanApplying &&
    vanillaRestoreChanges.length > 0;

  useEffect(() => {
    if (!encounter) {
      return;
    }

    setDraftsByEntryIndex((currentDrafts) =>
      pruneFieldDraftRecord(currentDrafts, encounter.entryIndex, adventureDraftDefaults)
    );
  }, [adventureDraftDefaults, encounter]);

  useEffect(() => {
    previewRunRef.current += 1;
    previewRequestKeyRef.current = null;
    if (encounter) {
      setDraftFieldOptionsByEntryIndex((currentOptions) =>
        deleteFieldDraftRecord(currentOptions, encounter.entryIndex)
      );
    }
  }, [encounter]);

  const requestAdventureDefaultsPreview = (
    nextDrafts: Record<string, string>,
    species: number,
    form: number,
    level: number
  ) => {
    if (!encounter || !canEditSelectedAdventure) {
      return;
    }

    const previewRun = previewRunRef.current + 1;
    previewRunRef.current = previewRun;
    const previewRequestKey = `${encounter.entryIndex}:${species}:${form}:${level}`;
    previewRequestKeyRef.current = previewRequestKey;
    const previewDrafts = { ...nextDrafts };
    for (const dependentFieldName of dynamaxAdventurePreviewDependentFieldNames) {
      previewDrafts[dependentFieldName] = '';
    }

    setDraftFieldOptionsByEntryIndex((currentOptions) =>
      deleteFieldDraftRecord(currentOptions, encounter.entryIndex)
    );
    setDraftsByEntryIndex((currentDrafts) =>
      setFieldDraftRecord(
        currentDrafts,
        encounter.entryIndex,
        previewDrafts,
        adventureDraftDefaults
      )
    );

    void onPreviewDynamaxAdventureDefaults(encounter.entryIndex, species, form, level).then(
      (response) => {
        if (
          previewRunRef.current !== previewRun ||
          previewRequestKeyRef.current !== previewRequestKey
        ) {
          return;
        }

        previewRequestKeyRef.current = null;
        if (
          !response ||
          response.diagnostics.some((diagnostic) => diagnostic.severity === 'error')
        ) {
          return;
        }

        setDraftFieldOptionsByEntryIndex((currentOptions) => ({
          ...currentOptions,
          [encounter.entryIndex.toString()]: {
            [abilityFieldName]: response.abilityOptions,
            [dynamaxAdventureGigantamaxStateFieldName]: response.gigantamaxOptions,
            [staticEncounterMoveFieldNames[0]]: response.moveOptions,
            [staticEncounterMoveFieldNames[1]]: response.moveOptions,
            [staticEncounterMoveFieldNames[2]]: response.moveOptions,
            [staticEncounterMoveFieldNames[3]]: response.moveOptions
          }
        }));
        setDraftsByEntryIndex((currentDrafts) => {
          const currentEncounterDrafts =
            currentDrafts[encounter.entryIndex.toString()] ?? adventureDraftDefaults;
          const speciesField = adventureFields.find(
            (candidate) => candidate.field === giftSpeciesFieldName
          );
          const levelField = adventureFields.find(
            (candidate) => candidate.field === levelFieldName
          );
          const currentSpecies = parseEditableIntegerDraft(
            currentEncounterDrafts[giftSpeciesFieldName] ?? '',
            speciesField?.options
          );
          const currentLevel = parseEditableIntegerDraft(
            currentEncounterDrafts[levelFieldName] ?? '',
            levelField?.options
          );
          if (currentSpecies !== species || currentLevel !== level) {
            return currentDrafts;
          }

          const resolvedDrafts = { ...currentEncounterDrafts };
          for (const change of response.changes) {
            resolvedDrafts[change.field] = change.value;
          }

          return setFieldDraftRecord(
            currentDrafts,
            encounter.entryIndex,
            resolvedDrafts,
            adventureDraftDefaults
          );
        });
      }
    );
  };

  const parsePreviewDriverValue = (
    value: string,
    driverField: NumericEditableField | undefined,
    requireListedOption: boolean
  ) => {
    const parsedValue = parseEditableIntegerDraft(value, driverField?.options);
    if (
      parsedValue === null ||
      (driverField?.minimumValue !== null &&
        driverField?.minimumValue !== undefined &&
        parsedValue < driverField.minimumValue) ||
      (driverField?.maximumValue !== null &&
        driverField?.maximumValue !== undefined &&
        parsedValue > driverField.maximumValue) ||
      (requireListedOption &&
        !driverField?.options.some((option) => option.value === parsedValue))
    ) {
      return null;
    }

    return parsedValue;
  };

  const handleAdventureDraftChange = (field: NumericEditableField, value: string) => {
    if (!encounter) {
      return;
    }

    const currentDraftValue =
      drafts[field.field] ?? adventureDraftDefaults[field.field] ?? '';
    const parsedCurrentValue = parseEditableIntegerDraft(currentDraftValue, field.options);
    const parsedNextValue = parseEditableIntegerDraft(value, field.options);
    const isRepeatedNormalizedValue =
      parsedCurrentValue !== null && parsedNextValue !== null
        ? parsedCurrentValue === parsedNextValue
        : currentDraftValue.trim() === value.trim();
    const isSpeciesDriver = field.field === giftSpeciesFieldName;
    const isLevelDriver = field.field === levelFieldName;
    const speciesField = adventureFields.find(
      (candidate) => candidate.field === giftSpeciesFieldName
    );
    const levelField = adventureFields.find(
      (candidate) => candidate.field === levelFieldName
    );
    const formField = adventureFields.find(
      (candidate) => candidate.field === formFieldName
    );
    const parsedSpecies = isSpeciesDriver
      ? parsePreviewDriverValue(value, speciesField, true)
      : parsePreviewDriverValue(
          drafts[giftSpeciesFieldName] ?? encounter.speciesId.toString(),
          speciesField,
          true
        );
    const parsedLevel = isLevelDriver
      ? parsePreviewDriverValue(value, levelField, false)
      : parsePreviewDriverValue(
          drafts[levelFieldName] ?? encounter.level.toString(),
          levelField,
          false
        );
    const draftedForm = parseEditableIntegerDraft(
      drafts[formFieldName] ?? encounter.form.toString(),
      formField?.options
    );
    const previewForm =
      parsedSpecies === encounter.speciesId
        ? (draftedForm ?? encounter.form)
        : parsedSpecies === encounter.vanillaPokemon?.speciesId
          ? encounter.vanillaPokemon.form
          : 0;
    const previewRequestKey =
      parsedSpecies !== null && parsedLevel !== null
        ? `${encounter.entryIndex}:${parsedSpecies}:${previewForm}:${parsedLevel}`
        : null;
    const hasMissingPreviewDependencies =
      dynamaxAdventurePreviewDependentFieldNames.some(
        (fieldName) => (drafts[fieldName] ?? '').trim().length === 0
      );
    const shouldRetryRepeatedDriver =
      isRepeatedNormalizedValue &&
      (isSpeciesDriver || isLevelDriver) &&
      hasMissingPreviewDependencies &&
      previewRequestKey !== null &&
      previewRequestKeyRef.current !== previewRequestKey;
    if (isRepeatedNormalizedValue && !shouldRetryRepeatedDriver) {
      return;
    }

    onCancelDynamaxAdventurePreview();
    const nextDrafts = { ...drafts, [field.field]: value };

    if (isSpeciesDriver || isLevelDriver) {
      if (parsedSpecies !== null && parsedLevel !== null) {
        requestAdventureDefaultsPreview(
          nextDrafts,
          parsedSpecies,
          previewForm,
          parsedLevel
        );
        return;
      }

      previewRunRef.current += 1;
      previewRequestKeyRef.current = null;
      const unresolvedDrafts = { ...nextDrafts };
      for (const dependentFieldName of dynamaxAdventurePreviewDependentFieldNames) {
        unresolvedDrafts[dependentFieldName] = '';
      }
      setDraftFieldOptionsByEntryIndex((currentOptions) =>
        deleteFieldDraftRecord(currentOptions, encounter.entryIndex)
      );
      setDraftsByEntryIndex((currentDrafts) =>
        setFieldDraftRecord(
          currentDrafts,
          encounter.entryIndex,
          unresolvedDrafts,
          adventureDraftDefaults
        )
      );
      return;
    }

    previewRunRef.current += 1;
    previewRequestKeyRef.current = null;
    setDraftsByEntryIndex((currentDrafts) =>
      setFieldDraftRecord(
        currentDrafts,
        encounter.entryIndex,
        nextDrafts,
        adventureDraftDefaults
      )
    );
  };

  return (
    <>
      <aside
        aria-label="Selected Dynamax Adventure provenance"
        className="trainer-inspector dynamax-adventure-summary"
      >
        <div className="panel-heading">
          <ShieldCheck aria-hidden="true" size={18} />
          <h3 id="selected-dynamax-adventure-heading">Selected Adventure</h3>
        </div>

        {encounter ? (
          <>
            <div
              className="dynamax-adventure-selection-summary"
              data-localization-ignore="true"
            >
              <PokemonSummaryCard
                editorFamily="swsh"
                form={encounter.form}
                name={formatSpeciesFormLabel(
                  encounter.species,
                  encounter.form,
                  encounter.speciesId
                )}
                speciesId={encounter.speciesId}
                subtitle={`Adventure #${encounter.adventureIndex} | Lv. ${encounter.level}`}
                title={formatSpeciesFormLabel(
                  encounter.species,
                  encounter.form,
                  encounter.speciesId
                )}
              />
            </div>

            <dl className="item-provenance-list dynamax-adventure-provenance">
              <div>
                <dt>Encounter</dt>
                <dd data-localization-ignore="true">{encounter.label}</dd>
              </div>
              <div>
                <dt>Index</dt>
                <dd data-localization-ignore="true">{encounter.entryIndex}</dd>
              </div>
              <div>
                <dt>Adventure</dt>
                <dd data-localization-ignore="true">{encounter.adventureIndex}</dd>
              </div>
              <div>
                <dt>Data file</dt>
                <dd data-localization-ignore="true">{encounter.provenance.sourceFile}</dd>
              </div>
              <div>
                <dt>Layer</dt>
                <dd>{formatSourceLayer(encounter.provenance.sourceLayer)}</dd>
              </div>
              <div>
                <dt>File state</dt>
                <dd>{formatFileState(encounter.provenance.fileState)}</dd>
              </div>
              <div>
                <dt>Pokemon</dt>
                <dd data-localization-ignore="true">{`${formatSpeciesFormLabel(encounter.species, encounter.form, encounter.speciesId)} Lv. ${encounter.level}`}</dd>
              </div>
              <div>
                <dt>Ability</dt>
                <dd data-localization-ignore="true">{encounter.abilityLabel}</dd>
              </div>
              <div>
                <dt>Gigantamax</dt>
                <dd>{encounter.gigantamaxLabel}</dd>
              </div>
              <div>
                <dt>Moves</dt>
                <dd data-localization-ignore="true">
                  {formatDynamaxAdventureMoves(encounter)}
                </dd>
              </div>
              <div>
                <dt>IV detail</dt>
                <dd data-localization-ignore="true">
                  {formatDynamaxAdventureIvs(encounter)}
                </dd>
              </div>
              <div>
                <dt>Ball item</dt>
                <dd data-localization-ignore="true">{encounter.ballItem}</dd>
              </div>
              <div>
                <dt>Game version</dt>
                <dd>{encounter.versionLabel}</dd>
              </div>
              <div>
                <dt>Shiny roll</dt>
                <dd>{encounter.shinyRollLabel}</dd>
              </div>
              <div>
                <dt>OT gender</dt>
                <dd>{encounter.otGenderLabel}</dd>
              </div>
              <div>
                <dt>Single-capture Pokemon</dt>
                <dd>{encounter.isSingleCapture ? 'Yes' : 'No'}</dd>
              </div>
              <div>
                <dt>Requires story progress</dt>
                <dd>{encounter.isStoryProgressGated ? 'Yes' : 'No'}</dd>
              </div>
            </dl>
          </>
        ) : (
          <p className="empty-copy">No Adventure encounter selected.</p>
        )}
      </aside>

      {encounter ? (
        <section
          aria-labelledby="selected-dynamax-adventure-heading"
          className="trainer-inspector dynamax-adventure-editor"
        >
          <div className="trainer-edit-form dynamax-adventure-edit-form">
            {!encounter.isEditable ? (
              <span className="status-pill">Read-only</span>
            ) : null}
            {hasPendingSessionChanges ? (
              <p
                aria-live="polite"
                className="dynamax-adventure-pending-owner"
                role="status"
              >
                {hasPendingTableRestore ? (
                  <>
                    {translateLiteral('Full vanilla-table restore is pending.')}{' '}
                    {translateLiteral(
                      'Restoring the vanilla table removes all layered Dynamax Adventures table changes.'
                    )}
                    {!ownsSolePendingAdventure ? (
                      <>
                        {' '}
                        {translateLiteral(
                          'Select the highlighted marker owner to review or apply.'
                        )}
                      </>
                    ) : null}
                  </>
                ) : pendingOwnerEntryIndex !== null ? (
                  <>
                    {translateLiteral('Pending changes belong to Adventure index')}{' '}
                    <span data-localization-ignore="true">{pendingOwnerEntryIndex}</span>.
                    {!ownsSolePendingAdventure ? (
                      <> {translateLiteral('Select that row to review or apply.')}</>
                    ) : null}
                  </>
                ) : (
                  translateLiteral(
                    'Pending Dynamax Adventure changes do not have one safe row owner. Review and apply are disabled.'
                  )
                )}
              </p>
            ) : null}
            <div className="dynamax-adventure-integrity-notice" role="note">
              <AlertTriangle aria-hidden="true" size={16} />
              <div>
                {hasPendingTableRestore ? (
                  <p>
                    This recovery action restores the entire verified vanilla Adventure table. Review the output plan before applying it.
                  </p>
                ) : (
                  <>
                    <p>Stage and apply one Pokemon at a time. This keeps the Dynamax Adventures table aligned with the selected row, preserves table integrity, and helps prevent save freezes or returns to lobby.</p>
                    <p>Ability choices may be limited by the selected row's table layout. Missing slots are hidden when they cannot be written safely, even if that Pokemon can normally have the ability.</p>
                  </>
                )}
              </div>
            </div>
            <div className="editable-field-groups dynamax-adventure-field-groups">
              {adventureFieldGroups.map((group) => (
                <fieldset
                  className="editable-field-group dynamax-adventure-field-group"
                  data-field-group={group.group}
                  key={group.group}
                >
                  <legend>{group.group}</legend>
                  <div className="editable-field-grid">
                    {group.fields.map((field) => {
                      const currentValue = getEditableDynamaxAdventureFieldValue(
                        encounter,
                        field.field
                      );
                      const disabledReason =
                        editDisabledReason ??
                        getPokemonInstanceIvStatDisabledReason(
                          field.field,
                          adventureFields,
                          drafts
                        ) ??
                        getDynamaxAdventureFieldDisabledReason(field, encounter) ??
                        undefined;
                      const draftValue = drafts[field.field] ?? '';
                      const draftState = getTrainerFieldDraftState(
                        draftValue,
                        currentValue,
                        field,
                        {
                          clampIvStats: isPokemonInstanceIvCustomSelected(
                            adventureFields,
                            drafts
                          ),
                          drafts,
                          fields: adventureFields,
                          getValue: (fieldName) =>
                            getEditableDynamaxAdventureFieldValue(encounter, fieldName)
                        }
                      );
                      const draftedSpeciesId =
                        parseEditableIntegerDraft(
                          drafts[giftSpeciesFieldName] ?? encounter.speciesId.toString(),
                          adventureFields.find(
                            (candidate) => candidate.field === giftSpeciesFieldName
                          )?.options
                        ) ?? encounter.speciesId;

                      return (
                        <GiftPokemonDraftField
                          currentValue={currentValue}
                          disabled={
                            !canEditSelectedAdventure ||
                            isDynamaxAdventureUpdating
                          }
                          disabledReason={disabledReason}
                          draftState={draftState}
                          draftValue={draftValue}
                          field={field}
                          formOptionContext={{
                            abilityOptions: adventureAbilityOptions,
                            gameFamily: 'swsh',
                            species: encounter.species,
                            speciesId: draftedSpeciesId
                          }}
                          key={field.field}
                          onChange={(value) => handleAdventureDraftChange(field, value)}
                        />
                      );
                    })}
                  </div>
                </fieldset>
              ))}
            </div>
            <div className="draft-action-row">
              <button
                aria-busy={isDynamaxAdventureUpdating || undefined}
                className="primary-button"
                disabled={!canSaveAdventureDrafts}
                onClick={async () => {
                  const didSave = await onUpdateDynamaxAdventureFields(
                    encounter.entryIndex,
                    adventureDraftSummary.changedFields.map((change) => ({
                      field: change.field as DynamaxAdventureEditableFieldName,
                      value: change.value
                    }))
                  );
                  if (didSave) {
                    setDraftsByEntryIndex((currentDrafts) =>
                      deleteFieldDraftRecord(currentDrafts, encounter.entryIndex)
                    );
                    setDraftFieldOptionsByEntryIndex((currentOptions) =>
                      deleteFieldDraftRecord(currentOptions, encounter.entryIndex)
                    );
                  }
                }}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Staging"
                  icon={<Wrench aria-hidden="true" size={16} />}
                  isBusy={isDynamaxAdventureUpdating}
                  label="Stage Changes"
                />
              </button>
              <button
                aria-busy={isDynamaxAdventureUpdating || undefined}
                className="secondary-button"
                disabled={
                  !canEditSelectedAdventure ||
                  hasPendingDifferentAdventure ||
                  isDynamaxAdventureUpdating ||
                  isChangePlanCreating ||
                  isChangePlanApplying ||
                  (!canRestoreVanilla &&
                    adventureDraftSummary.changedFields.length === 0 &&
                    adventureDraftSummary.invalidFields.length === 0)
                }
                onClick={async () => {
                  if (vanillaRestoreChanges.length === 0) {
                    setDraftsByEntryIndex((currentDrafts) =>
                      deleteFieldDraftRecord(currentDrafts, encounter.entryIndex)
                    );
                    setDraftFieldOptionsByEntryIndex((currentOptions) =>
                      deleteFieldDraftRecord(currentOptions, encounter.entryIndex)
                    );
                    return;
                  }

                  const didSave = await onUpdateDynamaxAdventureEntryChanges([
                    { entryIndex: encounter.entryIndex, changes: vanillaRestoreChanges }
                  ]);
                  if (didSave) {
                    setDraftsByEntryIndex((currentDrafts) =>
                      deleteFieldDraftRecord(currentDrafts, encounter.entryIndex)
                    );
                    setDraftFieldOptionsByEntryIndex((currentOptions) =>
                      deleteFieldDraftRecord(currentOptions, encounter.entryIndex)
                    );
                  }
                }}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Staging"
                  icon={<RotateCcw aria-hidden="true" size={16} />}
                  isBusy={isDynamaxAdventureUpdating}
                  label="Stage Restore"
                />
              </button>
              <button
                aria-busy={isChangePlanCreating || undefined}
                className="secondary-button"
                disabled={!canReviewPlan}
                onClick={onCreateChangePlan}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Reviewing"
                  icon={<ClipboardCheck aria-hidden="true" size={16} />}
                  isBusy={isChangePlanCreating}
                  label="Review"
                />
              </button>
              <button
                aria-busy={isChangePlanApplying || undefined}
                className="primary-button"
                disabled={!canApplyPlan}
                onClick={onApplyChangePlan}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Applying"
                  icon={<Save aria-hidden="true" size={16} />}
                  isBusy={isChangePlanApplying}
                  label="Apply"
                />
              </button>
              <span className="draft-action-summary">
                {formatDraftSummary(adventureDraftSummary)}
              </span>
            </div>
          </div>
        </section>
      ) : null}
    </>
  );
}

function StaticEncountersSection({
  editSession,
  isEditStarting,
  isStaticEncounterUpdating,
  onSearchChange,
  onSelectEncounter,
  onStartEditSession,
  onRemoveStaticEncounterShinyLocks,
  onUpdateStaticEncounterFields,
  searchText,
  selectedEncounterIndex,
  workflow
}: {
  editSession: EditSession | null;
  isEditStarting: boolean;
  isStaticEncounterUpdating: boolean;
  onSearchChange: (searchText: string) => void;
  onSelectEncounter: (encounterIndex: number | null) => void;
  onStartEditSession: () => void;
  onRemoveStaticEncounterShinyLocks: (
    encounters: Array<{ encounterId: string; encounterIndex: number }>,
    value: string
  ) => Promise<boolean>;
  onUpdateStaticEncounterFields: (
    encounterIndex: number,
    encounterId: string,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  searchText: string;
  selectedEncounterIndex: number | null;
  workflow: StaticEncountersWorkflow | null;
}) {
  const { translateLiteral } = useLocalization();
  const [isShinyLockConfirmationOpen, setIsShinyLockConfirmationOpen] = useState(false);
  const encounters = workflow?.encounters ?? [];
  const editorFamily = workflow?.editorFamily ?? 'swsh';
  const isSvStaticEncounters = editorFamily === 'sv';
  const isZaStaticEncounters = editorFamily === 'za';
  const filteredEncounters = useMemo(
    () => filterStaticEncounters(encounters, searchText),
    [encounters, searchText]
  );
  const selectedEncounter = useMemo(
    () =>
      filteredEncounters.find(
        (encounter) => encounter.encounterIndex === selectedEncounterIndex
      ) ??
      filteredEncounters[0] ??
      null,
    [filteredEncounters, selectedEncounterIndex]
  );
  const canEditStaticEncounters = workflow?.summary.availability === 'available';
  const pendingEncounterIndexes = useMemo(
    () => getPendingStaticEncounterIndexes(editSession),
    [editSession]
  );
  const shinyReset = useMemo(
    () => getStaticEncounterShinyReset(workflow),
    [workflow]
  );
  const shinyField = workflow?.editableFields.find(
    (field) => field.field === giftShinyLockFieldName
  );
  const lockedEncounters = useMemo(
    () =>
      encounters
        .filter(
          (encounter) =>
            shinyField !== undefined &&
            isStaticEncounterFieldVisible(shinyField, encounter) &&
            !shinyField.isReadOnly &&
            encounter.fieldReadOnly[giftShinyLockFieldName] !== true &&
            encounter.shinyLock !== shinyReset.value
        )
        .map((encounter) => ({
          encounterId: encounter.encounterId,
          encounterIndex: encounter.encounterIndex
        })),
    [encounters, shinyField, shinyReset.value]
  );
  const canRemoveStaticShinyLocks =
    canEditStaticEncounters &&
    editSession !== null &&
    !isStaticEncounterUpdating &&
    lockedEncounters.length > 0;
  const removeStaticShinyLockTitle =
    editSession === null
      ? 'Start editing before removing static shiny locks.'
      : lockedEncounters.length === 0
      ? 'No static shiny locks are currently set.'
      : `Set every locked static encounter shiny setting to ${shinyReset.label}.`;

  return (
    <>
      <section
        aria-labelledby="static-encounters-heading"
        className={`panel wide-panel static-encounters-section ${editorFamily}-static-encounters-section`}
      >
        <div className="panel-heading">
          <MapPin aria-hidden="true" size={18} />
          <h2 id="static-encounters-heading">{translateLiteral('Static Encounters')}</h2>
        </div>

        <div className="items-toolbar trainers-toolbar shiny-lock-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label={translateLiteral('Search static encounters')}
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder={translateLiteral('Search static encounters')}
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label={translateLiteral('Loaded encounters')}
            value={workflow ? workflow.stats.totalEncounterCount.toString() : '0'}
          />
          {isSvStaticEncounters ? (
            <>
              <Metric
                label={translateLiteral('Fixed Symbols')}
                value={workflow ? workflow.stats.fixedSymbolCount.toString() : '0'}
              />
              <Metric
                label={translateLiteral('Coin Symbols')}
                value={workflow ? workflow.stats.coinSymbolCount.toString() : '0'}
              />
              <Metric
                label={translateLiteral('Sources')}
                value={workflow ? workflow.stats.sourceFileCount.toString() : '0'}
              />
            </>
          ) : (
            <>
              <Metric
                label={translateLiteral('Gigantamax')}
                value={workflow ? (workflow.stats.gigantamaxEncounterCount ?? 0).toString() : '0'}
              />
              <Metric
                label={translateLiteral('Custom IV rows')}
                value={workflow ? workflow.stats.fixedIvEncounterCount.toString() : '0'}
              />
            </>
          )}
          <button
            className="primary-button compact-button"
            disabled={!canRemoveStaticShinyLocks}
            onClick={() => setIsShinyLockConfirmationOpen(true)}
            title={translateLiteral(removeStaticShinyLockTitle)}
            type="button"
          >
            <ShieldCheck aria-hidden="true" size={14} />
            <span>{translateLiteral('Remove Static Shiny Lock')}</span>
          </button>
        </div>

        {workflow ? (
          <div className="trainers-layout">
            <div
              aria-colcount={isZaStaticEncounters ? 4 : 6}
              aria-label={translateLiteral('Static Encounters')}
              aria-rowcount={filteredEncounters.length + 1}
              className="trainers-table"
              role="table"
            >
              <div className="trainers-row static-encounters-row trainers-row-heading" role="row">
                <span role="columnheader">{translateLiteral('Index')}</span>
                <span role="columnheader">{translateLiteral('Species')}</span>
                <span role="columnheader">{translateLiteral('Level')}</span>
                <span role="columnheader">
                  {translateLiteral(isSvStaticEncounters ? 'Category' : 'Scenario')}
                </span>
                {isZaStaticEncounters ? null : (
                  <>
                    <span role="columnheader">{translateLiteral('IVs')}</span>
                    <span role="columnheader">{translateLiteral('Source')}</span>
                  </>
                )}
              </div>
              <VirtualTableBody
                getKey={(encounter) => encounter.encounterIndex}
                items={filteredEncounters}
                renderRow={(encounter) => {
                  const speciesLabel = formatSpeciesFormLabel(
                    encounter.species,
                    encounter.form,
                    encounter.speciesId,
                    encounter.editorFamily
                  );
                  const scenarioLabel = isSvStaticEncounters
                    ? encounter.categoryLabel ?? encounter.encounterScenarioLabel
                    : encounter.encounterScenarioLabel;

                  return (
                    <button
                      className={`trainers-row static-encounters-row ${
                        selectedEncounter?.encounterIndex === encounter.encounterIndex
                          ? 'trainers-row-selected'
                          : ''
                      } ${
                        pendingEncounterIndexes.has(encounter.encounterIndex)
                          ? 'trainers-row-pending'
                          : ''
                      }`}
                      onClick={() => onSelectEncounter(encounter.encounterIndex)}
                      role="row"
                      type="button"
                    >
                      <span role="cell">{getStaticEncounterDisplayIndex(encounter)}</span>
                      <span role="cell" title={speciesLabel}>
                        {speciesLabel}
                      </span>
                      <span role="cell">{encounter.level}</span>
                      <span role="cell" title={scenarioLabel}>
                        {scenarioLabel}
                      </span>
                      {isZaStaticEncounters ? null : (
                        <>
                          <span role="cell" title={encounter.ivSummary}>
                            {encounter.ivSummary}
                          </span>
                          <span role="cell">
                            {formatSourceLayer(encounter.provenance.sourceLayer)}
                          </span>
                        </>
                      )}
                    </button>
                  );
                }}
              />
            </div>

            <SelectedStaticEncounterPanel
              canEditStaticEncounters={canEditStaticEncounters}
              editSession={editSession}
              editableFields={workflow.editableFields}
              encounter={selectedEncounter}
              isEditStarting={isEditStarting}
              isStaticEncounterUpdating={isStaticEncounterUpdating}
              onStartEditSession={onStartEditSession}
              onUpdateStaticEncounterFields={onUpdateStaticEncounterFields}
            />
          </div>
        ) : (
          <p className="empty-copy">
            {translateLiteral('Open Static Encounters from Workflows to load backend encounter data.')}
          </p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
      {isShinyLockConfirmationOpen ? (
        <ShinyLockRemovalConfirmationModal
          affectedCount={lockedEncounters.length}
          isApplying={isStaticEncounterUpdating}
          label="Static"
          recordLabel="static encounter"
          recordLabelPlural="static encounters"
          targetLabel={shinyReset.label}
          onCancel={() => setIsShinyLockConfirmationOpen(false)}
          onConfirm={async () => {
            const didSave = await onRemoveStaticEncounterShinyLocks(
              lockedEncounters,
              shinyReset.value.toString()
            );
            if (didSave) {
              setIsShinyLockConfirmationOpen(false);
            }
          }}
        />
      ) : null}
    </>
  );
}

function SelectedStaticEncounterPanel({
  canEditStaticEncounters,
  editSession,
  editableFields,
  encounter,
  isEditStarting,
  isStaticEncounterUpdating,
  onStartEditSession,
  onUpdateStaticEncounterFields
}: {
  canEditStaticEncounters: boolean;
  editSession: EditSession | null;
  editableFields: StaticEncounterEditableField[];
  encounter: StaticEncounterRecord | null;
  isEditStarting: boolean;
  isStaticEncounterUpdating: boolean;
  onStartEditSession: () => void;
  onUpdateStaticEncounterFields: (
    encounterIndex: number,
    encounterId: string,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
}) {
  const { translateLiteral } = useLocalization();
  const [encounterDraftsByIndex, setEncounterDraftsByIndex] = useState<
    Record<string, Record<string, string>>
  >({});
  const cancelActiveEditSession = useCancelActiveEditSession();
  const encounterFields = useMemo(
    () =>
      editableFields
        .filter((field) => isStaticEncounterFieldVisible(field, encounter))
        .map((field) => withStaticEncounterFieldState(field, encounter))
        .map(withPokemonInstanceIvPresetOptions),
    [editableFields, encounter]
  );
  const encounterFieldGroups = useMemo(
    () => groupNumericEditableFields(encounterFields, getStaticEncounterFieldGroup),
    [encounterFields]
  );
  const encounterDraftDefaults = useMemo(
    () =>
      encounter
        ? createPokemonInstanceDrafts(encounterFields, (field) =>
            getEditableStaticEncounterFieldValue(encounter, field)
          )
        : {},
    [encounter, encounterFields]
  );
  const encounterDraftKey = encounter ? getStaticEncounterDraftKey(encounter) : null;
  const encounterDraftOverrides = encounter
    ? encounterDraftsByIndex[encounterDraftKey!] ?? {}
    : {};
  const encounterDrafts = useMemo(
    () => ({ ...encounterDraftDefaults, ...encounterDraftOverrides }),
    [encounterDraftDefaults, encounterDraftOverrides]
  );
  const encounterDraftSummary = useMemo(
    () =>
      getStaticEncounterDraftSummary(
        encounter,
        getActivePokemonInstanceFields(encounterFields, encounterDrafts),
        encounterDrafts,
        encounterFields
      ),
    [encounter, encounterDrafts, encounterFields]
  );
  const staticEncounterFormOptionContext = useMemo(() => {
    if (!encounter) {
      return undefined;
    }

    const speciesField = encounterFields.find(
      (field) => field.field === giftSpeciesFieldName
    );
    const abilityField = encounterFields.find((field) => field.field === abilityFieldName);
    const context = createDraftSpeciesFormOptionContext(
      speciesField,
      encounterDrafts[giftSpeciesFieldName],
      encounter.species,
      encounter.speciesId,
      undefined,
      encounter.editorFamily
    );

    return {
      ...context,
      abilityOptions:
        context.speciesId === encounter.speciesId
          ? encounter.abilityOptions
          : abilityField?.options
    };
  }, [encounter, encounterDrafts, encounterFields]);
  const writableEncounterFieldNames = useMemo(
    () =>
      new Set(
        encounterFields
          .filter((field) => !field.isReadOnly)
          .map((field) => field.field)
      ),
    [encounterFields]
  );
  useRegisterEditorDraftDirty(
    'staticEncounters',
    countFieldDraftRecords(encounterDraftsByIndex) > 0
  );
  const canSaveEncounterDrafts =
    encounter !== null &&
    editSession !== null &&
    canEditStaticEncounters &&
    !isStaticEncounterUpdating &&
    encounterDraftSummary.changedFields.length > 0 &&
    encounterDraftSummary.invalidFields.length === 0;

  useEffect(() => {
    if (!encounter) {
      return;
    }

    setEncounterDraftsByIndex((currentDrafts) =>
      pruneSparseFieldDraftRecord(
        currentDrafts,
        encounterDraftKey!,
        encounterDraftDefaults,
        writableEncounterFieldNames
      )
    );
  }, [encounter, encounterDraftDefaults, encounterDraftKey, writableEncounterFieldNames]);

  const handleEncounterDraftChange = (
    field: StaticEncounterEditableField,
    value: string
  ) => {
    if (!encounter) {
      return;
    }

    const nextDrafts = { ...encounterDrafts, [field.field]: value };
    if (field.field === giftSpeciesFieldName) {
      const formField = encounterFields.find(
        (candidate) => candidate.field === formFieldName
      );
      const abilityField = encounterFields.find(
        (candidate) => candidate.field === abilityFieldName
      );

      if (formField && !formField.isReadOnly) {
        nextDrafts[formFieldName] = '0';
      }

      if (
        abilityField &&
        !abilityField.isReadOnly &&
        abilityField.options.some((option) => option.value === 0)
      ) {
        nextDrafts[abilityFieldName] = '0';
      }
    }

    setEncounterDraftsByIndex((currentDrafts) =>
      setSparseFieldDraftRecord(
        currentDrafts,
        getStaticEncounterDraftKey(encounter),
        nextDrafts,
        encounterDraftDefaults
      )
    );
  };

  return (
    <aside
      aria-label={translateLiteral('Selected static encounter provenance')}
      className="trainer-inspector"
    >
      <div className="panel-heading">
        <ShieldCheck aria-hidden="true" size={18} />
        <h3>{translateLiteral('Selected Static Encounter')}</h3>
      </div>

      {encounter ? (
        <>
          <PokemonSummaryCard
            name={formatSpeciesFormLabel(
              encounter.species,
              encounter.form,
              encounter.speciesId,
              encounter.editorFamily
            )}
            subtitle={`Static #${getStaticEncounterDisplayIndex(encounter)} | Lv. ${encounter.level}`}
            title={formatSpeciesFormLabel(
              encounter.species,
              encounter.form,
              encounter.speciesId,
              encounter.editorFamily
            )}
          />

          <dl className="item-provenance-list">
            <div>
              <dt>{translateLiteral('Encounter')}</dt>
              <dd>{encounter.label}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Encounter ID')}</dt>
              <dd>{encounter.encounterId}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Data file')}</dt>
              <dd>{encounter.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Layer')}</dt>
              <dd>{formatSourceLayer(encounter.provenance.sourceLayer)}</dd>
            </div>
            <div>
              <dt>{translateLiteral('File state')}</dt>
              <dd>{formatFileState(encounter.provenance.fileState)}</dd>
            </div>
            <div>
              <dt>{translateLiteral(encounter.editorFamily === 'sv' ? 'Category' : 'Scenario')}</dt>
              <dd>
                {encounter.editorFamily === 'sv'
                  ? encounter.categoryLabel ?? encounter.encounterScenarioLabel
                  : encounter.encounterScenarioLabel}
              </dd>
            </div>
            {encounter.scenarioDetails ? (
              <div>
                <dt>{translateLiteral('Mission')}</dt>
                <dd>{encounter.scenarioDetails}</dd>
              </div>
            ) : null}
            {encounter.editorFamily === 'sv' ? (
              <>
                <div>
                  <dt>{translateLiteral('Tera type')}</dt>
                  <dd>{getStaticEncounterDisplayValue(encounter, giftTeraTypeFieldName)}</dd>
                </div>
                <div>
                  <dt>{translateLiteral('Scale')}</dt>
                  <dd>{formatStaticEncounterScale(encounter)}</dd>
                </div>
              </>
            ) : null}
            <div>
              <dt>{translateLiteral('Held item')}</dt>
              <dd>{encounter.heldItem ?? 'None'}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Moves')}</dt>
              <dd>{formatStaticEncounterMoves(encounter)}</dd>
            </div>
            <div>
              <dt>{translateLiteral('EV detail')}</dt>
              <dd>{formatStaticEncounterStats(encounter.evs)}</dd>
            </div>
            <div>
              <dt>{translateLiteral('IV detail')}</dt>
              <dd>{formatStaticEncounterIvs(encounter)}</dd>
            </div>
          </dl>

          <div className="trainer-edit-form">
            <div className="editable-field-groups">
              {encounterFieldGroups.map((group) => (
                <fieldset className="editable-field-group" key={group.group}>
                  <legend>{translateLiteral(group.group)}</legend>
                  <div className="editable-field-grid">
                    {group.fields.map((field) => {
                      const currentValue = getEditableStaticEncounterFieldValue(
                        encounter,
                        field.field
                      );
                      const draftValue = encounterDrafts[field.field] ?? '';
                      const draftState = getStaticEncounterFieldDraftState(
                        encounter,
                        draftValue,
                        currentValue,
                        field,
                        encounterFields,
                        encounterDrafts
                      );
                      const readOnlyReason = field.isReadOnly
                        ? field.description.trim() ||
                          'This field is read only for the selected encounter.'
                        : null;

                      return (
                        <GiftPokemonDraftField
                          currentValue={currentValue}
                          disabled={
                            field.isReadOnly ||
                            !canEditStaticEncounters ||
                            editSession === null ||
                            isStaticEncounterUpdating
                          }
                          disabledReason={
                            readOnlyReason ??
                            getPokemonInstanceIvStatDisabledReason(
                              field.field,
                              encounterFields,
                              encounterDrafts
                            ) ??
                            undefined
                          }
                          draftState={draftState}
                          draftValue={draftValue}
                          field={field}
                          formOptionContext={staticEncounterFormOptionContext}
                          key={field.field}
                          onChange={(value) => handleEncounterDraftChange(field, value)}
                        />
                      );
                    })}
                  </div>
                </fieldset>
              ))}
            </div>
            {editSession ? (
              <div className="draft-action-row">
                <button
                  aria-busy={isStaticEncounterUpdating || undefined}
                  className="primary-button"
                  disabled={!canSaveEncounterDrafts}
                  onClick={async () => {
                    const didSave = await onUpdateStaticEncounterFields(
                      encounter.encounterIndex,
                      encounter.encounterId,
                      encounterDraftSummary.changedFields.map((change) => ({
                        field: change.field,
                        value: change.value
                      }))
                    );
                    if (didSave) {
                      setEncounterDraftsByIndex((currentDrafts) =>
                        deleteFieldDraftRecord(
                          currentDrafts,
                          getStaticEncounterDraftKey(encounter)
                        )
                      );
                    }
                  }}
                  type="button"
                >
                  <BusyActionContent
                    busyLabel="Staging"
                    icon={<Save aria-hidden="true" size={16} />}
                    isBusy={isStaticEncounterUpdating}
                    label="Stage"
                  />
                </button>
                <button
                  className="danger-button"
                  disabled={
                    isStaticEncounterUpdating
                  }
                  onClick={() => cancelActiveEditSession(() => setEncounterDraftsByIndex({}))}
                  type="button"
                >
                  <X aria-hidden="true" size={16} />
                  <span>Cancel</span>
                </button>
                <span className="draft-action-summary">
                  {formatDraftSummary(encounterDraftSummary)}
                </span>
              </div>
            ) : null}

            {!editSession ? (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditStaticEncounters || isEditStarting}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            ) : null}
          </div>
        </>
      ) : (
        <p className="empty-copy">{translateLiteral('No static encounter selected.')}</p>
      )}
    </aside>
  );
}

function ShopsSection({
  editSession,
  isEditStarting,
  isItemUpdating,
  isShopUpdating,
  onOpenItem,
  onSearchChange,
  onSelectShop,
  onStartEditSession,
  onUpdateShopChanges,
  searchText,
  selectedShopId,
  workflow
}: {
  editSession: EditSession | null;
  isEditStarting: boolean;
  isItemUpdating: boolean;
  isShopUpdating: boolean;
  onOpenItem: (itemId: number) => void;
  onSearchChange: (searchText: string) => void;
  onSelectShop: (shopId: string | null) => void;
  onStartEditSession: () => void;
  onUpdateShopChanges: (
    shopId: string,
    inventoryChanges: ShopInventoryDraftChange[],
    priceChanges: ShopItemPriceChange[],
    rowFieldChanges?: ShopInventoryDraftChange[]
  ) => Promise<boolean>;
  searchText: string;
  selectedShopId: string | null;
  workflow: ShopsWorkflow | null;
}) {
  const { translateLiteral } = useLocalization();
  const [selectedSlot, setSelectedSlot] = useState<number | null>(null);
  const filteredShops = useMemo(
    () => filterShops(workflow?.shops ?? [], searchText, translateLiteral),
    [searchText, translateLiteral, workflow?.shops]
  );
  const isFlatShopList = workflow?.editorFamily === 'sv' || workflow?.editorFamily === 'za';
  const badgeShops = useMemo(
    () => (isFlatShopList ? [] : filteredShops.filter(isBadgeShopRecord)),
    [filteredShops, isFlatShopList]
  );
  const miscellaneousShops = useMemo(
    () => (isFlatShopList ? filteredShops : filteredShops.filter((shop) => !isBadgeShopRecord(shop))),
    [filteredShops, isFlatShopList]
  );
  const selectedShop =
    filteredShops.find((shop) => shop.shopId === selectedShopId) ??
    (isFlatShopList ? filteredShops[0] : badgeShops[0] ?? miscellaneousShops[0]) ??
    null;
  const canEditShops = workflow?.summary.availability === 'available';
  const pendingShopIds = getPendingShopIds(editSession);

  useEffect(() => {
    if (!selectedShop) {
      setSelectedSlot(null);
      return;
    }

    const hasSelectedSlot = selectedShop.inventory.some((item) => item.slot === selectedSlot);
    if (!hasSelectedSlot) {
      setSelectedSlot(selectedShop.inventory[0]?.slot ?? null);
    }
  }, [selectedShop?.inventory, selectedShop?.shopId, selectedSlot]);

  const renderShopTable = (label: string, shops: ShopRecord[]) => {
    const localizedLabel = translateLiteral(label);

    return (
      <section className="shop-table-section" aria-label={localizedLabel}>
        <h3>{localizedLabel}</h3>
        <div className="shops-table" role="table" aria-label={localizedLabel}>
          <div className="shops-row shops-row-heading" role="row">
            <span role="columnheader">{translateLiteral('Type')}</span>
            <span role="columnheader">{translateLiteral('Name')}</span>
            <span role="columnheader">{translateLiteral('Inventory')}</span>
            <span role="columnheader">{translateLiteral('Location')}</span>
            <span role="columnheader">{translateLiteral('Items')}</span>
            <span role="columnheader">{translateLiteral('Summary')}</span>
          </div>
          {shops.map((shop) => (
            <button
              className={`shops-row ${
                selectedShop?.shopId === shop.shopId ? 'shops-row-selected' : ''
              } ${pendingShopIds.has(shop.shopId) ? 'shops-row-pending' : ''}`}
              aria-selected={selectedShop?.shopId === shop.shopId}
              key={shop.shopId}
              onClick={() => onSelectShop(shop.shopId)}
              role="row"
              type="button"
            >
              <span role="cell">{translateLiteral(shop.kind)}</span>
              <span role="cell">{translateLiteral(shop.name)}</span>
              <span role="cell">{translateLiteral(shop.inventoryLabel)}</span>
              <span role="cell">{translateLiteral(shop.location)}</span>
              <span role="cell">{shop.inventory.length}</span>
              <span role="cell">{translateLiteral(shop.inventorySummary)}</span>
            </button>
          ))}
          {shops.length === 0 ? (
            <p className="empty-copy shop-table-empty">{translateLiteral('No matching shops.')}</p>
          ) : null}
        </div>
      </section>
    );
  };

  return (
    <>
      <section aria-labelledby="shops-heading" className="panel wide-panel">
        <div className="panel-heading">
          <ListChecks aria-hidden="true" size={18} />
          <h2 id="shops-heading">{translateLiteral('Shops')}</h2>
        </div>

        <div className="items-toolbar shops-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label={translateLiteral('Search shops')}
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder={translateLiteral('Search shops')}
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label={translateLiteral('Loaded shops')}
            value={workflow ? workflow.stats.totalShopCount.toString() : '0'}
          />
          <Metric
            label={translateLiteral('Inventory rows')}
            value={workflow ? workflow.stats.totalInventoryItemCount.toString() : '0'}
          />
          <Metric
            label={translateLiteral('Pending changes')}
            value={(editSession?.pendingEdits.length ?? 0).toString()}
          />
        </div>

        {workflow ? (
          <div className={`shops-layout ${isFlatShopList ? 'sv-shops-layout' : 'swsh-shops-layout'}`}>
            <div className="shops-table-stack">
              {isFlatShopList ? (
                renderShopTable('Shops', filteredShops)
              ) : (
                <>
                  {renderShopTable('Badge Shops', badgeShops)}
                  {renderShopTable('Miscellaneous Shops', miscellaneousShops)}
                </>
              )}
            </div>

            <SelectedShopPanel
              canEditShops={canEditShops}
              editSession={editSession}
              editableFields={workflow.editableFields}
              isEditStarting={isEditStarting}
              isItemUpdating={isItemUpdating}
              isShopUpdating={isShopUpdating}
              onOpenItem={onOpenItem}
              onSelectSlot={setSelectedSlot}
              onStartEditSession={onStartEditSession}
              onUpdateShopChanges={onUpdateShopChanges}
              selectedSlot={selectedSlot}
              shop={selectedShop}
            />
          </div>
        ) : (
          <p className="empty-copy">
            {translateLiteral('Open Shops from Workflows to load backend shop data.')}
          </p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
    </>
  );
}

function SelectedShopPanel({
  canEditShops,
  editSession,
  editableFields,
  isEditStarting,
  isItemUpdating,
  isShopUpdating,
  onOpenItem,
  onSelectSlot,
  onStartEditSession,
  onUpdateShopChanges,
  selectedSlot,
  shop
}: {
  canEditShops: boolean;
  editSession: EditSession | null;
  editableFields: ShopEditableField[];
  isEditStarting: boolean;
  isItemUpdating: boolean;
  isShopUpdating: boolean;
  onOpenItem: (itemId: number) => void;
  onSelectSlot: (slot: number | null) => void;
  onStartEditSession: () => void;
  onUpdateShopChanges: (
    shopId: string,
    inventoryChanges: ShopInventoryDraftChange[],
    priceChanges: ShopItemPriceChange[],
    rowFieldChanges?: ShopInventoryDraftChange[]
  ) => Promise<boolean>;
  selectedSlot: number | null;
  shop: ShopRecord | null;
}) {
  const { translateLiteral } = useLocalization();
  const [inventoryDraftsByShopId, setInventoryDraftsByShopId] = useState<
    Record<string, ShopInventoryDraftState>
  >({});
  const [pendingOpenItem, setPendingOpenItem] =
    useState<{ itemId: number; itemName: string } | null>(null);
  const cancelActiveEditSession = useCancelActiveEditSession();
  const itemIdField = editableFields.find((field) => field.field === shopItemIdFieldName);
  const itemIdOptions = itemIdField?.options ?? [];
  const hasItemIdOptions = itemIdOptions.length > 0;
  const defaultShopDraft = useMemo<ShopInventoryDraftState>(
    () => ({
      addedRows: [],
      fieldDrafts: {},
      itemIdDrafts: Object.fromEntries(
        shop?.inventory.map((item) => [item.slot, item.itemId.toString()]) ?? []
      ),
      newItemIdDraft: (itemIdOptions[0]?.value ?? 0).toString(),
      nextAddedRowId: getNextShopInventoryDraftId(shop?.inventory ?? []),
      priceDrafts: {},
      rowOrder: shop?.inventory.map((item) => getShopExistingRowKey(item.slot)) ?? [],
      removedSlots: []
    }),
    [itemIdOptions, shop?.inventory, shop?.shopId]
  );
  const currentShopDraft = shop
    ? normalizeShopInventoryDraft(inventoryDraftsByShopId[shop.shopId] ?? defaultShopDraft, shop)
    : defaultShopDraft;
  const { newItemIdDraft } = currentShopDraft;
  const updateCurrentShopDraft = useCallback(
    (updater: (currentDraft: ShopInventoryDraftState) => ShopInventoryDraftState) => {
      if (!shop) {
        return;
      }

      setInventoryDraftsByShopId((currentDrafts) => ({
        ...currentDrafts,
        [shop.shopId]: normalizeShopInventoryDraft(
          updater(normalizeShopInventoryDraft(currentDrafts[shop.shopId] ?? defaultShopDraft, shop)),
          shop
        )
      }));
    },
    [defaultShopDraft, shop]
  );
  const resetShopDrafts = useCallback(() => {
    setInventoryDraftsByShopId({});
  }, []);
  useRegisterEditorDraftDirty('shops', Object.keys(inventoryDraftsByShopId).length > 0);

  const shopInventoryRows = useMemo(
    () => createShopInventoryDraftRows(shop, currentShopDraft, itemIdOptions, translateLiteral),
    [currentShopDraft, itemIdOptions, shop, translateLiteral]
  );
  const selectedInventoryItem =
    shop?.inventory.find((item) => item.slot === selectedSlot) ?? null;
  const selectedRowFields = useMemo(
    () =>
      selectedInventoryItem?.supportedFields
        .map((fieldName) => editableFields.find((field) => field.field === fieldName))
        .filter((field): field is ShopEditableField => field !== undefined) ?? [],
    [editableFields, selectedInventoryItem?.supportedFields]
  );
  const shopDraftChanges = useMemo(() => {
    if (!shop || !itemIdField || !shop.canEditInventoryOrder) {
      return [];
    }

    const finalRows: Array<{ itemId: number; rowId: string | null }> = [];
    for (const item of shopInventoryRows) {
      if (item.parsedItemId === null) {
        return [];
      }

      if (item.parsedItemId !== shopNoneItemId) {
        finalRows.push({ itemId: item.parsedItemId, rowId: item.rowId });
      }
    }

    const value = createShopInventoryUpdateValue(
      shop.editorFamily,
      shop.inventory.map((item) => ({ itemId: item.itemId, rowId: item.rowId })),
      finalRows
    );
    if (value === null) {
      return [];
    }

    return [
      {
        field: shopSetInventoryFieldName,
        slot: 1,
        value
      }
    ];
  }, [itemIdField, shop, shopInventoryRows]);
  const shopPriceDraftChanges = useMemo<ShopItemPriceChange[]>(() => {
    const changes: ShopItemPriceChange[] = [];
    const changedItemIds = new Set<number>();
    const priceField = shop?.globalPriceField ?? null;

    if (priceField === null) {
      return changes;
    }

    for (const row of shopInventoryRows) {
      const parsedPrice = row.parsedPrice;
      if (
        !row.isKnownItem ||
        row.parsedItemId === null ||
        row.parsedItemId === shopNoneItemId ||
        parsedPrice === null ||
        row.priceField !== null ||
        !row.canEditPrice ||
        !isIntegerDraftInFieldRange(parsedPrice, shopPriceEditableField) ||
        parsedPrice === row.price ||
        changedItemIds.has(row.parsedItemId)
      ) {
        continue;
      }

      changedItemIds.add(row.parsedItemId);
      changes.push({
        field: priceField,
        itemId: row.parsedItemId,
        value: parsedPrice.toString()
      });
    }

    return changes;
  }, [shop?.globalPriceField, shopInventoryRows]);
  const shopRowFieldDraftChanges = useMemo<ShopInventoryDraftChange[]>(() => {
    if (!shop) {
      return [];
    }

    const changes: ShopInventoryDraftChange[] = [];
    const removedSlots = new Set(currentShopDraft.removedSlots);
    for (const inventoryItem of shop.inventory) {
      if (removedSlots.has(inventoryItem.slot)) {
        continue;
      }

      const fieldDrafts = currentShopDraft.fieldDrafts[inventoryItem.slot] ?? {};
      for (const fieldName of inventoryItem.supportedFields) {
        const field = editableFields.find((candidate) => candidate.field === fieldName);
        if (!field) {
          continue;
        }

        const contextualField = getContextualShopRowField(
          field,
          inventoryItem,
          currentShopDraft
        );
        const originalValue = inventoryItem.fieldValues[field.field] ?? '';
        const draftValue = fieldDrafts[field.field] ?? originalValue;
        if (
          draftValue === originalValue ||
          isShopRowFieldDraftInvalid(contextualField, draftValue)
        ) {
          continue;
        }

        changes.push({
          field: field.field,
          rowId: inventoryItem.rowId ?? undefined,
          slot: inventoryItem.slot,
          value: draftValue
        });
      }
    }

    return changes;
  }, [currentShopDraft, editableFields, shop]);
  const invalidShopItemDraftCount = shopInventoryRows.filter(
    (row) => !isIntegerDraftInFieldRange(row.parsedItemId, itemIdField)
  ).length;
  const invalidShopPriceDraftCount = shopInventoryRows.filter(
    (row) =>
      row.isKnownItem &&
      row.canEditPrice &&
      row.priceField === null &&
      shop?.globalPriceField != null &&
      !isIntegerDraftInFieldRange(row.parsedPrice, shopPriceEditableField)
  ).length;
  const invalidShopRowFieldDraftCount = shop
    ? shop.inventory.reduce((invalidCount, inventoryItem) => {
        if (currentShopDraft.removedSlots.includes(inventoryItem.slot)) {
          return invalidCount;
        }

        const fieldDrafts = currentShopDraft.fieldDrafts[inventoryItem.slot] ?? {};
        return (
          invalidCount +
          inventoryItem.supportedFields.filter((fieldName) => {
            const field = editableFields.find((candidate) => candidate.field === fieldName);
            if (!field || fieldDrafts[field.field] === undefined) {
              return false;
            }

            const originalValue = inventoryItem.fieldValues[field.field] ?? '';
            const draftValue = fieldDrafts[field.field]!;
            return (
              draftValue !== originalValue &&
              isShopRowFieldDraftInvalid(
                getContextualShopRowField(field, inventoryItem, currentShopDraft),
                draftValue
              )
            );
          }).length
        );
      }, 0)
    : 0;
  const changedSlotCount =
    shopDraftChanges.length + shopPriceDraftChanges.length + shopRowFieldDraftChanges.length;
  const hasInvalidShopDrafts =
    invalidShopItemDraftCount > 0 ||
    invalidShopPriceDraftCount > 0 ||
    invalidShopRowFieldDraftCount > 0;
  const canSaveShopDrafts =
    shop !== null &&
    editSession !== null &&
    canEditShops &&
    !isShopUpdating &&
    !isItemUpdating &&
    changedSlotCount > 0 &&
    !hasInvalidShopDrafts;
  const parsedNewItemId = parseEditableIntegerDraft(newItemIdDraft, itemIdField?.options);
  const newItemInRange =
    parsedNewItemId !== null &&
    (itemIdField?.minimumValue === null ||
      itemIdField?.minimumValue === undefined ||
      parsedNewItemId >= itemIdField.minimumValue) &&
    (itemIdField?.maximumValue === null ||
      itemIdField?.maximumValue === undefined ||
      parsedNewItemId <= itemIdField.maximumValue);
  const canAddInventoryRow =
    shop !== null &&
    editSession !== null &&
    canEditShops &&
    !isShopUpdating &&
    !isItemUpdating &&
    itemIdField !== undefined &&
    (shop?.canEditInventoryOrder ?? false) &&
    newItemInRange;
  useEffect(() => {
    if (!shop || hasInvalidShopDrafts || changedSlotCount > 0) {
      return;
    }

    const currentDraft = inventoryDraftsByShopId[shop.shopId];
    if (!currentDraft) {
      return;
    }

    const hasDefaultExistingItems = shop.inventory.every(
      (item) => (currentDraft.itemIdDrafts[item.slot] ?? item.itemId.toString()) === item.itemId.toString()
    );
    const hasDefaultExistingPrices = shopInventoryRows.every(
      (item) =>
        item.sourceSlot === null ||
        (currentDraft.priceDrafts[item.sourceSlot] ?? item.price.toString()) ===
          item.price.toString()
    );
    const hasDefaultFieldDrafts = shop.inventory.every((item) => {
      const fieldDrafts = currentDraft.fieldDrafts[item.slot] ?? {};
      return Object.entries(fieldDrafts).every(
        ([fieldName, draftValue]) => draftValue === (item.fieldValues[fieldName] ?? '')
      );
    });
    const hasDefaultRowState =
      currentDraft.addedRows.length === 0 &&
      currentDraft.removedSlots.length === 0 &&
      areStringArraysEqual(
        normalizeShopInventoryRowOrder(currentDraft, shop),
        defaultShopDraft.rowOrder
      ) &&
      currentDraft.newItemIdDraft === defaultShopDraft.newItemIdDraft &&
      hasDefaultExistingItems &&
      hasDefaultExistingPrices &&
      hasDefaultFieldDrafts;
    if (!hasDefaultRowState) {
      return;
    }

    setInventoryDraftsByShopId((currentDrafts) => {
      const nextDrafts = { ...currentDrafts };
      delete nextDrafts[shop.shopId];
      return nextDrafts;
    });
  }, [
    changedSlotCount,
    defaultShopDraft.newItemIdDraft,
    defaultShopDraft.rowOrder,
    hasInvalidShopDrafts,
    inventoryDraftsByShopId,
    shop,
    shopInventoryRows
  ]);
  const handleConfirmOpenItem = useCallback(() => {
    if (pendingOpenItem) {
      onOpenItem(pendingOpenItem.itemId);
      setPendingOpenItem(null);
    }
  }, [onOpenItem, pendingOpenItem]);

  return (
    <aside aria-label={translateLiteral('Selected shop provenance')} className="shop-inspector">
      <div className="panel-heading">
        <ShieldCheck aria-hidden="true" size={18} />
        <h3>{translateLiteral('Selected Shop')}</h3>
      </div>

      {shop ? (
        <>
          <dl className="item-provenance-list">
            <div>
              <dt>{translateLiteral('Name')}</dt>
              <dd>{translateLiteral(shop.name)}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Inventory')}</dt>
              <dd>{translateLiteral(shop.inventoryLabel)}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Type')}</dt>
              <dd>{translateLiteral(shop.kind)}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Hash')}</dt>
              <dd>{shop.sourceHash}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Summary')}</dt>
              <dd>{translateLiteral(shop.inventorySummary)}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Source file')}</dt>
              <dd>{shop.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Layer')}</dt>
              <dd>{translateLiteral(formatSourceLayer(shop.provenance.sourceLayer))}</dd>
            </div>
            <div>
              <dt>{translateLiteral('File state')}</dt>
              <dd>{translateLiteral(formatFileState(shop.provenance.fileState))}</dd>
            </div>
          </dl>

          <div className="shop-edit-form">
            <div className="shop-inventory-header">
              <strong>{translateLiteral('Inventory')}</strong>
              <span className="draft-action-summary">
                {changedSlotCount} {translateLiteral('Pending changes')} / {shopInventoryRows.length}{' '}
                {translateLiteral('slots')}
              </span>
            </div>

            {editSession ? (
              <div className="draft-action-row">
                <button
                  aria-busy={(isShopUpdating || isItemUpdating) || undefined}
                  className="primary-button"
                  disabled={!canSaveShopDrafts}
                  onClick={async () => {
                    const didSave = await onUpdateShopChanges(
                      shop.shopId,
                      shopDraftChanges,
                      shopPriceDraftChanges,
                      shopRowFieldDraftChanges
                    );
                    if (didSave) {
                      setInventoryDraftsByShopId((currentDrafts) =>
                        deleteFieldDraftRecord(currentDrafts, shop.shopId)
                      );
                    }
                  }}
                  type="button"
                >
                  <BusyActionContent
                    busyLabel={translateLiteral('Staging')}
                    icon={<Save aria-hidden="true" size={16} />}
                    isBusy={isShopUpdating || isItemUpdating}
                    label={translateLiteral('Stage')}
                  />
                </button>
                <button
                  className="danger-button"
                  disabled={isShopUpdating || isItemUpdating}
                  onClick={() => cancelActiveEditSession(resetShopDrafts)}
                  type="button"
                >
                  <X aria-hidden="true" size={16} />
                  <span>{translateLiteral('Cancel')}</span>
                </button>
                <span className="draft-action-summary">
                  {hasInvalidShopDrafts
                    ? invalidShopRowFieldDraftCount > 0
                      ? translateLiteral('Fix invalid slot fields.')
                      : invalidShopPriceDraftCount > 0
                      ? translateLiteral('Fix invalid prices.')
                      : translateLiteral('Fix invalid inventory rows.')
                    : `${changedSlotCount} ${translateLiteral('Pending changes')}.`}
                </span>
              </div>
            ) : (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditShops || isEditStarting}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel={translateLiteral('Starting')}
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label={translateLiteral('Edit')}
                />
              </button>
            )}

            {shopInventoryRows.length > 0 ? (
              <div className="shop-inventory-editor-grid">
                <div className="shop-inventory-editor-row shop-inventory-editor-heading">
                  <span>{translateLiteral('Slot')}</span>
                  <span>{translateLiteral('Item')}</span>
                  <span>{translateLiteral('Price')}</span>
                  <span>{translateLiteral('Stock')}</span>
                  <span>{translateLiteral('Actions')}</span>
                </div>
                {shopInventoryRows.map((item, index) => {
                  const draftState = getIntegerDraftState(
                    item.itemIdDraft,
                    item.itemId,
                    itemIdField
                  );
                  const draftError =
                    isIntegerDraftInFieldRange(draftState.parsedValue, itemIdField)
                      ? null
                      : getIntegerDraftFieldError(item.itemIdDraft, itemIdField);
                  const rowAriaLabel = item.isAdded
                    ? `${translateLiteral('New shop slot')} ${item.displaySlot} ${translateLiteral('item')}`
                    : `${translateLiteral('Shop slot')} ${item.displaySlot} ${translateLiteral('item')}`;
                  const priceDraftError =
                    item.isKnownItem &&
                    item.canEditPrice &&
                    item.priceField === null &&
                    shop.globalPriceField !== null &&
                    !isIntegerDraftInFieldRange(item.parsedPrice, shopPriceEditableField)
                      ? getIntegerDraftFieldError(item.priceDraft, shopPriceEditableField)
                      : null;
                  const isPriceDisabled =
                    !canEditShops ||
                    editSession === null ||
                    isShopUpdating ||
                    isItemUpdating ||
                    !item.isKnownItem ||
                    !item.canEditPrice ||
                    item.priceField !== null ||
                    shop.globalPriceField === null;
                  const itemDraftErrorId = `shop-item-${shop.shopId}-${item.key}-error`;
                  const priceDraftErrorId = `shop-price-${shop.shopId}-${item.key}-error`;

                  return (
                    <div
                      className={`shop-inventory-editor-row ${
                        item.isAdded ? 'shop-inventory-editor-row-new' : ''
                      } ${
                        item.sourceSlot === selectedSlot ? 'shop-inventory-editor-row-selected' : ''
                      }`}
                      key={item.key}
                      onClick={() => {
                        if (item.sourceSlot !== null) {
                          onSelectSlot(item.sourceSlot);
                        }
                      }}
                    >
                      <span className="shop-slot-index">#{item.displaySlot}</span>
                      <label className="path-field shop-inventory-item-field">
                        <span>{translateLiteral(itemIdField?.label ?? 'Item ID')}</span>
                        {hasItemIdOptions ? (
                          <SearchableOptionInput
                            ariaDescribedBy={draftError ? itemDraftErrorId : undefined}
                            ariaInvalid={draftError ? true : undefined}
                            ariaLabel={rowAriaLabel}
                            disabled={
                              !canEditShops ||
                              !shop.canEditInventoryOrder ||
                              editSession === null ||
                              isShopUpdating ||
                              isItemUpdating
                            }
                            onChange={(value) =>
                              updateCurrentShopDraft((currentDraft) =>
                                clearShopInventoryRowPriceDraft(
                                  {
                                    ...currentDraft,
                                    addedRows:
                                      item.draftId === null
                                        ? currentDraft.addedRows
                                        : currentDraft.addedRows.map((row) =>
                                            row.draftId === item.draftId
                                              ? { ...row, itemIdDraft: value }
                                              : row
                                          ),
                                    itemIdDrafts:
                                      item.sourceSlot === null
                                        ? currentDraft.itemIdDrafts
                                        : {
                                            ...currentDraft.itemIdDrafts,
                                            [item.sourceSlot]: value
                                          }
                                  },
                                  item
                                )
                              )
                            }
                            options={addDraftFallbackOption(
                              itemIdOptions,
                              item.itemIdDraft,
                              formatShopItemFallbackOption(item.itemIdDraft, translateLiteral)
                            )}
                            value={item.itemIdDraft}
                          />
                        ) : (
                          <input
                            aria-describedby={draftError ? itemDraftErrorId : undefined}
                            aria-invalid={draftError ? true : undefined}
                            aria-label={rowAriaLabel}
                            disabled={
                              !canEditShops ||
                              !shop.canEditInventoryOrder ||
                              editSession === null ||
                              isShopUpdating ||
                              isItemUpdating
                            }
                            max={itemIdField?.maximumValue ?? undefined}
                            min={itemIdField?.minimumValue ?? undefined}
                            onChange={(event) =>
                              updateCurrentShopDraft((currentDraft) =>
                                clearShopInventoryRowPriceDraft(
                                  {
                                    ...currentDraft,
                                    addedRows:
                                      item.draftId === null
                                        ? currentDraft.addedRows
                                        : currentDraft.addedRows.map((row) =>
                                            row.draftId === item.draftId
                                              ? { ...row, itemIdDraft: event.target.value }
                                              : row
                                          ),
                                    itemIdDrafts:
                                      item.sourceSlot === null
                                        ? currentDraft.itemIdDrafts
                                        : {
                                            ...currentDraft.itemIdDrafts,
                                            [item.sourceSlot]: event.target.value
                                          }
                                  },
                                  item
                                )
                              )
                            }
                            type="number"
                            value={item.itemIdDraft}
                          />
                        )}
                        {draftError ? (
                          <small className="editable-field-error" id={itemDraftErrorId}>
                            {translateLiteral(draftError)}
                          </small>
                        ) : null}
                      </label>
                      <label
                        className={`path-field ${
                          isPriceDisabled ? 'shop-read-only-field' : ''
                        }`}
                      >
                        <span>{translateLiteral(shop.currency)}</span>
                        <input
                          aria-describedby={priceDraftError ? priceDraftErrorId : undefined}
                          aria-invalid={priceDraftError ? true : undefined}
                          aria-label={`${translateLiteral('Shop slot')} ${item.displaySlot} ${translateLiteral(
                            'price'
                          )}`}
                          disabled={isPriceDisabled}
                          max={maximumShopItemPrice}
                          min={0}
                          onChange={(event) =>
                            updateCurrentShopDraft((currentDraft) =>
                              setShopItemPriceDraft(
                                currentDraft,
                                shopInventoryRows,
                                item,
                                event.target.value
                              )
                            )
                          }
                          title={translateLiteral(
                            'Changes the item price used wherever this currency is accepted.'
                          )}
                          type="number"
                          value={item.priceDraft}
                        />
                        {priceDraftError ? (
                          <small className="editable-field-error" id={priceDraftErrorId}>
                            {translateLiteral(priceDraftError)}
                          </small>
                        ) : null}
                      </label>
                      <label className="path-field shop-read-only-field">
                        <span>{translateLiteral('Stock')}</span>
                        <input
                          aria-label={`${translateLiteral('Shop slot')} ${item.displaySlot} ${translateLiteral(
                            'stock'
                          )}`}
                          disabled
                          title={translateLiteral(
                            'Shop inventory data does not expose a limited-stock value here.'
                          )}
                          value={item.stockLimit ?? translateLiteral('None')}
                        />
                      </label>
                      <div className="shop-inventory-row-actions">
                        {item.isKnownItem ? (
                          <button
                            aria-label={`${translateLiteral('Open')} ${item.itemName} ${translateLiteral(
                              'in Items'
                            )}`}
                            className="secondary-button compact-button shop-item-link"
                            onClick={(event) => {
                              event.stopPropagation();
                              setPendingOpenItem({ itemId: item.itemId, itemName: item.itemName });
                            }}
                            title={translateLiteral('Open in Items')}
                            type="button"
                          >
                            <ExternalLink aria-hidden="true" size={14} />
                            <span>{translateLiteral('Open in Items')}</span>
                          </button>
                        ) : (
                          <span className="path-status-muted">{translateLiteral('Missing metadata')}</span>
                        )}
                        {editSession ? (
                          <>
                            <button
                              aria-label={`${translateLiteral('Move shop slot')} ${
                                item.displaySlot
                              } ${translateLiteral('up')}`}
                              className="secondary-button icon-button"
                              disabled={
                                !canEditShops ||
                                !shop.canEditInventoryOrder ||
                                isShopUpdating ||
                                isItemUpdating ||
                                index === 0
                              }
                              onClick={(event) => {
                                event.stopPropagation();
                                updateCurrentShopDraft((currentDraft) =>
                                  moveShopInventoryDraftRow(currentDraft, shop, item.key, -1)
                                );
                              }}
                              title={translateLiteral('Move shop slot up')}
                              type="button"
                            >
                              <ArrowUp aria-hidden="true" size={16} />
                            </button>
                            <button
                              aria-label={`${translateLiteral('Move shop slot')} ${
                                item.displaySlot
                              } ${translateLiteral('down')}`}
                              className="secondary-button icon-button"
                              disabled={
                                !canEditShops ||
                                !shop.canEditInventoryOrder ||
                                isShopUpdating ||
                                isItemUpdating ||
                                index >= shopInventoryRows.length - 1
                              }
                              onClick={(event) => {
                                event.stopPropagation();
                                updateCurrentShopDraft((currentDraft) =>
                                  moveShopInventoryDraftRow(currentDraft, shop, item.key, 1)
                                );
                              }}
                              title={translateLiteral('Move shop slot down')}
                              type="button"
                            >
                              <ArrowDown aria-hidden="true" size={16} />
                            </button>
                            <button
                              aria-label={`${translateLiteral('Remove shop slot')} ${item.displaySlot}`}
                              className="secondary-button icon-button danger-icon-button"
                              disabled={
                                !canEditShops ||
                                !shop.canEditInventoryOrder ||
                                isShopUpdating ||
                                isItemUpdating
                              }
                              onClick={(event) => {
                                event.stopPropagation();
                                updateCurrentShopDraft((currentDraft) =>
                                  removeShopInventoryDraftRow(currentDraft, item)
                                );
                              }}
                              title={translateLiteral('Remove shop slot')}
                              type="button"
                            >
                              <Trash2 aria-hidden="true" size={16} />
                            </button>
                          </>
                        ) : null}
                      </div>
                    </div>
                  );
                })}
              </div>
            ) : (
              <p className="empty-copy">{translateLiteral('No inventory slots.')}</p>
            )}
            {selectedInventoryItem && selectedRowFields.length > 0 ? (
              <div className="shop-row-detail-editor">
                <div className="shop-inventory-header">
                  <strong>{translateLiteral('Selected Slot Details')}</strong>
                  <span className="draft-action-summary">
                    {translateLiteral('Slot')} #{selectedInventoryItem.slot}
                  </span>
                </div>
                <div className="editable-field-grid shop-row-field-grid">
                  {selectedRowFields.map((field) => {
                    const rowField = getContextualShopRowField(
                      field,
                      selectedInventoryItem,
                      currentShopDraft
                    );
                    const originalValue = selectedInventoryItem.fieldValues[field.field] ?? '';
                    const draftValue =
                      currentShopDraft.fieldDrafts[selectedInventoryItem.slot]?.[field.field] ??
                      originalValue;
                    const isInvalid = isShopRowFieldDraftInvalid(rowField, draftValue);
                    const errorId = `shop-row-${shop.shopId}-${selectedInventoryItem.slot}-${field.field}-error`;

                    return (
                      <label
                        className={`path-field shop-slot-detail-field ${
                          draftValue !== originalValue ? 'editable-field-changed' : ''
                        } ${isInvalid ? 'editable-field-invalid' : ''}`}
                        key={field.field}
                      >
                        <span className="editable-field-label-row">
                          <span>{translateLiteral(rowField.label)}</span>
                        </span>
                        <ShopRowFieldInput
                          ariaDescribedBy={isInvalid ? errorId : undefined}
                          ariaInvalid={isInvalid ? true : undefined}
                          disabled={
                            !canEditShops ||
                            editSession === null ||
                            isShopUpdating ||
                            isItemUpdating
                          }
                          draftValue={draftValue}
                          field={rowField}
                          onChange={(value) =>
                            updateCurrentShopDraft((currentDraft) =>
                              updateShopRowFieldDraft(
                                currentDraft,
                                selectedInventoryItem,
                                field.field,
                                value
                              )
                            )
                          }
                          textOptions={getShopRowTextOptions(rowField, selectedInventoryItem, currentShopDraft)}
                        />
                        {isInvalid ? (
                          <small className="editable-field-error" id={errorId}>
                            {translateLiteral(getIntegerDraftFieldError(draftValue, rowField))}
                          </small>
                        ) : null}
                      </label>
                    );
                  })}
                </div>
              </div>
            ) : null}
            {editSession && shop.canEditInventoryOrder ? (
              <div className="shop-inventory-add-row">
                <label className="path-field shop-inventory-item-field">
                  <span>{translateLiteral('New item')}</span>
                  {hasItemIdOptions ? (
                    <SearchableOptionInput
                      ariaLabel={translateLiteral('New shop inventory item')}
                      disabled={!canEditShops || isShopUpdating || isItemUpdating}
                      onChange={(value) =>
                        updateCurrentShopDraft((currentDraft) => ({
                          ...currentDraft,
                          newItemIdDraft: value
                        }))
                      }
                      options={addDraftFallbackOption(
                        itemIdOptions,
                        newItemIdDraft,
                        formatShopItemFallbackOption(newItemIdDraft, translateLiteral)
                      )}
                      value={newItemIdDraft}
                    />
                  ) : (
                    <input
                      aria-label={translateLiteral('New shop inventory item')}
                      disabled={!canEditShops || isShopUpdating || isItemUpdating}
                      max={itemIdField?.maximumValue ?? undefined}
                      min={itemIdField?.minimumValue ?? undefined}
                      onChange={(event) =>
                        updateCurrentShopDraft((currentDraft) => ({
                          ...currentDraft,
                          newItemIdDraft: event.target.value
                        }))
                      }
                      type="number"
                      value={newItemIdDraft}
                    />
                  )}
                </label>
                <button
                  aria-label={translateLiteral('Add shop inventory row')}
                  className="secondary-button learnset-add-button"
                  disabled={!canAddInventoryRow}
                  onClick={() => {
                    if (parsedNewItemId !== null) {
                      updateCurrentShopDraft((currentDraft) => {
                        const nextDraftId = currentDraft.nextAddedRowId;
                        return {
                          ...currentDraft,
                          addedRows: [
                            ...currentDraft.addedRows,
                            {
                              draftId: nextDraftId,
                              itemIdDraft: parsedNewItemId.toString()
                            }
                          ],
                          newItemIdDraft: (itemIdOptions[0]?.value ?? 0).toString(),
                          nextAddedRowId: currentDraft.nextAddedRowId + 1,
                          rowOrder: [...currentDraft.rowOrder, getShopAddedRowKey(nextDraftId)]
                        };
                      });
                    }
                  }}
                  type="button"
                >
                  <Plus aria-hidden="true" size={16} />
                  <span>{translateLiteral('Add Row')}</span>
                </button>
              </div>
            ) : null}
          </div>
        </>
      ) : (
        <p className="empty-copy">{translateLiteral('No shop selected.')}</p>
      )}
      {pendingOpenItem ? (
        <ShopItemNavigationModal
          onCancel={() => setPendingOpenItem(null)}
          onConfirm={handleConfirmOpenItem}
        />
      ) : null}
    </aside>
  );
}

function ShopRowFieldInput({
  ariaDescribedBy,
  ariaInvalid,
  disabled,
  draftValue,
  field,
  onChange,
  textOptions
}: {
  ariaDescribedBy?: string;
  ariaInvalid?: boolean;
  disabled: boolean;
  draftValue: string;
  field: ShopEditableField;
  onChange: (value: string) => void;
  textOptions?: Array<{ label: string; value: string }>;
}) {
  const options = field.options ?? [];
  const { translateLiteral } = useLocalization();
  const localizedFieldLabel = translateLiteral(field.label);
  const localizedFieldHelpText = translateLiteral(getEditableFieldHelp(field));

  if (textOptions && textOptions.length > 0) {
    return (
      <select
        aria-describedby={ariaDescribedBy}
        aria-invalid={ariaInvalid}
        aria-label={localizedFieldLabel}
        disabled={disabled}
        onChange={(event) => onChange(event.target.value)}
        title={localizedFieldHelpText}
        value={draftValue}
      >
        {textOptions.map((option) => (
          <option key={option.value} value={option.value}>
            {translateLiteral(option.label)}
          </option>
        ))}
      </select>
    );
  }

  if (options.length > 0) {
    return (
      <SearchableOptionInput
        ariaDescribedBy={ariaDescribedBy}
        ariaInvalid={ariaInvalid}
        ariaLabel={localizedFieldLabel}
        disabled={disabled}
        onChange={onChange}
        options={addDraftFallbackOption(options, draftValue, draftValue || translateLiteral('Custom value'))}
        title={localizedFieldHelpText}
        value={draftValue}
      />
    );
  }

  return (
    <input
      aria-describedby={ariaDescribedBy}
      aria-invalid={ariaInvalid}
      aria-label={localizedFieldLabel}
      disabled={disabled}
      max={field.maximumValue ?? undefined}
      min={field.minimumValue ?? undefined}
      onChange={(event) => onChange(event.target.value)}
      title={localizedFieldHelpText}
      type={field.valueKind === 'text' ? 'text' : 'number'}
      value={draftValue}
    />
  );
}

function getContextualShopRowField(
  field: ShopEditableField,
  row: ShopInventoryRecord,
  draft: ShopInventoryDraftState
): ShopEditableField {
  if (
    field.field === shopGymBadgeCountFieldName &&
    getShopRowConditionKindDraft(row, draft) === shopGymBadgeConditionKindValue
  ) {
    return {
      ...field,
      options: shopGymBadgeOptions
    };
  }

  return field;
}

function getShopRowTextOptions(
  field: ShopEditableField,
  row: ShopInventoryRecord,
  draft: ShopInventoryDraftState
) {
  return field.field === shopConditionValueFieldName &&
    getShopRowConditionKindDraft(row, draft) === shopGymBadgeConditionKindValue
    ? shopGymBadgeConditionValueOptions
    : undefined;
}

function updateShopRowFieldDraft(
  draft: ShopInventoryDraftState,
  row: ShopInventoryRecord,
  field: string,
  value: string
): ShopInventoryDraftState {
  const currentRowDrafts = draft.fieldDrafts[row.slot] ?? {};
  const nextRowDrafts = {
    ...currentRowDrafts,
    [field]: value
  };
  const nextConditionKind =
    field === shopConditionKindFieldName
      ? value
      : nextRowDrafts[shopConditionKindFieldName] ??
        row.fieldValues[shopConditionKindFieldName] ??
        '';

  if (nextConditionKind === shopGymBadgeConditionKindValue) {
    // S/V badge-gated shop rows store the same gate as both BADGE# and a
    // numeric badge count. Keep the pair synchronized so staged rows stay valid.
    if (field === shopConditionValueFieldName) {
      const badgeCount = parseShopBadgeConditionValue(value);
      if (badgeCount !== null) {
        nextRowDrafts[shopGymBadgeCountFieldName] = badgeCount.toString();
      }
    }

    if (field === shopGymBadgeCountFieldName) {
      const badgeCount = parseShopBadgeCount(value);
      if (badgeCount !== null) {
        nextRowDrafts[shopConditionValueFieldName] = `BADGE${badgeCount}`;
      }
    }

    const conditionValue =
      nextRowDrafts[shopConditionValueFieldName] ??
      row.fieldValues[shopConditionValueFieldName] ??
      '';
    if (parseShopBadgeConditionValue(conditionValue) === null) {
      nextRowDrafts[shopConditionValueFieldName] = 'BADGE0';
    }

    const badgeCount =
      nextRowDrafts[shopGymBadgeCountFieldName] ??
      row.fieldValues[shopGymBadgeCountFieldName] ??
      '';
    if (parseShopBadgeCount(badgeCount) === null) {
      nextRowDrafts[shopGymBadgeCountFieldName] = '0';
    }
  }

  return {
    ...draft,
    fieldDrafts: {
      ...draft.fieldDrafts,
      [row.slot]: nextRowDrafts
    }
  };
}

function getShopRowConditionKindDraft(
  row: ShopInventoryRecord,
  draft: ShopInventoryDraftState
) {
  return (
    draft.fieldDrafts[row.slot]?.[shopConditionKindFieldName] ??
    row.fieldValues[shopConditionKindFieldName] ??
    ''
  );
}

function parseShopBadgeConditionValue(value: string) {
  const match = /^BADGE([0-8])$/i.exec(value.trim());
  return match ? Number.parseInt(match[1]!, 10) : null;
}

function parseShopBadgeCount(value: string) {
  return /^[0-8]$/.test(value.trim()) ? Number.parseInt(value, 10) : null;
}

function formatShopItemFallbackOption(
  value: string,
  translateLiteral: (literal: string) => string
) {
  return `${translateLiteral('Item')} ${value}`;
}

function getShopExistingRowKey(slot: number) {
  return `slot:${slot}`;
}

function getShopAddedRowKey(draftId: number) {
  return `new:${draftId}`;
}

function getShopRowSlot(key: string) {
  return key.startsWith('slot:') ? Number.parseInt(key.slice('slot:'.length), 10) : null;
}

function getShopRowDraftId(key: string) {
  return key.startsWith('new:') ? Number.parseInt(key.slice('new:'.length), 10) : null;
}

function isShopRowFieldDraftInvalid(field: ShopEditableField, draftValue: string) {
  if (field.valueKind === 'text') {
    return false;
  }

  return !isIntegerDraftInFieldRange(
    parseEditableIntegerDraft(draftValue, field.options),
    field
  );
}

function normalizeShopInventoryDraft(
  draft: ShopInventoryDraftState,
  shop: ShopRecord | null
): ShopInventoryDraftState {
  if (!shop) {
    return {
      ...draft,
      fieldDrafts: draft.fieldDrafts ?? {},
      priceDrafts: draft.priceDrafts ?? {}
    };
  }

  const nextDraft = {
    ...draft,
    fieldDrafts: draft.fieldDrafts ?? {},
    priceDrafts: draft.priceDrafts ?? {}
  };
  const rowOrder = normalizeShopInventoryRowOrder(nextDraft, shop);
  return areStringArraysEqual(rowOrder, nextDraft.rowOrder ?? [])
    ? nextDraft
    : {
        ...nextDraft,
        rowOrder
      };
}

function normalizeShopInventoryRowOrder(
  draft: ShopInventoryDraftState,
  shop: ShopRecord
): string[] {
  const removedSlots = new Set(draft.removedSlots);
  const availableKeys = new Set<string>();
  const defaultOrder = [
    ...shop.inventory
      .filter((item) => !removedSlots.has(item.slot))
      .map((item) => getShopExistingRowKey(item.slot)),
    ...draft.addedRows.map((row) => getShopAddedRowKey(row.draftId))
  ];

  for (const key of defaultOrder) {
    availableKeys.add(key);
  }

  const orderedKeys = (draft.rowOrder ?? []).filter((key) => availableKeys.has(key));
  for (const key of defaultOrder) {
    if (!orderedKeys.includes(key)) {
      orderedKeys.push(key);
    }
  }

  return orderedKeys;
}

function createShopInventoryDraftRows(
  shop: ShopRecord | null,
  draft: ShopInventoryDraftState,
  itemOptions: ShopEditableFieldOption[],
  translateLiteral: (literal: string) => string
): ShopInventoryDraftRow[] {
  if (!shop) {
    return [];
  }

  const normalizedDraft = normalizeShopInventoryDraft(draft, shop);
  const inventoryBySlot = new Map(shop.inventory.map((item) => [item.slot, item]));
  const addedRowsById = new Map(normalizedDraft.addedRows.map((row) => [row.draftId, row]));
  const itemOptionsById = new Map(itemOptions.map((option) => [option.value, option]));

  return normalizedDraft.rowOrder
    .map((key, index): ShopInventoryDraftRow | null => {
      const sourceSlot = getShopRowSlot(key);
      if (sourceSlot !== null && Number.isInteger(sourceSlot)) {
        const inventoryItem = inventoryBySlot.get(sourceSlot);
        if (!inventoryItem) {
          return null;
        }

        const itemIdDraft =
          normalizedDraft.itemIdDrafts[sourceSlot] ?? inventoryItem.itemId.toString();
        const parsedItemId = parseEditableIntegerDraft(itemIdDraft, itemOptions);
        const itemOption =
          parsedItemId === null ? undefined : itemOptionsById.get(parsedItemId);
        const isOriginalItem = parsedItemId === inventoryItem.itemId;
        const optionPrice = getShopOptionPrice(itemOption, shop.globalPriceField);
        const price = optionPrice ?? (isOriginalItem ? inventoryItem.price : 0);
        const priceDraft = normalizedDraft.priceDrafts[sourceSlot] ?? price.toString();

        return {
          canEditPrice: inventoryItem.canEditPrice,
          displaySlot: index + 1,
          draftId: null,
          fieldDisplayValues: inventoryItem.fieldDisplayValues,
          fieldValues: inventoryItem.fieldValues,
          isAdded: false,
          isKnownItem: itemOption !== undefined || (isOriginalItem && inventoryItem.isKnownItem),
          itemId: parsedItemId ?? inventoryItem.itemId,
          itemIdDraft,
          itemName:
            itemOption?.itemName ??
            (isOriginalItem
              ? inventoryItem.itemName
              : formatShopItemFallbackOption(itemIdDraft, translateLiteral)),
          key,
          parsedItemId,
          parsedPrice: parseEditableIntegerDraft(priceDraft),
          price,
          priceDraft,
          priceField: inventoryItem.priceField,
          rowId: inventoryItem.rowId ?? key,
          sourceSlot,
          stockLimit: isOriginalItem ? inventoryItem.stockLimit : null,
          supportedFields: inventoryItem.supportedFields
        };
      }

      const draftId = getShopRowDraftId(key);
      if (draftId === null || !Number.isInteger(draftId)) {
        return null;
      }

      const addedRow = addedRowsById.get(draftId);
      if (!addedRow) {
        return null;
      }

      const parsedItemId = parseEditableIntegerDraft(addedRow.itemIdDraft, itemOptions);
      const itemOption =
        parsedItemId === null ? undefined : itemOptionsById.get(parsedItemId);
      const price = getShopOptionPrice(itemOption, shop.globalPriceField) ?? 0;
      const priceDraft = addedRow.priceDraft ?? price.toString();

      return {
        canEditPrice: true,
        displaySlot: index + 1,
        draftId,
        fieldDisplayValues: {},
        fieldValues: {},
        isAdded: true,
        isKnownItem: itemOption !== undefined,
        itemId: parsedItemId ?? 0,
        itemIdDraft: addedRow.itemIdDraft,
        itemName:
          itemOption?.itemName ?? formatShopItemFallbackOption(addedRow.itemIdDraft, translateLiteral),
        key,
        parsedItemId,
        parsedPrice: parseEditableIntegerDraft(priceDraft),
        price,
        priceDraft,
        priceField: null,
        rowId: key,
        sourceSlot: null,
        stockLimit: null,
        supportedFields: []
      };
    })
    .filter((row): row is ShopInventoryDraftRow => row !== null);
}

function getShopOptionPrice(
  option: ShopEditableFieldOption | undefined,
  priceField: string | null
) {
  if (!option) {
    return undefined;
  }

  return priceField === null ? option.price : (option.prices[priceField] ?? option.price);
}

function moveShopInventoryDraftRow(
  draft: ShopInventoryDraftState,
  shop: ShopRecord,
  rowKey: string,
  direction: -1 | 1
): ShopInventoryDraftState {
  const rowOrder = normalizeShopInventoryRowOrder(draft, shop);
  const currentIndex = rowOrder.indexOf(rowKey);
  const nextIndex = currentIndex + direction;
  if (currentIndex < 0 || nextIndex < 0 || nextIndex >= rowOrder.length) {
    return draft;
  }

  const nextRowOrder = [...rowOrder];
  [nextRowOrder[currentIndex], nextRowOrder[nextIndex]] = [
    nextRowOrder[nextIndex]!,
    nextRowOrder[currentIndex]!
  ];

  return {
    ...draft,
    rowOrder: nextRowOrder
  };
}

function removeShopInventoryDraftRow(
  draft: ShopInventoryDraftState,
  row: ShopInventoryDraftRow
): ShopInventoryDraftState {
  if (row.sourceSlot !== null) {
    return draft.removedSlots.includes(row.sourceSlot)
      ? draft
      : {
          ...draft,
          removedSlots: [...draft.removedSlots, row.sourceSlot],
          rowOrder: draft.rowOrder.filter((key) => key !== row.key)
        };
  }

  if (row.draftId === null) {
    return draft;
  }

  return {
    ...draft,
    addedRows: draft.addedRows.filter((draftRow) => draftRow.draftId !== row.draftId),
    rowOrder: draft.rowOrder.filter((key) => key !== row.key)
  };
}

function clearShopInventoryRowPriceDraft(
  draft: ShopInventoryDraftState,
  row: ShopInventoryDraftRow
): ShopInventoryDraftState {
  const nextDraft = {
    ...draft,
    priceDrafts: {
      ...draft.priceDrafts
    }
  };

  if (row.sourceSlot !== null) {
    delete nextDraft.priceDrafts[row.sourceSlot];
  }

  if (row.draftId !== null) {
    nextDraft.addedRows = nextDraft.addedRows.map((draftRow) => {
      if (draftRow.draftId !== row.draftId || draftRow.priceDraft === undefined) {
        return draftRow;
      }

      const nextRow = { ...draftRow };
      delete nextRow.priceDraft;
      return nextRow;
    });
  }

  return nextDraft;
}

function setShopItemPriceDraft(
  draft: ShopInventoryDraftState,
  rows: ShopInventoryDraftRow[],
  targetRow: ShopInventoryDraftRow,
  value: string
): ShopInventoryDraftState {
  if (targetRow.parsedItemId === null) {
    return draft;
  }

  const matchingDraftIds = new Set<number>();
  const nextPriceDrafts = { ...draft.priceDrafts };
  for (const row of rows) {
    if (row.parsedItemId !== targetRow.parsedItemId) {
      continue;
    }

    if (row.sourceSlot !== null) {
      nextPriceDrafts[row.sourceSlot] = value;
    }

    if (row.draftId !== null) {
      matchingDraftIds.add(row.draftId);
    }
  }

  return {
    ...draft,
    addedRows: draft.addedRows.map((row) =>
      matchingDraftIds.has(row.draftId) ? { ...row, priceDraft: value } : row
    ),
    priceDrafts: nextPriceDrafts
  };
}

function overlayShopWorkflowItemPrices(
  workflow: ShopsWorkflow,
  priceChanges: ShopItemPriceChange[]
): ShopsWorkflow {
  const pricesByFieldAndItemId = new Map<string, Map<number, number>>();
  for (const change of priceChanges) {
    const price = Number.parseInt(change.value, 10);
    if (Number.isInteger(price)) {
      const pricesByItemId =
        pricesByFieldAndItemId.get(change.field) ?? new Map<number, number>();
      pricesByItemId.set(change.itemId, price);
      pricesByFieldAndItemId.set(change.field, pricesByItemId);
    }
  }

  if (pricesByFieldAndItemId.size === 0) {
    return workflow;
  }

  return {
    ...workflow,
    editableFields: workflow.editableFields.map((field) =>
      field.field !== shopItemIdFieldName
        ? field
        : {
            ...field,
            options: field.options.map((option) => {
              let nextOption = option;
              for (const [priceField, pricesByItemId] of pricesByFieldAndItemId) {
                const price = pricesByItemId.get(option.value);
                if (price === undefined) {
                  continue;
                }

                nextOption = {
                  ...nextOption,
                  price: priceField === buyPriceFieldName ? price : nextOption.price,
                  prices: {
                    ...nextOption.prices,
                    [priceField]: price
                  }
                };
              }

              return nextOption;
            })
          }
    ),
    shops: workflow.shops.map((shop) => ({
      ...shop,
      inventory: shop.inventory.map((item) => {
        const price =
          shop.globalPriceField === null
            ? undefined
            : pricesByFieldAndItemId.get(shop.globalPriceField)?.get(item.itemId);
        return price !== undefined
          ? {
              ...item,
              price
            }
          : item;
      })
    }))
  };
}

function isBadgeShopRecord(shop: ShopRecord) {
  return (
    shop.inventoryCount === 9 &&
    (shop.name.toLocaleLowerCase().includes('0-8 badges') ||
      shop.inventoryLabel.toLocaleLowerCase().includes('badge'))
  );
}

type EncountersSectionProps = {
  editSession: EditSession | null;
  editorFamily: EditorUiFamily;
  isEditStarting: boolean;
  isEncounterUpdating: boolean;
  onSearchChange: (searchText: string) => void;
  onSelectTable: (tableId: string | null) => void;
  onStartEditSession: () => void;
  onUpdateEncounterSlotFields: (
    tableId: string,
    slot: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  onUpdateEncounterSlotUpdates: (updates: EncounterSlotFieldUpdate[]) => Promise<boolean>;
  searchText: string;
  selectedTableId: string | null;
  workflow: EncountersWorkflow | null;
};

type EncountersSectionPublicProps = Omit<EncountersSectionProps, 'editorFamily'>;

function SwShEncountersSection(props: EncountersSectionPublicProps) {
  return <EncountersSection {...props} editorFamily="swsh" />;
}

function SvEncountersSection(props: EncountersSectionPublicProps) {
  return <EncountersSection {...props} editorFamily="sv" />;
}

function ZaEncountersSection(props: EncountersSectionPublicProps) {
  return <EncountersSection {...props} editorFamily="za" />;
}

function EncountersSection({
  editSession,
  editorFamily,
  isEditStarting,
  isEncounterUpdating,
  onSearchChange,
  onSelectTable,
  onStartEditSession,
  onUpdateEncounterSlotFields,
  onUpdateEncounterSlotUpdates,
  searchText,
  selectedTableId,
  workflow
}: EncountersSectionProps) {
  const [selectedSlot, setSelectedSlot] = useState<number | null>(null);
  const allTables = workflow?.tables ?? [];
  const filteredTables = useMemo(
    () => filterEncounterTables(allTables, searchText),
    [allTables, searchText]
  );
  const selectedTableFromId =
    filteredTables.find((table) => table.tableId === selectedTableId) ?? null;
  const selectedTable = selectedTableFromId ?? getDefaultEncounterTable(filteredTables);
  const tableRows = useMemo(
    () => buildEncounterTableRows(filteredTables, selectedTable),
    [filteredTables, selectedTable]
  );
  const selectedZoneKey = selectedTable ? getEncounterTableZoneKey(selectedTable) : null;
  const selectedEncounterSlot =
    selectedTable?.slots.find((slot) => slot.slot === selectedSlot) ??
    selectedTable?.slots[0] ??
    null;
  const selectedTableIsScarletViolet = selectedTable
    ? isScarletVioletEncounterTable(selectedTable)
    : false;
  const areaTabs = useMemo(
    () =>
      selectedTable && workflow && !selectedTableIsScarletViolet
        ? buildEncounterAreaTabs(selectedTable, workflow.tables)
        : [],
    [selectedTable, selectedTableIsScarletViolet, workflow]
  );
  const conditionTabs = useMemo(
    () =>
      selectedTable && workflow && !selectedTableIsScarletViolet
        ? buildEncounterConditionTabs(selectedTable, workflow.tables)
        : [],
    [selectedTable, selectedTableIsScarletViolet, workflow]
  );
  const canEditEncounters = workflow?.summary.availability === 'available';
  const pendingEncounterTableIds = getPendingEncounterTableIds(editSession, workflow);

  useEffect(() => {
    if (!selectedTable) {
      setSelectedSlot(null);
      return;
    }

    const hasSelectedSlot = selectedTable.slots.some((slot) => slot.slot === selectedSlot);
    if (!hasSelectedSlot) {
      setSelectedSlot(selectedTable.slots[0]?.slot ?? null);
    }
  }, [selectedSlot, selectedTable?.slots, selectedTable?.tableId]);

  return (
    <>
      <section
        aria-labelledby="encounters-heading"
        className={`panel wide-panel ${editorFamily}-editor-surface ${editorFamily}-encounters-section`}
      >
        <div className="panel-heading">
          <Layers aria-hidden="true" size={18} />
          <h2 id="encounters-heading">Wild Encounters</h2>
        </div>

        <div className="items-toolbar encounters-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label="Search encounters"
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder="Search encounters"
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label="Loaded tables"
            value={workflow ? workflow.stats.totalTableCount.toString() : '0'}
          />
          <Metric
            label="Encounter slots"
            value={workflow ? workflow.stats.totalSlotCount.toString() : '0'}
          />
          <Metric
            label="Pending changes"
            value={(editSession?.pendingEdits.length ?? 0).toString()}
          />
        </div>

        {workflow ? (
          <div className="encounters-layout">
            <div className="encounters-table" role="table" aria-label="Encounter tables">
              <div className="encounters-row encounters-row-heading" role="row">
                <span role="columnheader">
                  {editorFamily === 'za' ? 'Location / Event' : 'Location'}
                </span>
                <span role="columnheader">
                  {editorFamily === 'za' ? 'Entries' : 'Game'}
                </span>
                <span role="columnheader">
                  {editorFamily === 'za' ? 'Preview' : 'Areas'}
                </span>
              </div>
              {tableRows.map((tableRow, rowIndex) => {
                const showSection =
                  editorFamily === 'za' &&
                  (rowIndex === 0 ||
                    tableRows[rowIndex - 1]?.sectionLabel !== tableRow.sectionLabel);

                return (
                  <Fragment key={tableRow.zoneKey}>
                    {showSection ? (
                      <div
                        aria-label={tableRow.sectionLabel ?? undefined}
                        className="encounters-row encounters-section-row"
                        role="row"
                      >
                        <span role="cell">{tableRow.sectionLabel ?? ''}</span>
                        <span role="cell" />
                        <span role="cell" />
                      </div>
                    ) : null}
                    <button
                      className={`encounters-row ${
                        selectedZoneKey === tableRow.zoneKey ? 'encounters-row-selected' : ''
                      } ${
                        tableRow.tableIds.some((tableId) => pendingEncounterTableIds.has(tableId))
                          ? 'encounters-row-pending'
                          : ''
                      }`}
                      onClick={() => onSelectTable(tableRow.table.tableId)}
                      role="row"
                      type="button"
                    >
                      <span role="cell">{tableRow.location}</span>
                      <span role="cell">
                        {editorFamily === 'za'
                          ? formatZaEncounterSpawnerCount(tableRow.tableIds.length)
                          : tableRow.gameVersion}
                      </span>
                      <span role="cell">{tableRow.areaLabel}</span>
                    </button>
                  </Fragment>
                );
              })}
            </div>

            <SelectedEncounterPanel
              areaTabs={areaTabs}
              canEditEncounters={canEditEncounters}
              editSession={editSession}
              editorFamily={editorFamily}
              editableFields={workflow.editableFields}
              encounterSlot={selectedEncounterSlot}
              conditionTabs={conditionTabs}
              isEditStarting={isEditStarting}
              isEncounterUpdating={isEncounterUpdating}
              onSelectSlot={setSelectedSlot}
              onSelectTable={onSelectTable}
              onStartEditSession={onStartEditSession}
              onUpdateEncounterSlotFields={onUpdateEncounterSlotFields}
              onUpdateEncounterSlotUpdates={onUpdateEncounterSlotUpdates}
              pendingTableIds={pendingEncounterTableIds}
              selectedSlot={selectedSlot}
              table={selectedTable}
              tables={workflow.tables}
            />
          </div>
        ) : (
          <p className="empty-copy">Open Wild Encounters from the sidebar to load backend wild data.</p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
    </>
  );
}

function SelectedEncounterPanel({
  areaTabs,
  canEditEncounters,
  conditionTabs,
  editSession,
  editorFamily,
  editableFields,
  encounterSlot,
  isEditStarting,
  isEncounterUpdating,
  onSelectSlot,
  onSelectTable,
  onStartEditSession,
  onUpdateEncounterSlotFields,
  onUpdateEncounterSlotUpdates,
  pendingTableIds,
  selectedSlot,
  table,
  tables
}: {
  areaTabs: EncounterAreaTab[];
  canEditEncounters: boolean;
  conditionTabs: EncounterConditionTab[];
  editSession: EditSession | null;
  editorFamily: EditorUiFamily;
  editableFields: EncounterEditableField[];
  encounterSlot: EncounterSlotRecord | null;
  isEditStarting: boolean;
  isEncounterUpdating: boolean;
  onSelectSlot: (slot: number | null) => void;
  onSelectTable: (tableId: string | null) => void;
  onStartEditSession: () => void;
  onUpdateEncounterSlotFields: (
    tableId: string,
    slot: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  onUpdateEncounterSlotUpdates: (updates: EncounterSlotFieldUpdate[]) => Promise<boolean>;
  pendingTableIds: ReadonlySet<string>;
  selectedSlot: number | null;
  table: EncounterTableRecord | null;
  tables: EncounterTableRecord[];
}) {
  const [draftsBySlotKey, setDraftsBySlotKey] = useState<
    Record<string, Record<string, string>>
  >({});
  const [levelDraftsByTableId, setLevelDraftsByTableId] = useState<
    Record<string, Record<string, string>>
  >({});
  const [areaCopyRequest, setAreaCopyRequest] = useState<EncounterAreaCopyRequest | null>(null);
  const cancelActiveEditSession = useCancelActiveEditSession();
  const { t } = useLocalization();
  const defaultEncounterFields = useMemo(
    () =>
      editableFields.map((field) => {
        const numericField = toNumericEditableControlField(
          field,
          encounterSlot
            ? getContextualFieldOptions(field, {
                species: encounterSlot.species,
                speciesId: encounterSlot.speciesId
              })
            : undefined
        );
        return contextualizeZaEncounterField(numericField, encounterSlot, editorFamily);
      }),
    [
      editableFields,
      editorFamily,
      encounterSlot?.alphaChancePercent,
      encounterSlot?.isAlpha,
      encounterSlot?.species,
      encounterSlot?.speciesId
    ]
  );
  const encounterDraftDefaults = useMemo(
    () =>
      encounterSlot
        ? createTrainerDrafts(defaultEncounterFields, (field) =>
            getEditableEncounterFieldValue(encounterSlot, field)
          )
        : {},
    [
      defaultEncounterFields,
      encounterSlot?.alphaChancePercent,
      encounterSlot?.alphaLevelBonus,
      encounterSlot?.form,
      encounterSlot?.isAlpha,
      encounterSlot?.levelMax,
      encounterSlot?.levelMin,
      encounterSlot?.slot,
      encounterSlot?.speciesId,
      encounterSlot?.weight,
      table?.tableId
    ]
  );
  const encounterDraftKey =
    table && encounterSlot
      ? editorFamily === 'za'
        ? getZaEncounterGroupKey(table.tableId, encounterSlot)
        : `${table.tableId}:${encounterSlot.slot}`
      : null;
  const encounterLevelDraftKey =
    editorFamily === 'swsh' && table ? table.tableId : null;
  const encounterSlotDraftDefaults = useMemo<Record<string, string>>(
    () =>
      editorFamily === 'swsh'
        ? Object.fromEntries(
            Object.entries(encounterDraftDefaults).filter(
              ([field]) =>
                field !== encounterLevelMinFieldName && field !== encounterLevelMaxFieldName
            )
          )
        : encounterDraftDefaults,
    [editorFamily, encounterDraftDefaults]
  );
  const encounterLevelDraftDefaults = useMemo<Record<string, string>>(
    () => {
      if (!encounterLevelDraftKey) {
        return {};
      }

      const defaults: Record<string, string> = {};
      defaults[encounterLevelMinFieldName] =
        encounterDraftDefaults[encounterLevelMinFieldName] ?? '';
      defaults[encounterLevelMaxFieldName] =
        encounterDraftDefaults[encounterLevelMaxFieldName] ?? '';
      return defaults;
    },
    [encounterDraftDefaults, encounterLevelDraftKey]
  );
  const slotDrafts = encounterDraftKey
    ? draftsBySlotKey[encounterDraftKey] ?? encounterSlotDraftDefaults
    : {};
  const drafts = encounterLevelDraftKey
    ? {
        ...slotDrafts,
        ...(levelDraftsByTableId[encounterLevelDraftKey] ?? encounterLevelDraftDefaults)
      }
    : slotDrafts;
  const isSelectedZaGuaranteedAlpha =
    editorFamily === 'za' && encounterSlot !== null && isZaGuaranteedAlphaSlot(encounterSlot);
  const linkedZaAlphaReferenceKinds = useMemo(() => {
    const result = { hasOrdinary: false, hasSpecial: false };
    if (editorFamily !== 'za' || !encounterDraftKey) {
      return result;
    }

    for (const candidateTable of tables) {
      for (const candidateSlot of candidateTable.slots) {
        if (
          getZaEncounterGroupKey(candidateTable.tableId, candidateSlot) !== encounterDraftKey
        ) {
          continue;
        }

        if (candidateSlot.isAlpha === true) {
          result.hasSpecial = true;
        } else {
          result.hasOrdinary = true;
        }
      }
    }

    return result;
  }, [editorFamily, encounterDraftKey, tables]);
  const hasMixedLinkedZaAlphaReferences =
    linkedZaAlphaReferenceKinds.hasSpecial && linkedZaAlphaReferenceKinds.hasOrdinary;
  const isSelectedZaAlphaChanceUnavailable =
    editorFamily === 'za' &&
    encounterSlot !== null &&
    getZaAlphaChancePercent(encounterSlot) === null;
  const isSelectedZaAlphaLevelBonusUnavailable =
    editorFamily === 'za' &&
    encounterSlot !== null &&
    typeof encounterSlot.alphaLevelBonus !== 'number';
  const isZaAlphaChanceReadOnly =
    isSelectedZaGuaranteedAlpha ||
    linkedZaAlphaReferenceKinds.hasSpecial ||
    isSelectedZaAlphaChanceUnavailable;
  const selectedPlacementDrafts = useMemo(() => {
    if (!encounterSlot) {
      return drafts;
    }

    let nextDrafts = drafts;
    if (isZaAlphaChanceReadOnly) {
      const fixedChance = getEditableEncounterFieldValue(
        encounterSlot,
        zaEncounterAlphaChanceFieldName
      );
      nextDrafts = {
        ...nextDrafts,
        [zaEncounterAlphaChanceFieldName]: fixedChance?.toString() ?? ''
      };
    }
    if (isSelectedZaAlphaLevelBonusUnavailable) {
      nextDrafts = {
        ...nextDrafts,
        [zaEncounterAlphaLevelBonusFieldName]: ''
      };
    }
    return nextDrafts;
  }, [
    drafts,
    encounterSlot,
    isSelectedZaAlphaLevelBonusUnavailable,
    isZaAlphaChanceReadOnly
  ]);
  const alphaChanceDisabledReason = isSelectedZaAlphaChanceUnavailable
    ? t('za.alphaSettings.unavailableDisabled')
    : hasMixedLinkedZaAlphaReferences
      ? t('za.alphaSettings.mixedDisabled')
      : isSelectedZaGuaranteedAlpha
        ? t('za.alphaSettings.guaranteedDisabled')
        : linkedZaAlphaReferenceKinds.hasSpecial
          ? t('za.alphaSettings.specialReferenceDisabled')
          : undefined;
  const alphaLevelBonusDisabledReason = isSelectedZaAlphaLevelBonusUnavailable
    ? t('za.alphaSettings.levelBonusUnavailableDisabled')
    : undefined;
  const encounterFormOptionContext = useMemo(
    () =>
      encounterSlot
        ? createDraftSpeciesFormOptionContext(
            defaultEncounterFields.find(
              (field) => field.field === encounterSpeciesFieldName
            ) ?? null,
            selectedPlacementDrafts[encounterSpeciesFieldName],
            encounterSlot.species,
            encounterSlot.speciesId,
            undefined,
            editorFamily
          )
        : undefined,
    [defaultEncounterFields, selectedPlacementDrafts, editorFamily, encounterSlot]
  );
  const encounterFields = useMemo(
    () =>
      editableFields.map((field) => {
        const numericField = toNumericEditableControlField(
          field,
          encounterSlot ? getContextualFieldOptions(field, encounterFormOptionContext) : undefined
        );
        return contextualizeZaEncounterField(numericField, encounterSlot, editorFamily);
      }),
    [editableFields, encounterFormOptionContext, encounterSlot, editorFamily]
  );
  const encounterFieldGroups = useMemo(
    () => groupNumericEditableFields(encounterFields, getEncounterEditableFieldGroup),
    [encounterFields]
  );
  const encounterDraftSummary = useMemo(
    () =>
      getTrainerDraftSummary(
        encounterFields,
        selectedPlacementDrafts,
        encounterSlot ? (field) => getEditableEncounterFieldValue(encounterSlot, field) : null
      ),
    [selectedPlacementDrafts, encounterFields, encounterSlot]
  );
  useRegisterEditorDraftDirty(
    'encounters',
    countFieldDraftRecords(draftsBySlotKey) +
      countFieldDraftRecords(levelDraftsByTableId) >
      0
  );
  const isSvEncounterTable = table ? isScarletVioletEncounterTable(table) : false;
  const isZaEncounterTable = table ? isPokemonLegendsZAEncounterTable(table) : false;
  const isSwShEncounterTable = table !== null && !isSvEncounterTable && !isZaEncounterTable;
  const encounterLevelFieldNames = [encounterLevelMinFieldName, encounterLevelMaxFieldName];
  const encounterLevelChanges = encounterSlot
    ? getOrderedEncounterLevelChanges(encounterSlot, encounterDraftSummary.changedFields)
    : [];
  const hasChangedEncounterLevelDraft = encounterDraftSummary.changedFields.some((field) =>
    encounterLevelFieldNames.includes(field.field)
  );
  const hasInvalidEncounterLevelDraft = encounterDraftSummary.invalidFields.some((field) =>
    encounterLevelFieldNames.includes(field.field)
  );
  const hasInvalidEncounterLevelPair =
    hasChangedEncounterLevelDraft &&
    !hasInvalidEncounterLevelDraft &&
    encounterLevelChanges.length === 0;
  const encounterStageChanges = [
    ...encounterDraftSummary.changedFields.filter(
      (change) => !encounterLevelFieldNames.includes(change.field)
    ),
    ...encounterLevelChanges
  ];
  const encounterLevelConditionUpdates =
    table && isSwShEncounterTable
      ? createEncounterLevelConditionUpdates(table, tables, encounterLevelChanges)
      : [];
  const canSaveEncounterDrafts =
    table !== null &&
    encounterSlot !== null &&
    editSession !== null &&
    canEditEncounters &&
    !isEncounterUpdating &&
    encounterDraftSummary.changedFields.length > 0 &&
    encounterDraftSummary.invalidFields.length === 0 &&
    !hasInvalidEncounterLevelPair;
  const workflowHasZaAlphaChanceField = editableFields.some(
    (field) => field.field === zaEncounterAlphaChanceFieldName
  );
  const workflowHasZaAlphaLevelBonusField = editableFields.some(
    (field) => field.field === zaEncounterAlphaLevelBonusFieldName
  );
  const zaAlphaChanceDisplay =
    isZaEncounterTable && encounterSlot
      ? formatZaAlphaChance(encounterSlot, t) ??
        (workflowHasZaAlphaChanceField ? t('za.alphaSettings.unavailable') : null)
      : null;
  const zaAlphaLevelBonusDisplay =
    isZaEncounterTable && encounterSlot
      ? formatZaAlphaLevelBonus(encounterSlot, t) ??
        (workflowHasZaAlphaLevelBonusField
          ? t('za.alphaSettings.unavailable')
          : null)
      : null;
  const zaAlphaLevelRangeDisplay =
    isZaEncounterTable && encounterSlot ? formatZaAlphaLevelRange(encounterSlot, t) : null;
  const canClearEncounterSlot =
    table !== null &&
    encounterSlot !== null &&
    editSession !== null &&
    canEditEncounters &&
    !isEncounterUpdating &&
    !isSvEncounterTable &&
    !isZaEncounterTable &&
    (encounterSlot.speciesId !== 0 || encounterSlot.form !== 0 || encounterSlot.weight !== 0);
  const canApplyEncounterLevelsToScope =
    table !== null &&
    encounterSlot !== null &&
    editSession !== null &&
    canEditEncounters &&
    !isEncounterUpdating &&
    (isSwShEncounterTable
      ? encounterLevelConditionUpdates.length > 0
      : encounterLevelChanges.length > 0) &&
    !hasInvalidEncounterLevelDraft;
  const areaCopyTargetArea =
    table?.area === 'Symbol' ? 'Hidden' : table?.area === 'Hidden' ? 'Symbol' : null;
  const areaCopyTargetTable =
    areaCopyTargetArea === null
      ? null
      : areaTabs.find((areaTab) => areaTab.label === areaCopyTargetArea)?.table ?? null;
  const preparedAreaCopyRequest =
    table && areaCopyTargetArea
      ? createEncounterAreaCopyRequest(table, tables, areaCopyTargetArea)
      : null;
  const canPrepareEncounterAreaCopy =
    table !== null &&
    preparedAreaCopyRequest !== null &&
    editSession !== null &&
    canEditEncounters &&
    !isEncounterUpdating;
  const encounterAreaCopyDisabledTitle =
    editSession === null
      ? 'Start editing before copying encounters.'
      : areaCopyTargetTable === null
      ? `${areaCopyTargetArea ?? 'Target'} encounters are not available for this location.`
      : preparedAreaCopyRequest === null
      ? 'No matching destination conditions or slots are available to copy.'
      : undefined;
  const svEncounterFacets = table ? parseSvEncounterFacets(table) : null;
  const displayedEncounterSlots = table?.slots ?? [];
  const encounterWeightTotal = displayedEncounterSlots.reduce(
    (total, slot) => total + slot.weight,
    0
  );

  useEffect(() => {
    if (!encounterDraftKey) {
      return;
    }

    setDraftsBySlotKey((currentDrafts) =>
      pruneFieldDraftRecord(currentDrafts, encounterDraftKey, encounterSlotDraftDefaults)
    );
  }, [encounterDraftKey, encounterSlotDraftDefaults]);

  useEffect(() => {
    if (!encounterLevelDraftKey) {
      return;
    }

    setLevelDraftsByTableId((currentDrafts) =>
      pruneFieldDraftRecord(
        currentDrafts,
        encounterLevelDraftKey,
        encounterLevelDraftDefaults
      )
    );
  }, [encounterLevelDraftDefaults, encounterLevelDraftKey]);

  return (
    <aside aria-label="Selected encounter provenance" className="encounter-inspector">
      <div className="panel-heading">
        <ShieldCheck aria-hidden="true" size={18} />
        <h3>Selected Encounter</h3>
      </div>

      {table ? (
        <>
          <dl className="item-provenance-list">
            <div>
              <dt>Location</dt>
              <dd>{table.location}</dd>
            </div>
            {isZaEncounterTable && table.locationDetails ? (
              <div>
                <dt>Mission</dt>
                <dd>{table.locationDetails}</dd>
              </div>
            ) : null}
            {!svEncounterFacets ? (
              <div>
                <dt>{isZaEncounterTable ? 'Spawner' : 'Table'}</dt>
                <dd>{isZaEncounterTable ? table.tableLabel ?? table.tableId : table.tableId}</dd>
              </div>
            ) : null}
            {isZaEncounterTable && table.locationKey ? (
              <div>
                <dt>Group</dt>
                <dd>{getZaEncounterZoneFamily(table).label}</dd>
              </div>
            ) : null}
            <div>
              <dt>Archive member</dt>
              <dd>{table.archiveMember}</dd>
            </div>
            <div>
              <dt>Source file</dt>
              <dd>{table.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>Layer</dt>
              <dd>{formatSourceLayer(table.provenance.sourceLayer)}</dd>
            </div>
            <div>
              <dt>File state</dt>
              <dd>{formatFileState(table.provenance.fileState)}</dd>
            </div>
          </dl>

          {isSvEncounterTable ? (
            <SvEncounterConditionBrowser
              onSelectTable={onSelectTable}
              table={table}
              tables={tables}
            />
          ) : null}
          {isZaEncounterTable ? (
            <ZaEncounterGroupBrowser
              onSelectReference={(tableId, slot) => {
                onSelectSlot(slot);
                onSelectTable(tableId);
              }}
              pendingRecordIds={getPendingEncounterRecordIds(editSession)}
              selectedSlot={selectedSlot}
              table={table}
              tables={tables}
            />
          ) : null}

          <div className="encounter-edit-form">
            {!isSvEncounterTable && !isZaEncounterTable && areaTabs.length > 0 ? (
              <div
                className="encounter-area-tabs"
                role="tablist"
                aria-label="Encounter area"
              >
                {areaTabs.map((areaTab) => {
                  const hasPendingChanges = areaTab.tableIds.some((tableId) =>
                    pendingTableIds.has(tableId)
                  );
                  return (
                    <button
                      aria-label={`${areaTab.label}${hasPendingChanges ? ' (pending changes)' : ''}`}
                      aria-selected={areaTab.label === table.area}
                      className={`condition-tab-button ${
                        areaTab.isAvailable ? '' : 'condition-tab-button-unavailable'
                      } ${hasPendingChanges ? 'condition-tab-button-pending' : ''}`}
                      disabled={!areaTab.isAvailable}
                      key={areaTab.label}
                      onClick={() => {
                        if (areaTab.tableId) {
                          onSelectTable(areaTab.tableId);
                        }
                      }}
                      role="tab"
                      title={
                        areaTab.isAvailable
                          ? areaTab.title
                          : `${areaTab.label} encounters are not available for this location.`
                      }
                      type="button"
                    >
                      {areaTab.label}
                    </button>
                  );
                })}
              </div>
            ) : null}

            {!isSvEncounterTable && !isZaEncounterTable && conditionTabs.length > 0 ? (
              <div
                className="encounter-condition-tabs"
                role="tablist"
                aria-label="Encounter conditions"
              >
                {conditionTabs.map((conditionTab) => {
                  const hasPendingChanges =
                    conditionTab.tableId !== null && pendingTableIds.has(conditionTab.tableId);
                  return (
                    <button
                      aria-label={`${conditionTab.label}${hasPendingChanges ? ' (pending changes)' : ''}`}
                      aria-selected={conditionTab.tableId === table.tableId}
                      className={`condition-tab-button ${
                        conditionTab.isAvailable ? '' : 'condition-tab-button-unavailable'
                      } ${hasPendingChanges ? 'condition-tab-button-pending' : ''}`}
                      disabled={!conditionTab.isAvailable}
                      key={conditionTab.label}
                      onClick={() => {
                        if (conditionTab.tableId) {
                          onSelectTable(conditionTab.tableId);
                        }
                      }}
                      role="tab"
                      title={
                        conditionTab.isAvailable
                          ? conditionTab.label
                          : `${conditionTab.label} is not available for this location.`
                      }
                      type="button"
                    >
                      {conditionTab.label}
                    </button>
                  );
                })}
              </div>
            ) : null}

            {!isSvEncounterTable && !isZaEncounterTable && areaCopyTargetArea ? (
              <div className="encounter-area-copy-actions">
                <button
                  className="secondary-button"
                  disabled={!canPrepareEncounterAreaCopy}
                  onClick={() => {
                    if (!preparedAreaCopyRequest || !canPrepareEncounterAreaCopy) {
                      return;
                    }

                    setAreaCopyRequest(preparedAreaCopyRequest);
                  }}
                  title={
                    encounterAreaCopyDisabledTitle ??
                    `Copy this ${table.area} table to ${areaCopyTargetArea}.`
                  }
                  type="button"
                >
                  <ArrowLeftRight aria-hidden="true" size={16} />
                  <span>Apply to {areaCopyTargetArea}</span>
                </button>
              </div>
            ) : null}

            <div className="encounter-slot-header">
              <strong>Slots</strong>
              <span
                className={
                  isSvEncounterTable || encounterWeightTotal === 100
                    ? 'encounter-total-status'
                    : 'encounter-total-status encounter-total-warning'
                }
              >
                {isSvEncounterTable
                  ? `Total lot weight: ${encounterWeightTotal}`
                  : `Total chance: ${encounterWeightTotal}%`}
              </span>
            </div>

            {encounterSlot ? (
              <>
                <div className="encounter-slot-tabs" aria-label="Encounter slot list">
                  {displayedEncounterSlots.map((slot) => {
                    const slotLabel = formatEncounterSlotSpeciesLabel(slot, editorFamily);
                    const slotSpriteLabel = formatSpeciesFormLabel(
                      slot.species,
                      slot.form,
                      slot.speciesId,
                      editorFamily
                    );
                    const slotBadge = formatEncounterSlotBadge(slot, {
                      isScarletViolet: isSvEncounterTable,
                      isPokemonLegendsZA: isZaEncounterTable
                    });

                    return (
                      <button
                        aria-pressed={slot.slot === selectedSlot}
                        className="slot-tab-button"
                        key={slot.slot}
                        onClick={() => onSelectSlot(slot.slot)}
                        type="button"
                      >
                        <PokemonSprite className="slot-tab-sprite" name={slotSpriteLabel} preferStatic />
                        <strong>{slotBadge}</strong>
                        <span>{slotLabel}</span>
                        {isZaEncounterTable &&
                        (slot.isAlpha ||
                          typeof slot.contributesToWildZoneCompletion === 'boolean') ? (
                          <div className="slot-tab-pills">
                            {slot.isAlpha ? <span className="slot-tab-pill">Alpha</span> : null}
                            {typeof slot.contributesToWildZoneCompletion === 'boolean' ? (
                              <span
                                className={`slot-tab-pill za-wild-zone-completion-status za-wild-zone-completion-status-${
                                  slot.contributesToWildZoneCompletion
                                    ? 'contributing'
                                    : 'excluded'
                                }`}
                              >
                                {t(
                                  getZaWildZoneCompletionStatusKey(
                                    slot.contributesToWildZoneCompletion
                                      ? 'contributing'
                                      : 'excluded'
                                  )
                                )}
                              </span>
                            ) : null}
                          </div>
                        ) : null}
                        <small>
                          {formatEncounterSlotWeightSummary(
                            slot,
                            encounterWeightTotal,
                            isSvEncounterTable
                          )}
                        </small>
                      </button>
                    );
                  })}
                </div>
                {isSvEncounterTable && displayedEncounterSlots.length === 1 ? (
                  <p className="empty-copy sv-encounter-slot-note">
                    This exact S/V condition row has one slot. Use the condition browser above to
                    inspect adjacent rows for this location.
                  </p>
                ) : null}

                <dl className="encounter-slot-detail">
                  <div>
                    <dt>Species</dt>
                    <dd>
                      {formatEncounterSlotSpeciesLabel(encounterSlot, editorFamily)}
                    </dd>
                  </div>
                  {isZaEncounterTable ? (
                    <div>
                      <dt>Encounter type</dt>
                      <dd>{encounterSlot.encounterKind ?? (encounterSlot.isAlpha ? 'Alpha' : 'Wild')}</dd>
                    </div>
                  ) : null}
                  {isZaEncounterTable && encounterSlot.encounterDataId ? (
                    <div>
                      <dt>Encounter data</dt>
                      <dd>{encounterSlot.encounterDataId}</dd>
                    </div>
                  ) : null}
                  <div>
                    <dt>Levels</dt>
                    <dd>
                      {encounterSlot.levelMin}-{encounterSlot.levelMax}
                    </dd>
                  </div>
                  <div>
                    <dt>{isSvEncounterTable ? 'Lot weight' : 'Probability'}</dt>
                    <dd>{encounterSlot.weight}</dd>
                  </div>
                  {zaAlphaChanceDisplay ? (
                    <div>
                      <dt>{t('za.alphaSettings.chanceLabel')}</dt>
                      <dd>{zaAlphaChanceDisplay}</dd>
                    </div>
                  ) : null}
                  {zaAlphaLevelBonusDisplay ? (
                    <div>
                      <dt>{t('za.alphaSettings.levelBonusLabel')}</dt>
                      <dd>{zaAlphaLevelBonusDisplay}</dd>
                    </div>
                  ) : null}
                  {zaAlphaLevelRangeDisplay ? (
                    <div>
                      <dt>{t('za.alphaSettings.levelRangeLabel')}</dt>
                      <dd>{zaAlphaLevelRangeDisplay}</dd>
                    </div>
                  ) : null}
                  {isSvEncounterTable ? (
                    <div>
                      <dt title="Calculated from this slot's lot weight divided by the selected condition row's total lot weight.">
                        Share in row
                      </dt>
                      <dd>{formatEncounterLotShare(encounterSlot.weight, encounterWeightTotal)}</dd>
                    </div>
                  ) : null}
                  {isSvEncounterTable ? (
                    <div>
                      <dt
                        title="Biome weights, height range, linked group spawn metadata, voice class, and outbreak weight from the S/V encounter row."
                      >
                        S/V Conditions
                      </dt>
                      <dd>{encounterSlot.weather}</dd>
                    </div>
                  ) : null}
                  {isZaEncounterTable &&
                  typeof encounterSlot.contributesToWildZoneCompletion === 'boolean' ? (
                    <div>
                      <dt>{t('za.wildZoneCompletion.detailLabel')}</dt>
                      <dd>
                        {t(
                          getZaWildZoneCompletionStatusKey(
                            encounterSlot.contributesToWildZoneCompletion
                              ? 'contributing'
                              : 'excluded'
                          )
                        )}
                      </dd>
                    </div>
                  ) : null}
                </dl>

                <div className="editable-field-groups">
                  {encounterFieldGroups.map((group) => (
                    <fieldset className="editable-field-group" key={group.group}>
                      <legend>{group.group}</legend>
                      <div className="editable-field-grid">
                        {group.fields.map((field) => {
                          const currentValue = getEditableEncounterFieldValue(
                            encounterSlot,
                            field.field
                          );
                          const draftValue = selectedPlacementDrafts[field.field] ?? '';
                          const draftState = getTrainerFieldDraftState(
                            draftValue,
                            currentValue,
                            field
                          );

                          return (
                            <TrainerDraftField
                              currentValue={currentValue}
                              disabled={
                                !canEditEncounters ||
                                editSession === null ||
                                isEncounterUpdating
                              }
                              disabledReason={
                                field.field === zaEncounterAlphaChanceFieldName
                                  ? alphaChanceDisabledReason
                                  : field.field === zaEncounterAlphaLevelBonusFieldName
                                    ? alphaLevelBonusDisabledReason
                                    : undefined
                              }
                              draftState={draftState}
                              draftValue={draftValue}
                              field={field}
                              formOptionContext={encounterFormOptionContext}
                              idPrefix="encounter-field"
                              key={field.field}
                              onChange={(value) => {
                                if (!encounterDraftKey) {
                                  return;
                                }

                                if (
                                  encounterLevelDraftKey &&
                                  encounterLevelFieldNames.includes(field.field)
                                ) {
                                  const currentLevelDrafts =
                                    levelDraftsByTableId[encounterLevelDraftKey] ??
                                    encounterLevelDraftDefaults;
                                  setLevelDraftsByTableId((currentDrafts) =>
                                    setFieldDraftRecord(
                                      currentDrafts,
                                      encounterLevelDraftKey,
                                      { ...currentLevelDrafts, [field.field]: value },
                                      encounterLevelDraftDefaults
                                    )
                                  );
                                  return;
                                }

                                const nextSlotDrafts = {
                                  ...slotDrafts,
                                  [field.field]: value
                                };
                                const nextSpeciesId = Number.parseInt(value, 10);
                                if (
                                  editorFamily === 'swsh' &&
                                  field.field === encounterSpeciesFieldName &&
                                  Number.isInteger(nextSpeciesId)
                                ) {
                                  nextSlotDrafts[encounterFormFieldName] =
                                    nextSpeciesId === encounterSlot.speciesId
                                      ? encounterSlot.form.toString()
                                      : '0';
                                }

                                setDraftsBySlotKey((currentDrafts) =>
                                  setFieldDraftRecord(
                                    currentDrafts,
                                    encounterDraftKey,
                                    nextSlotDrafts,
                                    encounterSlotDraftDefaults
                                  )
                                );
                              }}
                            />
                          );
                        })}
                      </div>
                      {group.group === 'Levels' ? (
                        <div className="field-group-action-row">
                          {isSwShEncounterTable ? (
                            <small className="editable-field-status">
                              Levels are stored per encounter condition. Stage edits for this
                              condition, or apply them to every available condition below.
                            </small>
                          ) : null}
                          {hasInvalidEncounterLevelPair ? (
                            <small className="editable-field-error">
                              Minimum level cannot be higher than maximum level.
                            </small>
                          ) : null}
                          <button
                            aria-busy={isEncounterUpdating || undefined}
                            className="secondary-button"
                            disabled={!canApplyEncounterLevelsToScope}
                            onClick={async () => {
                              if (!table || !encounterSlot || !encounterDraftKey) {
                                return;
                              }

                              const didSave = isSwShEncounterTable
                                ? await onUpdateEncounterSlotUpdates(
                                    encounterLevelConditionUpdates
                                  )
                                : await onUpdateEncounterSlotFields(
                                    table.tableId,
                                    encounterSlot.slot,
                                    encounterLevelChanges
                                  );
                              if (didSave) {
                                if (encounterLevelDraftKey) {
                                  const updatedTableIds = new Set(
                                    encounterLevelConditionUpdates.map(
                                      (update) => update.tableId
                                    )
                                  );
                                  setLevelDraftsByTableId((currentDrafts) =>
                                    Object.fromEntries(
                                      Object.entries(currentDrafts).filter(
                                        ([tableId]) => !updatedTableIds.has(tableId)
                                      )
                                    )
                                  );
                                } else {
                                  setDraftsBySlotKey((currentDrafts) =>
                                    removeDraftFieldsFromRecord(
                                      currentDrafts,
                                      encounterDraftKey,
                                      encounterSlotDraftDefaults,
                                      encounterLevelFieldNames
                                    )
                                  );
                                }
                              }
                            }}
                            title={
                              isSwShEncounterTable
                                ? 'Apply these level changes to every available condition in the current encounter table.'
                                : "Apply this slot's level changes to every editable table in the current zone."
                            }
                            type="button"
                          >
                            <BusyActionContent
                              busyLabel="Applying"
                              icon={null}
                              isBusy={isEncounterUpdating}
                              label={
                                isSwShEncounterTable
                                  ? 'Apply to All Conditions'
                                  : 'Apply to Entire Zone'
                              }
                            />
                          </button>
                        </div>
                      ) : null}
                    </fieldset>
                  ))}
                </div>
                {editSession ? (
                  <div className="draft-action-row">
                    <button
                      aria-busy={isEncounterUpdating || undefined}
                      className="primary-button"
                      disabled={!canSaveEncounterDrafts}
                      onClick={async () => {
                        if (!table || !encounterSlot || !encounterDraftKey) {
                          return;
                        }

                        const didSave = await onUpdateEncounterSlotFields(
                          table.tableId,
                          encounterSlot.slot,
                          encounterStageChanges.map((change) => ({
                            field: change.field,
                            value: change.value
                          }))
                        );
                        if (didSave) {
                          setDraftsBySlotKey((currentDrafts) =>
                            deleteFieldDraftRecord(currentDrafts, encounterDraftKey)
                          );
                          if (encounterLevelDraftKey) {
                            setLevelDraftsByTableId((currentDrafts) =>
                              deleteFieldDraftRecord(currentDrafts, encounterLevelDraftKey)
                            );
                          }
                        }
                      }}
                      type="button"
                    >
                      <BusyActionContent
                        busyLabel="Staging"
                        icon={<Save aria-hidden="true" size={16} />}
                        isBusy={isEncounterUpdating}
                        label="Stage"
                      />
                    </button>
                    {!isSvEncounterTable && !isZaEncounterTable ? (
                      <button
                        aria-busy={isEncounterUpdating || undefined}
                        className="danger-button"
                        disabled={!canClearEncounterSlot}
                        onClick={async () => {
                          if (!table || !encounterSlot || !encounterDraftKey) {
                            return;
                          }

                          const didSave = await onUpdateEncounterSlotFields(
                            table.tableId,
                            encounterSlot.slot,
                            [
                              { field: encounterSpeciesFieldName, value: '0' },
                              { field: encounterFormFieldName, value: '0' },
                              { field: encounterProbabilityFieldName, value: '0' }
                            ]
                          );
                          if (didSave) {
                            setDraftsBySlotKey((currentDrafts) =>
                              removeDraftFieldsFromRecord(
                                currentDrafts,
                                encounterDraftKey,
                                encounterSlotDraftDefaults,
                                encounterClearFieldNames
                              )
                            );
                          }
                        }}
                        title="Set this SwSh encounter slot to Empty at 0% probability."
                        type="button"
                      >
                        <BusyActionContent
                          busyLabel="Clearing"
                          icon={<Trash2 aria-hidden="true" size={16} />}
                          isBusy={isEncounterUpdating}
                          label="Clear Slot"
                        />
                      </button>
                    ) : null}
                    <button
                      className="danger-button"
                      disabled={isEncounterUpdating}
                      onClick={() =>
                        cancelActiveEditSession(() => {
                          setDraftsBySlotKey({});
                          setLevelDraftsByTableId({});
                        })
                      }
                      type="button"
                    >
                      <X aria-hidden="true" size={16} />
                      <span>Cancel</span>
                    </button>
                    <span className="draft-action-summary">
                      {formatDraftSummary(encounterDraftSummary)}
                    </span>
                  </div>
                ) : null}
              </>
            ) : (
              <p className="empty-copy">No encounter slot selected.</p>
            )}

            {!editSession ? (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditEncounters || isEditStarting || table.slots.length === 0}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            ) : null}
          </div>
          {areaCopyRequest ? (
            <EncounterAreaCopyConfirmationModal
              isApplying={isEncounterUpdating}
              onCancel={() => setAreaCopyRequest(null)}
              onConfirm={async () => {
                setAreaCopyRequest(null);
                const didSave = await onUpdateEncounterSlotUpdates(areaCopyRequest.updates);
                if (didSave) {
                  const copiedSlotKeys = new Set(
                    areaCopyRequest.updates.map(
                      (update) => `${update.tableId}:${update.slot}`
                    )
                  );
                  const copiedLevelTableIds = new Set(
                    areaCopyRequest.updates
                      .filter((update) =>
                        update.changes.some((change) =>
                          encounterLevelFieldNames.includes(change.field)
                        )
                      )
                      .map((update) => update.tableId)
                  );
                  setDraftsBySlotKey((currentDrafts) =>
                    Object.fromEntries(
                      Object.entries(currentDrafts).filter(
                        ([recordKey]) => !copiedSlotKeys.has(recordKey)
                      )
                    )
                  );
                  setLevelDraftsByTableId((currentDrafts) =>
                    Object.fromEntries(
                      Object.entries(currentDrafts).filter(
                        ([tableId]) => !copiedLevelTableIds.has(tableId)
                      )
                    )
                  );
                  onSelectTable(areaCopyRequest.targetTableId);
                }
              }}
              request={areaCopyRequest}
            />
          ) : null}
        </>
      ) : (
        <p className="empty-copy">No encounter table selected.</p>
      )}
    </aside>
  );
}

function SvEncounterConditionBrowser({
  onSelectTable,
  table,
  tables
}: {
  onSelectTable: (tableId: string | null) => void;
  table: EncounterTableRecord;
  tables: EncounterTableRecord[];
}) {
  const conditionRows = useMemo(
    () => buildSvEncounterConditionRows(table, tables),
    [table, tables]
  );
  const selectedRow =
    conditionRows.find((row) => row.tableId === table.tableId) ?? conditionRows[0] ?? null;

  if (!selectedRow) {
    return null;
  }

  return (
    <section className="sv-encounter-browser" aria-label="Scarlet/Violet encounter conditions">
      <div className="sv-encounter-browser-summary">
        <span>{conditionRows.length} condition rows in this location</span>
        <span>
          {selectedRow.slotCount} {selectedRow.slotCount === 1 ? 'slot' : 'slots'} in the
          selected row
        </span>
        <span>Lot weights are relative inside the selected row</span>
      </div>

      <div className="sv-encounter-condition-table" role="table" aria-label="S/V condition rows">
        <div className="sv-encounter-condition-row sv-encounter-condition-heading" role="row">
          <span role="columnheader">Area</span>
          <span role="columnheader">Game</span>
          <span role="columnheader">Terrain</span>
          <span role="columnheader">Time</span>
          <span role="columnheader">Biome</span>
          <span role="columnheader">Flag</span>
          <span role="columnheader">Slots</span>
          <span role="columnheader">Total weight</span>
        </div>
        {conditionRows.map((row) => (
          <button
            aria-pressed={row.tableId === table.tableId}
            className={`sv-encounter-condition-row ${
              row.tableId === table.tableId ? 'sv-encounter-condition-row-selected' : ''
            }`}
            key={row.tableId}
            onClick={() => {
              if (row.tableId !== table.tableId) {
                onSelectTable(row.tableId);
              }
            }}
            role="row"
            title={row.label}
            type="button"
          >
            <span role="cell">{row.area}</span>
            <span role="cell">{row.gameVersion}</span>
            <span role="cell">{row.terrain}</span>
            <span role="cell">{row.time}</span>
            <span role="cell">{row.biome}</span>
            <span role="cell">{row.flag}</span>
            <span role="cell">{row.slotCount}</span>
            <span role="cell">{row.totalWeight}</span>
          </button>
        ))}
      </div>
    </section>
  );
}

function ZaEncounterGroupBrowser({
  onSelectReference,
  pendingRecordIds,
  selectedSlot,
  table,
  tables
}: {
  onSelectReference: (tableId: string, slot: number) => void;
  pendingRecordIds: ReadonlySet<string>;
  selectedSlot: number | null;
  table: EncounterTableRecord;
  tables: EncounterTableRecord[];
}) {
  const { t } = useLocalization();
  const isDimensionWildTable = isZaDimensionWildEncounterTable(table);
  const dimensionWildData = useMemo(
    () => (isDimensionWildTable ? buildZaDimensionWildBrowserData(table, tables) : null),
    [isDimensionWildTable, table, tables]
  );
  const spawnerRows = useMemo(
    () => buildZaEncounterSpawnerRows(table, tables),
    [table, tables]
  );
  const spawnerCategoryData = useMemo(
    () => (!dimensionWildData ? buildZaEncounterSpawnerCategoryData(table, spawnerRows) : null),
    [dimensionWildData, spawnerRows, table]
  );
  const displayedRows = dimensionWildData
    ? dimensionWildData.rows
    : spawnerCategoryData
      ? spawnerCategoryData.rows
      : spawnerRows;
  const groupingRows = dimensionWildData ? dimensionWildData.rows : spawnerRows;
  const tableById = useMemo(
    () => new Map(tables.map((candidate) => [candidate.tableId, candidate])),
    [tables]
  );
  const groupingTables = useMemo(
    () =>
      groupingRows
        .map((row) => tableById.get(row.tableId))
        .filter((candidate): candidate is EncounterTableRecord => candidate !== undefined),
    [groupingRows, tableById]
  );
  const encounterGroups = useMemo(
    () => buildZaEncounterGroups(groupingTables, tables),
    [groupingTables, tables]
  );
  const displayedTableIds = new Set(displayedRows.map((row) => row.tableId));
  const displayedTables = displayedRows
    .map((row) => tableById.get(row.tableId))
    .filter((candidate): candidate is EncounterTableRecord => candidate !== undefined);
  const visibleEncounterGroups = encounterGroups.filter((group) =>
    group.placements.some((placement) => displayedTableIds.has(placement.table.tableId))
  );
  const rowByTableId = new Map(
    [...spawnerRows, ...(dimensionWildData?.rows ?? [])].map((row) => [row.tableId, row])
  );
  const selectedGroup =
    visibleEncounterGroups.find((group) =>
      group.placements.some(
        (placement) =>
          placement.table.tableId === table.tableId && placement.slot.slot === selectedSlot
      )
    ) ?? visibleEncounterGroups[0] ?? null;

  const selectReferenceForTable = (tableId: string) => {
    const nextSlot = tableById.get(tableId)?.slots[0];
    if (nextSlot) {
      onSelectReference(tableId, nextSlot.slot);
    }
  };

  const selectGroup = (group: ZaEncounterGroup) => {
    const currentPlacement = group.placements.find(
      (placement) =>
        placement.table.tableId === table.tableId && placement.slot.slot === selectedSlot
    );
    const displayedPlacement = group.placements.find((placement) =>
      displayedTableIds.has(placement.table.tableId)
    );
    const placement = currentPlacement ?? displayedPlacement ?? group.placements[0];
    if (placement) {
      onSelectReference(placement.table.tableId, placement.slot.slot);
    }
  };

  if (!selectedGroup) {
    return null;
  }

  const selectedGroupLabel = formatZaEncounterGroupLabel(selectedGroup);
  const showCompletionRole = visibleEncounterGroups.some(
    (group) => getZaWildZoneCompletionState(group.placements.map(({ slot }) => slot)) !== 'notApplicable'
  );
  const selectedCompletionState = getZaWildZoneCompletionState(
    selectedGroup.placements.map(({ slot }) => slot)
  );
  const selectedGroupHasAlphaSettings = selectedGroup.placements.some(({ slot }) =>
    hasZaAlphaSettings(slot)
  );
  const selectedGroupHasOrdinaryAlphaReference = selectedGroup.placements.some(
    ({ slot }) => slot.isAlpha !== true
  );
  const selectedGroupHasSpecialAlphaReference = selectedGroup.placements.some(
    ({ slot }) => slot.isAlpha === true
  );
  const selectedGroupHasMixedAlphaReferences =
    selectedGroupHasOrdinaryAlphaReference && selectedGroupHasSpecialAlphaReference;
  const showPlacementAlphaChance = selectedGroup.placements.some(
    ({ slot }) => slot.alphaChancePercent !== undefined || slot.isAlpha === true
  );
  const placementLayoutClass = showPlacementAlphaChance
    ? selectedCompletionState !== 'notApplicable'
      ? 'za-encounter-placement-row-with-alpha-and-completion'
      : 'za-encounter-placement-row-with-alpha'
    : selectedCompletionState !== 'notApplicable'
      ? 'za-encounter-placement-row-with-completion'
      : '';
  const visibleSlotCount = displayedTables.reduce(
    (total, displayedTable) => total + displayedTable.slots.length,
    0
  );

  return (
    <section className="za-encounter-group-browser" aria-label="Legends Z-A linked wild encounters">
      <div className="sv-encounter-browser-summary">
        <span>{table.location}</span>
        <span>{formatZaEncounterGroupCount(visibleEncounterGroups.length)}</span>
        <span>{formatZaEncounterSpawnerCount(displayedTables.length)}</span>
        <span>
          {visibleSlotCount} {visibleSlotCount === 1 ? 'slot' : 'slots'} in this view
        </span>
      </div>

      {dimensionWildData ? (
        <>
          <div
            className="encounter-area-tabs za-dimension-wild-pool-tabs"
            role="tablist"
            aria-label="Dimension wild pools"
          >
            {dimensionWildData.poolTabs.map((poolTab) => (
              <button
                aria-selected={poolTab.isSelected}
                className="condition-tab-button"
                key={poolTab.key}
                onClick={() => {
                  if (poolTab.tableId !== table.tableId) {
                    selectReferenceForTable(poolTab.tableId);
                  }
                }}
                role="tab"
                title={poolTab.title}
                type="button"
              >
                {poolTab.label}
              </button>
            ))}
          </div>

          <div
            className="encounter-condition-tabs za-dimension-wild-rank-tabs"
            role="tablist"
            aria-label="Dimension wild ranks"
          >
            {dimensionWildData.rankTabs.map((rankTab) => (
              <button
                aria-selected={rankTab.isSelected}
                className="condition-tab-button"
                key={rankTab.key}
                onClick={() => {
                  if (rankTab.tableId !== table.tableId) {
                    selectReferenceForTable(rankTab.tableId);
                  }
                }}
                role="tab"
                title={rankTab.title}
                type="button"
              >
                {rankTab.label}
              </button>
            ))}
          </div>
        </>
      ) : null}

      {spawnerCategoryData && spawnerCategoryData.categoryTabs.length > 1 ? (
        <div
          className="encounter-condition-tabs za-encounter-category-tabs"
          role="tablist"
          aria-label="Spawner groups"
        >
          {spawnerCategoryData.categoryTabs.map((categoryTab) => (
            <button
              aria-selected={categoryTab.isSelected}
              className="condition-tab-button"
              key={categoryTab.key}
              onClick={() => {
                if (categoryTab.tableId !== table.tableId) {
                  selectReferenceForTable(categoryTab.tableId);
                }
              }}
              role="tab"
              title={categoryTab.title}
              type="button"
            >
              {categoryTab.label}
            </button>
          ))}
        </div>
      ) : null}

      <div className="za-encounter-group-table" role="table" aria-label="Z-A linked encounters">
        <div
          className={`za-encounter-group-row za-encounter-group-heading ${
            showCompletionRole ? 'za-encounter-group-row-with-completion' : ''
          }`}
          role="row"
        >
          <span role="columnheader">Pokemon</span>
          <span role="columnheader">Used by</span>
          <span role="columnheader">Levels</span>
          <span role="columnheader">Source</span>
          {showCompletionRole ? (
            <span role="columnheader">{t('za.wildZoneCompletion.column')}</span>
          ) : null}
        </div>
        {visibleEncounterGroups.map((group) => {
          const groupLabel = formatZaEncounterGroupLabel(group);
          const isSelected = group.key === selectedGroup.key;
          const isPending = isZaEncounterGroupPending(group, pendingRecordIds);
          const completionState = getZaWildZoneCompletionState(
            group.placements.map(({ slot }) => slot)
          );
          const completionLabel =
            completionState === 'notApplicable'
              ? ''
              : t(getZaWildZoneCompletionStatusKey(completionState));
          return (
            <button
              aria-label={`${groupLabel}, ${formatZaEncounterGroupUsage(group)}, levels ${group.slot.levelMin} to ${group.slot.levelMax}, source ${formatZaEncounterGroupSource(group)}${
                completionLabel ? `, ${t('za.wildZoneCompletion.column')} ${completionLabel}` : ''
              }`}
              aria-pressed={isSelected}
              className={`za-encounter-group-row ${
                isSelected ? 'za-encounter-group-row-selected' : ''
              } ${isPending ? 'za-encounter-group-row-pending' : ''} ${
                showCompletionRole ? 'za-encounter-group-row-with-completion' : ''
              }`}
              key={group.key}
              onClick={() => selectGroup(group)}
              role="row"
              type="button"
            >
              <span role="cell">{groupLabel}</span>
              <span role="cell">{formatZaEncounterGroupUsage(group)}</span>
              <span role="cell">
                {group.slot.levelMin}-{group.slot.levelMax}
              </span>
              <span role="cell">{formatZaEncounterGroupSource(group)}</span>
              {showCompletionRole ? (
                <span
                  className={
                    completionLabel
                      ? `za-wild-zone-completion-status za-wild-zone-completion-status-${completionState}`
                      : undefined
                  }
                  role="cell"
                >
                  {completionLabel}
                </span>
              ) : null}
            </button>
          );
        })}
      </div>

      {selectedGroup.slotCount > 1 ? (
        <div
          className="za-encounter-placement-table"
          role="table"
          aria-label={`${selectedGroupLabel} linked spawners`}
        >
          <div
            className={`za-encounter-placement-row za-encounter-placement-heading ${placementLayoutClass}`}
            role="row"
          >
            <span role="columnheader">Spawner</span>
            <span role="columnheader">Slot</span>
            <span role="columnheader">Probability</span>
            <span role="columnheader">Conditions</span>
            {showPlacementAlphaChance ? (
              <span role="columnheader">{t('za.alphaSettings.chanceLabel')}</span>
            ) : null}
            {selectedCompletionState !== 'notApplicable' ? (
              <span role="columnheader">{t('za.wildZoneCompletion.column')}</span>
            ) : null}
          </div>
          {selectedGroup.placements.map((placement) => {
            const placementLabel = formatZaEncounterPlacementLabel(placement, rowByTableId);
            const isSelected =
              placement.table.tableId === table.tableId && placement.slot.slot === selectedSlot;
            const placementCompletionState = getZaWildZoneCompletionState([placement.slot]);
            const placementCompletionLabel =
              placementCompletionState === 'notApplicable'
                ? ''
                : t(getZaWildZoneCompletionStatusKey(placementCompletionState));
            const placementAlphaChanceLabel = showPlacementAlphaChance
              ? formatZaAlphaChance(placement.slot, t) ?? t('za.alphaSettings.unavailable')
              : null;
            return (
              <button
                aria-label={`${placementLabel}, slot ${placement.slot.slot + 1}, probability ${placement.slot.weight}, ${formatZaEncounterPlacementConditions(placement)}${
                  placementAlphaChanceLabel
                    ? `, ${t('za.alphaSettings.chanceLabel')} ${placementAlphaChanceLabel}`
                    : ''
                }${
                  placementCompletionLabel
                    ? `, ${t('za.wildZoneCompletion.column')} ${placementCompletionLabel}`
                    : ''
                }`}
                aria-pressed={isSelected}
                className={`za-encounter-placement-row ${
                  isSelected ? 'za-encounter-placement-row-selected' : ''
                } ${placementLayoutClass}`}
                key={`${placement.table.tableId}:${placement.slot.slot}`}
                onClick={() =>
                  onSelectReference(placement.table.tableId, placement.slot.slot)
                }
                role="row"
                type="button"
              >
                <span role="cell">{placementLabel}</span>
                <span role="cell">{placement.slot.slot + 1}</span>
                <span role="cell">{placement.slot.weight}</span>
                <span role="cell">{formatZaEncounterPlacementConditions(placement)}</span>
                {placementAlphaChanceLabel ? (
                  <span role="cell">{placementAlphaChanceLabel}</span>
                ) : null}
                {selectedCompletionState !== 'notApplicable' ? (
                  <span
                    className={
                      placementCompletionLabel
                        ? `za-wild-zone-completion-status za-wild-zone-completion-status-${placementCompletionState}`
                        : undefined
                    }
                    role="cell"
                  >
                    {placementCompletionLabel}
                  </span>
                ) : null}
              </button>
            );
          })}
        </div>
      ) : null}

      <ZaWildZoneCompletionNote state={selectedCompletionState} />

      {selectedGroup.slotCount > 1 || selectedGroup.outsideScopeSpawnerCount > 0 ? (
        <p className="za-encounter-shared-scope-note">
          {t(
            selectedGroup.slotCount === 1
              ? 'za.sharedPlacements.summary.one'
              : 'za.sharedPlacements.summary.many',
            { count: selectedGroup.slotCount }
          )}{' '}
          {t(
            selectedGroupHasMixedAlphaReferences
              ? 'za.sharedPlacements.sharedFields.mixed'
              : selectedGroupHasAlphaSettings
                ? 'za.sharedPlacements.sharedFields.alpha'
                : 'za.sharedPlacements.sharedFields.basic'
          )}{' '}
          {t('za.sharedPlacements.specificFields')}{' '}
          {selectedGroupHasAlphaSettings ? `${t('za.sharedPlacements.alphaRolls')} ` : ''}
          {selectedGroup.outsideScopeSpawnerCount > 0
            ? t(
                selectedGroup.outsideScopeSpawnerCount === 1
                  ? 'za.sharedPlacements.outside.one'
                  : 'za.sharedPlacements.outside.many',
                { count: selectedGroup.outsideScopeSpawnerCount }
              )
            : ''}
        </p>
      ) : null}
    </section>
  );
}

function ZaWildZoneCompletionNote({ state }: { state: ZaWildZoneCompletionState }) {
  const { t } = useLocalization();
  if (state === 'notApplicable') {
    return null;
  }

  return (
    <p
      aria-label={t('za.wildZoneCompletion.detailLabel')}
      className="za-encounter-shared-scope-note za-wild-zone-completion-note"
    >
      <MapPinned aria-hidden="true" size={16} />
      <span>
        <strong>{t(getZaWildZoneCompletionStatusKey(state))}:</strong>{' '}
        {t(`za.wildZoneCompletion.note.${state}`)}
      </span>
    </p>
  );
}

function getZaWildZoneCompletionStatusKey(state: Exclude<ZaWildZoneCompletionState, 'notApplicable'>) {
  return `za.wildZoneCompletion.status.${state}`;
}

function EncounterAreaCopyConfirmationModal({
  isApplying,
  onCancel,
  onConfirm,
  request
}: {
  isApplying: boolean;
  onCancel: () => void;
  onConfirm: () => void;
  request: EncounterAreaCopyRequest;
}) {
  const dialogRef = useModalDialog<HTMLDivElement>({
    canClose: !isApplying,
    onClose: onCancel
  });
  const conditionLabel = request.conditionLabels.join(', ');
  const slotLabel = request.updates.length === 1 ? 'slot' : 'slots';
  const skippedLabel = request.skippedConditionLabels.join(', ');

  return (
    <div
      aria-labelledby="encounter-area-copy-heading"
      aria-modal="true"
      className="modal-backdrop"
      ref={dialogRef}
      role="dialog"
      tabIndex={-1}
    >
      <section className="modal-panel">
        <div className="panel-heading">
          <ArrowLeftRight aria-hidden="true" size={18} />
          <h2 id="encounter-area-copy-heading">Apply to {request.targetArea}?</h2>
        </div>
        <p className="modal-copy">
          Copy Pokemon, forms, percentages, and min/max levels from {request.sourceArea} to{' '}
          {request.targetArea} for {request.sourceLocation}.
        </p>
        <p className="modal-copy modal-copy-muted">
          This will update {request.updates.length} matching {slotLabel} across {conditionLabel}.
          Missing destination conditions or slot numbers are ignored.
        </p>
        {request.skippedConditionLabels.length > 0 ? (
          <p className="modal-copy modal-copy-muted">Skipped: {skippedLabel}.</p>
        ) : null}
        <div className="modal-actions">
          <button className="secondary-button" disabled={isApplying} onClick={onCancel} type="button">
            <X aria-hidden="true" size={16} />
            <span>Cancel</span>
          </button>
          <button
            aria-busy={isApplying || undefined}
            className="primary-button"
            disabled={isApplying}
            onClick={onConfirm}
            type="button"
          >
            <BusyActionContent
              busyLabel="Applying"
              icon={<ArrowLeftRight aria-hidden="true" size={16} />}
              isBusy={isApplying}
              label={`Apply to ${request.targetArea}`}
            />
          </button>
        </div>
      </section>
    </div>
  );
}

function TeraRaidsSection({
  editSession,
  isEditStarting,
  isTeraRaidUpdating,
  onSearchChange,
  onSelectRaid,
  onStartEditSession,
  onUpdateTeraRaidField,
  onUpdateTeraRaidFields,
  searchText,
  selectedRaidRecordId,
  workflow
}: {
  editSession: EditSession | null;
  isEditStarting: boolean;
  isTeraRaidUpdating: boolean;
  onSearchChange: (value: string) => void;
  onSelectRaid: (recordId: string | null) => void;
  onStartEditSession: () => void;
  onUpdateTeraRaidField: (
    recordId: string,
    field: string,
    value: string
  ) => Promise<boolean>;
  onUpdateTeraRaidFields: (
    recordId: string,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  searchText: string;
  selectedRaidRecordId: string | null;
  workflow: TeraRaidsWorkflow | null;
}) {
  const { translateLiteral } = useLocalization();
  const [draftsByRecordId, setDraftsByRecordId] = useState<
    Record<string, Record<string, string>>
  >({});
  const [rewardKind, setRewardKind] = useState<'fixed' | 'lottery'>('fixed');
  const [selectedRewardRecordId, setSelectedRewardRecordId] = useState<string | null>(null);
  const normalizedSearch = searchText.trim().toLocaleLowerCase();
  const filteredRaids =
    workflow?.raids.filter((raid) => {
      if (!normalizedSearch) {
        return true;
      }

      return [
        raid.recordId,
        raid.region,
        raid.starLabel,
        raid.versionLabel,
        raid.raidNo.toString(),
        raid.species,
        raid.speciesId.toString(),
        raid.teraTypeLabel,
        raid.fixedRewardPreview,
        raid.lotteryRewardPreview,
        raid.provenance.sourceFile
      ]
        .join(' ')
        .toLocaleLowerCase()
        .includes(normalizedSearch);
    }) ?? [];
  const selectedRaid =
    filteredRaids.find((raid) => raid.recordId === selectedRaidRecordId) ??
    workflow?.raids.find((raid) => raid.recordId === selectedRaidRecordId) ??
    filteredRaids[0] ??
    workflow?.raids[0] ??
    null;
  const canEditTeraRaids = workflow?.summary.availability === 'available';
  const pendingTeraRaidRecordIds = getPendingTeraRaidRecordIds(editSession);
  const raidFields = useMemo(
    () =>
      (workflow?.editableFields ?? [])
        .filter(isTeraRaidBossField)
        .map((field) =>
          toNumericEditableControlField(
            field,
            field.field === abilityFieldName && selectedRaid
              ? selectedRaid.abilityOptions
              : undefined
          )
        ),
    [selectedRaid?.abilityOptions, workflow?.editableFields]
  );
  const fixedRewardFields = useMemo(
    () =>
      (workflow?.editableFields ?? [])
        .filter(isTeraRaidFixedRewardField)
        .map((field) => toNumericEditableControlField(field)),
    [workflow?.editableFields]
  );
  const lotteryRewardFields = useMemo(
    () =>
      (workflow?.editableFields ?? [])
        .filter(isTeraRaidLotteryRewardField)
        .map((field) => toNumericEditableControlField(field)),
    [workflow?.editableFields]
  );
  const fixedRewardTable = selectedRaid
    ? findTeraRaidRewardTableByHash(
        workflow?.fixedRewardTables ?? [],
        selectedRaid.fixedRewardTableHash
      )
    : null;
  const lotteryRewardTable = selectedRaid
    ? findTeraRaidRewardTableByHash(
        workflow?.lotteryRewardTables ?? [],
        selectedRaid.lotteryRewardTableHash
      )
    : null;
  const activeRewardTable = rewardKind === 'fixed' ? fixedRewardTable : lotteryRewardTable;
  const activeRewardFields = rewardKind === 'fixed' ? fixedRewardFields : lotteryRewardFields;
  const activeRewardRows =
    activeRewardTable?.rewards.filter((reward) => !isEmptyTeraRaidReward(reward)) ?? [];
  const emptyRewardRows =
    activeRewardTable?.rewards.filter((reward) => isEmptyTeraRaidReward(reward)) ?? [];
  const selectedReward =
    activeRewardRows.find((reward) => reward.recordId === selectedRewardRecordId) ??
    (editSession
      ? emptyRewardRows.find((reward) => reward.recordId === selectedRewardRecordId)
      : null) ??
    activeRewardRows[0] ??
    null;

  useRegisterEditorDraftDirty('teraRaids', countFieldDraftRecords(draftsByRecordId) > 0);

  useEffect(() => {
    if (selectedRaid && selectedRaid.recordId !== selectedRaidRecordId) {
      onSelectRaid(selectedRaid.recordId);
    }
  }, [onSelectRaid, selectedRaid?.recordId, selectedRaidRecordId]);

  useEffect(() => {
    if (selectedReward && selectedReward.recordId !== selectedRewardRecordId) {
      setSelectedRewardRecordId(selectedReward.recordId);
    }
  }, [selectedReward?.recordId, selectedRewardRecordId]);

  return (
    <>
      <section aria-labelledby="tera-raids-heading" className="panel wide-panel">
        <div className="panel-heading">
          <Gem aria-hidden="true" size={18} />
          <h2 id="tera-raids-heading">{translateLiteral('Tera Raids')}</h2>
        </div>

        <div className="items-toolbar encounters-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label={translateLiteral('Search Tera raids')}
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder={translateLiteral('Search Tera raids')}
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label="Loaded raids"
            value={workflow ? workflow.stats.totalRaidCount.toString() : '0'}
          />
          <Metric
            label="Reward tables"
            value={workflow ? workflow.stats.totalRewardTableCount.toString() : '0'}
          />
          <Metric
            label="Reward rows"
            value={workflow ? workflow.stats.totalRewardItemCount.toString() : '0'}
          />
          <Metric
            label="Sources"
            value={workflow ? workflow.stats.sourceFileCount.toString() : '0'}
          />
          <Metric
            label="Pending changes"
            value={(editSession?.pendingEdits.length ?? 0).toString()}
          />
        </div>

        {workflow ? (
          <div className="encounters-layout">
            <div
              className="raid-rewards-table"
              role="table"
              aria-label={translateLiteral('Tera raid rows')}
            >
              <div className="raid-rewards-row raid-rewards-row-heading" role="row">
                <span role="columnheader">{translateLiteral('Region')}</span>
                <span role="columnheader">{translateLiteral('Stars')}</span>
                <span role="columnheader">{translateLiteral('Game')}</span>
                <span role="columnheader">{translateLiteral('Pokemon')}</span>
              </div>
              {filteredRaids.map((raid) => {
                const raidLabel = formatSpeciesFormLabel(raid.species, raid.form, raid.speciesId);

                return (
                  <button
                    className={`raid-rewards-row ${
                      selectedRaid?.recordId === raid.recordId ? 'raid-rewards-row-selected' : ''
                    } ${
                      pendingTeraRaidRecordIds.has(raid.recordId) ? 'raid-rewards-row-pending' : ''
                    }`}
                    key={raid.recordId}
                    onClick={() => onSelectRaid(raid.recordId)}
                    role="row"
                    type="button"
                  >
                    <span role="cell">{raid.region}</span>
                    <span role="cell">{raid.starLabel}</span>
                    <span role="cell">{raid.versionLabel}</span>
                    <span role="cell">{raidLabel}</span>
                  </button>
                );
              })}
            </div>

            <aside
              aria-label={translateLiteral('Selected Tera raid')}
              className="encounter-inspector"
            >
              <div className="panel-heading">
                <Gem aria-hidden="true" size={18} />
                <h3>{translateLiteral('Selected Raid')}</h3>
              </div>

              {selectedRaid ? (
                <>
                  <dl className="item-provenance-list">
                    <div>
                      <dt>{translateLiteral('Pokemon')}</dt>
                      <dd data-localization-ignore="true">
                        {formatSpeciesFormLabel(
                          selectedRaid.species,
                          selectedRaid.form,
                          selectedRaid.speciesId
                        )}
                      </dd>
                    </div>
                    <div>
                      <dt>{translateLiteral('Region')}</dt>
                      <dd>{translateLiteral(selectedRaid.region)}</dd>
                    </div>
                    <div>
                      <dt>{translateLiteral('Stars')}</dt>
                      <dd>{translateLiteral(selectedRaid.starLabel)}</dd>
                    </div>
                    <div>
                      <dt>{translateLiteral('Game')}</dt>
                      <dd>{translateLiteral(selectedRaid.versionLabel)}</dd>
                    </div>
                    <div>
                      <dt>{translateLiteral('Source file')}</dt>
                      <dd data-localization-ignore="true">{selectedRaid.provenance.sourceFile}</dd>
                    </div>
                    <div>
                      <dt>{translateLiteral('Layer')}</dt>
                      <dd>{translateLiteral(formatSourceLayer(selectedRaid.provenance.sourceLayer))}</dd>
                    </div>
                    <div>
                      <dt>{translateLiteral('File state')}</dt>
                      <dd>{translateLiteral(formatFileState(selectedRaid.provenance.fileState))}</dd>
                    </div>
                  </dl>

                  <div className="encounter-edit-form">
                    <div
                      className="encounter-slot-tabs"
                      aria-label={translateLiteral('Selected Tera raid summary')}
                    >
                      <div className="slot-tab-button slot-tab-button-readonly">
                        <PokemonSprite
                          className="slot-tab-sprite"
                          name={formatSpeciesFormLabel(
                            selectedRaid.species,
                            selectedRaid.form,
                            selectedRaid.speciesId
                          )}
                          preferStatic
                        />
                        <strong>{selectedRaid.starLabel}</strong>
                        <span data-localization-ignore="true">
                          {formatSpeciesFormLabel(
                            selectedRaid.species,
                            selectedRaid.form,
                            selectedRaid.speciesId
                          )}
                        </span>
                        <small>
                          {`${translateLiteral(selectedRaid.teraTypeLabel)} ${translateLiteral('Tera')}`}
                        </small>
                      </div>
                    </div>

                    <dl className="encounter-slot-detail">
                      <div>
                        <dt>{translateLiteral('Level')}</dt>
                        <dd>{selectedRaid.level}</dd>
                      </div>
                      <div>
                        <dt>{translateLiteral('Tera type')}</dt>
                        <dd>{translateLiteral(selectedRaid.teraTypeLabel)}</dd>
                      </div>
                      <div>
                        <dt>{translateLiteral('Ability')}</dt>
                        <dd>{translateLiteral(selectedRaid.abilityLabel)}</dd>
                      </div>
                      <div>
                        <dt>{translateLiteral('Nature')}</dt>
                        <dd>{translateLiteral(selectedRaid.natureLabel)}</dd>
                      </div>
                      <div>
                        <dt>{translateLiteral('IVs')}</dt>
                        <dd>{translateLiteral(selectedRaid.ivSummary)}</dd>
                      </div>
                      <div>
                        <dt>{translateLiteral('Fixed rewards')}</dt>
                        <dd data-localization-ignore="true">{selectedRaid.fixedRewardPreview}</dd>
                      </div>
                      <div>
                        <dt>{translateLiteral('Lottery rewards')}</dt>
                        <dd data-localization-ignore="true">{selectedRaid.lotteryRewardPreview}</dd>
                      </div>
                    </dl>

                    {editSession ? (
                      <TeraRaidDraftPanel
                        canEdit={canEditTeraRaids}
                        disabled={isTeraRaidUpdating}
                        draftKey={selectedRaid.recordId}
                        draftsByRecordId={draftsByRecordId}
                        fields={raidFields}
                        formOptionContext={createTeraRaidFormOptionContext(
                          selectedRaid,
                          raidFields,
                          draftsByRecordId[selectedRaid.recordId]
                        )}
                        getGroup={getTeraRaidEditableFieldGroup}
                        getValue={(field) =>
                          getEditableTeraRaidFieldValue(
                            selectedRaid,
                            field,
                            workflow.fixedRewardTables,
                            workflow.lotteryRewardTables
                          )
                        }
                        isBusy={isTeraRaidUpdating}
                        onChangeDrafts={setDraftsByRecordId}
                        onUpdateField={onUpdateTeraRaidField}
                        onUpdateFields={onUpdateTeraRaidFields}
                        saveLabel="Stage"
                      />
                    ) : (
                      <button
                        aria-busy={isEditStarting || undefined}
                        className="secondary-button"
                        disabled={!canEditTeraRaids || isEditStarting}
                        onClick={onStartEditSession}
                        type="button"
                      >
                        <BusyActionContent
                          busyLabel={translateLiteral('Starting')}
                          icon={<Pencil aria-hidden="true" size={16} />}
                          isBusy={isEditStarting}
                          label={translateLiteral('Edit')}
                        />
                      </button>
                    )}

                    <div className="encounter-slot-header">
                      <strong>{translateLiteral('Rewards')}</strong>
                      <select
                        aria-label={translateLiteral('Tera raid reward kind')}
                        onChange={(event) => {
                          setRewardKind(event.target.value === 'lottery' ? 'lottery' : 'fixed');
                          setSelectedRewardRecordId(null);
                        }}
                        value={rewardKind}
                      >
                        <option value="fixed">{translateLiteral('Fixed rewards')}</option>
                        <option value="lottery">{translateLiteral('Lottery rewards')}</option>
                      </select>
                    </div>

                    {activeRewardTable ? (
                      <>
                        <dl className="encounter-slot-detail">
                          <div>
                            <dt>{translateLiteral('Table')}</dt>
                            <dd>{activeRewardTable.tableHash}</dd>
                          </div>
                          <div>
                            <dt>{translateLiteral('Reward rows')}</dt>
                            <dd>{activeRewardTable.rewardItemCount}</dd>
                          </div>
                          <div>
                            <dt>{translateLiteral('Preview')}</dt>
                            <dd data-localization-ignore="true">{activeRewardTable.preview}</dd>
                          </div>
                        </dl>

                        {editSession && emptyRewardRows.length > 0 ? (
                          <label className="path-field">
                            <span>{translateLiteral('Add reward in empty slot')}</span>
                            <select
                              aria-label={translateLiteral('Add reward in empty slot')}
                              onChange={(event) =>
                                setSelectedRewardRecordId(event.target.value || null)
                              }
                              value={
                                selectedReward && isEmptyTeraRaidReward(selectedReward)
                                  ? selectedReward.recordId
                                  : ''
                              }
                            >
                              <option value="">{translateLiteral('Choose an empty slot')}</option>
                              {emptyRewardRows.map((reward) => (
                                <option key={reward.recordId} value={reward.recordId}>
                                  {`#${reward.slot}: ${translateLiteral('Empty slot')}`}
                                </option>
                              ))}
                            </select>
                          </label>
                        ) : null}

                        <div
                          className="encounter-slot-tabs"
                          aria-label={translateLiteral('Tera raid reward rows')}
                        >
                          {activeRewardRows.map((reward) => (
                            <button
                              aria-pressed={reward.recordId === selectedReward?.recordId}
                              className={`slot-tab-button ${
                                pendingTeraRaidRecordIds.has(reward.recordId)
                                  ? 'slot-tab-button-pending'
                                  : ''
                              }`}
                              key={reward.recordId}
                              onClick={() => setSelectedRewardRecordId(reward.recordId)}
                              type="button"
                            >
                              <strong>{`#${reward.slot}`}</strong>
                              <span data-localization-ignore="true">{reward.itemName}</span>
                              <small>
                                {rewardKind === 'lottery' && reward.rate !== null
                                  ? `${reward.count} ${translateLiteral('at')} ${reward.rate}`
                                  : `${translateLiteral('Count')} ${reward.count}`}
                              </small>
                            </button>
                          ))}
                        </div>

                        {selectedReward ? (
                          <>
                            <dl className="encounter-slot-detail">
                              <div>
                                <dt>{translateLiteral('Item')}</dt>
                                <dd>
                                  {isEmptyTeraRaidReward(selectedReward) ? (
                                    translateLiteral('Empty slot')
                                  ) : (
                                    <span data-localization-ignore="true">
                                      {selectedReward.itemName}
                                    </span>
                                  )}
                                </dd>
                              </div>
                              <div>
                                <dt>{translateLiteral('Category')}</dt>
                                <dd>{translateLiteral(selectedReward.categoryLabel)}</dd>
                              </div>
                              <div>
                                <dt>{translateLiteral('Subject')}</dt>
                                <dd>
                                  {translateLiteral(selectedReward.subjectTypeLabel ?? 'n/a')}
                                </dd>
                              </div>
                              <div>
                                <dt>{translateLiteral('Count')}</dt>
                                <dd>{selectedReward.count}</dd>
                              </div>
                              {selectedReward.rate !== null ? (
                                <div>
                                  <dt>{translateLiteral('Rate')}</dt>
                                  <dd>{selectedReward.rate}</dd>
                                </div>
                              ) : null}
                            </dl>

                            {editSession ? (
                              <TeraRaidDraftPanel
                                canEdit={canEditTeraRaids}
                                disabled={isTeraRaidUpdating}
                                draftKey={selectedReward.recordId}
                                draftsByRecordId={draftsByRecordId}
                                fields={activeRewardFields}
                                getGroup={getTeraRaidEditableFieldGroup}
                                getValue={(field) =>
                                  getEditableTeraRaidRewardFieldValue(selectedReward, field)
                                }
                                isBusy={isTeraRaidUpdating}
                                onChangeDrafts={setDraftsByRecordId}
                                onUpdateField={onUpdateTeraRaidField}
                                onUpdateFields={onUpdateTeraRaidFields}
                                saveLabel="Stage"
                              />
                            ) : null}
                          </>
                        ) : (
                          <p className="empty-copy">
                            {translateLiteral('No reward row selected.')}
                          </p>
                        )}
                      </>
                    ) : (
                      <p className="empty-copy">
                        {translateLiteral('No linked reward table found for this raid.')}
                      </p>
                    )}
                  </div>
                </>
              ) : (
                <p className="empty-copy">{translateLiteral('No Tera raid selected.')}</p>
              )}
            </aside>
          </div>
        ) : (
          <p className="empty-copy">
            {translateLiteral('Open Tera Raids from Workflows to load backend raid data.')}
          </p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
    </>
  );
}

function TeraRaidDraftPanel({
  canEdit,
  disabled,
  draftKey,
  draftsByRecordId,
  fields,
  formOptionContext,
  getGroup,
  getValue,
  isBusy,
  onChangeDrafts,
  onUpdateField,
  onUpdateFields,
  saveLabel
}: {
  canEdit: boolean;
  disabled: boolean;
  draftKey: string;
  draftsByRecordId: Record<string, Record<string, string>>;
  fields: NumericEditableField[];
  formOptionContext?: SpeciesFormOptionContext;
  getGroup: (field: NumericEditableField) => string;
  getValue: (field: string) => number | null;
  isBusy: boolean;
  onChangeDrafts: (
    updater: (
      currentDrafts: Record<string, Record<string, string>>
    ) => Record<string, Record<string, string>>
  ) => void;
  onUpdateField: (recordId: string, field: string, value: string) => Promise<boolean>;
  onUpdateFields: (
    recordId: string,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  saveLabel: string;
}) {
  const { translateLiteral } = useLocalization();
  const cancelActiveEditSession = useCancelActiveEditSession();
  const currentValueSignature = fields
    .map((field) => `${field.field}:${getValue(field.field) ?? ''}`)
    .join('|');
  const draftDefaults = useMemo(
    () => createTrainerDrafts(fields, getValue),
    [currentValueSignature, fields, getValue]
  );
  const drafts = draftsByRecordId[draftKey] ?? draftDefaults;
  const draftSummary = useMemo(
    () => getTrainerDraftSummary(fields, drafts, getValue),
    [drafts, fields, getValue]
  );
  const fieldGroups = useMemo(
    () => groupNumericEditableFields(fields, getGroup),
    [fields, getGroup]
  );
  const canSave =
    canEdit &&
    !disabled &&
    draftSummary.changedFields.length > 0 &&
    draftSummary.invalidFields.length === 0;

  useEffect(() => {
    onChangeDrafts((currentDrafts) =>
      pruneFieldDraftRecord(currentDrafts, draftKey, draftDefaults)
    );
  }, [draftDefaults, draftKey, onChangeDrafts]);

  if (fields.length === 0) {
    return null;
  }

  return (
    <>
      <div className="editable-field-groups">
        {fieldGroups.map((group) => (
          <fieldset className="editable-field-group" key={group.group}>
            <legend>{translateLiteral(group.group)}</legend>
            <div className="editable-field-grid">
              {group.fields.map((field) => {
                const currentValue = getValue(field.field);
                const draftValue = drafts[field.field] ?? '';
                const draftState = getTrainerFieldDraftState(
                  draftValue,
                  currentValue,
                  field
                );

                return (
                  <TrainerDraftField
                    currentValue={currentValue}
                    disabled={!canEdit || disabled}
                    draftState={draftState}
                    draftValue={draftValue}
                    field={field}
                    formOptionContext={formOptionContext}
                    idPrefix="tera-raid-field"
                    key={field.field}
                    onChange={(value) => {
                      const nextDrafts = {
                        ...drafts,
                        [field.field]: value
                      };
                      onChangeDrafts((currentDrafts) =>
                        setFieldDraftRecord(
                          currentDrafts,
                          draftKey,
                          nextDrafts,
                          draftDefaults
                        )
                      );
                    }}
                  />
                );
              })}
            </div>
          </fieldset>
        ))}
      </div>

      <div className="draft-action-row">
        <button
          aria-busy={isBusy || undefined}
          className="primary-button"
          disabled={!canSave}
          onClick={async () => {
            const changes = draftSummary.changedFields.map((change) => ({
              field: change.field,
              value: change.value
            }));
            const firstChange = changes[0];
            const didSave =
              changes.length === 1 && firstChange
                ? await onUpdateField(draftKey, firstChange.field, firstChange.value)
                : await onUpdateFields(draftKey, changes);

            if (didSave) {
              onChangeDrafts((currentDrafts) =>
                deleteFieldDraftRecord(currentDrafts, draftKey)
              );
            }
          }}
          type="button"
        >
          <BusyActionContent
            busyLabel={translateLiteral('Staging')}
            icon={<Save aria-hidden="true" size={16} />}
            isBusy={isBusy}
            label={translateLiteral(saveLabel)}
          />
        </button>
        <button
          className="danger-button"
          disabled={disabled}
          onClick={() =>
            cancelActiveEditSession(() =>
              onChangeDrafts((currentDrafts) =>
                deleteFieldDraftRecord(currentDrafts, draftKey)
              )
            )
          }
          type="button"
        >
          <X aria-hidden="true" size={16} />
          <span>{translateLiteral('Cancel')}</span>
        </button>
        <span className="draft-action-summary">
          {translateLiteral(formatDraftSummary(draftSummary))}
        </span>
      </div>
    </>
  );
}

function RaidBattlesSection({
  editSession,
  isEditStarting,
  isRaidBattleUpdating,
  onSearchChange,
  onSelectTable,
  onStartEditSession,
  onUpdateRaidBattleSlotFields,
  searchText,
  selectedTableId,
  workflow
}: {
  editSession: EditSession | null;
  isEditStarting: boolean;
  isRaidBattleUpdating: boolean;
  onSearchChange: (value: string) => void;
  onSelectTable: (tableId: string) => void;
  onStartEditSession: () => void;
  onUpdateRaidBattleSlotFields: (
    updates: Array<{ tableId: string; slot: number; field: string; value: string }>
  ) => Promise<boolean>;
  searchText: string;
  selectedTableId: string | null;
  workflow: RaidBattlesWorkflow | null;
}) {
  const [selectedSlot, setSelectedSlot] = useState<number | null>(null);
  const { translateLiteral } = useLocalization();
  const normalizedSearch = searchText.trim().toLocaleLowerCase();
  const filteredTables =
    workflow?.tables.filter((table) => {
      if (!normalizedSearch) {
        return true;
      }

      return [
        table.denId,
        table.displayName,
        table.gameVersion,
        table.sourceTableHash,
        ...table.slots.flatMap((slot) => [
          slot.species,
          slot.speciesId.toString(),
          slot.levelTableHash,
          slot.dropTableHash,
          slot.dropRewardLink.preview,
          slot.dropRewardLink.rewardKindLabel,
          slot.dropRewardLink.sourceTableHash,
          slot.dropRewardLink.tableId,
          slot.bonusTableHash,
          slot.bonusRewardLink.preview,
          slot.bonusRewardLink.rewardKindLabel,
          slot.bonusRewardLink.sourceTableHash,
          slot.bonusRewardLink.tableId
        ])
      ]
        .flatMap((value) => [value, translateLiteral(value)])
        .join(' ')
        .toLocaleLowerCase()
        .includes(normalizedSearch);
    }) ?? [];
  const selectedTable =
    filteredTables.find((table) => table.tableId === selectedTableId) ??
    filteredTables[0] ??
    null;
  const selectedBattleSlot =
    selectedTable?.slots.find((slot) => slot.slot === selectedSlot) ??
    selectedTable?.slots[0] ??
    null;
  const canEditRaidBattles = workflow?.summary.availability === 'available';
  const pendingRaidBattleTableIds = getPendingRaidBattleTableIds(editSession);

  useEffect(() => {
    if (!selectedTable) {
      setSelectedSlot(null);
      return;
    }

    const hasSelectedSlot = selectedTable.slots.some((slot) => slot.slot === selectedSlot);
    if (!hasSelectedSlot) {
      setSelectedSlot(selectedTable.slots[0]?.slot ?? null);
    }
  }, [selectedSlot, selectedTable?.slots, selectedTable?.tableId]);

  return (
    <>
      <section aria-labelledby="raid-battles-heading" className="panel wide-panel">
        <div className="panel-heading">
          <ShieldCheck aria-hidden="true" size={18} />
          <h2 id="raid-battles-heading">Raid Battles</h2>
        </div>

        <div className="items-toolbar encounters-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label="Search raid battles"
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder="Search raid battles"
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label="Loaded tables"
            value={workflow ? workflow.stats.totalTableCount.toString() : '0'}
          />
          <Metric
            label="Battle slots"
            value={workflow ? workflow.stats.totalSlotCount.toString() : '0'}
          />
          <Metric
            label="G-Max slots"
            value={workflow ? workflow.stats.gigantamaxSlotCount.toString() : '0'}
          />
          <Metric
            label="Pending changes"
            value={(editSession?.pendingEdits.length ?? 0).toString()}
          />
        </div>

        {workflow ? (
          <div className="encounters-layout">
            <div
              className="raid-rewards-table"
              role="table"
              aria-label={translateLiteral('Raid battle tables')}
            >
              <div className="raid-rewards-row raid-rewards-row-heading" role="row">
                <span role="columnheader">{translateLiteral('Table')}</span>
                <span role="columnheader">{translateLiteral('Version')}</span>
                <span role="columnheader">{translateLiteral('Slots')}</span>
                <span role="columnheader">{translateLiteral('G-Max')}</span>
              </div>
              {filteredTables.map((table) => (
                <button
                  className={`raid-rewards-row ${
                    selectedTable?.tableId === table.tableId ? 'raid-rewards-row-selected' : ''
                  } ${
                    pendingRaidBattleTableIds.has(table.tableId) ? 'raid-rewards-row-pending' : ''
                  }`}
                  aria-selected={selectedTable?.tableId === table.tableId}
                  key={table.tableId}
                  onClick={() => onSelectTable(table.tableId)}
                  role="row"
                  type="button"
                >
                  <span role="cell">{translateLiteral(table.displayName)}</span>
                  <span role="cell">{translateLiteral(table.gameVersion)}</span>
                  <span role="cell">{table.slots.length}</span>
                  <span role="cell">{table.slots.filter((slot) => slot.isGigantamax).length}</span>
                </button>
              ))}
              {filteredTables.length === 0 ? (
                <p className="empty-copy raid-rewards-table-empty" role="status">
                  {translateLiteral('No matching raid battle tables.')}
                </p>
              ) : null}
            </div>

            <SelectedRaidBattlePanel
              battleSlot={selectedBattleSlot}
              canEditRaidBattles={canEditRaidBattles}
              editSession={editSession}
              editableFields={workflow.editableFields}
              isEditStarting={isEditStarting}
              isRaidBattleUpdating={isRaidBattleUpdating}
              onSelectSlot={setSelectedSlot}
              onStartEditSession={onStartEditSession}
              onUpdateRaidBattleSlotFields={onUpdateRaidBattleSlotFields}
              selectedSlot={selectedSlot}
              table={selectedTable}
            />
          </div>
        ) : (
          <p className="empty-copy">Open Raid Battles from Workflows to load backend battle data.</p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
    </>
  );
}

function SelectedRaidBattlePanel({
  battleSlot,
  canEditRaidBattles,
  editSession,
  editableFields,
  isEditStarting,
  isRaidBattleUpdating,
  onSelectSlot,
  onStartEditSession,
  onUpdateRaidBattleSlotFields,
  selectedSlot,
  table
}: {
  battleSlot: RaidBattleSlotRecord | null;
  canEditRaidBattles: boolean;
  editSession: EditSession | null;
  editableFields: RaidBattleEditableField[];
  isEditStarting: boolean;
  isRaidBattleUpdating: boolean;
  onSelectSlot: (slot: number | null) => void;
  onStartEditSession: () => void;
  onUpdateRaidBattleSlotFields: (
    updates: Array<{ tableId: string; slot: number; field: string; value: string }>
  ) => Promise<boolean>;
  selectedSlot: number | null;
  table: RaidBattleTableRecord | null;
}) {
  const [draftsBySlotKey, setDraftsBySlotKey] = useState<
    Record<string, Record<string, string>>
  >({});
  const cancelActiveEditSession = useCancelActiveEditSession();
  const raidBattleDraftKey = table && battleSlot ? `${table.tableId}:${battleSlot.slot}` : null;
  const storedRaidBattleDrafts = raidBattleDraftKey
    ? draftsBySlotKey[raidBattleDraftKey]
    : undefined;
  const draftSpeciesChanged = hasRaidBattleDraftFieldChanged(
    battleSlot,
    storedRaidBattleDrafts,
    raidBattleSpeciesFieldName
  );
  const draftFormChanged = hasRaidBattleDraftFieldChanged(
    battleSlot,
    storedRaidBattleDrafts,
    raidBattleFormFieldName
  );
  const raidBattleFields = useMemo(
    () =>
      battleSlot
        ? createRaidBattleDraftFields(editableFields, battleSlot, storedRaidBattleDrafts)
        : editableFields.map((field) => toNumericEditableControlField(field)),
    [
      battleSlot?.abilityOptions,
      battleSlot?.formOptions,
      battleSlot?.species,
      battleSlot?.speciesId,
      editableFields,
      storedRaidBattleDrafts
    ]
  );
  const raidBattleFieldGroups = useMemo(
    () => groupNumericEditableFields(raidBattleFields, getRaidBattleEditableFieldGroup),
    [raidBattleFields]
  );
  const raidBattleDraftDefaults = useMemo(
    () =>
      battleSlot
        ? createTrainerDrafts(raidBattleFields, (field) =>
            getEditableRaidBattleFieldValue(battleSlot, field)
          )
        : {},
    [
      battleSlot?.ability,
      battleSlot?.flawlessIvs,
      battleSlot?.form,
      battleSlot?.gender,
      battleSlot?.isGigantamax,
      battleSlot?.probabilities.join('|'),
      battleSlot?.slot,
      battleSlot?.speciesId,
      raidBattleFields,
      table?.tableId
    ]
  );
  const drafts = raidBattleDraftKey
    ? storedRaidBattleDrafts ?? raidBattleDraftDefaults
    : {};
  const raidBattleTableDraftSummary = useMemo(() => {
    const changedFields: TrainerDraftChange[] = [];
    const invalidFields: TrainerDraftChange[] = [];
    const updates: Array<{ tableId: string; slot: number; field: string; value: string }> = [];
    let dirtyFieldCount = 0;

    if (!table) {
      return { changedFields, dirtyFieldCount, invalidFields, updates };
    }

    for (const slotRecord of table.slots) {
      const draftKey = `${table.tableId}:${slotRecord.slot}`;
      const slotDrafts = draftsBySlotKey[draftKey];
      if (!slotDrafts) {
        continue;
      }

      const slotFields = createRaidBattleDraftFields(editableFields, slotRecord, slotDrafts);
      const summary = getTrainerDraftSummary(
        slotFields,
        slotDrafts,
        (field) => getEditableRaidBattleFieldValue(slotRecord, field)
      );
      dirtyFieldCount += summary.dirtyFieldCount;
      changedFields.push(...summary.changedFields);
      invalidFields.push(...summary.invalidFields);
      updates.push(
        ...summary.changedFields.map((change) => ({
          field: change.field,
          slot: slotRecord.slot,
          tableId: table.tableId,
          value: change.value
        }))
      );
    }

    return { changedFields, dirtyFieldCount, invalidFields, updates };
  }, [draftsBySlotKey, editableFields, table]);
  useRegisterEditorDraftDirty('raidBattles', countFieldDraftRecords(draftsBySlotKey) > 0);
  const canSaveRaidBattleDrafts =
    table !== null &&
    battleSlot !== null &&
    editSession !== null &&
    canEditRaidBattles &&
    !isRaidBattleUpdating &&
    raidBattleTableDraftSummary.updates.length > 0 &&
    raidBattleTableDraftSummary.invalidFields.length === 0;

  useEffect(() => {
    if (!raidBattleDraftKey) {
      return;
    }

    setDraftsBySlotKey((currentDrafts) =>
      pruneFieldDraftRecord(currentDrafts, raidBattleDraftKey, raidBattleDraftDefaults)
    );
  }, [raidBattleDraftDefaults, raidBattleDraftKey]);

  return (
    <aside aria-label="Selected raid battle provenance" className="encounter-inspector">
      <div className="panel-heading">
        <ShieldCheck aria-hidden="true" size={18} />
        <h3>Selected Battle</h3>
      </div>

      {table ? (
        <>
          <dl className="item-provenance-list">
            <div>
              <dt>Table</dt>
              <dd>{table.displayName}</dd>
            </div>
            <div>
              <dt>Hash</dt>
              <dd>{table.sourceTableHash}</dd>
            </div>
            <div>
              <dt>Game</dt>
              <dd>{table.gameVersion}</dd>
            </div>
            <div>
              <dt>Source file</dt>
              <dd>{table.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>Layer</dt>
              <dd>{formatSourceLayer(table.provenance.sourceLayer)}</dd>
            </div>
            <div>
              <dt>File state</dt>
              <dd>{formatFileState(table.provenance.fileState)}</dd>
            </div>
          </dl>

          <div className="encounter-edit-form">
            <div className="encounter-slot-header">
              <strong>Battle slots</strong>
              <select
                aria-label="Raid battle slot"
                disabled={table.slots.length === 0}
                onChange={(event) => onSelectSlot(Number(event.target.value))}
                value={selectedSlot ?? ''}
              >
                {table.slots.map((candidate) => (
                  <option key={candidate.slot} value={candidate.slot}>
                    Slot {candidate.slot}: {formatSpeciesFormLabel(
                      candidate.species,
                      candidate.form,
                      candidate.speciesId
                    )}
                  </option>
                ))}
              </select>
            </div>

            {battleSlot ? (
              <>
                <div className="encounter-slot-tabs" aria-label="Raid battle slot list">
                  {table.slots.map((candidate) => {
                    const slotLabel = formatSpeciesFormLabel(
                      candidate.species,
                      candidate.form,
                      candidate.speciesId
                    );

                    return (
                      <button
                        aria-pressed={candidate.slot === selectedSlot}
                        className="slot-tab-button"
                        key={candidate.slot}
                        onClick={() => onSelectSlot(candidate.slot)}
                        type="button"
                      >
                        <PokemonSprite className="slot-tab-sprite" name={slotLabel} preferStatic />
                        <strong>{`#${candidate.slot}`}</strong>
                        <span>{slotLabel}</span>
                        <small>{candidate.probabilitySummary}</small>
                      </button>
                    );
                  })}
                </div>

                <dl className="encounter-slot-detail">
                  <div>
                    <dt>Pokemon</dt>
                    <dd>
                      {formatSpeciesFormLabel(
                        battleSlot.species,
                        battleSlot.form,
                        battleSlot.speciesId
                      )} ({battleSlot.speciesId})
                    </dd>
                  </div>
                  <div>
                    <dt>Ability</dt>
                    <dd>{battleSlot.abilityLabel}</dd>
                  </div>
                  <div>
                    <dt>Gender</dt>
                    <dd>{battleSlot.genderLabel}</dd>
                  </div>
                  <div>
                    <dt>G-Max</dt>
                    <dd>{battleSlot.isGigantamax ? 'Yes' : 'No'}</dd>
                  </div>
                  <div>
                    <dt>Perfect IVs</dt>
                    <dd>{battleSlot.flawlessIvs}</dd>
                  </div>
                  <div>
                    <dt>Star odds</dt>
                    <dd>{battleSlot.probabilitySummary}</dd>
                  </div>
                  <div>
                    <dt>Level table</dt>
                    <dd>{battleSlot.levelTableHash}</dd>
                  </div>
                  <div>
                    <dt>Drop table</dt>
                    <dd>{battleSlot.dropTableHash}</dd>
                  </div>
                  <div>
                    <dt>Drop rewards</dt>
                    <dd>{formatRaidBattleRewardLink(battleSlot.dropRewardLink)}</dd>
                  </div>
                  <div>
                    <dt>Bonus table</dt>
                    <dd>{battleSlot.bonusTableHash}</dd>
                  </div>
                  <div>
                    <dt>Bonus rewards</dt>
                    <dd>{formatRaidBattleRewardLink(battleSlot.bonusRewardLink)}</dd>
                  </div>
                </dl>

                <div className="editable-field-groups">
                  {raidBattleFieldGroups.map((group) => (
                    <fieldset className="editable-field-group" key={group.group}>
                      <legend>{group.group}</legend>
                      <div className="editable-field-grid">
                        {group.fields.map((field) => {
                          const currentValue = getEditableRaidBattleFieldValue(
                            battleSlot,
                            field.field
                          );
                          const draftValue = drafts[field.field] ?? '';
                          const draftState = getTrainerFieldDraftState(
                            draftValue,
                            currentValue,
                            field
                          );

                          return (
                            <TrainerDraftField
                              currentValue={currentValue}
                              disabled={
                                !canEditRaidBattles ||
                                editSession === null ||
                                isRaidBattleUpdating
                              }
                              draftState={draftState}
                              draftValue={draftValue}
                              field={field}
                              formOptionContext={
                                (field.field === raidBattleFormFieldName && draftSpeciesChanged) ||
                                (field.field === raidBattleAbilityFieldName &&
                                  (draftSpeciesChanged || draftFormChanged))
                                  ? undefined
                                  : {
                                      abilityOptions: battleSlot.abilityOptions,
                                      formOptions: battleSlot.formOptions,
                                      gameFamily: 'swsh',
                                      species: battleSlot.species,
                                      speciesId: battleSlot.speciesId
                                    }
                              }
                              idPrefix="raid-battle-field"
                              key={field.field}
                              onChange={(value) => {
                                if (!raidBattleDraftKey) {
                                  return;
                                }

                                const nextDrafts = {
                                  ...drafts,
                                  [field.field]: value
                                };
                                setDraftsBySlotKey((currentDrafts) =>
                                  setFieldDraftRecord(
                                    currentDrafts,
                                    raidBattleDraftKey,
                                    nextDrafts,
                                    raidBattleDraftDefaults
                                  )
                                );
                              }}
                            />
                          );
                        })}
                      </div>
                    </fieldset>
                  ))}
                </div>
                {editSession ? (
                  <div className="draft-action-row">
                    <button
                      aria-busy={isRaidBattleUpdating || undefined}
                      className="primary-button"
                      disabled={!canSaveRaidBattleDrafts}
                      onClick={async () => {
                        if (!table || !battleSlot || !raidBattleDraftKey) {
                          return;
                        }

                        const didSave = await onUpdateRaidBattleSlotFields(
                          raidBattleTableDraftSummary.updates
                        );
                        if (didSave) {
                          setDraftsBySlotKey((currentDrafts) => {
                            const nextDrafts = { ...currentDrafts };
                            for (const slotRecord of table.slots) {
                              delete nextDrafts[`${table.tableId}:${slotRecord.slot}`];
                            }
                            return nextDrafts;
                          });
                        }
                      }}
                      type="button"
                    >
                      <BusyActionContent
                        busyLabel="Staging"
                        icon={<Save aria-hidden="true" size={16} />}
                        isBusy={isRaidBattleUpdating}
                        label="Stage"
                      />
                    </button>
                    <button
                      className="danger-button"
                      disabled={isRaidBattleUpdating}
                      onClick={() => cancelActiveEditSession(() => setDraftsBySlotKey({}))}
                      type="button"
                    >
                      <X aria-hidden="true" size={16} />
                      <span>Cancel</span>
                    </button>
                    <span className="draft-action-summary">
                      {formatDraftSummary(raidBattleTableDraftSummary)}
                    </span>
                  </div>
                ) : null}
              </>
            ) : (
              <p className="empty-copy">No raid battle selected.</p>
            )}

            {!editSession ? (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditRaidBattles || isEditStarting || table.slots.length === 0}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            ) : null}
          </div>
        </>
      ) : (
        <p className="empty-copy">No raid battle table selected.</p>
      )}
    </aside>
  );
}

function RaidRewardsSection({
  editSession,
  emptyCopy,
  headingId,
  isEditStarting,
  isRaidRewardUpdating,
  onSearchChange,
  onSelectTable,
  onStartEditSession,
  onUpdateRaidRewardFields,
  pendingDomain,
  searchText,
  searchPlaceholder,
  sectionId,
  selectedTableId,
  title,
  workflow
}: {
  editSession: EditSession | null;
  emptyCopy: string;
  headingId: string;
  isEditStarting: boolean;
  isRaidRewardUpdating: boolean;
  onSearchChange: (value: string) => void;
  onSelectTable: (tableId: string) => void;
  onStartEditSession: () => void;
  onUpdateRaidRewardFields: (
    tableId: string,
    slot: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  pendingDomain: string;
  searchText: string;
  searchPlaceholder: string;
  sectionId: WorkbenchSection;
  selectedTableId: string | null;
  title: string;
  workflow: RaidRewardsWorkflow | null;
}) {
  const { translateLiteral } = useLocalization();
  const [selectedSlot, setSelectedSlot] = useState<number | null>(null);
  const filteredTables = useMemo(() => {
    const normalizedSearch = searchText.trim().toLocaleLowerCase();
    if (!normalizedSearch) {
      return workflow?.tables ?? [];
    }

    return (
      workflow?.tables.filter((table) =>
        [
          table.archiveMember,
          table.denId,
          table.displayName,
          table.rewardKindLabel,
          table.sourceTableHash,
          ...table.rewards.flatMap((reward) => [reward.itemName, reward.itemId.toString()])
        ]
          .flatMap((value) => [value, translateLiteral(value)])
          .join(' ')
          .toLocaleLowerCase()
          .includes(normalizedSearch)
      ) ?? []
    );
  }, [searchText, translateLiteral, workflow?.tables]);
  const selectedTable =
    filteredTables.find((table) => table.tableId === selectedTableId) ??
    filteredTables[0] ??
    null;
  const selectedReward =
    selectedTable?.rewards.find((reward) => reward.slot === selectedSlot) ??
    selectedTable?.rewards[0] ??
    null;
  const canEditRaidRewards = workflow?.summary.availability === 'available';
  const pendingRaidRewardTableIds = getPendingRaidRewardTableIds(editSession, pendingDomain);

  useEffect(() => {
    if (!selectedTable) {
      setSelectedSlot(null);
      return;
    }

    const hasSelectedSlot = selectedTable.rewards.some((reward) => reward.slot === selectedSlot);
    if (!hasSelectedSlot) {
      setSelectedSlot(selectedTable.rewards[0]?.slot ?? null);
    }
  }, [selectedSlot, selectedTable?.rewards, selectedTable?.tableId]);

  return (
    <>
      <section aria-labelledby={headingId} className="panel wide-panel">
        <div className="panel-heading">
          <ShieldCheck aria-hidden="true" size={18} />
          <h2 id={headingId}>{translateLiteral(title)}</h2>
        </div>

        <div className="items-toolbar encounters-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label={translateLiteral(searchPlaceholder)}
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder={translateLiteral(searchPlaceholder)}
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label={translateLiteral('Loaded tables')}
            value={workflow ? workflow.stats.totalTableCount.toString() : '0'}
          />
          <Metric
            label={translateLiteral('Reward rows')}
            value={workflow ? workflow.stats.totalRewardItemCount.toString() : '0'}
          />
          <Metric
            label={translateLiteral('Pending changes')}
            value={(editSession?.pendingEdits.length ?? 0).toString()}
          />
        </div>

        {workflow ? (
          <div className="encounters-layout">
            <div
              className="raid-rewards-table"
              role="table"
              aria-label={translateLiteral(title)}
            >
              <div className="raid-rewards-row raid-rewards-row-heading" role="row">
                <span role="columnheader">{translateLiteral('Table')}</span>
                <span role="columnheader">{translateLiteral('Hash')}</span>
                <span role="columnheader">{translateLiteral('Rewards')}</span>
                <span role="columnheader">{translateLiteral('Member')}</span>
              </div>
              {filteredTables.map((table) => (
                <button
                  className={`raid-rewards-row ${
                    selectedTable?.tableId === table.tableId ? 'raid-rewards-row-selected' : ''
                  } ${
                    pendingRaidRewardTableIds.has(table.tableId) ? 'raid-rewards-row-pending' : ''
                  }`}
                  aria-selected={selectedTable?.tableId === table.tableId}
                  key={table.tableId}
                  onClick={() => onSelectTable(table.tableId)}
                  role="row"
                  type="button"
                >
                  <span role="cell">{translateLiteral(table.displayName)}</span>
                  <span role="cell">{table.sourceTableHash}</span>
                  <span role="cell">{table.rewards.length}</span>
                  <span role="cell">{translateLiteral(table.archiveMember)}</span>
                </button>
              ))}
              {filteredTables.length === 0 ? (
                <p className="empty-copy raid-rewards-table-empty" role="status">
                  {translateLiteral('No matching reward tables.')}
                </p>
              ) : null}
            </div>

            <SelectedRaidRewardPanel
              canEditRaidRewards={canEditRaidRewards}
              editSession={editSession}
              editableFields={workflow.editableFields}
              isEditStarting={isEditStarting}
              isRaidRewardUpdating={isRaidRewardUpdating}
              onSelectSlot={setSelectedSlot}
              onStartEditSession={onStartEditSession}
              onUpdateRaidRewardFields={onUpdateRaidRewardFields}
              reward={selectedReward}
              sectionId={sectionId}
              selectedSlot={selectedSlot}
              table={selectedTable}
            />
          </div>
        ) : (
          <p className="empty-copy">{translateLiteral(emptyCopy)}</p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
    </>
  );
}

function SelectedRaidRewardPanel({
  canEditRaidRewards,
  editSession,
  editableFields,
  isEditStarting,
  isRaidRewardUpdating,
  onSelectSlot,
  onStartEditSession,
  onUpdateRaidRewardFields,
  reward,
  sectionId,
  selectedSlot,
  table
}: {
  canEditRaidRewards: boolean;
  editSession: EditSession | null;
  editableFields: RaidRewardEditableField[];
  isEditStarting: boolean;
  isRaidRewardUpdating: boolean;
  onSelectSlot: (slot: number | null) => void;
  onStartEditSession: () => void;
  onUpdateRaidRewardFields: (
    tableId: string,
    slot: number,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  reward: RaidRewardItemRecord | null;
  sectionId: WorkbenchSection;
  selectedSlot: number | null;
  table: RaidRewardTableRecord | null;
}) {
  const { translateLiteral } = useLocalization();
  const [draftsBySlotKey, setDraftsBySlotKey] = useState<
    Record<string, Record<string, string>>
  >({});
  const cancelActiveEditSession = useCancelActiveEditSession();
  const raidRewardFields = useMemo(
    () =>
      editableFields.map((field) => {
        const numericField = toNumericEditableControlField(
          getRaidRewardFieldForKind(field, table?.rewardKind)
        );
        if (
          field.field !== raidRewardItemIdFieldName ||
          reward === null ||
          numericField.options.some((option) => option.value === reward.itemId)
        ) {
          return numericField;
        }

        return {
          ...numericField,
          options: [
            {
              label: `${reward.itemId.toString().padStart(3, '0')} ${reward.itemName}`,
              value: reward.itemId
            },
            ...numericField.options
          ]
        };
      }),
    [editableFields, reward, table?.rewardKind]
  );
  const raidRewardFieldGroups = useMemo(
    () => groupNumericEditableFields(raidRewardFields, getRaidRewardEditableFieldGroup),
    [raidRewardFields]
  );
  const raidRewardDraftDefaults = useMemo(
    () =>
      reward
        ? createTrainerDrafts(raidRewardFields, (field) =>
            getEditableRaidRewardFieldValue(reward, field)
          )
        : {},
    [raidRewardFields, reward?.itemId, reward?.slot, reward?.values.join('|'), table?.tableId]
  );
  const raidRewardDraftKey = table && reward ? `${table.tableId}:${reward.slot}` : null;
  const drafts = raidRewardDraftKey
    ? draftsBySlotKey[raidRewardDraftKey] ?? raidRewardDraftDefaults
    : {};
  const raidRewardDraftSummary = useMemo(
    () =>
      getTrainerDraftSummary(
        raidRewardFields,
        drafts,
        reward ? (field) => getEditableRaidRewardFieldValue(reward, field) : null
      ),
    [drafts, raidRewardFields, reward]
  );
  useRegisterEditorDraftDirty(sectionId, countFieldDraftRecords(draftsBySlotKey) > 0);
  const canSaveRaidRewardDrafts =
    table !== null &&
    reward !== null &&
    editSession !== null &&
    canEditRaidRewards &&
    !isRaidRewardUpdating &&
    raidRewardDraftSummary.changedFields.length > 0 &&
    raidRewardDraftSummary.invalidFields.length === 0;

  useEffect(() => {
    if (!raidRewardDraftKey) {
      return;
    }

    setDraftsBySlotKey((currentDrafts) =>
      pruneFieldDraftRecord(currentDrafts, raidRewardDraftKey, raidRewardDraftDefaults)
    );
  }, [raidRewardDraftDefaults, raidRewardDraftKey]);

  return (
    <aside
      aria-label={translateLiteral('Selected raid reward provenance')}
      className="encounter-inspector"
    >
      <div className="panel-heading">
        <ShieldCheck aria-hidden="true" size={18} />
        <h3>{translateLiteral('Selected Reward')}</h3>
      </div>

      {table ? (
        <>
          <dl className="item-provenance-list">
            <div>
              <dt>{translateLiteral('Table')}</dt>
              <dd>{table.sourceTableHash}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Kind')}</dt>
              <dd>{translateLiteral(table.rewardKindLabel)}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Archive member')}</dt>
              <dd>{translateLiteral(table.archiveMember)}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Source file')}</dt>
              <dd>{table.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Layer')}</dt>
              <dd>{translateLiteral(formatSourceLayer(table.provenance.sourceLayer))}</dd>
            </div>
            <div>
              <dt>{translateLiteral('File state')}</dt>
              <dd>{translateLiteral(formatFileState(table.provenance.fileState))}</dd>
            </div>
          </dl>

          <div className="encounter-edit-form">
            <div className="encounter-slot-header">
              <strong>{translateLiteral('Rewards')}</strong>
              <select
                aria-label={translateLiteral('Raid reward slot')}
                disabled={table.rewards.length === 0}
                onChange={(event) => onSelectSlot(Number(event.target.value))}
                value={selectedSlot ?? ''}
              >
                {table.rewards.map((candidate) => (
                  <option key={candidate.slot} value={candidate.slot}>
                    {translateLiteral('Slot')} {candidate.slot}:{' '}
                    {translateLiteral(candidate.itemName)}
                  </option>
                ))}
              </select>
            </div>

            {reward ? (
              <>
                <dl className="encounter-slot-detail">
                  <div>
                    <dt>{translateLiteral('Item')}</dt>
                    <dd>
                      {translateLiteral(reward.itemName)} ({reward.itemId})
                    </dd>
                  </div>
                  <div>
                    <dt>{translateLiteral('Entry ID')}</dt>
                    <dd>{reward.entryId}</dd>
                  </div>
                  <div>
                    <dt>{translateLiteral(getRaidRewardValuesLabel(table.rewardKind))}</dt>
                    <dd>
                      {translateLiteral(formatRaidRewardValues(table.rewardKind, reward.values))}
                    </dd>
                  </div>
                </dl>

                <div
                  className="raid-reward-slot-grid"
                  aria-label={translateLiteral('Raid reward slots')}
                >
                  {table.rewards.slice(0, 10).map((candidate) => (
                    <button
                      aria-pressed={candidate.slot === selectedSlot}
                      className="slot-tab-button"
                      key={candidate.slot}
                      onClick={() => onSelectSlot(candidate.slot)}
                      type="button"
                    >
                      <strong>{`#${candidate.slot}`}</strong>
                      <span>{translateLiteral(candidate.itemName)}</span>
                      <small>
                        {translateLiteral(formatRaidRewardSlotSummary(table.rewardKind, candidate))}
                      </small>
                    </button>
                  ))}
                </div>

                <div className="editable-field-groups">
                  {raidRewardFieldGroups.map((group) => (
                    <fieldset className="editable-field-group" key={group.group}>
                      <legend>{translateLiteral(group.group)}</legend>
                      <div className="editable-field-grid">
                        {group.fields.map((field) => {
                          const currentValue = getEditableRaidRewardFieldValue(
                            reward,
                            field.field
                          );
                          const draftValue = drafts[field.field] ?? '';
                          const draftState = getTrainerFieldDraftState(
                            draftValue,
                            currentValue,
                            field
                          );

                          return (
                            <TrainerDraftField
                              currentValue={currentValue}
                              disabled={
                                !canEditRaidRewards ||
                                editSession === null ||
                                isRaidRewardUpdating
                              }
                              draftState={draftState}
                              draftValue={draftValue}
                              field={field}
                              idPrefix="raid-reward-field"
                              key={field.field}
                              onChange={(value) => {
                                if (!raidRewardDraftKey) {
                                  return;
                                }

                                const nextDrafts = {
                                  ...drafts,
                                  [field.field]: value
                                };
                                setDraftsBySlotKey((currentDrafts) =>
                                  setFieldDraftRecord(
                                    currentDrafts,
                                    raidRewardDraftKey,
                                    nextDrafts,
                                    raidRewardDraftDefaults
                                  )
                                );
                              }}
                            />
                          );
                        })}
                      </div>
                    </fieldset>
                  ))}
                </div>
                {editSession ? (
                  <div className="draft-action-row">
                    <button
                      aria-busy={isRaidRewardUpdating || undefined}
                      className="primary-button"
                      disabled={!canSaveRaidRewardDrafts}
                      onClick={async () => {
                        if (!table || !reward || !raidRewardDraftKey) {
                          return;
                        }

                        const didSave = await onUpdateRaidRewardFields(
                          table.tableId,
                          reward.slot,
                          raidRewardDraftSummary.changedFields.map((change) => ({
                            field: change.field,
                            value: change.value
                          }))
                        );
                        if (didSave) {
                          setDraftsBySlotKey((currentDrafts) =>
                            deleteFieldDraftRecord(currentDrafts, raidRewardDraftKey)
                          );
                        }
                      }}
                      type="button"
                    >
                      <BusyActionContent
                        busyLabel="Staging"
                        icon={<Save aria-hidden="true" size={16} />}
                        isBusy={isRaidRewardUpdating}
                        label="Stage"
                      />
                    </button>
                    <button
                      className="danger-button"
                      disabled={isRaidRewardUpdating}
                      onClick={() => cancelActiveEditSession(() => setDraftsBySlotKey({}))}
                      type="button"
                    >
                      <X aria-hidden="true" size={16} />
                      <span>{translateLiteral('Cancel')}</span>
                    </button>
                    <span className="draft-action-summary">
                      {formatDraftSummary(raidRewardDraftSummary)}
                    </span>
                  </div>
                ) : null}
              </>
            ) : (
              <p className="empty-copy">{translateLiteral('No raid reward selected.')}</p>
            )}

            {!editSession ? (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditRaidRewards || isEditStarting || table.rewards.length === 0}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            ) : null}
          </div>
        </>
      ) : (
        <p className="empty-copy">{translateLiteral('No reward table selected.')}</p>
      )}
    </aside>
  );
}

function getRaidRewardFieldForKind(
  field: RaidRewardEditableField,
  rewardKind?: string
): RaidRewardEditableField {
  if (
    !raidRewardValueFieldNames.includes(field.field as (typeof raidRewardValueFieldNames)[number])
  ) {
    return field;
  }

  const starLabel = field.label.match(/^(\d-star)/)?.[1];
  if (!starLabel) {
    return field;
  }

  const valueLabel = rewardKind === 'drop' ? 'drop chance' : 'quantity';
  return {
    ...field,
    label: `${starLabel} ${valueLabel}`,
    maximumValue:
      rewardKind === 'drop' ? Math.min(field.maximumValue ?? 100, 100) : field.maximumValue
  };
}

function getRaidRewardValuesLabel(rewardKind: string) {
  return rewardKind === 'drop' ? 'Drop chances by star' : 'Reward quantities by star';
}

function formatRaidRewardValues(rewardKind: string, values: number[]) {
  return values
    .slice(0, 5)
    .map((value, index) =>
      rewardKind === 'drop'
        ? `${index + 1}-star ${value}% chance`
        : `${index + 1}-star ${value} item${value === 1 ? '' : 's'}`
    )
    .join(' / ');
}

function formatRaidRewardSlotSummary(rewardKind: string, reward: RaidRewardItemRecord) {
  return rewardKind === 'drop'
    ? `Drop chance ${reward.values.slice(0, 5).join('/')}%`
    : `Quantity ${reward.values.slice(0, 5).join('/')}`;
}

function BehaviorSection({
  editSession,
  isBehaviorUpdating,
  isEditStarting,
  onSearchChange,
  onSelectEntry,
  onStartEditSession,
  onUpdateBehaviorEntryFields,
  searchText,
  selectedEntryId,
  workflow
}: {
  editSession: EditSession | null;
  isBehaviorUpdating: boolean;
  isEditStarting: boolean;
  onSearchChange: (value: string) => void;
  onSelectEntry: (entryId: string | null) => void;
  onStartEditSession: () => void;
  onUpdateBehaviorEntryFields: (
    entryId: string,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  searchText: string;
  selectedEntryId: string | null;
  workflow: BehaviorWorkflow | null;
}) {
  const { translateLiteral } = useLocalization();
  const normalizedSearch = searchText.trim().toLocaleLowerCase();
  const filteredEntries =
    workflow?.entries.filter((entry) => {
      if (!normalizedSearch) {
        return true;
      }

      const fieldSearchValues = entry.fields.flatMap((fieldValue) => {
        const field = workflow.fields.find((candidate) => candidate.field === fieldValue.field);
        const options = fieldValue.field === 'form' ? entry.formOptions : field?.options;
        const option = options?.find(
          (candidate) => candidate.value === fieldValue.value
        );
        const hasLocalizedOption =
          field?.field === 'behavior' || field?.field === 'form';

        return [
          fieldValue.field,
          fieldValue.value,
          option?.label ?? '',
          hasLocalizedOption && option ? translateLiteral(option.label) : ''
        ];
      });

      return [
        entry.behavior,
        entry.behaviorLabel,
        translateLiteral(entry.behaviorLabel),
        entry.form.toString(),
        formatBehaviorSpecies(entry),
        formatBehaviorNumber(entry.grassShakeRadius),
        formatBehaviorNumber(entry.hitboxRadius),
        entry.hash1,
        entry.hash2,
        entry.index.toString(),
        `#${entry.index}`,
        entry.internalSpeciesName,
        entry.label,
        entry.modelPart,
        entry.provenance.fileState,
        entry.provenance.sourceFile,
        entry.provenance.sourceLayer,
        formatFileState(entry.provenance.fileState),
        translateLiteral(formatFileState(entry.provenance.fileState)),
        formatSourceLayer(entry.provenance.sourceLayer),
        translateLiteral(formatSourceLayer(entry.provenance.sourceLayer)),
        entry.speciesId.toString(),
        entry.speciesName,
        ...fieldSearchValues
      ]
        .join(' ')
        .toLocaleLowerCase()
        .includes(normalizedSearch);
    }) ?? [];
  const selectedEntry =
    filteredEntries.find((entry) => entry.entryId === selectedEntryId) ??
    filteredEntries[0] ??
    null;
  const canEditBehavior = workflow?.summary.availability === 'available';
  const pendingBehaviorEntryIds = getPendingBehaviorEntryIds(editSession);
  const pendingBehaviorEditCount = (editSession?.pendingEdits ?? []).filter(
    (edit) => edit.domain === 'workflow.behavior'
  ).length;

  useEffect(() => {
    if (selectedEntry && selectedEntry.entryId !== selectedEntryId) {
      onSelectEntry(selectedEntry.entryId);
    }
  }, [onSelectEntry, selectedEntry?.entryId, selectedEntryId]);

  return (
    <>
      <section aria-labelledby="behavior-heading" className="panel wide-panel swsh-behavior-section">
        <div className="panel-heading">
          <Activity aria-hidden="true" size={18} />
          <h2 id="behavior-heading">{translateLiteral('Behavior')}</h2>
        </div>

        <div className="items-toolbar encounters-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label={translateLiteral('Search behavior')}
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder={translateLiteral('Search behavior')}
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label={translateLiteral('Loaded entries')}
            value={workflow ? workflow.stats.totalEntryCount.toString() : '0'}
          />
          <Metric
            label={translateLiteral('Profiles')}
            value={workflow ? workflow.stats.totalBehaviorCount.toString() : '0'}
          />
          <Metric
            label={translateLiteral('Pending changes')}
            value={pendingBehaviorEditCount.toString()}
          />
        </div>

        {workflow ? (
          <div className="encounters-layout behavior-layout">
            <div className="raid-rewards-table" role="table" aria-label={translateLiteral('Behavior entries')}>
              <div className="raid-rewards-row raid-rewards-row-heading" role="row">
                <span role="columnheader">{translateLiteral('Pokemon')}</span>
                <span role="columnheader">{translateLiteral('Behavior')}</span>
                <span role="columnheader">{translateLiteral('Anchor')}</span>
                <span role="columnheader">{translateLiteral('Range')}</span>
              </div>
              {filteredEntries.map((entry) => (
                <button
                  aria-selected={selectedEntry?.entryId === entry.entryId}
                  className={`raid-rewards-row ${
                    selectedEntry?.entryId === entry.entryId
                      ? 'raid-rewards-row-selected'
                      : ''
                  } ${
                    pendingBehaviorEntryIds.has(entry.entryId) ? 'raid-rewards-row-pending' : ''
                  }`}
                  key={entry.entryId}
                  onClick={() => onSelectEntry(entry.entryId)}
                  role="row"
                  type="button"
                >
                  <span data-localization-ignore="true" role="cell">
                    {formatBehaviorSpecies(entry)}
                  </span>
                  <span role="cell">{translateLiteral(entry.behaviorLabel)}</span>
                  <span data-localization-ignore={entry.modelPart ? 'true' : undefined} role="cell">
                    {entry.modelPart || translateLiteral('n/a')}
                  </span>
                  <span role="cell">
                    {translateLiteral('Hitbox radius')} {formatBehaviorNumber(entry.hitboxRadius)} /{' '}
                    {translateLiteral('Grass shake radius')}{' '}
                    {formatBehaviorNumber(entry.grassShakeRadius)}
                  </span>
                </button>
              ))}
              {filteredEntries.length === 0 ? (
                <div className="empty-copy" role="status">
                  {translateLiteral('No matching behavior entries.')}
                </div>
              ) : null}
            </div>

            <SelectedBehaviorPanel
              canEditBehavior={canEditBehavior}
              editSession={editSession}
              entry={selectedEntry}
              fields={workflow.fields}
              isBehaviorUpdating={isBehaviorUpdating}
              isEditStarting={isEditStarting}
              onStartEditSession={onStartEditSession}
              onUpdateBehaviorEntryFields={onUpdateBehaviorEntryFields}
            />
          </div>
        ) : (
          <p className="empty-copy">
            {translateLiteral('Open Behavior from Workflows to load symbol behavior data.')}
          </p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
    </>
  );
}

function SelectedBehaviorPanel({
  canEditBehavior,
  editSession,
  entry,
  fields,
  isBehaviorUpdating,
  isEditStarting,
  onStartEditSession,
  onUpdateBehaviorEntryFields
}: {
  canEditBehavior: boolean;
  editSession: EditSession | null;
  entry: BehaviorEntryRecord | null;
  fields: BehaviorField[];
  isBehaviorUpdating: boolean;
  isEditStarting: boolean;
  onStartEditSession: () => void;
  onUpdateBehaviorEntryFields: (
    entryId: string,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
}) {
  const [draftsByEntryId, setDraftsByEntryId] = useState<
    Record<string, Record<string, string>>
  >({});
  const { translateLiteral } = useLocalization();
  const cancelActiveEditSession = useCancelActiveEditSession();
  const behaviorFieldGroups = useMemo(() => groupBehaviorFields(fields), [fields]);
  const behaviorDraftDefaults = useMemo(
    () => (entry ? createBehaviorDraftDefaults(fields, entry) : {}),
    [entry?.entryId, entry?.fields, fields]
  );
  const drafts = entry ? draftsByEntryId[entry.entryId] ?? behaviorDraftDefaults : {};
  const behaviorDraftSummary = useMemo(
    () => getBehaviorDraftSummary(fields, drafts, entry),
    [drafts, entry, fields]
  );
  useRegisterEditorDraftDirty('behavior', countFieldDraftRecords(draftsByEntryId) > 0);
  const canSaveBehaviorDrafts =
    entry !== null &&
    editSession !== null &&
    canEditBehavior &&
    !isBehaviorUpdating &&
    behaviorDraftSummary.changedFields.length > 0 &&
    behaviorDraftSummary.invalidFields.length === 0;

  useEffect(() => {
    if (!entry) {
      return;
    }

    setDraftsByEntryId((currentDrafts) =>
      pruneFieldDraftRecord(currentDrafts, entry.entryId, behaviorDraftDefaults)
    );
  }, [entry, behaviorDraftDefaults]);

  return (
    <aside
      aria-label={translateLiteral('Selected behavior entry provenance')}
      className="encounter-inspector"
    >
      <div className="panel-heading">
        <Activity aria-hidden="true" size={18} />
        <h3>{translateLiteral('Selected Behavior')}</h3>
      </div>

      {entry ? (
        <>
          <dl className="item-provenance-list">
            <div>
              <dt>{translateLiteral('Pokemon')}</dt>
              <dd data-localization-ignore="true">{formatBehaviorSpecies(entry)}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Behavior')}</dt>
              <dd>{translateLiteral(entry.behaviorLabel)}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Model anchor')}</dt>
              <dd data-localization-ignore={entry.modelPart ? 'true' : undefined}>
                {entry.modelPart || translateLiteral('n/a')}
              </dd>
            </div>
            <div>
              <dt>{translateLiteral('Source file')}</dt>
              <dd>{entry.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>{translateLiteral('Layer')}</dt>
              <dd>{translateLiteral(formatSourceLayer(entry.provenance.sourceLayer))}</dd>
            </div>
            <div>
              <dt>{translateLiteral('File state')}</dt>
              <dd>{translateLiteral(formatFileState(entry.provenance.fileState))}</dd>
            </div>
          </dl>

          <div className="encounter-edit-form">
            <dl className="encounter-slot-detail">
              <div>
                <dt>{translateLiteral('Hitbox radius')}</dt>
                <dd>{formatBehaviorNumber(entry.hitboxRadius)}</dd>
              </div>
              <div>
                <dt>{translateLiteral('Grass shake radius')}</dt>
                <dd>{formatBehaviorNumber(entry.grassShakeRadius)}</dd>
              </div>
              <div>
                <dt>{translateLiteral('Internal name')}</dt>
                <dd data-localization-ignore={entry.internalSpeciesName ? 'true' : undefined}>
                  {entry.internalSpeciesName || translateLiteral('n/a')}
                </dd>
              </div>
              <div>
                <dt>{translateLiteral('Hash 1')}</dt>
                <dd>{entry.hash1}</dd>
              </div>
              <div>
                <dt>{translateLiteral('Hash 2')}</dt>
                <dd>{entry.hash2}</dd>
              </div>
              <div>
                <dt>{translateLiteral('Entry')}</dt>
                <dd>#{entry.index}</dd>
              </div>
            </dl>

            <div className="editable-field-groups behavior-field-groups">
              {behaviorFieldGroups.map((group) => (
                <fieldset className="editable-field-group" key={group.group}>
                  <legend>{translateLiteral(group.group)}</legend>
                  <div className="editable-field-grid">
                    {group.fields.map((field) => {
                      const currentValue = getBehaviorEntryFieldValue(entry, field.field);
                      const draftValue = drafts[field.field] ?? currentValue;
                      const fieldOptions = getEffectiveBehaviorFieldOptions(
                        field,
                        entry,
                        drafts
                      );
                      const draftState = getBehaviorDraftState(
                        draftValue,
                        currentValue,
                        field,
                        fieldOptions
                      );
                      const isDirty = draftValue !== currentValue;
                      const isInvalid =
                        !field.isReadOnly &&
                        isDirty &&
                        draftState.normalizedValue === null;
                      const isChanged =
                        !field.isReadOnly && isDirty && draftState.normalizedValue !== null;
                      const isDisabled =
                        !canEditBehavior ||
                        editSession === null ||
                        isBehaviorUpdating ||
                        field.isReadOnly;
                      const statusText = field.isReadOnly
                        ? field.description || 'Read-only'
                        : isInvalid
                          ? getBehaviorFieldValidationText(field, fieldOptions, draftValue)
                          : isChanged
                            ? 'Changed'
                            : null;

                      return (
                        <label
                          className={`path-field editable-field-control ${
                            isChanged ? 'editable-field-changed' : ''
                          } ${isInvalid ? 'editable-field-invalid' : ''}`}
                          htmlFor={`behavior-field-${field.field}`}
                          key={field.field}
                        >
                          <span>{translateLiteral(field.label)}</span>
                          {fieldOptions && fieldOptions.length > 0 ? (
                            <select
                              aria-label={translateLiteral(field.label)}
                              disabled={isDisabled}
                              id={`behavior-field-${field.field}`}
                              onChange={(event) => {
                                const nextDrafts = {
                                  ...drafts,
                                  [field.field]: event.target.value
                                };
                                setDraftsByEntryId((currentDrafts) =>
                                  setFieldDraftRecord(
                                    currentDrafts,
                                    entry.entryId,
                                    nextDrafts,
                                    behaviorDraftDefaults
                                  )
                                );
                              }}
                              title={translateLiteral(field.description)}
                              value={draftValue}
                            >
                              {addBehaviorDraftFallbackOption(
                                fieldOptions,
                                draftValue,
                                currentValue
                              ).map((option) => (
                                <option
                                  data-localization-ignore={
                                    field.field === 'behavior' || field.field === 'form'
                                      ? undefined
                                      : 'true'
                                  }
                                  key={`${field.field}-${option.value}`}
                                  value={option.value}
                                >
                                  {field.field === 'behavior' || field.field === 'form'
                                    ? translateLiteral(option.label)
                                    : option.label}
                                </option>
                              ))}
                            </select>
                          ) : (
                            <input
                              aria-label={translateLiteral(field.label)}
                              disabled={isDisabled}
                              id={`behavior-field-${field.field}`}
                              max={field.valueKind === 'string' ? undefined : field.maximumValue}
                              min={field.valueKind === 'string' ? undefined : field.minimumValue}
                              onChange={(event) => {
                                const nextDrafts = {
                                  ...drafts,
                                  [field.field]: event.target.value
                                };
                                setDraftsByEntryId((currentDrafts) =>
                                  setFieldDraftRecord(
                                    currentDrafts,
                                    entry.entryId,
                                    nextDrafts,
                                    behaviorDraftDefaults
                                  )
                                );
                              }}
                              step={field.valueKind === 'integer' ? 1 : 'any'}
                              title={translateLiteral(field.description)}
                              type={field.valueKind === 'string' || field.valueKind === 'hash' ? 'text' : 'number'}
                              value={draftValue}
                            />
                          )}
                          {statusText ? (
                            <small
                              className={
                                isInvalid ? 'editable-field-error' : 'editable-field-status'
                              }
                            >
                              {translateLiteral(statusText)}
                            </small>
                          ) : null}
                        </label>
                      );
                    })}
                  </div>
                </fieldset>
              ))}
            </div>

            {editSession ? (
              <div className="draft-action-row">
                <button
                  aria-busy={isBehaviorUpdating || undefined}
                  className="primary-button"
                  disabled={!canSaveBehaviorDrafts}
                  onClick={async () => {
                    if (!entry) {
                      return;
                    }

                    const didSave = await onUpdateBehaviorEntryFields(
                      entry.entryId,
                      behaviorDraftSummary.changedFields.map((change) => ({
                        field: change.field,
                        value: change.value
                      }))
                    );
                    if (didSave) {
                      setDraftsByEntryId((currentDrafts) =>
                        deleteFieldDraftRecord(currentDrafts, entry.entryId)
                      );
                    }
                  }}
                  type="button"
                >
                  <BusyActionContent
                    busyLabel="Staging"
                    icon={<Save aria-hidden="true" size={16} />}
                    isBusy={isBehaviorUpdating}
                    label="Stage"
                  />
                </button>
                <button
                  className="danger-button"
                  disabled={isBehaviorUpdating}
                  onClick={() => cancelActiveEditSession(() => setDraftsByEntryId({}))}
                  type="button"
                >
                  <X aria-hidden="true" size={16} />
                  <span>Cancel</span>
                </button>
                <span className="draft-action-summary">
                  {formatDraftSummary(behaviorDraftSummary)}
                </span>
              </div>
            ) : null}

            {!editSession ? (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditBehavior || isEditStarting}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            ) : null}
          </div>
        </>
      ) : (
        <p className="empty-copy">{translateLiteral('No behavior entry selected.')}</p>
      )}
    </aside>
  );
}

type PlacementSectionProps = {
  editSession: EditSession | null;
  editorFamily: EditorUiFamily;
  isEditStarting: boolean;
  isPlacementUpdating: boolean;
  onSearchChange: (value: string) => void;
  onSelectObject: (objectId: string | null) => void;
  onStartEditSession: () => void;
  onUpdatePlacementObjectFields: (
    objectId: string,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  searchText: string;
  selectedObjectId: string | null;
  updateDiagnostics: ApiDiagnostic[];
  workflow: PlacementWorkflow | null;
};

type PlacementSectionPublicProps = Omit<
  PlacementSectionProps,
  'editorFamily'
>;

function SwShPlacementSection(props: PlacementSectionPublicProps) {
  return <PlacementSection {...props} editorFamily="swsh" />;
}

function SvPlacementSection(props: PlacementSectionPublicProps) {
  return <PlacementSection {...props} editorFamily="sv" />;
}

function ZaPlacementSection(props: PlacementSectionPublicProps) {
  return <PlacementSection {...props} editorFamily="za" />;
}

function PlacementSection({
  editSession,
  editorFamily,
  isEditStarting,
  isPlacementUpdating,
  onSearchChange,
  onSelectObject,
  onStartEditSession,
  onUpdatePlacementObjectFields,
  searchText,
  selectedObjectId,
  updateDiagnostics,
  workflow
}: PlacementSectionProps) {
  const normalizedSearch = searchText.trim().toLocaleLowerCase();
  const placementCategories = getPlacementCategories(workflow);
  const supportsPlacementCategories =
    placementCategories.length > 0 &&
    (workflow?.objects.some((placedObject) => placedObject.categoryId?.trim()) ?? false);
  const [selectedCategoryId, setSelectedCategoryId] = useState<string | null>(null);
  const activeCategoryId = supportsPlacementCategories
    ? placementCategories.find((category) => category.id === selectedCategoryId)?.id ??
      placementCategories[0]?.id ??
      null
    : null;
  const filteredObjects =
    workflow?.objects.filter((placedObject) => {
      if (
        activeCategoryId &&
        getPlacementCategoryId(placedObject) !== activeCategoryId
      ) {
        return false;
      }

      if (!normalizedSearch) {
        return true;
      }

      return [
        placedObject.archiveMember,
        placedObject.categoryLabel ?? '',
        ...(placedObject.fields ?? []).flatMap((field) => [
          field.label,
          field.value,
          field.displayValue,
          field.group
        ]),
        placedObject.itemHash,
        placedObject.itemId?.toString() ?? '',
        placedObject.itemName,
        placedObject.label,
        placedObject.map,
        placedObject.objectType,
        placedObject.scriptId ?? ''
      ]
        .join(' ')
        .toLocaleLowerCase()
        .includes(normalizedSearch);
    }) ?? [];
  const groupedObjects = useMemo(
    () =>
      buildPlacementObjectGroups(filteredObjects, {
        groupItemBallSpawners: editorFamily === 'za',
        groupPokemonSpawners: editorFamily === 'za'
      }),
    [editorFamily, filteredObjects]
  );
  const selectedObject =
    filteredObjects.find((placedObject) => placedObject.objectId === selectedObjectId) ??
    groupedObjects[0]?.objects[0] ??
    null;
  const selectedGroup =
    groupedObjects.find((group) =>
      selectedObject ? group.objects.some((placedObject) => placedObject.objectId === selectedObject.objectId) : false
    ) ??
    groupedObjects[0] ??
    null;
  const canEditPlacement = workflow?.summary.availability === 'available';
  const pendingPlacementObjectIds = getPendingPlacementObjectIds(editSession);

  useEffect(() => {
    if (selectedObject && selectedObject.objectId !== selectedObjectId) {
      onSelectObject(selectedObject.objectId);
      return;
    }

    if (!selectedObject && selectedObjectId !== null) {
      onSelectObject(null);
    }
  }, [onSelectObject, selectedObject?.objectId, selectedObjectId]);

  useEffect(() => {
    if (!supportsPlacementCategories) {
      if (selectedCategoryId !== null) setSelectedCategoryId(null);
      return;
    }

    if (
      activeCategoryId === null ||
      placementCategories.some((category) => category.id === selectedCategoryId)
    ) {
      return;
    }

    setSelectedCategoryId(activeCategoryId);
  }, [activeCategoryId, placementCategories, selectedCategoryId, supportsPlacementCategories]);

  return (
    <>
      <section
        aria-labelledby="placement-heading"
        className={`panel wide-panel ${editorFamily}-editor-surface ${editorFamily}-placement-section`}
      >
        <div className="panel-heading">
          <MapPin aria-hidden="true" size={18} />
          <h2 id="placement-heading">Placement</h2>
        </div>

        <div className="items-toolbar encounters-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label="Search placement"
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder="Search placement"
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label="Loaded objects"
            value={workflow ? workflow.stats.totalObjectCount.toString() : '0'}
          />
          <Metric
            label="Areas"
            value={workflow ? workflow.stats.totalAreaCount.toString() : '0'}
          />
          <Metric
            label="Pending changes"
            value={(editSession?.pendingEdits.length ?? 0).toString()}
          />
        </div>

        {supportsPlacementCategories && placementCategories.length > 0 ? (
          <div
            aria-label="Placement categories"
            className="condition-tabs placement-category-tabs"
            role="tablist"
          >
            {placementCategories.map((category) => (
              <button
                aria-selected={category.id === activeCategoryId}
                className="condition-tab-button placement-category-tab"
                key={category.id}
                onClick={() => {
                  setSelectedCategoryId(category.id);
                  const categoryObjects = workflow?.objects.filter(
                    (placedObject) => getPlacementCategoryId(placedObject) === category.id
                  ) ?? [];
                  const firstGroup = buildPlacementObjectGroups(categoryObjects, {
                    groupItemBallSpawners: editorFamily === 'za',
                    groupPokemonSpawners: editorFamily === 'za'
                  })[0];
                  onSelectObject(firstGroup?.objects[0]?.objectId ?? null);
                }}
                role="tab"
                title={category.description}
                type="button"
              >
                <span>{category.label}</span>
                <small>{category.objectCount}</small>
              </button>
            ))}
          </div>
        ) : null}

        {workflow ? (
          <div className="encounters-layout placement-layout">
            <div className="raid-rewards-table placement-object-table" role="table" aria-label="Placed objects">
              <div className="raid-rewards-row raid-rewards-row-heading placement-object-row" role="row">
                <span role="columnheader">Object</span>
                <span role="columnheader">Pokemon / Data</span>
                <span role="columnheader">Position</span>
              </div>
              {groupedObjects.map((objectGroup) => {
                const isSelected = selectedObject
                  ? objectGroup.objects.some((placedObject) => placedObject.objectId === selectedObject.objectId)
                  : false;
                const isPending = objectGroup.objects.some((placedObject) =>
                  pendingPlacementObjectIds.has(placedObject.objectId)
                );
                const nextObjectId = isSelected
                  ? selectedObject?.objectId ?? objectGroup.objects[0]?.objectId ?? null
                  : objectGroup.objects[0]?.objectId ?? null;
                return (
                  <button
                    className={`raid-rewards-row placement-object-row ${
                      isSelected ? 'raid-rewards-row-selected' : ''
                    } ${isPending ? 'raid-rewards-row-pending' : ''}`}
                    key={objectGroup.key}
                    onClick={() => onSelectObject(nextObjectId)}
                    role="row"
                    type="button"
                  >
                    <span className="placement-object-name" role="cell">
                      <strong>{objectGroup.label}</strong>
                      <small>{objectGroup.map}</small>
                    </span>
                    <span className="placement-primary-cell" role="cell">
                      {objectGroup.preview}
                    </span>
                    <span role="cell">{objectGroup.position}</span>
                  </button>
                );
              })}
              {groupedObjects.length === 0 ? (
                <div className="raid-rewards-row placement-object-row placement-empty-row" role="row">
                  <span role="cell">{activeCategoryId === null ? 'No placement entries.' : `No entries in ${placementCategories.find((category) => category.id === activeCategoryId)?.label ?? 'placement'}.`}</span>
                </div>
              ) : null}
            </div>

            <SelectedPlacementPanel
              canEditPlacement={canEditPlacement}
              editSession={editSession}
              editableFields={workflow.editableFields}
              isEditStarting={isEditStarting}
              isPlacementUpdating={isPlacementUpdating}
              onStartEditSession={onStartEditSession}
              onUpdatePlacementObjectFields={onUpdatePlacementObjectFields}
              onSelectObject={onSelectObject}
              placementGroup={selectedGroup}
              placedObject={selectedObject}
            />
          </div>
        ) : (
          <p className="empty-copy">Open Placement from Workflows to load backend placement data.</p>
        )}
      </section>

      <DiagnosticsSection diagnostics={[...(workflow?.diagnostics ?? []), ...updateDiagnostics]} />
    </>
  );
}

function SelectedPlacementPanel({
  canEditPlacement,
  editSession,
  editableFields,
  isEditStarting,
  isPlacementUpdating,
  onSelectObject,
  onStartEditSession,
  onUpdatePlacementObjectFields,
  placementGroup,
  placedObject
}: {
  canEditPlacement: boolean;
  editSession: EditSession | null;
  editableFields: PlacementEditableField[];
  isEditStarting: boolean;
  isPlacementUpdating: boolean;
  onSelectObject: (objectId: string | null) => void;
  onStartEditSession: () => void;
  onUpdatePlacementObjectFields: (
    objectId: string,
    changes: Array<{ field: string; value: string }>
  ) => Promise<boolean>;
  placementGroup: PlacementObjectGroup | null;
  placedObject: PlacedObjectRecord | null;
}) {
  const [draftsByObjectId, setDraftsByObjectId] = useState<
    Record<string, Record<string, string>>
  >({});
  const { translateLiteral } = useLocalization();
  const cancelActiveEditSession = useCancelActiveEditSession();
  const visibleFields = useMemo(
    () => (placedObject ? getPlacementFieldControls(placedObject, editableFields) : []),
    [editableFields, placedObject]
  );
  const placementFieldGroups = useMemo(() => {
    const groups: Array<{ group: string; fields: PlacementFieldControl[] }> = [];

    for (const field of visibleFields) {
      const groupName = field.group || 'Placement Data';
      let group = groups.find((candidate) => candidate.group === groupName);
      if (!group) {
        group = { group: groupName, fields: [] };
        groups.push(group);
      }

      group.fields.push(field);
    }

    return groups;
  }, [visibleFields]);
  const placementDraftDefaults = useMemo(
    () =>
      placedObject
        ? Object.fromEntries(visibleFields.map((field) => [field.field, field.value]))
        : {},
    [
      placedObject?.objectId,
      visibleFields
        .map((field) => `${field.field}:${field.value}:${field.isReadOnly ? '1' : '0'}`)
        .join('|')
    ]
  );
  const drafts = placedObject
    ? draftsByObjectId[placedObject.objectId] ?? placementDraftDefaults
    : {};
  const placementDraftSummary = useMemo(
    () =>
      getPlacementDraftSummary(
        visibleFields,
        drafts,
        placedObject ? (field) => getPlacementFieldValue(placedObject, field) : null
      ),
    [drafts, placedObject, visibleFields]
  );
  useRegisterEditorDraftDirty('placement', countFieldDraftRecords(draftsByObjectId) > 0);
  const canSavePlacementDrafts =
    placedObject !== null &&
    editSession !== null &&
    canEditPlacement &&
    !isPlacementUpdating &&
    placementDraftSummary.changedFields.length > 0 &&
    placementDraftSummary.invalidFields.length === 0;
  const inspectorPrimaryData = placedObject
    ? getPlacementInspectorPrimaryData(placedObject)
    : null;

  useEffect(() => {
    if (!placedObject) {
      return;
    }

    setDraftsByObjectId((currentDrafts) =>
      pruneFieldDraftRecord(currentDrafts, placedObject.objectId, placementDraftDefaults)
    );
  }, [placedObject, placementDraftDefaults]);

  return (
    <aside aria-label="Selected placement object provenance" className="encounter-inspector">
      <div className="panel-heading">
        <MapPin aria-hidden="true" size={18} />
        <h3>Selected Object</h3>
      </div>

      {placedObject ? (
        <>
          <dl className="item-provenance-list">
            <div>
              <dt>Object</dt>
              <dd>{placedObject.label}</dd>
            </div>
            <div>
              <dt>Type</dt>
              <dd>{placedObject.objectType}</dd>
            </div>
            <div>
              <dt>Map</dt>
              <dd>{placedObject.map}</dd>
            </div>
            <div>
              <dt>Archive member</dt>
              <dd>{placedObject.archiveMember}</dd>
            </div>
            <div>
              <dt>Source file</dt>
              <dd>{placedObject.provenance.sourceFile}</dd>
            </div>
            <div>
              <dt>Layer</dt>
              <dd>{formatSourceLayer(placedObject.provenance.sourceLayer)}</dd>
            </div>
            <div>
              <dt>File state</dt>
              <dd>{formatFileState(placedObject.provenance.fileState)}</dd>
            </div>
          </dl>

          {placementGroup && placementGroup.objects.length > 1 ? (
            <PlacementObjectGroupBrowser
              group={placementGroup}
              onSelectObject={onSelectObject}
              selectedObjectId={placedObject.objectId}
            />
          ) : null}

          <div className="encounter-edit-form">
            <dl className="encounter-slot-detail">
              <div>
                <dt>{inspectorPrimaryData?.label ?? 'Placement Data'}</dt>
                <dd>{inspectorPrimaryData?.value ?? 'n/a'}</dd>
              </div>
              {inspectorPrimaryData?.isItem ? (
                <>
                  <div>
                    <dt>Quantity</dt>
                    <dd>{placedObject.quantity}</dd>
                  </div>
                  <div>
                    <dt>Chance</dt>
                    <dd>{placedObject.chance ?? 'n/a'}</dd>
                  </div>
                </>
              ) : null}
              <div>
                <dt>Position</dt>
                <dd>{formatPlacementCoordinates(placedObject)}</dd>
              </div>
              <div>
                <dt>Link</dt>
                <dd>{placedObject.scriptId || 'n/a'}</dd>
              </div>
            </dl>

            <div className="editable-field-groups placement-field-groups">
              {placementFieldGroups.map((group) => (
                <fieldset className="editable-field-group" key={group.group}>
                  <legend>{group.group}</legend>
                  <div className="editable-field-grid placement-field-grid">
                    {group.fields.map((field) => {
                      const currentValue = getPlacementFieldValue(placedObject, field.field);
                      const draftValue = drafts[field.field] ?? '';
                      const draftState = getPlacementDraftState(draftValue, currentValue, field);
                      const isInvalid =
                        draftValue.trim() !== '' && draftState.isValid === false;
                      const isChanged = draftState.canSubmit;
                      const fieldOptions = field.options ?? [];
                      const isFieldReadOnly = field.isReadOnly;
                      const isTextLikePlacementField =
                        field.valueKind === 'text' ||
                        field.valueKind === 'string' ||
                        field.valueKind === 'hash' ||
                        field.valueKind === 'boolean';
                      const resolvedDisplayHint =
                        field.displayValue &&
                        field.displayValue !== field.value &&
                        !isChanged &&
                        !isInvalid
                          ? field.displayValue
                          : null;
                      const statusText = isInvalid
                        ? getPlacementFieldErrorText(field)
                        : isChanged
                          ? 'Changed'
                          : isFieldReadOnly
                            ? 'Read-only'
                            : resolvedDisplayHint;
                      const fieldHelpText = field.description || getEditableFieldHelp(field);
                      const localizedFieldHelpText = translateLiteral(fieldHelpText);

                      return (
                        <label
                          className={`path-field editable-field-control ${
                            isChanged ? 'editable-field-changed' : ''
                          } ${isInvalid ? 'editable-field-invalid' : ''} ${
                            isFieldReadOnly ? 'editable-field-disabled placement-read-only-field' : ''
                          }`}
                          htmlFor={`placement-field-${field.field}`}
                          key={field.field}
                          title={
                            isFieldReadOnly
                              ? translateLiteral(
                                  field.description ||
                                    'This Placement field is visible but not editable yet.'
                                )
                              : localizedFieldHelpText
                          }
                        >
                          <span>{translateLiteral(field.label)}</span>
                          {isFieldReadOnly ? (
                            <input
                              aria-label={translateLiteral(field.label)}
                              disabled
                              id={`placement-field-${field.field}`}
                              type="text"
                              value={translateLiteral(field.displayValue || field.value)}
                            />
                          ) : fieldOptions.length > 0 ? (
                            <SearchableOptionInput
                              ariaLabel={field.label}
                              disabled={
                                !canEditPlacement ||
                                editSession === null ||
                                isPlacementUpdating ||
                                isFieldReadOnly
                              }
                              id={`placement-field-${field.field}`}
                              onChange={(value) => {
                                const nextDrafts = {
                                  ...drafts,
                                  [field.field]: value
                                };
                                setDraftsByObjectId((currentDrafts) =>
                                  setFieldDraftRecord(
                                    currentDrafts,
                                    placedObject.objectId,
                                    nextDrafts,
                                    placementDraftDefaults
                                  )
                                );
                              }}
                              options={addDraftFallbackOption(
                                fieldOptions,
                                draftValue,
                                `${field.label} ${draftValue}`
                              )}
                              title={localizedFieldHelpText}
                              value={draftValue}
                            />
                          ) : (
                            <input
                              aria-label={translateLiteral(field.label)}
                              disabled={
                                !canEditPlacement ||
                                editSession === null ||
                                isPlacementUpdating ||
                                isFieldReadOnly
                              }
                              id={`placement-field-${field.field}`}
                              onChange={(event) => {
                                const nextDrafts = {
                                  ...drafts,
                                  [field.field]: event.target.value
                                };
                                setDraftsByObjectId((currentDrafts) =>
                                  setFieldDraftRecord(
                                    currentDrafts,
                                    placedObject.objectId,
                                    nextDrafts,
                                    placementDraftDefaults
                                  )
                                );
                              }}
                              step={field.valueKind === 'integer' ? 1 : 'any'}
                              title={localizedFieldHelpText}
                              max={isTextLikePlacementField ? undefined : field.maximumValue}
                              min={isTextLikePlacementField ? undefined : field.minimumValue}
                              type={isTextLikePlacementField ? 'text' : 'number'}
                              value={draftValue}
                            />
                          )}
                          {statusText ? (
                            <small
                              className={
                                isInvalid ? 'editable-field-error' : 'editable-field-status'
                              }
                            >
                              {translateLiteral(statusText)}
                            </small>
                          ) : null}
                        </label>
                      );
                    })}
                  </div>
                </fieldset>
              ))}
            </div>
            {editSession ? (
              <div className="draft-action-row">
                <button
                  aria-busy={isPlacementUpdating || undefined}
                  className="primary-button"
                  disabled={!canSavePlacementDrafts}
                  onClick={async () => {
                    if (!placedObject) {
                      return;
                    }

                    const didSave = await onUpdatePlacementObjectFields(
                      placedObject.objectId,
                      placementDraftSummary.changedFields.map((change) => ({
                        field: change.field,
                        value: change.value
                      }))
                    );
                    if (didSave) {
                      setDraftsByObjectId((currentDrafts) =>
                        deleteFieldDraftRecord(currentDrafts, placedObject.objectId)
                      );
                    }
                  }}
                  type="button"
                >
                  <BusyActionContent
                    busyLabel="Staging Changes"
                    icon={<Save aria-hidden="true" size={16} />}
                    isBusy={isPlacementUpdating}
                    label="Stage Changes"
                  />
                </button>
                <button
                  className="danger-button"
                  disabled={isPlacementUpdating}
                  onClick={() => cancelActiveEditSession(() => setDraftsByObjectId({}))}
                  type="button"
                >
                  <X aria-hidden="true" size={16} />
                  <span>Cancel</span>
                </button>
                <span className="draft-action-summary">
                  {formatDraftSummary(placementDraftSummary)}
                </span>
              </div>
            ) : null}

            {!editSession ? (
              <button
                aria-busy={isEditStarting || undefined}
                className="secondary-button"
                disabled={!canEditPlacement || isEditStarting}
                onClick={onStartEditSession}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Starting"
                  icon={<Pencil aria-hidden="true" size={16} />}
                  isBusy={isEditStarting}
                  label="Edit"
                />
              </button>
            ) : null}
          </div>
        </>
      ) : (
        <p className="empty-copy">No placement object selected.</p>
      )}
    </aside>
  );
}

function PlacementObjectGroupBrowser({
  group,
  onSelectObject,
  selectedObjectId
}: {
  group: PlacementObjectGroup;
  onSelectObject: (objectId: string | null) => void;
  selectedObjectId: string;
}) {
  const subgroups = getPlacementObjectSubgroups(group);
  const selectedSubgroup =
    subgroups.find((subgroup) =>
      subgroup.objects.some((object) => object.objectId === selectedObjectId)
    ) ??
    subgroups[0] ??
    null;
  const tabs = selectedSubgroup
    ? selectedSubgroup.tabs
    : getPlacementObjectGroupTabs(group);
  const selectedSubgroupObjects = selectedSubgroup?.objects ?? group.objects;
  const useListPicker =
    selectedSubgroupObjects.length > 8 ||
    selectedSubgroupObjects.some(isZaItemBallPlacementObject);

  return (
    <section className="za-placement-object-browser" aria-label="Z-A placement spawner group">
      <div className="sv-encounter-browser-summary">
        <span>{group.label}</span>
        <span>{group.objects.length} transforms</span>
        {subgroups.length > 1 ? <span>{subgroups.length} locations</span> : null}
        <span>{group.map}</span>
      </div>
      {subgroups.length > 1 ? (
        <div
          className="encounter-condition-tabs placement-object-tabs placement-location-tabs"
          role="tablist"
          aria-label="Placement locations"
        >
          {subgroups.map((subgroup) => {
            const isSelected = subgroup.key === selectedSubgroup?.key;
            return (
              <button
                aria-selected={isSelected}
                className="condition-tab-button"
                key={subgroup.key}
                onClick={() => {
                  const nextObjectId = subgroup.objects[0]?.objectId ?? null;
                  if (nextObjectId && nextObjectId !== selectedObjectId) {
                    onSelectObject(nextObjectId);
                  }
                }}
                role="tab"
                title={`${subgroup.label} - ${subgroup.objects.length} transforms`}
                type="button"
              >
                {subgroup.label}
              </button>
            );
          })}
        </div>
      ) : null}
      {useListPicker ? (
        <div
          className="placement-object-picker-list"
          role="tablist"
          aria-label={
            selectedSubgroup
              ? `Placement spawner transforms in ${selectedSubgroup.label}`
              : 'Placement spawner transforms'
          }
        >
          {tabs.map((tab) => (
            <button
              aria-selected={tab.objectId === selectedObjectId}
              className="placement-object-picker-row"
              key={tab.objectId}
              onClick={() => {
                if (tab.objectId !== selectedObjectId) {
                  onSelectObject(tab.objectId);
                }
              }}
              role="tab"
              title={tab.title}
              type="button"
            >
              <span>{tab.label}</span>
              <small>{tab.title}</small>
            </button>
          ))}
        </div>
      ) : (
        <div
          className="encounter-condition-tabs placement-object-tabs"
          role="tablist"
          aria-label={
            selectedSubgroup
              ? `Placement spawner transforms in ${selectedSubgroup.label}`
              : 'Placement spawner transforms'
          }
        >
          {tabs.map((tab) => (
            <button
              aria-selected={tab.objectId === selectedObjectId}
              className="condition-tab-button"
              key={tab.objectId}
              onClick={() => {
                if (tab.objectId !== selectedObjectId) {
                  onSelectObject(tab.objectId);
                }
              }}
              role="tab"
              title={tab.title}
              type="button"
            >
              {tab.label}
            </button>
          ))}
        </div>
      )}
    </section>
  );
}

function FlagworkSaveSection({
  onSearchChange,
  onSelectFlag,
  onSelectSaveBlock,
  searchText,
  selectedFlagId,
  selectedSaveBlockId,
  workflow
}: {
  onSearchChange: (value: string) => void;
  onSelectFlag: (flagId: string | null) => void;
  onSelectSaveBlock: (blockId: string | null) => void;
  searchText: string;
  selectedFlagId: string | null;
  selectedSaveBlockId: string | null;
  workflow: FlagworkSaveWorkflow | null;
}) {
  const filteredFlags = filterFlagRecords(workflow?.flags ?? [], searchText);
  const filteredSaveBlocks = filterSaveBlockRecords(workflow?.saveBlocks ?? [], searchText);
  const selectedFlag =
    filteredFlags.find((flag) => flag.flagId === selectedFlagId) ??
    workflow?.flags.find((flag) => flag.flagId === selectedFlagId) ??
    filteredFlags[0] ??
    workflow?.flags[0] ??
    null;
  const selectedSaveBlock =
    filteredSaveBlocks.find((saveBlock) => saveBlock.blockId === selectedSaveBlockId) ??
    workflow?.saveBlocks.find((saveBlock) => saveBlock.blockId === selectedSaveBlockId) ??
    filteredSaveBlocks[0] ??
    workflow?.saveBlocks[0] ??
    null;

  useEffect(() => {
    if (selectedFlag && selectedFlag.flagId !== selectedFlagId) {
      onSelectFlag(selectedFlag.flagId);
    }
  }, [onSelectFlag, selectedFlag?.flagId, selectedFlagId]);

  useEffect(() => {
    if (selectedSaveBlock && selectedSaveBlock.blockId !== selectedSaveBlockId) {
      onSelectSaveBlock(selectedSaveBlock.blockId);
    }
  }, [onSelectSaveBlock, selectedSaveBlock?.blockId, selectedSaveBlockId]);

  return (
    <>
      <section aria-labelledby="flagwork-save-heading" className="panel wide-panel">
        <div className="panel-heading">
          <Save aria-hidden="true" size={18} />
          <h2 id="flagwork-save-heading">Flagwork and Save Inspectors</h2>
        </div>

        <div className="items-toolbar flagwork-toolbar">
          <label className="search-box items-search">
            <Search aria-hidden="true" size={18} />
            <input
              aria-label="Search flagwork and save keys"
              disabled={!workflow}
              onChange={(event) => onSearchChange(event.target.value)}
              placeholder="Search flagwork"
              type="search"
              value={searchText}
            />
          </label>
          <Metric
            label="Flags and works"
            value={workflow ? workflow.stats.totalFlagCount.toString() : '0'}
          />
          <Metric
            label="Save keys"
            value={workflow ? workflow.stats.totalSaveBlockCount.toString() : '0'}
          />
          <Metric
            label="Source files"
            value={workflow ? workflow.stats.sourceFileCount.toString() : '0'}
          />
          <Metric
            label="Save file"
            value={workflow?.stats.hasSaveFile ? 'Configured' : 'Not set'}
          />
        </div>

        {workflow ? (
          <div className="flagwork-layout">
            <div className="flagwork-stack">
              <div className="flagwork-table" role="table" aria-label="Flagwork records">
                <div className="flagwork-row flagwork-row-heading" role="row">
                  <span role="columnheader">Table</span>
                  <span role="columnheader">Index</span>
                  <span role="columnheader">Kind</span>
                  <span role="columnheader">Name</span>
                  <span role="columnheader">Save key</span>
                </div>
                {filteredFlags.map((flag) => (
                  <button
                    className={`flagwork-row ${
                      selectedFlag?.flagId === flag.flagId ? 'flagwork-row-selected' : ''
                    }`}
                    key={flag.flagId}
                    onClick={() => onSelectFlag(flag.flagId)}
                    role="row"
                    type="button"
                  >
                    <span role="cell">{flag.table}</span>
                    <span role="cell">{flag.index}</span>
                    <span role="cell">{flag.kind}</span>
                    <span role="cell">{flag.name}</span>
                    <span role="cell">{flag.low32Key}</span>
                  </button>
                ))}
              </div>

              <div className="flagwork-table" role="table" aria-label="Save key records">
                <div className="flagwork-row flagwork-row-heading" role="row">
                  <span role="columnheader">Key</span>
                  <span role="columnheader">Kind</span>
                  <span role="columnheader">Value</span>
                  <span role="columnheader">Name</span>
                  <span role="columnheader">Hash</span>
                </div>
                {filteredSaveBlocks.map((saveBlock) => (
                  <button
                    className={`flagwork-row ${
                      selectedSaveBlock?.blockId === saveBlock.blockId
                        ? 'flagwork-row-selected'
                        : ''
                    }`}
                    key={saveBlock.blockId}
                    onClick={() => onSelectSaveBlock(saveBlock.blockId)}
                    role="row"
                    type="button"
                  >
                    <span role="cell">{saveBlock.key}</span>
                    <span role="cell">{saveBlock.kind}</span>
                    <span role="cell">{saveBlock.valueKind}</span>
                    <span role="cell">{saveBlock.name}</span>
                    <span role="cell">{saveBlock.hash}</span>
                  </button>
                ))}
              </div>
            </div>

            <SelectedFlagworkSavePanel
              flag={selectedFlag}
              saveBlock={selectedSaveBlock}
              saveFile={workflow.saveFile}
            />
          </div>
        ) : (
          <p className="empty-copy">
            Open Flagwork from Workflows to inspect backend flagwork tables.
          </p>
        )}
      </section>

      <DiagnosticsSection diagnostics={workflow?.diagnostics ?? []} />
    </>
  );
}

