function SettingsSection({
  appVersion,
  isSvCacheClearing,
  isSvCacheRefreshing,
  isSvCacheWarming,
  onChangeSvCacheLimit,
  onChangeSvCacheMode,
  onCheckForUpdates,
  onClearSvCache,
  onRefreshSvCacheStatus,
  selectedGame,
  status,
  svCacheRefreshTick,
  svCacheStatus
}: {
  appVersion: string;
  isSvCacheClearing: boolean;
  isSvCacheRefreshing: boolean;
  isSvCacheWarming: boolean;
  onChangeSvCacheLimit: (maxCacheSizeBytes: number) => void;
  onChangeSvCacheMode: (mode: TrinityCacheMode) => void;
  onCheckForUpdates: () => void;
  onClearSvCache: () => void;
  onRefreshSvCacheStatus: () => void;
  selectedGame: ProjectGame;
  status: UpdateCheckStatus;
  svCacheRefreshTick: number;
  svCacheStatus: TrinityCacheStatus | null;
}) {
  const isBusy =
    status.kind === 'checking' ||
    status.kind === 'downloading' ||
    status.kind === 'installing' ||
    status.kind === 'opening' ||
    status.kind === 'preparing' ||
    status.kind === 'restarting';
  const activeCacheMode = svCacheStatus?.settings.mode ?? 'balanced';
  const activeCacheLimit = svCacheStatus?.settings.maxCacheSizeBytes ?? defaultTrinityCacheLimitBytes;
  const cacheSizeLabel = formatByteSize(svCacheStatus?.cacheSizeBytes ?? 0);
  const isCacheControlBusy = isSvCacheClearing || isSvCacheRefreshing || isSvCacheWarming;
  const canShowSvCacheSettings = isTrinityCacheGame(selectedGame);
  const cacheTitle = isPokemonLegendsZAGame(selectedGame)
    ? 'Pokemon Legends Z-A Data Cache'
    : 'Scarlet/Violet Data Cache';
  const cacheModeLabel = isPokemonLegendsZAGame(selectedGame)
    ? 'Z-A cache mode'
    : 'S/V cache mode';
  const cacheDescription = isPokemonLegendsZAGame(selectedGame)
    ? 'Controls how aggressively Z-A Trinity data is cached between editor loads.'
    : 'Controls how aggressively S/V Trinity data is cached between editor loads.';
  const { language, setLanguage, t } = useLocalization();
  const languageKeyByCode: Record<LanguageCode, string> = {
    de: 'german',
    en: 'english',
    es: 'spanish',
    fr: 'french',
    ru: 'russian',
    uk: 'ukrainian',
    zh: 'chinese'
  };
  const languageOptions = supportedLanguages.map((option) => {
    const languageKey = languageKeyByCode[option.code];

    return {
      ...option,
      description: t(`settings.language.${languageKey}.description`),
      label: t(`settings.language.${languageKey}`)
    };
  });

  return (
    <section aria-labelledby="settings-heading" className="panel wide-panel">
      <div className="panel-heading">
        <SettingsIcon aria-hidden="true" size={18} />
        <h2 id="settings-heading">Settings</h2>
      </div>

      <div className="settings-summary">
        <Metric label="Installed version" value={`v${appVersion}`} />
        <button
          className="primary-button"
          disabled={isBusy}
          onClick={onCheckForUpdates}
          type="button"
        >
          <RefreshCw aria-hidden="true" size={18} />
          <span>
            {status.kind === 'checking'
              ? 'Checking'
              : status.kind === 'preparing'
                ? 'Preparing'
              : status.kind === 'downloading'
                ? 'Downloading'
                : status.kind === 'installing'
                  ? 'Installing'
                  : 'Check for Updates'}
          </span>
        </button>
        <p
          className={`update-status update-status-${status.kind}`}
          role={status.kind === 'error' ? 'alert' : 'status'}
        >
          {status.message}
        </p>
      </div>

      {canShowSvCacheSettings ? (
        <section aria-labelledby="sv-cache-settings-heading" className="settings-subsection">
          <div className="settings-subsection-heading">
            <Layers aria-hidden="true" size={18} />
            <div>
              <h3 id="sv-cache-settings-heading">{cacheTitle}</h3>
              <p>{cacheDescription}</p>
            </div>
          </div>

          <div className="sv-cache-mode-options" role="radiogroup" aria-label={cacheModeLabel}>
            {svCacheModeOptions.map((option) => {
              const isSelected = option.id === activeCacheMode;

              return (
                <button
                  aria-checked={isSelected}
                  className={`sv-cache-mode-option${isSelected ? ' sv-cache-mode-option-selected' : ''}`}
                  disabled={isCacheControlBusy || isSelected}
                  key={option.id}
                  onClick={() => onChangeSvCacheMode(option.id)}
                  role="radio"
                  type="button"
                >
                  <span>
                    {option.label}
                    {option.recommended ? <small>Recommended</small> : null}
                    {isSelected ? (
                      <small className="sv-cache-mode-selected-label">
                        {t('settings.language.selected')}
                      </small>
                    ) : null}
                  </span>
                  <p>{option.description}</p>
                </button>
              );
            })}
          </div>

          <div className="sv-cache-settings-row">
            <label className="path-field sv-cache-limit-field">
              <span>Maximum cache size</span>
              <select
                disabled={isSvCacheClearing}
                onChange={(event) => onChangeSvCacheLimit(Number(event.target.value))}
                value={activeCacheLimit}
              >
                {svCacheLimitOptions.map((option) => (
                  <option key={option.bytes} value={option.bytes}>
                    {option.label}
                  </option>
                ))}
              </select>
            </label>

            <div aria-live="polite" className="metric sv-cache-size-metric">
              <span className="metric-label">Current cache size</span>
              <span
                className={`metric-value metric-value-small sv-cache-size-value${
                  svCacheRefreshTick > 0 ? ' sv-cache-size-value-refreshed' : ''
                }`}
                key={svCacheRefreshTick}
              >
                {cacheSizeLabel}
              </span>
            </div>

            <button
              aria-busy={isSvCacheRefreshing || undefined}
              className="secondary-button sv-cache-refresh-button"
              disabled={isSvCacheClearing || isSvCacheRefreshing}
              onClick={onRefreshSvCacheStatus}
              type="button"
            >
              <BusyActionContent
                busyLabel="Refreshing"
                icon={<RefreshCw aria-hidden="true" size={18} />}
                isBusy={isSvCacheRefreshing}
                label="Refresh Cache Size"
                size={18}
              />
            </button>
            <button
              aria-busy={isSvCacheClearing || undefined}
              className="danger-button"
              disabled={isSvCacheClearing}
              onClick={onClearSvCache}
              type="button"
            >
              <BusyActionContent
                busyLabel="Clearing Cache"
                icon={<Trash2 aria-hidden="true" size={18} />}
                isBusy={isSvCacheClearing}
                label={`Clear Cache (${cacheSizeLabel})`}
                size={18}
              />
            </button>
          </div>
        </section>
      ) : null}

      <section aria-labelledby="language-settings-heading" className="settings-subsection">
        <div className="settings-subsection-heading">
          <Languages aria-hidden="true" size={18} />
          <div>
            <h3 id="language-settings-heading">{t('settings.language.title')}</h3>
            <p>{t('settings.language.description')}</p>
          </div>
        </div>

        <div
          aria-label={t('settings.language.groupLabel')}
          className="language-options"
          role="radiogroup"
        >
          {languageOptions.map((option) => {
            const isSelected = language === option.code;

            return (
              <button
                aria-checked={isSelected}
                className={`language-option${isSelected ? ' language-option-selected' : ''}`}
                disabled={isSelected}
                key={option.code}
                onClick={() => setLanguage(option.code as LanguageCode)}
                role="radio"
                type="button"
              >
                <span className="language-option-flag" aria-hidden="true">
                  {option.flag}
                </span>
                <span className="language-option-copy">
                  <strong>{option.label}</strong>
                  <span>{option.description}</span>
                </span>
                {isSelected ? (
                  <small className="language-option-selected-label">
                    {t('settings.language.selected')}
                  </small>
                ) : null}
              </button>
            );
          })}
        </div>
      </section>
    </section>
  );
}

function ChangesSection({
  applyResult,
  canSaveValidatedChanges,
  changePlan,
  diagnostics,
  editSession,
  pendingEditContext,
  isEditSessionValidated,
  isChangePlanApplying,
  isChangePlanCreating,
  isEditSessionMutating,
  supportsTrinityOutput,
  isSessionValidating,
  onCancelEditSession,
  onOpenEditor,
  onRemovePendingEdit,
  onRequestTrinityOutput,
  onSaveValidatedChanges,
  onValidateEditSession
}: {
  applyResult: ApplyResult | null;
  canSaveValidatedChanges: boolean;
  changePlan: ChangePlan | null;
  diagnostics: ApiDiagnostic[];
  editSession: EditSession | null;
  pendingEditContext: PendingEditContext;
  isEditSessionValidated: boolean;
  isChangePlanApplying: boolean;
  isChangePlanCreating: boolean;
  isEditSessionMutating: boolean;
  supportsTrinityOutput: boolean;
  isSessionValidating: boolean;
  onCancelEditSession: () => void;
  onOpenEditor: (section: WorkbenchSection) => void;
  onRemovePendingEdit: (editIndex: number) => void;
  onRequestTrinityOutput: (mode: ChangePlanOutputMode) => void;
  onSaveValidatedChanges: () => void;
  onValidateEditSession: () => void;
}) {
  const { translateLiteral } = useLocalization();
  const pendingEdits = editSession?.pendingEdits ?? [];
  const isPendingValidationBusy = isSessionValidating || isChangePlanCreating;
  const pendingEditGroups: Array<{
    domain: string;
    editorLabel: string;
    edits: Array<{ details: PendingEditDisplayDetails; edit: PendingEdit; index: number }>;
    section: WorkbenchSection | null;
  }> = [];
  pendingEdits.forEach((edit, index) => {
    let group = pendingEditGroups.find((candidate) => candidate.domain === edit.domain);
    if (!group) {
      group = {
        domain: edit.domain,
        editorLabel: formatPendingEditDomain(edit.domain),
        edits: [],
        section: getPendingEditSection(edit.domain)
      };
      pendingEditGroups.push(group);
    }
    group.edits.push({ details: getPendingEditDisplayDetails(edit, pendingEditContext), edit, index });
  });
  const hasWriteErrors =
    applyResult?.diagnostics.some((diagnostic) => diagnostic.severity === 'error') ?? false;
  const progressSteps = [
    {
      complete: pendingEdits.length > 0 || changePlan !== null || applyResult !== null,
      label: 'Staged'
    },
    {
      complete: Boolean(changePlan?.canApply) || applyResult !== null,
      label: 'Review'
    },
    {
      complete: applyResult !== null && !hasWriteErrors,
      label: 'Written'
    }
  ];
  const activeProgressIndex = progressSteps.findIndex((step) => !step.complete);
  const combinedDiagnostics = [
    ...diagnostics,
    ...(changePlan?.diagnostics ?? []),
    ...(applyResult?.diagnostics ?? [])
  ];

  return (
    <>
      <section aria-labelledby="changes-heading" className="panel wide-panel">
        <div className="panel-heading">
          <ClipboardCheck aria-hidden="true" size={18} />
          <h2 id="changes-heading">{translateLiteral('Changes')}</h2>
        </div>

        <ol aria-label={translateLiteral('Changes')} className="changes-progress">
          {progressSteps.map((step, index) => (
            <li
              aria-current={index === activeProgressIndex ? 'step' : undefined}
              className={step.complete ? 'is-complete' : index === activeProgressIndex ? 'is-active' : ''}
              key={step.label}
            >
              <span aria-hidden="true">{index + 1}</span>
              <strong>{translateLiteral(step.label)}</strong>
            </li>
          ))}
        </ol>

        <div className="changes-summary">
          <Metric label="Pending changes" value={pendingEdits.length.toString()} />
          <Metric label="Target files" value={(changePlan?.writes.length ?? 0).toString()} />
          <Metric label="Written files" value={(applyResult?.writtenFiles.length ?? 0).toString()} />
          <Metric
            label="Validation"
            value={
              pendingEdits.length === 0
                ? 'No changes'
                : isEditSessionValidated
                  ? 'Valid'
                  : 'Needed'
            }
          />
          <button
            aria-label={
              translateLiteral(isPendingValidationBusy ? 'Validating' : 'Review')
            }
            aria-busy={isPendingValidationBusy || undefined}
            className="secondary-button"
            disabled={
              pendingEdits.length === 0 ||
              isEditSessionMutating ||
              isSessionValidating ||
              isChangePlanApplying
            }
            onClick={onValidateEditSession}
            type="button"
          >
            <BusyActionContent
              busyLabel="Validating"
              icon={<CheckCircle aria-hidden="true" size={18} />}
              isBusy={isPendingValidationBusy}
              label="Review"
              size={18}
            />
          </button>
          {supportsTrinityOutput ? (
            <>
              <button
                aria-busy={isChangePlanApplying || undefined}
                className="primary-button"
                disabled={!canSaveValidatedChanges}
                onClick={() => onRequestTrinityOutput('standalone')}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Outputting"
                  icon={<Package aria-hidden="true" size={18} />}
                  isBusy={isChangePlanApplying}
                  label="Output as Standalone"
                  size={18}
                />
              </button>
              <button
                aria-busy={isChangePlanApplying || undefined}
                className="secondary-button"
                disabled={!canSaveValidatedChanges}
                onClick={() => onRequestTrinityOutput('trinityModManager')}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Outputting"
                  icon={<GitMerge aria-hidden="true" size={18} />}
                  isBusy={isChangePlanApplying}
                  label="Output for Trinity Mod Manager"
                  size={18}
                />
              </button>
              <button
                aria-busy={isChangePlanApplying || undefined}
                className="secondary-button"
                disabled={!canSaveValidatedChanges}
                onClick={() => onRequestTrinityOutput('trinityBypass')}
                type="button"
              >
                <BusyActionContent
                  busyLabel="Outputting"
                  icon={<ShieldCheck aria-hidden="true" size={18} />}
                  isBusy={isChangePlanApplying}
                  label="Output for Trinity Bypass"
                  size={18}
                />
              </button>
            </>
          ) : (
            <button
              aria-busy={isChangePlanApplying || undefined}
              className="primary-button"
              disabled={!canSaveValidatedChanges}
              onClick={onSaveValidatedChanges}
              type="button"
            >
              <BusyActionContent
                busyLabel="Applying"
                icon={<CheckCircle aria-hidden="true" size={18} />}
                isBusy={isChangePlanApplying}
                label="Apply"
                size={18}
              />
            </button>
          )}
          <button
            className="danger-button"
            disabled={
              !editSession ||
              isEditSessionMutating ||
              isSessionValidating ||
              isChangePlanCreating ||
              isChangePlanApplying
            }
            onClick={onCancelEditSession}
            type="button"
          >
            <X aria-hidden="true" size={18} />
            <span>Cancel</span>
          </button>
        </div>

        {pendingEdits.length > 0 ? (
          <div
            aria-label={`Pending changes (${pendingEdits.length})`}
            className="pending-edit-groups"
            role="region"
          >
            {pendingEditGroups.map((group, groupIndex) => {
              const headingId = `pending-edit-group-${groupIndex}`;
              return (
                <section
                  aria-labelledby={headingId}
                  className="pending-edit-group"
                  key={group.domain}
                >
                  <div className="pending-edit-group-heading">
                    <div>
                      <h3 id={headingId}>{translateLiteral(group.editorLabel)}</h3>
                      <span>{group.edits.length}</span>
                    </div>
                    {group.section ? (
                      <button
                        aria-label={`${translateLiteral('Open')} ${translateLiteral(group.editorLabel)}`}
                        className="secondary-button compact-button"
                        disabled={
                          isEditSessionMutating ||
                          isSessionValidating ||
                          isChangePlanCreating ||
                          isChangePlanApplying
                        }
                        onClick={() => onOpenEditor(group.section!)}
                        type="button"
                      >
                        <ExternalLink aria-hidden="true" size={15} />
                        <span>{translateLiteral('Open')}</span>
                      </button>
                    ) : null}
                  </div>
                  <ul className="pending-edit-list">
                    {group.edits.map(({ details, edit, index }) => (
                      <li key={`${edit.domain}-${edit.recordId ?? index}-${edit.field ?? 'field'}`}>
                        <button
                          aria-label={`Remove pending change ${index + 1}: ${edit.summary}`}
                          className="danger-button icon-button pending-edit-remove-button"
                          disabled={
                            isEditSessionMutating ||
                            isSessionValidating ||
                            isChangePlanCreating ||
                            isChangePlanApplying
                          }
                          onClick={() => onRemovePendingEdit(index)}
                          title="Remove this pending change"
                          type="button"
                        >
                          <Trash2 aria-hidden="true" size={16} />
                        </button>
                        <div className="pending-edit-content">
                          <div className="pending-edit-title-row">
                            <strong>{edit.summary}</strong>
                          </div>
                          <dl className="pending-edit-meta pending-edit-summary-meta">
                            <div>
                              <dt>Record</dt>
                              <dd>{details.recordLabel}</dd>
                            </div>
                            <div>
                              <dt>Field</dt>
                              <dd>{details.fieldLabel}</dd>
                            </div>
                            <div>
                              <dt>New value</dt>
                              <dd>{details.newValueLabel}</dd>
                            </div>
                          </dl>
                          <details className="pending-edit-technical-details">
                            <summary>{translateLiteral('Technical details')}</summary>
                            <dl className="pending-edit-meta">
                              <div>
                                <dt>Record key</dt>
                                <dd>{details.recordKey}</dd>
                              </div>
                              <div>
                                <dt>Field key</dt>
                                <dd>{details.fieldKey}</dd>
                              </div>
                              <div>
                                <dt>Source</dt>
                                <dd>{details.sourceLabel}</dd>
                              </div>
                            </dl>
                          </details>
                        </div>
                      </li>
                    ))}
                  </ul>
                </section>
              );
            })}
          </div>
        ) : (
          <p className="empty-copy">{translateLiteral('No pending changes.')}</p>
        )}
      </section>

      {changePlan ? (
        <ChangePlanSection
          changePlan={changePlan}
        />
      ) : null}
      {applyResult ? <ApplyResultSection applyResult={applyResult} /> : null}
      <DiagnosticsSection diagnostics={combinedDiagnostics} />
    </>
  );
}

function WorkProgressModal({ progress }: { progress: WorkProgressState }) {
  const dialogRef = useModalDialog({
    canClose: false,
    onClose: () => undefined
  });
  const isDeterminate = progress.mode === 'determinate';
  const percent = isDeterminate ? Math.max(0, Math.min(100, progress.percent ?? 0)) : null;

  return (
    <div className="modal-backdrop" role="presentation">
      <section
        aria-labelledby="work-progress-heading"
        aria-modal="true"
        className="modal-panel work-progress-panel"
        ref={dialogRef}
        role="dialog"
        tabIndex={-1}
      >
        <div className="panel-heading">
          <Activity aria-hidden="true" size={18} />
          <h2 id="work-progress-heading">{progress.label}</h2>
        </div>
        <div
          aria-label={`${progress.label} progress`}
          aria-valuemax={isDeterminate ? 100 : undefined}
          aria-valuemin={isDeterminate ? 0 : undefined}
          aria-valuenow={percent ?? undefined}
          className={`work-progress-track${isDeterminate ? '' : ' work-progress-track-indeterminate'}`}
          role="progressbar"
        >
          <div
            className="work-progress-fill"
            style={isDeterminate ? { width: `${percent}%` } : undefined}
          />
        </div>
        <dl className="work-progress-detail">
          {isDeterminate ? (
            <div>
              <dt>Progress</dt>
              <dd>{percent}%</dd>
            </div>
          ) : null}
          <div>
            <dt>Current step</dt>
            <dd>{progress.detail}</dd>
          </div>
          {progress.step !== undefined &&
          progress.totalSteps !== undefined &&
          progress.totalSteps > 1 ? (
            <div>
              <dt>Phase</dt>
              <dd>
                {progress.step} of {progress.totalSteps}
              </dd>
            </div>
          ) : null}
        </dl>
        {progress.steps?.length ? (
          <ol className="work-progress-step-list">
            {progress.steps.map((step) => (
              <li className={`work-progress-step work-progress-step-${step.state}`} key={step.label}>
                <span aria-hidden="true" />
                <strong>{step.label}</strong>
              </li>
            ))}
          </ol>
        ) : null}
      </section>
    </div>
  );
}

