function UpdatePromptModal({
  onDismiss,
  onDownload,
  status,
  update
}: {
  onDismiss: () => void;
  onDownload: () => void;
  status: UpdateCheckStatus;
  update: AvailableUpdate;
}) {
  const isNativeUpdate = update.kind === 'native';
  const isApplying =
    status.kind === 'downloading' ||
    status.kind === 'installing' ||
    status.kind === 'opening' ||
    status.kind === 'preparing' ||
    status.kind === 'restarting';
  const dialogRef = useModalDialog({
    canClose: !isApplying,
    onClose: onDismiss
  });
  const isProgressVisible =
    status.kind === 'downloading' || status.kind === 'installing' || status.kind === 'preparing';
  const progressTitle =
    status.kind === 'preparing'
      ? 'Preparing update'
      : status.kind === 'installing'
        ? 'Installing update'
        : 'Downloading update';
  const downloadContentLength =
    status.kind === 'downloading' && status.contentLength !== null && status.contentLength > 0
      ? status.contentLength
      : null;
  const downloadedBytes = status.kind === 'downloading' ? status.downloadedBytes : 0;
  const downloadPercent =
    downloadContentLength !== null
      ? Math.max(0, Math.min(100, Math.round((downloadedBytes / downloadContentLength) * 100)))
      : null;

  return (
    <div className="modal-backdrop" role="presentation">
      <section
        aria-labelledby="update-prompt-heading"
        aria-modal="true"
        className="modal-panel update-prompt-panel"
        ref={dialogRef}
        role="dialog"
        tabIndex={-1}
      >
        <div className="panel-heading">
          <Download aria-hidden="true" size={18} />
          <h2 id="update-prompt-heading">Update Available</h2>
        </div>
        <p className="modal-copy">
          {isNativeUpdate
            ? `KM Editor v${update.version} is available. Install it now?`
            : `KM Editor v${update.version} is available. KM Editor will open ${update.releaseName}.`}
        </p>
        {update.kind === 'releasePage' && update.fallbackReason ? (
          <p className="modal-copy modal-copy-muted">
            Native update check was not available: {update.fallbackReason}
          </p>
        ) : null}
        {update.kind === 'native' && update.body ? (
          <p className="modal-copy modal-copy-muted">{update.body}</p>
        ) : null}
        {isProgressVisible ? (
          <div className="update-progress-panel" role="status">
            <div className="update-progress-header">
              <strong>{progressTitle}</strong>
              {downloadPercent !== null ? <span>{downloadPercent}%</span> : null}
            </div>
            <div
              aria-label="Update download progress"
              aria-valuemax={downloadContentLength !== null ? 100 : undefined}
              aria-valuemin={downloadContentLength !== null ? 0 : undefined}
              aria-valuenow={downloadPercent ?? undefined}
              aria-valuetext={status.message}
              className={`work-progress-track${
                downloadContentLength !== null ? '' : ' work-progress-track-indeterminate'
              }`}
              role="progressbar"
            >
              <div
                className="work-progress-fill"
                style={
                  downloadContentLength !== null ? { width: `${downloadPercent}%` } : undefined
                }
              />
            </div>
            <p>{status.message}</p>
          </div>
        ) : null}
        {status.kind === 'error' ? (
          <p className="update-status update-status-error" role="alert">
            {status.message}
          </p>
        ) : null}
        <div className="modal-actions">
          <button
            className="primary-button"
            disabled={isApplying}
            onClick={onDownload}
            type="button"
          >
            {isNativeUpdate ? (
              <Download aria-hidden="true" size={16} />
            ) : (
              <ExternalLink aria-hidden="true" size={16} />
            )}
            <span>
              {isApplying
                ? isNativeUpdate
                  ? status.kind === 'preparing'
                    ? 'Preparing'
                    : 'Installing'
                  : 'Opening'
                : isNativeUpdate
                  ? 'Install Update'
                  : 'Open Release'}
            </span>
          </button>
          <button
            className="secondary-button"
            disabled={isApplying}
            onClick={onDismiss}
            type="button"
          >
            <X aria-hidden="true" size={16} />
            <span>Not Now</span>
          </button>
        </div>
      </section>
    </div>
  );
}

function DependencyWarningModal({
  onClose,
  onOpenBagHook,
  warning
}: {
  onClose: () => void;
  onOpenBagHook: () => void;
  warning: DependencyWarningState;
}) {
  const dialogRef = useModalDialog({ onClose });

  return (
    <div className="modal-backdrop" role="presentation">
      <section
        aria-labelledby="dependency-warning-heading"
        aria-modal="true"
        className="modal-panel"
        ref={dialogRef}
        role="dialog"
        tabIndex={-1}
      >
        <div className="panel-heading">
          <AlertTriangle aria-hidden="true" size={18} />
          <h2 id="dependency-warning-heading">{warning.title}</h2>
        </div>
        <p className="modal-copy">{warning.message}</p>
        <p className="modal-copy modal-copy-muted">{warning.fix}</p>
        <div className="modal-actions">
          <button className="primary-button" onClick={onOpenBagHook} type="button">
            <Wrench aria-hidden="true" size={16} />
            <span>Open Bag Hook</span>
          </button>
          <button className="secondary-button" onClick={onClose} type="button">
            <X aria-hidden="true" size={16} />
            <span>Close</span>
          </button>
        </div>
      </section>
    </div>
  );
}

function ExitPromptModal({
  allowGoToChanges,
  isDiscardBlocked,
  kind,
  mode,
  onConfirmDiscard,
  onDeclineDiscard,
  onGoToChanges,
  onStay
}: {
  allowGoToChanges: boolean;
  isDiscardBlocked: boolean;
  kind: ExitPromptState['kind'];
  mode: ExitPromptState['mode'];
  onConfirmDiscard: () => void;
  onDeclineDiscard: () => void;
  onGoToChanges: () => void;
  onStay: () => void;
}) {
  const isConfirmMode = mode === 'confirm';
  const isCancelPrompt = kind === 'cancel';
  const isEditorSwitchPrompt = kind === 'editorSwitch';
  const dialogRef = useModalDialog({ onClose: onStay });

  return (
    <div className="modal-backdrop" role="presentation">
      <section
        aria-labelledby="exit-prompt-heading"
        aria-modal="true"
        className="modal-panel"
        ref={dialogRef}
        role="dialog"
        tabIndex={-1}
      >
        <div className="panel-heading">
          <X aria-hidden="true" size={18} />
          <h2 id="exit-prompt-heading">
            {isConfirmMode
              ? isEditorSwitchPrompt
                ? 'Switch Editors?'
                : isCancelPrompt
                ? 'Discard All Changes?'
                : 'Discard Pending Changes?'
              : 'Where To Go?'}
          </h2>
        </div>
        <p className="modal-copy">
          {isConfirmMode
            ? isEditorSwitchPrompt
              ? allowGoToChanges
                ? 'This editor has unsaved changes. Switching editors now will revert those edits.'
                : 'Review and apply the pending changes inside this advanced editor, or discard them before leaving.'
              : isCancelPrompt
              ? 'Canceling will discard every pending edit in this edit session. Are you sure you want to discard all changes?'
              : allowGoToChanges
                ? 'This editor has pending changes or an active edit session. Exiting will discard those pending edits.'
                : 'Review and apply the pending changes inside this advanced editor, or discard them before leaving.'
            : 'You can stay on this editor or go to Changes to validate and save the pending edits.'}
        </p>
        <div className="modal-actions">
          {isConfirmMode ? (
            <>
              <button
                className="danger-button"
                disabled={isDiscardBlocked}
                onClick={onConfirmDiscard}
                type="button"
              >
                <Trash2 aria-hidden="true" size={16} />
                <span>{isEditorSwitchPrompt ? 'Switch and Revert' : 'Yes, Discard'}</span>
              </button>
              <button
                className="secondary-button"
                onClick={isEditorSwitchPrompt || !allowGoToChanges ? onStay : onDeclineDiscard}
                type="button"
              >
                <X aria-hidden="true" size={16} />
                <span>{isEditorSwitchPrompt || !allowGoToChanges ? 'Stay Here' : 'No'}</span>
              </button>
            </>
          ) : (
            <>
              <button className="secondary-button" onClick={onStay} type="button">
                <ArrowLeftRight aria-hidden="true" size={16} />
                <span>Stay Here</span>
              </button>
              <button className="primary-button" onClick={onGoToChanges} type="button">
                <ClipboardCheck aria-hidden="true" size={16} />
                <span>Go To Changes</span>
              </button>
            </>
          )}
        </div>
      </section>
    </div>
  );
}

function getModMergerStatusClassName(status: string) {
  switch (status) {
    case 'ready':
      return 'status-ready';
    case 'priorityFallback':
    case 'needsResolution':
    case 'empty':
    case 'pending':
      return 'status-warning';
    case 'blocked':
    case 'error':
      return 'status-blocked';
    default:
      return 'status-warning';
  }
}

function getModMergerPreviewPriority(status: string) {
  switch (status) {
    case 'needsResolution':
      return 0;
    case 'blocked':
    case 'error':
    case 'empty':
      return 1;
    case 'ready':
      return 2;
    default:
      return 3;
  }
}

function formatModMergerStatus(status: string) {
  switch (status) {
    case 'ready':
      return 'Ready';
    case 'priorityFallback':
      return 'Priority fallback';
    case 'needsResolution':
      return 'Needs resolution';
    case 'blocked':
      return 'Blocked';
    case 'empty':
      return 'Empty';
    case 'error':
      return 'Error';
    case 'pending':
      return 'Pending';
    default:
      return status.replace(/([a-z])([A-Z])/g, '$1 $2');
  }
}

function formatSvModMergerMergeKind(mergeKind: string) {
  switch (mergeKind) {
    case 'smartMerge':
      return 'Smart merge';
    case 'priorityFallback':
      return 'Priority fallback';
    case 'singleSource':
      return 'Single source';
    case 'identical':
      return 'Identical';
    case 'readError':
      return 'Read error';
    default:
      return mergeKind.replace(/([a-z])([A-Z])/g, '$1 $2');
  }
}

function formatModMergerMergeKind(mergeKind: string) {
  switch (mergeKind) {
    case 'smartMerge':
      return 'Smart merge';
    case 'safeMerge':
      return 'Safe merge';
    case 'replacement':
      return 'Replacement';
    case 'singleSource':
      return 'Single source';
    case 'unchanged':
      return 'Same file';
    case 'manualChoice':
      return 'Choice applied';
    case 'needsChoice':
      return 'Needs choice';
    case 'error':
      return 'Error';
    default:
      return mergeKind.replace(/([a-z])([A-Z])/g, '$1 $2');
  }
}

function formatResolutionSource(source: ModMergerConflictResolution['source']) {
  return source === 'mod1' ? 'Mod Directory 1' : 'Mod Directory 2';
}

function getFileName(path: string) {
  const normalized = path.replace(/\\/g, '/').replace(/\/+$/, '');
  return normalized.split('/').pop() || path;
}

function filterItems(items: ItemRecord[], searchText: string) {
  const normalizedSearch = searchText.trim().toLocaleLowerCase();

  if (normalizedSearch.length === 0) {
    return items;
  }

  const machineSearch = normalizedSearch.match(/^(tm|tr)\s*(\d*)$/);
  if (machineSearch) {
    const [, machineKind, numericPrefix = ''] = machineSearch;
    return items
      .map((item) => ({ item, machine: parseMachineItemName(item.name) }))
      .filter(({ machine }) => {
        if (!machine || machine.kind !== machineKind.toUpperCase()) {
          return false;
        }

        const normalizedNumericPrefix = numericPrefix.replace(/^0+/, '') || '0';
        return (
          numericPrefix.length === 0 ||
          machine.numberText.startsWith(normalizedNumericPrefix) ||
          machine.paddedNumberText.startsWith(numericPrefix)
        );
      })
      .sort((left, right) => left.machine!.number - right.machine!.number)
      .map(({ item }) => item);
  }

  return items.filter((item) =>
    [
      item.itemId.toString(),
      item.name,
      item.category,
      item.buyPrice.toString(),
      item.sellPrice.toString(),
      item.wattsPrice.toString(),
      item.alternatePrice.toString(),
      ...item.detailGroups.flatMap((group) => [
        group.label,
        ...group.details.flatMap((detail) => [detail.label, detail.value])
      ])
    ].some((value) => value.toLocaleLowerCase().includes(normalizedSearch))
  );
}

function parseMachineItemName(name: string) {
  const match = name.match(/^(TM|TR)\s*0*(\d+)/i);
  if (!match) {
    return null;
  }

  const number = Number.parseInt(match[2], 10);
  return Number.isInteger(number)
    ? {
        kind: match[1].toUpperCase(),
        number,
        numberText: number.toString(),
        paddedNumberText: number.toString().padStart(2, '0')
      }
    : null;
}

function filterPokemon(
  pokemon: PokemonRecord[],
  searchText: string,
  editorFamily: EditorUiFamily = 'swsh'
) {
  const normalizedSearch = searchText.trim().toLocaleLowerCase();

  if (normalizedSearch.length === 0) {
    return pokemon;
  }

  return pokemon.filter((record) =>
    [
      record.personalId.toString(),
      record.speciesId.toString(),
      record.formLabel,
      formatPokemonRecordName(record, editorFamily),
      record.name,
      record.type1,
      record.type2,
      formatPokemonTypes(record)
    ].some((value) => value.toLocaleLowerCase().includes(normalizedSearch))
  );
}

function filterPokemonCompatibilityEntries(
  group: PokemonCompatibilityGroup,
  searchText: string
) {
  const normalizedSearch = searchText.trim().toLocaleLowerCase();

  if (normalizedSearch.length === 0) {
    return group.entries;
  }

  return group.entries.filter((entry) =>
    [
      entry.slot.toString(),
      entry.moveId.toString(),
      entry.moveName,
      entry.label,
      entry.canLearn ? 'enabled' : 'disabled'
    ].some((value) => value.toLocaleLowerCase().includes(normalizedSearch))
  );
}

function createPokemonCompatibilityFieldName(groupId: string, slot: number) {
  return `compatibility:${groupId}:${slot}`;
}

function formatReferenceLabel(
  labels: ReadonlyMap<number, string>,
  value: number,
  fallbackPrefix: string
) {
  return labels.get(value) ?? `${fallbackPrefix} ${value}`;
}

function formatEvolutionFormReference(
  speciesLabels: ReadonlyMap<number, string>,
  speciesId: number,
  form: number,
  gameFamily: EditorUiFamily = 'swsh'
) {
  return createEvolutionFormOptions(speciesId, speciesLabels, form.toString(), gameFamily).find(
    (option) => option.value === form
  )?.label ?? `Form ${form}`;
}

function createEvolutionFormOptions(
  speciesId: number | null,
  speciesLabels: ReadonlyMap<number, string>,
  draftValue: string,
  gameFamily: EditorUiFamily = 'swsh'
): EditableFieldOption[] {
  const formValues = new Set<number>([0]);
  const parsedDraft = Number.parseInt(draftValue, 10);
  const maximumForm = getPokemonEvolutionMaximumForm(gameFamily);

  const context = createEvolutionFormOptionContext(speciesId, speciesLabels, gameFamily);
  if (context !== null) {
    addKnownSpeciesFormValues(context, formValues);
    if (
      Number.isInteger(parsedDraft) &&
      parsedDraft >= 0 &&
      parsedDraft <= maximumForm &&
      (parsedDraft === 0 ||
        resolveSpeciesFormLabel(context.species, parsedDraft, context.speciesId, gameFamily) !==
          undefined)
    ) {
      formValues.add(parsedDraft);
    }
  } else if (Number.isInteger(parsedDraft) && parsedDraft >= 0 && parsedDraft <= maximumForm) {
    formValues.add(parsedDraft);
  }

  return [...formValues]
    .sort((left, right) => left - right)
    .map((form) => ({
      label: context === null ? (form === 0 ? 'Base' : `Form ${form}`) : formatSpeciesFormOptionLabel(form, context),
      value: form
    }));
}

function createPokemonEvolutionDraftFields(
  evolution: PokemonEvolutionRecord
): PokemonEvolutionDraftFields {
  return {
    argument: evolution.argument.toString(),
    form: evolution.form.toString(),
    level: evolution.level.toString(),
    method: evolution.method.toString(),
    species: evolution.species.toString()
  };
}

function pokemonEvolutionDraftEqualsRecord(
  draft: PokemonEvolutionDraftFields,
  evolution: PokemonEvolutionRecord
) {
  return (
    draft.argument === evolution.argument.toString() &&
    draft.form === evolution.form.toString() &&
    draft.level === evolution.level.toString() &&
    draft.method === evolution.method.toString() &&
    draft.species === evolution.species.toString()
  );
}

function createPokemonLearnsetDraftFields(move: PokemonLearnsetMove): PokemonLearnsetDraftFields {
  return {
    level: move.level.toString(),
    moveId: move.moveId.toString()
  };
}

function isIntegerInRange(
  value: number | null,
  minimum: number,
  maximum: number
): value is number {
  return value !== null && Number.isInteger(value) && value >= minimum && value <= maximum;
}

function isValidSwShLearnsetMove(
  moveId: number | null,
  moveOptions: PokemonEditableFieldOption[]
) {
  return (
    moveId !== null &&
    moveId > 0 &&
    moveId <= pokemonMaximumUshortValue &&
    (moveOptions.length === 0 || moveOptions.some((option) => option.value === moveId))
  );
}

function isValidSwShEvolutionMethod(
  method: number | null,
  methodOptions: PokemonEvolutionMethodOption[]
) {
  return (
    method !== null &&
    method > 0 &&
    method !== 35 &&
    method <= pokemonMaximumUshortValue &&
    methodOptions.some((option) => option.value === method)
  );
}

function isValidSwShEvolutionSpecies(
  species: number | null,
  speciesOptions: PokemonEditableFieldOption[]
) {
  return (
    species !== null &&
    species > 0 &&
    species <= pokemonMaximumUshortValue &&
    (speciesOptions.length === 0 || speciesOptions.some((option) => option.value === species))
  );
}

function isValidSwShEvolutionArgument(
  argument: number,
  methodOption: PokemonEvolutionMethodOption
) {
  if (methodOption.argumentKind === 'none' || methodOption.argumentKind === 'level') {
    return argument === 0;
  }

  if (methodOption.argumentOptions.length > 0) {
    return methodOption.argumentOptions.some((option) => option.value === argument);
  }

  return methodOption.argumentKind === 'item' ||
    methodOption.argumentKind === 'move' ||
    methodOption.argumentKind === 'species'
    ? argument !== 0
    : true;
}

function isValidSwShEvolutionAddition(
  method: number | null,
  argument: number | null,
  species: number | null,
  methodOptions: PokemonEvolutionMethodOption[],
  speciesOptions: PokemonEditableFieldOption[]
) {
  const methodOption = methodOptions.find((option) => option.value === method);
  return (
    isValidSwShEvolutionMethod(method, methodOptions) &&
    argument !== null &&
    methodOption !== undefined &&
    isValidSwShEvolutionArgument(argument, methodOption) &&
    isValidSwShEvolutionSpecies(species, speciesOptions)
  );
}

function getPokemonLearnsetMaximumLevel(gameFamily: EditorUiFamily) {
  if (gameFamily === 'swsh') {
    return swshPokemonLearnsetMaximumLevel;
  }

  return gameFamily === 'za' ? pokemonMaximumByteValue : pokemonMaximumUshortValue;
}

function getPokemonEvolutionMaximumForm(gameFamily: EditorUiFamily) {
  return gameFamily === 'swsh' ? pokemonMaximumByteValue : pokemonMaximumUshortValue;
}

function getPokemonEvolutionMaximumLevel(gameFamily: EditorUiFamily) {
  return gameFamily === 'swsh' ? swshPokemonLearnsetMaximumLevel : pokemonMaximumUshortValue;
}

function getPokemonLearnsetDraftDisplay(
  move: PokemonLearnsetMove,
  draft: PokemonLearnsetDraftFields | null,
  moveOptions: PokemonEditableFieldOption[],
  gameFamily: EditorUiFamily = 'swsh'
) {
  const moveIdDraft = draft?.moveId ?? move.moveId.toString();
  const levelDraft = draft?.level ?? move.level.toString();
  const moveId = parseEditableIntegerDraft(moveIdDraft, moveOptions);
  const level = parseEditableIntegerDraft(levelDraft);
  const levelValue = isIntegerInRange(level, 0, getPokemonLearnsetMaximumLevel(gameFamily))
    ? level
    : move.level;
  const masteryLabel = getPokemonLearnsetMasteryLabel(move);
  const levelLabel = getPokemonLearnsetPrimaryLevelLabel(
    move,
    levelValue,
    levelDraft,
    masteryLabel
  );
  const moveOption = moveId === null
    ? undefined
    : moveOptions.find((option) => option.value === moveId);

  return {
    level: levelValue,
    levelLabel,
    masteryLabel,
    moveId: moveId ?? move.moveId,
    moveName:
      moveOption?.label.replace(/^\d+\s+/, '') ??
      (moveId === move.moveId ? move.moveName : moveId === null ? moveIdDraft : `Move ${moveId}`)
  };
}

function getPokemonLearnsetMasteryLabel(move: PokemonLearnsetMove): string | null {
  if (move.rawLevel !== null && move.rawLevel !== undefined) {
    const masteryLevel = Math.floor(move.rawLevel / 256) & 0xff;
    if (masteryLevel > 0) {
      return `Mastery Lv. ${masteryLevel}`;
    }
  }

  const match = move.levelLabel?.match(/\bMastery Lv\.?\s+(\d+)\b/i);
  return match ? `Mastery Lv. ${match[1]}` : null;
}

function getPokemonLearnsetPrimaryLevelLabel(
  move: PokemonLearnsetMove,
  levelValue: number,
  levelDraft: string,
  masteryLabel: string | null
): string | null {
  if (levelValue !== move.level || levelDraft !== move.level.toString()) {
    return null;
  }

  const levelLabel = move.levelLabel ?? null;
  return levelLabel !== null && masteryLabel === null ? levelLabel : null;
}

function pokemonLearnsetDraftEqualsRecord(
  draft: PokemonLearnsetDraftFields,
  move: PokemonLearnsetMove
) {
  return draft.level === move.level.toString() && draft.moveId === move.moveId.toString();
}

function reviewPokemonLearnsetDrafts(
  pokemon: PokemonRecord | null,
  draftsBySlot: Record<number, PokemonLearnsetDraftFields>,
  learnsetMoveOptions: PokemonEditableFieldOption[],
  gameFamily: EditorUiFamily = 'swsh'
): { changes: PokemonLearnsetDraftChange[]; invalidCount: number } {
  if (!pokemon) {
    return { changes: [], invalidCount: 0 };
  }

  const changes: PokemonLearnsetDraftChange[] = [];
  let invalidCount = 0;

  for (const [slotText, draft] of Object.entries(draftsBySlot)) {
    const slot = Number.parseInt(slotText, 10);
    const move = pokemon.learnset.find((candidate) => candidate.slot === slot);
    if (!move || pokemonLearnsetDraftEqualsRecord(draft, move)) {
      continue;
    }

    const moveOptions = addCurrentPokemonFieldOption(learnsetMoveOptions, draft.moveId, 'Move');
    const moveId = parseEditableIntegerDraft(draft.moveId, moveOptions);
    const level = parseEditableIntegerDraft(draft.level);
    const moveIdChanged = moveId !== move.moveId;
    const levelChanged = level !== move.level;

    if (
      moveId === null ||
      level === null ||
      (moveIdChanged && !isIntegerInRange(moveId, 0, pokemonMaximumUshortValue)) ||
      (levelChanged &&
        !isIntegerInRange(level, 0, getPokemonLearnsetMaximumLevel(gameFamily))) ||
      (gameFamily === 'swsh' &&
        moveIdChanged &&
        !isValidSwShLearnsetMove(moveId, learnsetMoveOptions))
    ) {
      invalidCount += 1;
      continue;
    }

    changes.push({
      action: 'upsert',
      level,
      moveId,
      slot
    });
  }

  return { changes, invalidCount };
}

function reviewPokemonEvolutionDrafts(
  pokemon: PokemonRecord | null,
  draftsBySlot: Record<number, PokemonEvolutionDraftFields>,
  evolutionMethodOptions: PokemonEvolutionMethodOption[],
  pokemonSpeciesOptions: PokemonEditableFieldOption[],
  pokemonSpeciesLabels: ReadonlyMap<number, string>,
  gameFamily: EditorUiFamily = 'swsh'
): { changes: PokemonEvolutionDraftChange[]; invalidCount: number } {
  if (!pokemon) {
    return { changes: [], invalidCount: 0 };
  }

  const changes: PokemonEvolutionDraftChange[] = [];
  let invalidCount = 0;

  for (const [slotText, draft] of Object.entries(draftsBySlot)) {
    const slot = Number.parseInt(slotText, 10);
    const evolution = pokemon.evolutions.find((candidate) => candidate.slot === slot);
    if (!evolution || pokemonEvolutionDraftEqualsRecord(draft, evolution)) {
      continue;
    }

    const methodOptions = addCurrentEvolutionMethodOption(evolutionMethodOptions, draft.method);
    const method = parseEditableIntegerDraft(draft.method, methodOptions);
    const methodOption = findEvolutionMethodOption(methodOptions, draft.method);
    const supportedMethodOption = evolutionMethodOptions.find(
      (option) => option.value === method
    );
    const argumentOptions = addCurrentPokemonFieldOption(
      methodOption?.argumentOptions ?? [],
      draft.argument,
      methodOption?.argumentLabel ?? 'Argument'
    );
    const argument = parseEditableIntegerDraft(draft.argument, argumentOptions);
    const species = parseEditableIntegerDraft(draft.species, pokemonSpeciesOptions);
    const formOptions = createEvolutionFormOptions(
      species,
      pokemonSpeciesLabels,
      draft.form,
      gameFamily
    );
    const form = parseEditableIntegerDraft(draft.form, formOptions);
    const level = parseEditableIntegerDraft(draft.level);
    const methodChanged = method !== evolution.method;
    const argumentChanged = argument !== evolution.argument;
    const speciesChanged = species !== evolution.species;
    const formChanged = form !== evolution.form;
    const levelChanged = level !== evolution.level;

    if (
      method === null ||
      argument === null ||
      species === null ||
      form === null ||
      level === null ||
      (methodChanged && !isIntegerInRange(method, 0, pokemonMaximumUshortValue)) ||
      (argumentChanged && !isIntegerInRange(argument, 0, pokemonMaximumUshortValue)) ||
      (speciesChanged && !isIntegerInRange(species, 0, pokemonMaximumUshortValue)) ||
      (formChanged &&
        !isIntegerInRange(form, 0, getPokemonEvolutionMaximumForm(gameFamily))) ||
      (levelChanged &&
        !isIntegerInRange(level, 0, getPokemonEvolutionMaximumLevel(gameFamily))) ||
      (gameFamily === 'swsh' &&
        methodChanged &&
        !isValidSwShEvolutionMethod(method, evolutionMethodOptions)) ||
      (gameFamily === 'swsh' &&
        speciesChanged &&
        !isValidSwShEvolutionSpecies(species, pokemonSpeciesOptions)) ||
      (gameFamily === 'swsh' && argumentChanged && supportedMethodOption === undefined) ||
      (gameFamily === 'swsh' &&
        (methodChanged || argumentChanged) &&
        supportedMethodOption !== undefined &&
        !isValidSwShEvolutionArgument(argument, supportedMethodOption))
    ) {
      invalidCount += 1;
      continue;
    }

    changes.push({
      action: 'upsert',
      argument,
      form,
      level,
      method,
      slot,
      species
    });
  }

  return { changes, invalidCount };
}

function createPokemonSpeciesLabelMap(
  options: PokemonEditableFieldOption[],
  pokemonRecords: PokemonRecord[]
) {
  const labels = new Map(options.map((option) => [option.value, option.label]));

  for (const record of pokemonRecords) {
    if (
      record.speciesId <= 0 ||
      labels.has(record.speciesId) ||
      /^Unused \d+$/i.test(record.name)
    ) {
      continue;
    }

    labels.set(
      record.speciesId,
      `${record.speciesId.toString().padStart(3, '0')} ${record.name}`
    );
  }

  return labels;
}

function createPokemonSpeciesOptions(pokemonRecords: PokemonRecord[]): PokemonEditableFieldOption[] {
  const labels = createPokemonSpeciesLabelMap([], pokemonRecords);
  return [...labels.entries()]
    .sort((left, right) => left[0] - right[0])
    .map(([value, label]) => ({ label, value }));
}

function createEvolutionFormOptionContext(
  speciesId: number | null,
  speciesLabels: ReadonlyMap<number, string>,
  gameFamily: EditorUiFamily = 'swsh'
): SpeciesFormOptionContext | null {
  if (speciesId === null || !Number.isInteger(speciesId)) {
    return null;
  }

  const speciesLabel = formatReferenceLabel(speciesLabels, speciesId, 'Species');
  const species = getReferenceSpriteName(speciesLabel);
  return {
    gameFamily,
    species: species || speciesLabel,
    speciesId
  };
}

function createDraftSpeciesFormOptionContext(
  speciesField: EditableFieldWithOptions | null | undefined,
  draftValue: string | undefined,
  fallbackSpecies: string,
  fallbackSpeciesId: number,
  abilityOptions?: EditableFieldOption[],
  gameFamily?: EditorUiFamily,
  genderOptions?: EditableFieldOption[]
): SpeciesFormOptionContext {
  const options = speciesField?.options ?? [];
  const parsedSpeciesId =
    draftValue && draftValue.trim().length > 0
      ? parseEditableIntegerDraft(draftValue, options)
      : fallbackSpeciesId;
  const speciesId = parsedSpeciesId ?? fallbackSpeciesId;
  const speciesLabel =
    options.find((option) => option.value === speciesId)?.label ??
    `${speciesId.toString().padStart(3, '0')} ${fallbackSpecies}`;
  const species = getReferenceSpriteName(speciesLabel) || fallbackSpecies;

  return {
    abilityOptions,
    gameFamily,
    genderOptions,
    species,
    speciesId
  };
}

function createTrainerPokemonAbilityOptions(pokemon: PokemonRecord): EditableFieldOption[] {
  const options: EditableFieldOption[] = [];
  if (pokemon.abilities.ability1 > 0) {
    options.push(
      {
        label: `Default - ${pokemon.abilities.ability1Label}`,
        value: 0
      },
      {
        label: `Ability 1 - ${pokemon.abilities.ability1Label}`,
        value: 1
      }
    );
  }
  if (pokemon.abilities.ability2 > 0) {
    options.push({
      label: `Ability 2 - ${pokemon.abilities.ability2Label}`,
      value: 2
    });
  }
  if (pokemon.abilities.hiddenAbility > 0) {
    options.push({
      label: `Hidden Ability - ${pokemon.abilities.hiddenAbilityLabel}`,
      value: 3
    });
  }

  return options;
}

function createRentalPokemonAbilityOptions(pokemon: PokemonRecord): EditableFieldOption[] {
  const options: EditableFieldOption[] = [];
  if (pokemon.abilities.ability1 > 0) {
    options.push({
      label: `Ability 1 - ${pokemon.abilities.ability1Label}`,
      value: 0
    });
  }
  if (pokemon.abilities.ability2 > 0) {
    options.push({
      label: `Ability 2 - ${pokemon.abilities.ability2Label}`,
      value: 1
    });
  }
  if (pokemon.abilities.hiddenAbility > 0) {
    options.push({
      label: `Hidden Ability - ${pokemon.abilities.hiddenAbilityLabel}`,
      value: 2
    });
  }

  return options;
}

function createGiftPokemonGenderOptions(pokemon: PokemonRecord): EditableFieldOption[] {
  if (pokemon.personal.genderRatio === 255) {
    return [
      { label: 'Random', value: 0 },
      { label: 'Genderless', value: 2 }
    ];
  }

  if (pokemon.personal.genderRatio === 0) {
    return [
      { label: 'Random', value: 0 },
      { label: 'Male', value: 1 }
    ];
  }

  if (pokemon.personal.genderRatio === 254) {
    return [
      { label: 'Random', value: 0 },
      { label: 'Female', value: 2 }
    ];
  }

  return [
    { label: 'Random', value: 0 },
    { label: 'Male', value: 1 },
    { label: 'Female', value: 2 }
  ];
}

function preserveValidGiftDependencyOrReset(
  drafts: Record<string, string>,
  fields: NumericEditableField[],
  fieldName: string,
  currentValue: number,
  availableOptions: EditableFieldOption[]
) {
  const field = fields.find((candidate) => candidate.field === fieldName);
  if (!field || availableOptions.length === 0) {
    return;
  }

  const parsedValue = parseEditableIntegerDraft(
    drafts[fieldName] ?? currentValue.toString(),
    field.options
  );
  if (
    parsedValue !== null &&
    availableOptions.some((option) => option.value === parsedValue)
  ) {
    return;
  }

  const fallbackOption =
    availableOptions.find((option) => option.value === 0) ?? availableOptions[0];
  if (fallbackOption) {
    drafts[fieldName] = fallbackOption.value.toString();
  }
}

function addKnownSpeciesFormValues(context: SpeciesFormOptionContext, formValues: Set<number>) {
  const formLabels = getSpeciesFormLabelData(context.gameFamily);
  if (context.speciesId !== undefined) {
    for (const key of formLabels.labelsBySpeciesId.keys()) {
      const [speciesIdText, formText] = key.split(':');
      if (Number.parseInt(speciesIdText, 10) === context.speciesId) {
        formValues.add(Number.parseInt(formText, 10));
      }
    }
  }

  const normalizedSpecies = normalizeSpeciesName(context.species);
  for (const key of formLabels.labelsBySpeciesName.keys()) {
    const [speciesName, formText] = key.split(':');
    if (speciesName === normalizedSpecies) {
      formValues.add(Number.parseInt(formText, 10));
    }
  }
}

function addCurrentEvolutionMethodOption(
  options: PokemonEvolutionMethodOption[],
  draftValue: string
) {
  const parsedValue = parseEditableIntegerDraft(draftValue, options);
  if (
    parsedValue === null ||
    !Number.isInteger(parsedValue) ||
    options.some((option) => option.value === parsedValue)
  ) {
    return options;
  }

  return [
    ...options,
    {
      argumentKind: 'value',
      argumentLabel: 'Argument',
      argumentOptions: [],
      label: `${parsedValue.toString().padStart(3, '0')} Method ${parsedValue}`,
      value: parsedValue
    }
  ];
}

function addCurrentPokemonFieldOption(
  options: PokemonEditableFieldOption[],
  draftValue: string,
  fallbackLabel: string,
  valueLabels?: ReadonlyMap<number, string>
) {
  const parsedValue = parseEditableIntegerDraft(draftValue, options);
  if (
    parsedValue === null ||
    !Number.isInteger(parsedValue) ||
    options.some((option) => option.value === parsedValue)
  ) {
    return options;
  }

  return [
    ...options,
    {
      label: valueLabels?.get(parsedValue) ?? `${parsedValue} ${fallbackLabel}`,
      value: parsedValue
    }
  ];
}

function addDraftFallbackOption(
  options: EditableFieldOption[],
  draftValue: string,
  fallbackLabel: string
) {
  const parsedValue = parseEditableIntegerDraft(draftValue, options);
  return parsedValue !== null &&
    Number.isInteger(parsedValue) &&
    !options.some((option) => option.value === parsedValue)
    ? [
        {
          label: fallbackLabel,
          value: parsedValue!
        },
        ...options
      ]
    : options;
}

function findEvolutionMethodOption(
  options: PokemonEvolutionMethodOption[],
  draftValue: string
) {
  const parsedValue = parseEditableIntegerDraft(draftValue, options);
  return parsedValue !== null && Number.isInteger(parsedValue)
    ? options.find((option) => option.value === parsedValue) ?? null
    : null;
}

function getDefaultEvolutionArgumentDraft(methodOption: PokemonEvolutionMethodOption | null) {
  if (
    !methodOption ||
    methodOption.argumentKind === 'none' ||
    methodOption.argumentKind === 'level'
  ) {
    return '0';
  }

  return methodOption.argumentOptions[0]?.value.toString() ?? '0';
}

function usesEvolutionArgumentSelector(methodOption: PokemonEvolutionMethodOption | null) {
  return Boolean(
    methodOption &&
      methodOption.argumentKind !== 'none' &&
      methodOption.argumentKind !== 'level' &&
      methodOption.argumentOptions.length > 0
  );
}

function usesEvolutionArgumentNumberInput(methodOption: PokemonEvolutionMethodOption | null) {
  return Boolean(
    methodOption &&
      methodOption.argumentKind !== 'none' &&
      methodOption.argumentKind !== 'level' &&
      methodOption.argumentOptions.length === 0
  );
}

function formatEvolutionMethodSummary(evolution: PokemonEvolutionRecord) {
  const methodName = evolution.methodName || `Method ${evolution.method}`;
  return `${evolution.method.toString().padStart(3, '0')} ${methodName}`;
}

function formatEvolutionArgumentSummary(evolution: PokemonEvolutionRecord) {
  if (evolution.argumentKind === 'none' || evolution.argumentKind === 'level') {
    return 'Arg -';
  }

  return `${evolution.argumentLabel} ${evolution.argumentValue || evolution.argument}`;
}

