function SearchableOptionInput({
  ariaLabel,
  ariaDescribedBy,
  ariaInvalid,
  disabled,
  emptyOptionLabel,
  id,
  onChange,
  onFocus,
  options,
  title,
  value
}: {
  ariaLabel: string;
  ariaDescribedBy?: string;
  ariaInvalid?: boolean;
  disabled: boolean;
  emptyOptionLabel?: string;
  id?: string;
  onChange: (value: string) => void;
  onFocus?: () => void;
  options: EditableFieldOption[];
  title?: string;
  value: string;
}) {
  const { translateLiteral } = useLocalization();
  const containerRef = useRef<HTMLDivElement | null>(null);
  const [isOpen, setIsOpen] = useState(false);
  const localizedAriaLabel = translateLiteral(ariaLabel);
  const localizedEmptyOptionLabel =
    emptyOptionLabel !== undefined ? translateLiteral(emptyOptionLabel) : undefined;
  const localizedTitle = title !== undefined ? translateLiteral(title) : undefined;
  const localizedOptions = useMemo(
    () => options.map((option) => ({ ...option, label: translateLiteral(option.label) })),
    [options, translateLiteral]
  );
  const formattedValue = useMemo(
    () => formatOptionInputValue(value, localizedOptions, localizedEmptyOptionLabel),
    [localizedEmptyOptionLabel, localizedOptions, value]
  );
  const [query, setQuery] = useState(formattedValue);
  const [hasUserQuery, setHasUserQuery] = useState(false);
  const optionQuery = hasUserQuery ? query : '';
  const trimmedOptionQuery = optionQuery.trim().toLocaleLowerCase();
  const hasEmptyOption = localizedEmptyOptionLabel !== undefined;
  const emptyOptionMatches =
    hasEmptyOption &&
    (trimmedOptionQuery.length === 0 ||
      localizedEmptyOptionLabel.toLocaleLowerCase().includes(trimmedOptionQuery));
  const filteredOptions = useMemo(
    () => getSmartOptionMatches(optionQuery, localizedOptions),
    [localizedOptions, optionQuery]
  );
  const hasMenu = isOpen && !disabled && (emptyOptionMatches || filteredOptions.length > 0);

  useEffect(() => {
    if (!isOpen) {
      setQuery(formattedValue);
      setHasUserQuery(false);
    }
  }, [formattedValue, isOpen]);

  useEffect(() => {
    if (disabled) {
      setIsOpen(false);
    }
  }, [disabled]);

  useEffect(() => {
    if (!isOpen) {
      return undefined;
    }

    const handlePointerDown = (event: MouseEvent) => {
      if (!containerRef.current?.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };

    document.addEventListener('mousedown', handlePointerDown);
    return () => document.removeEventListener('mousedown', handlePointerDown);
  }, [isOpen]);

  const selectOption = (option: EditableFieldOption) => {
    onChange(option.value.toString());
    setQuery(option.label);
    setHasUserQuery(false);
    setIsOpen(false);
  };

  const selectEmptyOption = () => {
    onChange('');
    setQuery(localizedEmptyOptionLabel ?? '');
    setHasUserQuery(false);
    setIsOpen(false);
  };

  const commitTypedOption = () => {
    const trimmedQuery = query.trim();
    if (
      localizedEmptyOptionLabel !== undefined &&
      trimmedQuery.toLocaleLowerCase() === localizedEmptyOptionLabel.toLocaleLowerCase()
    ) {
      selectEmptyOption();
      return;
    }

    const exactOption = findExactOptionMatch(trimmedQuery, localizedOptions);
    const optionToCommit = exactOption ?? (filteredOptions.length === 1 ? filteredOptions[0] : null);
    if (!hasUserQuery || !optionToCommit) {
      setIsOpen(false);
      return;
    }

    selectOption(optionToCommit);
  };

  const handleInputChange = (nextValue: string) => {
    setQuery(nextValue);
    setHasUserQuery(true);
    setIsOpen(true);
    onChange(
      normalizeExactOptionInputValue(nextValue, localizedOptions, localizedEmptyOptionLabel)
    );
  };

  return (
    <div
      className={`searchable-option-input ${disabled ? 'searchable-option-disabled' : ''}`}
      ref={containerRef}
    >
      <input
        aria-describedby={ariaDescribedBy}
        aria-expanded={hasMenu}
        aria-label={localizedAriaLabel}
        aria-haspopup="listbox"
        aria-invalid={ariaInvalid}
        autoComplete="off"
        disabled={disabled}
        id={id}
        inputMode="search"
        onBlur={commitTypedOption}
        onChange={(event) => handleInputChange(event.target.value)}
        onFocus={() => {
          setQuery(formattedValue);
          setHasUserQuery(false);
          setIsOpen(true);
          onFocus?.();
        }}
        onKeyDown={(event) => {
          if (event.key === 'Escape') {
            setIsOpen(false);
            return;
          }

          if (event.key === 'Enter' && filteredOptions.length > 0) {
            event.preventDefault();
            const trimmedQuery = query.trim();
            const exactOption = findExactOptionMatch(trimmedQuery, localizedOptions);
            const isDigitLeadingQuery = /^\d/.test(trimmedQuery);
            const optionToCommit =
              exactOption ??
              (filteredOptions.length === 1 || !isDigitLeadingQuery
                ? filteredOptions[0]
                : null);
            if (optionToCommit) {
              selectOption(optionToCommit);
            } else {
              setIsOpen(false);
            }
          }
        }}
        title={localizedTitle}
        type="text"
        value={query}
      />
      <button
        aria-label={translateLiteral(`Show ${ariaLabel} options`)}
        className="searchable-option-toggle"
        disabled={disabled}
        onMouseDown={(event) => {
          event.preventDefault();
          setQuery(formattedValue);
          setHasUserQuery(false);
          setIsOpen((current) => (current && !hasUserQuery ? false : true));
        }}
        tabIndex={-1}
        type="button"
      >
        <ChevronDown aria-hidden="true" size={16} />
      </button>
      {hasMenu ? (
        <div className="searchable-option-menu" role="listbox">
          {emptyOptionMatches ? (
            <button
              className="searchable-option-row"
              key={`${ariaLabel}:empty`}
              onMouseDown={(event) => {
                event.preventDefault();
                selectEmptyOption();
              }}
              role="option"
              type="button"
            >
              <span>{localizedEmptyOptionLabel}</span>
            </button>
          ) : null}
          {filteredOptions.map((option) => (
            <button
              className="searchable-option-row"
              key={`${ariaLabel}:${option.value}`}
              onMouseDown={(event) => {
                event.preventDefault();
                selectOption(option);
              }}
              role="option"
              type="button"
            >
              <span>{option.label}</span>
            </button>
          ))}
        </div>
      ) : null}
    </div>
  );
}

function normalizeExactOptionInputValue(
  value: string,
  options: EditableFieldOption[],
  emptyOptionLabel?: string
) {
  const normalizedValue = value.trim().toLocaleLowerCase();
  if (normalizedValue.length === 0) {
    return value;
  }

  if (
    emptyOptionLabel !== undefined &&
    normalizedValue === emptyOptionLabel.toLocaleLowerCase()
  ) {
    return '';
  }

  const optionMatch = options.find(
    (option) =>
      option.label.toLocaleLowerCase() === normalizedValue ||
    option.value.toString() === normalizedValue
  );

  if (optionMatch) {
    return optionMatch.value.toString();
  }

  const smartMatches = getSmartOptionMatches(value, options);
  return smartMatches.length === 1 ? smartMatches[0]!.value.toString() : value;
}

function findExactOptionMatch(value: string, options: EditableFieldOption[]) {
  const normalizedValue = value.toLocaleLowerCase();
  return options.find(
    (option) =>
      option.value.toString() === value || option.label.toLocaleLowerCase() === normalizedValue
  );
}

function formatOptionInputValue(
  value: string,
  options: EditableFieldOption[],
  emptyOptionLabel?: string
) {
  const trimmedValue = value.trim();
  if (trimmedValue.length === 0) {
    return emptyOptionLabel ?? value;
  }

  return (
    options.find((option) => option.value.toString() === trimmedValue)?.label ??
    options.find((option) => option.label === value)?.label ??
    value
  );
}

function areStringArraysEqual(left: readonly string[], right: readonly string[]) {
  return left.length === right.length && left.every((value, index) => value === right[index]);
}

function areFieldDraftsEqual(
  left: Record<string, string>,
  right: Record<string, string>
) {
  const keys = new Set([...Object.keys(left), ...Object.keys(right)]);
  for (const key of keys) {
    if ((left[key] ?? '') !== (right[key] ?? '')) {
      return false;
    }
  }

  return true;
}

function setFieldDraftRecord(
  records: Record<string, Record<string, string>>,
  recordKey: string | number,
  nextDrafts: Record<string, string>,
  defaultDrafts: Record<string, string>
) {
  const normalizedKey = recordKey.toString();
  const nextRecords = { ...records };
  if (areFieldDraftsEqual(nextDrafts, defaultDrafts)) {
    delete nextRecords[normalizedKey];
  } else {
    nextRecords[normalizedKey] = nextDrafts;
  }

  return nextRecords;
}

function setSparseFieldDraftRecord(
  records: Record<string, Record<string, string>>,
  recordKey: string | number,
  nextDrafts: Record<string, string>,
  defaultDrafts: Record<string, string>
) {
  const normalizedKey = recordKey.toString();
  const sparseDrafts = Object.fromEntries(
    Object.entries(nextDrafts).filter(
      ([field, value]) => value !== (defaultDrafts[field] ?? '')
    )
  );
  const nextRecords = { ...records };

  if (Object.keys(sparseDrafts).length === 0) {
    delete nextRecords[normalizedKey];
  } else {
    nextRecords[normalizedKey] = sparseDrafts;
  }

  return nextRecords;
}

function pruneSparseFieldDraftRecord(
  records: Record<string, Record<string, string>>,
  recordKey: string | number,
  defaultDrafts: Record<string, string>,
  allowedFields: ReadonlySet<string>
) {
  const normalizedKey = recordKey.toString();
  const currentDrafts = records[normalizedKey];
  if (!currentDrafts) {
    return records;
  }

  const writableDrafts = Object.fromEntries(
    Object.entries(currentDrafts).filter(([field]) => allowedFields.has(field))
  );
  return setSparseFieldDraftRecord(records, recordKey, writableDrafts, defaultDrafts);
}

function pruneFieldDraftRecord(
  records: Record<string, Record<string, string>>,
  recordKey: string | number,
  defaultDrafts: Record<string, string>
) {
  const normalizedKey = recordKey.toString();
  const currentDrafts = records[normalizedKey];
  if (!currentDrafts || !areFieldDraftsEqual(currentDrafts, defaultDrafts)) {
    return records;
  }

  const nextRecords = { ...records };
  delete nextRecords[normalizedKey];
  return nextRecords;
}

function deleteFieldDraftRecord<T>(records: Record<string, T>, recordKey: string | number) {
  const normalizedKey = recordKey.toString();
  if (!Object.prototype.hasOwnProperty.call(records, normalizedKey)) {
    return records;
  }

  const nextRecords = { ...records };
  delete nextRecords[normalizedKey];
  return nextRecords;
}

function removeDraftFieldsFromRecord(
  records: Record<string, Record<string, string>>,
  recordKey: string | number,
  defaultDrafts: Record<string, string>,
  fields: readonly string[]
) {
  const normalizedKey = recordKey.toString();
  const currentDrafts = records[normalizedKey];
  if (!currentDrafts) {
    return records;
  }

  const nextDrafts = { ...currentDrafts };
  for (const field of fields) {
    delete nextDrafts[field];
  }

  return setFieldDraftRecord(records, recordKey, nextDrafts, defaultDrafts);
}

function countFieldDraftRecords(records: Record<string, Record<string, string>>) {
  return Object.keys(records).length;
}

function getIntegerDraftError(value: string) {
  return value.trim().length === 0 ? 'Enter a value.' : 'Enter a whole number.';
}

function getIntegerDraftFieldError(
  value: string,
  field?: Pick<ShopEditableField, 'maximumValue' | 'minimumValue' | 'options'>
) {
  const parsedValue = parseEditableIntegerDraft(value, field?.options);
  if (parsedValue === null) {
    return getIntegerDraftError(value);
  }

  if (field?.minimumValue !== null && field?.minimumValue !== undefined) {
    if (parsedValue < field.minimumValue) {
      return `Value must be at least ${field.minimumValue}.`;
    }
  }

  if (field?.maximumValue !== null && field?.maximumValue !== undefined) {
    if (parsedValue > field.maximumValue) {
      return `Value must be at most ${field.maximumValue}.`;
    }
  }

  return getIntegerDraftError(value);
}

function getSmartOptionMatches(value: string, options: EditableFieldOption[]) {
  const query = value.trim();
  if (query.length === 0) {
    return options;
  }

  const normalizedQuery = query.toLocaleLowerCase();
  const numericPrefix = normalizedQuery.match(/^\d+/)?.[0] ?? null;
  const letterPrefix = normalizedQuery.match(/^[a-z]+/)?.[0] ?? null;

  if (numericPrefix) {
    const normalizedNumericPrefix = numericPrefix.replace(/^0+/, '') || '0';

    return options
      .filter((option) => {
        const rawValue = option.value.toString();
        const normalizedValue = rawValue.replace(/^0+/, '') || '0';
        const labelNumericPrefix =
          option.label.match(/^\s*\$?\s*0*([\d,]+)/)?.[1]?.replace(/,/g, '') ?? null;

        return (
          rawValue.startsWith(numericPrefix) ||
          normalizedValue.startsWith(normalizedNumericPrefix) ||
          labelNumericPrefix?.startsWith(normalizedNumericPrefix)
        );
      })
      .slice(0, 100);
  }

  if (letterPrefix) {
    return options
      .filter((option) =>
        option.label
          .toLocaleLowerCase()
          .split(/[^a-z0-9]+/)
          .some((token) => token.startsWith(letterPrefix))
      )
      .slice(0, 100);
  }

  return options
    .filter((option) => option.label.toLocaleLowerCase().startsWith(normalizedQuery))
    .slice(0, 100);
}

function useCancelActiveEditSession() {
  const requestCancelEditSession = useContext(CancelEditSessionContext);

  if (!requestCancelEditSession) {
    throw new Error('Cancel edit session context is not available.');
  }

  return requestCancelEditSession;
}

function useRegisterEditorDraftDirty(section: WorkbenchSection, isDirty: boolean) {
  const registerEditorDraftDirty = useContext(EditorDraftDirtyContext);

  if (!registerEditorDraftDirty) {
    throw new Error('Editor draft dirty context is not available.');
  }

  useEffect(() => {
    registerEditorDraftDirty(section, isDirty);
    return () => registerEditorDraftDirty(section, false);
  }, [isDirty, registerEditorDraftDirty, section]);
}

function PokemonSummaryCard({
  editorFamily,
  form,
  name,
  speciesId,
  spriteName,
  subtitle,
  title
}: {
  editorFamily?: EditorUiFamily;
  form?: number;
  name: string;
  speciesId?: number;
  spriteName?: string | null;
  subtitle: string;
  title: string;
}) {
  return (
    <div className="pokemon-summary-card">
      <PokemonSprite
        className="pokemon-summary-sprite"
        editorFamily={editorFamily}
        form={form}
        name={name}
        speciesId={speciesId}
        spriteName={spriteName}
      />
      <div className="pokemon-summary-main">
        <strong className="pokemon-summary-title">{title}</strong>
        <span className="pokemon-summary-subtitle">{subtitle}</span>
      </div>
    </div>
  );
}

function PokemonSprite({
  className = '',
  editorFamily,
  form,
  name,
  preferStatic = false,
  speciesId,
  spriteName
}: {
  className?: string;
  editorFamily?: EditorUiFamily;
  form?: number;
  name: string;
  preferStatic?: boolean;
  speciesId?: number;
  spriteName?: string | null;
}) {
  const urls = useMemo(
    () =>
      getPokemonSpriteUrls(
        {
          editorFamily,
          form,
          name,
          speciesId,
          spriteName
        },
        preferStatic
      ),
    [editorFamily, form, name, preferStatic, speciesId, spriteName]
  );
  const [urlIndex, setUrlIndex] = useState(0);

  useEffect(() => {
    setUrlIndex(0);
  }, [urls]);

  if (urls.length === 0 || !urls[urlIndex]) {
    return <span aria-hidden="true" className={`pokemon-sprite-placeholder ${className}`} />;
  }

  return (
    <img
      alt=""
      className={`pokemon-sprite ${className} ${
        urls[urlIndex].includes('/ani/') ? 'pokemon-sprite-animated' : ''
      }`}
      onError={() => setUrlIndex((currentIndex) => currentIndex + 1)}
      src={urls[urlIndex]}
    />
  );
}

type PokemonSpriteIdentity = {
  editorFamily?: EditorUiFamily;
  form?: number;
  name: string;
  speciesId?: number;
  spriteName?: string | null;
};

function getPokemonSpriteUrls(identity: PokemonSpriteIdentity, preferStatic: boolean) {
  const spriteIds = getPokemonSpriteIdsForIdentity(identity);
  if (spriteIds.length === 0) {
    return [];
  }

  return spriteIds.flatMap((spriteId) => {
    const localStatic = getPublicAssetUrl(`sprites/gen5/${spriteId}.png`);
    const localAnimated = getPublicAssetUrl(`sprites/ani/${spriteId}.gif`);
    const remoteStatic = `https://play.pokemonshowdown.com/sprites/gen5/${spriteId}.png`;

    return preferStatic
      ? [localStatic, remoteStatic]
      : [localAnimated, localStatic, remoteStatic];
  });
}

function getPublicAssetUrl(path: string) {
  const baseUrl = import.meta.env.BASE_URL || '/';
  const normalizedBaseUrl = baseUrl.endsWith('/') ? baseUrl : `${baseUrl}/`;
  return `${normalizedBaseUrl}${path.replace(/^\/+/, '')}`;
}

export function getPokemonSpriteIdsForIdentity(identity: PokemonSpriteIdentity) {
  const candidateLabels = getPokemonSpriteCandidateLabels(identity);
  return uniqueStrings(candidateLabels.flatMap((label) => getPokemonSpriteIds(label)));
}

function getPokemonSpriteCandidateLabels({
  editorFamily,
  form,
  name,
  speciesId,
  spriteName
}: PokemonSpriteIdentity) {
  const candidates: string[] = [];
  const normalizedSpriteName = spriteName?.trim();

  if (normalizedSpriteName) {
    if (form !== undefined) {
      candidates.push(formatSpeciesFormLabel(normalizedSpriteName, form, speciesId, editorFamily));
    }
    candidates.push(normalizedSpriteName);
  }

  candidates.push(name);

  return uniqueStrings(candidates.filter((candidate) => candidate.trim().length > 0));
}

function uniqueStrings(values: string[]) {
  return Array.from(new Set(values));
}

