export function getPokemonSpriteId(name: string) {
  const normalizedName = normalizePokemonSpriteName(name);
  if (!normalizedName) {
    return '';
  }

  const normalizedKey = normalizedName.toLocaleLowerCase();
  const override = pokemonSpriteIdOverrides.get(normalizedKey);
  if (override) {
    return override;
  }

  return normalizedName
    .split('-')
    .map(toPokemonSpriteIdPart)
    .filter(Boolean)
    .join('-');
}

export function getPokemonSpriteIds(name: string) {
  const spriteId = getPokemonSpriteId(name);
  if (!spriteId) {
    return [];
  }

  const spriteIds = [spriteId];
  let fallbackId = spriteId;
  while (fallbackId.includes('-')) {
    fallbackId = fallbackId.replace(/-[^-]+$/, '');
    if (fallbackId && !spriteIds.includes(fallbackId)) {
      spriteIds.push(fallbackId);
    }
  }

  return spriteIds;
}

function normalizePokemonSpriteName(name: string) {
  const trimmedName = name.trim();
  if (!trimmedName || /^Pokemon \d+$/i.test(trimmedName) || /^Unused \d+$/i.test(trimmedName)) {
    return '';
  }

  return trimmedName
    .replace(/\s*\((Alolan)\)$/i, '-Alola')
    .replace(/\s*\((Galarian)\)$/i, '-Galar')
    .replace(/\s*\((Hisuian)\)$/i, '-Hisui')
    .replace(/\s*\((Paldean)\)$/i, '-Paldea')
    .replace(/\s*\((Female|Male)\)$/i, '-$1')
    .replace(/\s*\((Low Key)\)/i, '-Low-Key')
    .replace(/\s*\((Gigantamax|G-Max)\)$/i, '-Gmax')
    .replace(/\s*\((Mega X)\)$/i, '-MegaX')
    .replace(/\s*\((Mega Y)\)$/i, '-MegaY')
    .replace(/\s*\((Mega)\)$/i, '-Mega')
    .replace(/\s*\((Regional Form \d+|Regional Form|Form \d+)\)$/i, '')
    .replace(/[()]/g, '')
    .replace(/\s+/g, '-');
}

function getReferenceSpriteName(label: string) {
  return label.replace(/^\d+\s+/, '').replace(/^Species\s+\d+$/i, '');
}

function toPokemonSpriteIdPart(value: string) {
  return value
    .toLocaleLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '');
}

function getEditableFieldHelp(field: EditableFieldWithOptions) {
  const specificHelp: Record<string, string> = {
    aiFlags: 'Battle AI behavior bitmask. Use the named AI flag checkboxes when they are shown.',
    canUseMove: 'Controls whether the move is enabled. Enabling a base-disabled move does not restore missing battle animations, resources, or learnset references; verify its required game assets before using it.',
    canDynamax: 'Whether this Pokemon is allowed to Dynamax in trainer battles.',
    canGigantamax: 'Whether this Pokemon can use its Gigantamax form when eligible.',
    [trainerCanTerastallizeFieldName]: 'S/V trainer-level flag that allows the trainer to Terastallize. The target comes from party Pokemon with a fixed Tera type.',
    [zaLastHandFieldName]: 'Z-A trainer flag preserved from trainer data. Battle behavior still needs more research.',
    [zaMegaEvolutionFieldName]: 'Whether this Z-A trainer battle enables Mega Evolution behavior.',
    [zaRankFieldName]: 'Z-A trainer rank value.',
    dynamaxLevel: 'Dynamax level. Valid game values are 0 through 10.',
    effectSequence: 'Advanced raw battle effect script/sequence ID. This controls special behavior and is not fully mapped yet; preserve it unless the move has been verified in game.',
    [itemBattlePouchFieldName]: 'Controls the battle item category: none, Balls, or usable battle items.',
    [itemCureStatusFlagsFieldName]: 'Raw cure-status bitmask. Use the named cure controls so unrelated bits remain intact.',
    [itemFieldFlagsFieldName]: 'Legacy name for Battle pouch. It remains visible only for compatibility.',
    flinch: 'Percent chance that the move causes flinching.',
    gift: 'Unknown raw Gen 8 trainer header value. It is read-only because no game behavior has been verified for it.',
    inflictPercent: 'Percent chance to inflict the selected condition or secondary effect. Zero on a move with an inflict effect means it is a primary effect with no separate chance roll.',
    money: 'Stored trainer money value. Sword/Shield payout semantics are not verified, so KM exposes the raw rate.',
    quality: 'Advanced effect-quality value. When named options are unavailable, preserve this raw value unless the move has been verified in game.',
    rawHealing: 'Advanced signed raw HP behavior. Positive values restore that percentage of HP; negative values cost that percentage of HP. Preserve the value unless the move has been verified in game.',
    rawInflictCount: 'Duration mode for the inflicted condition/effect. Sword/Shield exposes five known modes.',
    recoil: 'Signed drain/recoil percent. Positive values drain HP; negative values deal recoil. The effect sequence determines the exact battle behavior.',
    specialMoveId: 'Gift table special move field.',
    stat1: 'First stat-change slot. There are three Sword/Shield move stat-change slots total.',
    stat1Percent: 'Percent chance for stat-change slot 1 to apply. Zero on an occupied slot means a primary effect with no separate chance roll.',
    stat1Stage: 'Stage delta for stat-change slot 1. Positive raises the stat; negative lowers it.',
    stat2: 'Second stat-change slot. Use when a move changes more than one stat.',
    stat2Percent: 'Percent chance for stat-change slot 2 to apply. Zero on an occupied slot means a primary effect with no separate chance roll.',
    stat2Stage: 'Stage delta for stat-change slot 2. Positive raises the stat; negative lowers it.',
    stat3: 'Third and final Sword/Shield stat-change slot.',
    stat3Percent: 'Percent chance for stat-change slot 3 to apply. Zero on an occupied slot means a primary effect with no separate chance roll.',
    turnMax: 'Maximum number of turns for an inflicted condition or effect. Zero means the duration is effect-defined.',
    turnMin: 'Minimum number of turns for an inflicted condition or effect. Zero means the duration is effect-defined.',
    stat3Stage: 'Stage delta for stat-change slot 3. Positive raises the stat; negative lowers it.',
    [itemUseFlags1FieldName]: 'Raw item use bitmask. Locked from direct editing; use the decoded PP restore, HP restore, and EV flag fields instead.',
    [itemUseFlags2FieldName]: 'Raw item use bitmask. Decoded bits are shown in item details; bits 5-7 remain unknown.',
    zaConditionKind: 'Z-A shop unlock condition type for this inventory slot.',
    zaConditionComparison: 'Comparison used by the selected Z-A shop unlock condition. Value 5 is greater than or equal.',
    zaConditionArguments: 'Arguments for the selected Z-A condition. Scenario phase uses a phase value, flag condition uses a flag id, work value uses a work id, and have item uses item id plus optional count.'
  };
  const range =
    field.minimumValue === null || field.maximumValue === null
      ? null
      : field.minimumValue === undefined || field.maximumValue === undefined
        ? null
        : `${field.minimumValue}-${field.maximumValue}`;
  const optionCount = field.options?.length ?? 0;
  const optionHint = optionCount > 0 ? `${optionCount} available option${optionCount === 1 ? '' : 's'}` : null;
  const specificText =
    field.field === healFieldName && field.label.toLocaleLowerCase().includes('flag')
      ? 'Unknown raw Gen 8 trainer header flag. It is read-only because no game behavior has been verified for it.'
      : field.field === healFieldName
        ? 'True if the move is treated as a healing move for battle rules and move interactions.'
        : field.field
          ? specificHelp[field.field]
          : null;

  return [
    field.label,
    specificText,
    range ? `Allowed range: ${range}` : null,
    optionHint
  ]
    .filter((part): part is string => Boolean(part))
    .map((part) => part.replace(/\.+$/, ''))
    .join('. ');
}

function getContextualFieldOptions(
  field: EditableFieldWithOptions,
  formOptionContext?: SpeciesFormOptionContext
): EditableFieldOption[] {
  const options = field.options ?? [];
  if (
    field.field === abilityFieldName ||
    field.field === raidBattleAbilityFieldName
  ) {
    return formOptionContext?.abilityOptions?.length ? formOptionContext.abilityOptions : options;
  }

  if (field.field === genderFieldName) {
    return formOptionContext?.genderOptions?.length ? formOptionContext.genderOptions : options;
  }

  if (!isSpeciesFormField(field.field) || formOptionContext === undefined) {
    return options;
  }

  const formOptions = formOptionContext.formOptions?.length
    ? formOptionContext.formOptions
    : options;

  return formOptions.map((option) => ({
    ...option,
    label: formatSpeciesFormOptionLabel(option.value, formOptionContext)
  }));
}

function useContextualSpeciesFormOptions(
  field: EditableFieldWithOptions,
  formOptionContext: SpeciesFormOptionContext | undefined,
  currentValue: number | null
) {
  const knownFormCount = useWorkbenchStore((state) => {
    if (!formOptionContext?.speciesId) {
      return undefined;
    }

    return state.pokemonWorkflow?.pokemon.find(
      (pokemon) => pokemon.speciesId === formOptionContext.speciesId && pokemon.form === 0
    )?.personal.formCount;
  });
  const contextualFormOptionContext = useMemo(
    () =>
      createContextualSpeciesFormOptionContext(
        field,
        formOptionContext,
        currentValue,
        knownFormCount
      ),
    [currentValue, field, formOptionContext, knownFormCount]
  );
  const options = getContextualFieldOptions(field, contextualFormOptionContext);

  return { contextualFormOptionContext, knownFormCount, options };
}

function createContextualSpeciesFormOptionContext(
  field: EditableFieldWithOptions,
  formOptionContext: SpeciesFormOptionContext | undefined,
  currentValue: number | null,
  knownFormCount?: number
): SpeciesFormOptionContext | undefined {
  if (
    formOptionContext === undefined ||
    !isSpeciesFormField(field.field) ||
    formOptionContext.formOptions?.length
  ) {
    return formOptionContext;
  }

  return {
    ...formOptionContext,
    formOptions: createContextualSpeciesFormOptions(
      formOptionContext,
      currentValue,
      knownFormCount
    )
  };
}

function createContextualSpeciesFormOptions(
  formOptionContext: SpeciesFormOptionContext,
  currentValue: number | null,
  knownFormCount?: number
): EditableFieldOption[] {
  const formValues = new Set<number>([0]);

  addKnownSpeciesFormValues(formOptionContext, formValues);

  if (knownFormCount !== undefined && knownFormCount > 1) {
    for (let form = 1; form < knownFormCount && form <= 255; form += 1) {
      if (
        resolveSpeciesFormLabel(
          formOptionContext.species,
          form,
          formOptionContext.speciesId,
          formOptionContext.gameFamily
        ) !== undefined
      ) {
        formValues.add(form);
      }
    }
  }

  return [...formValues]
    .sort((left, right) => left - right)
    .map((form) => ({
      label: formatSpeciesFormOptionLabel(form, formOptionContext),
      value: form
    }))
    .reduce<EditableFieldOption[]>((options, option) => {
      const duplicateIndex = options.findIndex(
        (candidate) => normalizeSpeciesName(candidate.label) === normalizeSpeciesName(option.label)
      );
      if (duplicateIndex === -1) {
        options.push(option);
      } else if (option.value === currentValue) {
        options[duplicateIndex] = option;
      }

      return options;
    }, []);
}

function isSpeciesFormField(fieldName: string | undefined) {
  return fieldName === 'form' || fieldName === tradeRequiredFormFieldName;
}

function getFormFieldDisabledReason(
  field: EditableFieldWithOptions,
  formOptionContext: SpeciesFormOptionContext | undefined,
  currentValue: number | null,
  knownFormCount?: number
) {
  if (!isSpeciesFormField(field.field)) {
    return null;
  }

  if (currentValue !== null && currentValue !== 0) {
    return null;
  }

  if (knownFormCount !== undefined) {
    return knownFormCount <= 1 ? 'No alternate forms available for this Pokemon.' : null;
  }

  if (!formOptionContext) {
    return null;
  }

  return speciesHasKnownAlternateForms(formOptionContext)
    ? null
    : 'No alternate forms available for this Pokemon.';
}

function speciesHasKnownAlternateForms(context: SpeciesFormOptionContext) {
  const formLabels = getSpeciesFormLabelData(context.gameFamily);
  return (
    (context.speciesId !== undefined && formLabels.alternateSpeciesIds.has(context.speciesId)) ||
    formLabels.alternateSpeciesNames.has(normalizeSpeciesName(context.species))
  );
}

function getIntegerDraftState(
  draftValue: string,
  currentValue: number | null,
  field:
    | EncounterEditableField
    | RaidBattleEditableField
    | RaidRewardEditableField
    | ShopEditableField
    | TrainerEditableField
    | undefined
) {
  const parsedValue = parseEditableIntegerDraft(draftValue, field?.options);
  const minimumValue = field?.minimumValue ?? null;
  const maximumValue = field?.maximumValue ?? null;
  const inRange =
    parsedValue !== null &&
    (minimumValue === null || parsedValue >= minimumValue) &&
    (maximumValue === null || parsedValue <= maximumValue);

  return {
    canSubmit:
      field !== undefined &&
      currentValue !== null &&
      inRange &&
      parsedValue !== currentValue,
    parsedValue
  };
}

function isIntegerDraftInFieldRange(
  parsedValue: number | null,
  field:
    | EncounterEditableField
    | RaidBattleEditableField
    | RaidRewardEditableField
    | ShopEditableField
    | TrainerEditableField
    | undefined
) {
  if (field === undefined || parsedValue === null) {
    return false;
  }

  const minimumValue = field.minimumValue ?? null;
  const maximumValue = field.maximumValue ?? null;
  return (
    (minimumValue === null || parsedValue >= minimumValue) &&
    (maximumValue === null || parsedValue <= maximumValue)
  );
}

function formatRaidBattleRewardLink(link: RaidBattleSlotRecord['dropRewardLink']) {
  const status = link.isMatched ? 'Matched' : 'Unmatched';
  const target = link.tableId || link.sourceTableHash;
  return `${status}: ${link.preview} (${target})`;
}

function getPendingItemIds(editSession: EditSession | null, items: ItemRecord[]) {
  const pendingItemIds = new Set<number>();
  for (const edit of editSession?.pendingEdits ?? []) {
    if (edit.domain !== 'workflow.items') {
      continue;
    }

    const itemId = Number.parseInt(edit.recordId ?? '', 10);
    if (!Number.isInteger(itemId)) {
      continue;
    }

    const item = items.find((candidate) => candidate.itemId === itemId);
    const affectedItems =
      edit.field === itemMachineMoveIdFieldName && item && item.metadata.machineSlot !== null
        ? items.filter(
            (candidate) => candidate.metadata.machineSlot === item.metadata.machineSlot
          )
        : item
          ? [item]
          : [];

    if (affectedItems.length === 0) {
      pendingItemIds.add(itemId);
      continue;
    }

    for (const affectedItem of affectedItems) {
      const sharedIds =
        affectedItem.sharedItemIds.length > 0
          ? affectedItem.sharedItemIds
          : [affectedItem.itemId];
      for (const sharedId of sharedIds) {
        pendingItemIds.add(sharedId);
      }
    }
  }

  return pendingItemIds;
}

function getItemStorageDraftKey(item: ItemRecord) {
  const physicalRowItemIds = [item.itemId, ...item.sharedItemIds].filter(Number.isInteger);
  return `row:${Math.min(...physicalRowItemIds)}`;
}

function synchronizeLinkedItemPriceDrafts(
  field: string,
  value: string,
  drafts: Record<string, string>,
  defaults: Record<string, string>
) {
  if (field !== buyPriceFieldName && field !== sellPriceFieldName) {
    return drafts;
  }

  const linkedField = field === buyPriceFieldName ? sellPriceFieldName : buyPriceFieldName;
  if (value === (defaults[field] ?? '')) {
    return {
      ...drafts,
      [linkedField]: defaults[linkedField] ?? drafts[linkedField] ?? ''
    };
  }

  const parsedValue = parseUnsignedIntegerDraft(value);
  if (parsedValue === null) {
    return drafts;
  }

  return {
    ...drafts,
    [linkedField]:
      field === buyPriceFieldName
        ? (parsedValue / 2n).toString()
        : (parsedValue * 2n).toString()
  };
}

function normalizeLinkedItemPriceChanges(changes: TrainerDraftChange[]) {
  const buyPriceChange = changes.find((change) => change.field === buyPriceFieldName);
  const sellPriceChange = changes.find((change) => change.field === sellPriceFieldName);
  if (!buyPriceChange || !sellPriceChange) {
    return changes;
  }

  const buyPrice = parseUnsignedIntegerDraft(buyPriceChange.value);
  const sellPrice = parseUnsignedIntegerDraft(sellPriceChange.value);
  if (buyPrice === null || sellPrice === null || buyPrice / 2n !== sellPrice) {
    return changes;
  }

  return changes.filter((change) => change.field !== sellPriceFieldName);
}

function parseUnsignedIntegerDraft(value: string) {
  const trimmedValue = value.trim();
  if (!/^\d+$/.test(trimmedValue)) {
    return null;
  }

  try {
    return BigInt(trimmedValue);
  } catch {
    return null;
  }
}

