function groupBehaviorFields(fields: BehaviorField[]) {
  const groups: Array<{ group: string; fields: BehaviorField[] }> = [];

  for (const field of fields) {
    let group = groups.find((candidate) => candidate.group === field.group);
    if (!group) {
      group = { group: field.group, fields: [] };
      groups.push(group);
    }

    group.fields.push(field);
  }

  return groups
    .map((group, index) => ({ ...group, index }))
    .sort((left, right) => {
      const leftIsBehavior = left.group === 'Behavior';
      const rightIsBehavior = right.group === 'Behavior';

      if (leftIsBehavior !== rightIsBehavior) {
        return leftIsBehavior ? -1 : 1;
      }

      return left.index - right.index;
    })
    .map((orderedGroup) => ({
      group: orderedGroup.group,
      fields: orderedGroup.fields
    }));
}

function createBehaviorDraftDefaults(fields: BehaviorField[], entry: BehaviorEntryRecord) {
  return Object.fromEntries(
    fields.map((field) => [field.field, getBehaviorEntryFieldValue(entry, field.field)])
  );
}

function getBehaviorEntryFieldValue(entry: BehaviorEntryRecord, field: string) {
  return entry.fields.find((fieldValue) => fieldValue.field === field)?.value ?? '';
}

function getEffectiveBehaviorFieldOptions(
  field: BehaviorField,
  entry: BehaviorEntryRecord,
  drafts: Record<string, string>
) {
  if (field.field !== 'form' || !entry.formOptions || entry.formOptions.length === 0) {
    return field.options;
  }

  const currentSpeciesValue = getBehaviorEntryFieldValue(entry, 'speciesId');
  const draftSpeciesValue = drafts.speciesId ?? currentSpeciesValue;
  return draftSpeciesValue === currentSpeciesValue ? entry.formOptions : field.options;
}

function getBehaviorDraftState(
  draftValue: string,
  currentValue: string,
  field: BehaviorField,
  fieldOptions: BehaviorFieldOption[] | undefined = field.options
) {
  const normalizedValue = draftValue.trim();
  if (field.isReadOnly || !normalizedValue) {
    return {
      isChanged: false,
      normalizedValue: null
    };
  }

  if (field.valueKind === 'string') {
    const isKnownOption =
      !fieldOptions ||
      fieldOptions.length === 0 ||
      fieldOptions.some((option) => option.value === normalizedValue);
    const isInRange =
      normalizedValue.length >= field.minimumValue &&
      normalizedValue.length <= field.maximumValue;

    return {
      isChanged:
        isKnownOption && isInRange && normalizedValue !== currentValue
          ? true
          : false,
      normalizedValue:
        isKnownOption && isInRange && normalizedValue !== currentValue
          ? normalizedValue
          : null
    };
  }

  if (field.valueKind === 'integer') {
    const parsedValue = Number.parseInt(normalizedValue, 10);
    const isValid =
      Number.isInteger(parsedValue) &&
      parsedValue.toString() === normalizedValue &&
      parsedValue >= field.minimumValue &&
      parsedValue <= field.maximumValue &&
      (!fieldOptions ||
        fieldOptions.length === 0 ||
        fieldOptions.some((option) => option.value === normalizedValue));

    return {
      isChanged: isValid && normalizedValue !== currentValue,
      normalizedValue: isValid && normalizedValue !== currentValue ? normalizedValue : null
    };
  }

  if (field.valueKind === 'number') {
    const parsedValue = Number(normalizedValue);
    const isValid =
      Number.isFinite(parsedValue) &&
      parsedValue >= field.minimumValue &&
      parsedValue <= field.maximumValue;
    const nextValue = parsedValue.toString();

    return {
      isChanged: isValid && nextValue !== Number(currentValue).toString(),
      normalizedValue: isValid && nextValue !== Number(currentValue).toString() ? nextValue : null
    };
  }

  return {
    isChanged: false,
    normalizedValue: null
  };
}

function getBehaviorDraftSummary(
  fields: BehaviorField[],
  drafts: Record<string, string>,
  entry: BehaviorEntryRecord | null
): { changedFields: TrainerDraftChange[]; dirtyFieldCount: number; invalidFields: TrainerDraftChange[] } {
  const changedFields: TrainerDraftChange[] = [];
  const invalidFields: TrainerDraftChange[] = [];
  let dirtyFieldCount = 0;

  if (!entry) {
    return { changedFields, dirtyFieldCount, invalidFields };
  }

  for (const field of fields) {
    if (field.isReadOnly) {
      continue;
    }

    const currentValue = getBehaviorEntryFieldValue(entry, field.field);
    const draftValue = drafts[field.field] ?? currentValue;
    const fieldOptions = getEffectiveBehaviorFieldOptions(field, entry, drafts);
    const draftState = getBehaviorDraftState(draftValue, currentValue, field, fieldOptions);
    const isDirty = draftValue !== currentValue;
    const isChanged = isDirty && draftState.normalizedValue !== null;
    const isInvalid = isDirty && draftState.normalizedValue === null;

    if (isChanged || isInvalid) {
      dirtyFieldCount += 1;
    }

    if (isInvalid) {
      invalidFields.push({ field: field.field, label: field.label, value: draftValue });
      continue;
    }

    if (isChanged && draftState.normalizedValue !== null) {
      changedFields.push({
        field: field.field,
        label: field.label,
        value: draftState.normalizedValue
      });
    }
  }

  return { changedFields, dirtyFieldCount, invalidFields };
}

function addBehaviorDraftFallbackOption(
  options: BehaviorFieldOption[],
  draftValue: string,
  currentValue: string
) {
  if (options.some((option) => option.value === draftValue)) {
    return options;
  }

  if (draftValue.trim().length === 0) {
    return options;
  }

  return [
    {
      label: currentValue === draftValue ? draftValue : `${draftValue} (custom)`,
      value: draftValue
    },
    ...options
  ];
}

function getBehaviorFieldRangeText(field: BehaviorField) {
  if (field.valueKind === 'string') {
    return `Use 1-${field.maximumValue} characters.`;
  }

  return `Allowed range: ${field.minimumValue}-${field.maximumValue}.`;
}

function getBehaviorFieldValidationText(
  field: BehaviorField,
  options: BehaviorFieldOption[] | undefined,
  draftValue: string
) {
  if (
    options &&
    options.length > 0 &&
    !options.some((option) => option.value === draftValue.trim())
  ) {
    return 'Choose one of the available options.';
  }

  return getBehaviorFieldRangeText(field);
}

function formatBehaviorSpecies(entry: BehaviorEntryRecord) {
  return entry.form === 0 ? entry.speciesName : `${entry.speciesName}-${entry.form}`;
}

function formatBehaviorNumber(value: number) {
  return Number.isInteger(value) ? value.toString() : value.toFixed(2);
}

function getTextDraftState(
  draftValue: string,
  entry: TextEntryRecord | null,
  field: TextEditableField | undefined
) {
  const minimumLength = field?.minimumLength ?? null;
  const maximumLength = field?.maximumLength ?? null;
  const inRange =
    (minimumLength === null || draftValue.length >= minimumLength) &&
    (maximumLength === null || draftValue.length <= maximumLength);

  return {
    canSubmit:
      entry !== null &&
      entry.canEdit &&
      inRange &&
      draftValue !== entry.value
  };
}

function formatSharedItemIds(item: ItemRecord) {
  if (item.sharedItemIds.length <= 1) {
    return 'No';
  }

  return item.sharedItemIds.join(', ');
}

function getExeFsStatusClassName(status: string) {
  switch (status.toLocaleLowerCase()) {
    case 'pass':
    case 'info':
    case 'available':
    case 'installed':
    case 'ready':
    case 'empty':
      return 'status-ready';
    case 'occupied':
    case 'readonly':
    case 'read-only':
    case 'warning':
    case 'review':
      return 'status-warning';
    case 'fail':
    case 'blocked':
    case 'conflict':
    case 'foreign':
    case 'legacy':
    case 'unavailable':
      return 'status-blocked';
    default:
      return 'status-warning';
  }
}

function formatExeFsStatusLabel(status: string) {
  return formatRoyalCandyStatus(status);
}

function formatRoyalCandyStatus(status: string) {
  switch (status.toLocaleLowerCase()) {
    case 'installed':
      return 'Installed';
    case 'blocked':
      return 'Blocked';
    case 'warning':
      return 'Warning';
    case 'available':
      return 'Available';
    case 'readonly':
    case 'read-only':
      return 'Read-only';
    case 'ready':
      return 'Ready';
    case 'review':
      return 'Review';
    case 'pass':
      return 'Pass';
    case 'fail':
      return 'Fail';
    case 'info':
      return 'Info';
    default:
      return status.length > 0 ? `${status[0]!.toLocaleUpperCase()}${status.slice(1)}` : status;
  }
}

function formatStartingItemOption(option: StartingItemOptionRecord) {
  return `${option.name} (#${option.itemId})${option.isKeyItem ? ' [Key]' : ''}`;
}

function formatRoyalCandyMode(mode: string) {
  switch (mode) {
    case 'storyLimits':
      return 'Story limits';
    case 'unlimited':
      return 'Unlimited';
    case 'uninstall':
      return 'Remove';
    default:
      return mode;
  }
}

function getImportStatusClassName(status: string) {
  switch (status.toLocaleLowerCase()) {
    case 'accepted':
      return 'status-ready';
    case 'skipped':
      return 'status-warning';
    case 'rejected':
      return 'status-blocked';
    default:
      return getExeFsStatusClassName(status);
  }
}

const teraRaidRewardTableFieldNames = ['fixedRewardTable', 'lotteryRewardTable'] as const;
const teraRaidFixedRewardFieldNames = [
  'fixedCategory',
  'fixedSubject',
  'fixedItemId',
  'fixedCount'
] as const;
const teraRaidLotteryRewardFieldNames = [
  'lotteryCategory',
  'lotteryItemId',
  'lotteryCount',
  'lotteryRate',
  'lotteryRareFlag'
] as const;
const teraRaidMoveFieldNames = ['move1Id', 'move2Id', 'move3Id', 'move4Id'] as const;
const teraRaidIvFieldNames = [
  'flawlessIvCount',
  'ivHp',
  'ivAttack',
  'ivDefense',
  'ivSpeed',
  'ivSpecialAttack',
  'ivSpecialDefense'
] as const;
const teraRaidSizeFieldNames = [
  'scaleMode',
  'scaleValue',
  'heightMode',
  'heightValue',
  'weightMode',
  'weightValue'
] as const;
const teraRaidBossBehaviorFieldNames = [
  'hpMultiplier',
  'shieldTriggerHp',
  'shieldTriggerTime',
  'doubleActionHp',
  'doubleActionTime',
  'doubleActionRate'
] as const;
const teraRaidSetupFieldNames = [
  'version',
  'difficulty',
  'deliveryGroupId',
  'spawnRate',
  'captureRate',
  'captureLevel'
] as const;
const teraRaidPokemonFieldNames = [
  'species',
  'form',
  'level',
  'heldItemId',
  'ballItemId',
  'ability',
  'nature',
  'gender',
  'shinyLock',
  'teraType',
  'moveMode'
] as const;

function isTeraRaidBossField(field: TeraRaidEditableField) {
  return !isTeraRaidFixedRewardField(field) && !isTeraRaidLotteryRewardField(field);
}

function isTeraRaidFixedRewardField(field: TeraRaidEditableField) {
  return teraRaidFixedRewardFieldNames.includes(
    field.field as (typeof teraRaidFixedRewardFieldNames)[number]
  );
}

function isTeraRaidLotteryRewardField(field: TeraRaidEditableField) {
  return teraRaidLotteryRewardFieldNames.includes(
    field.field as (typeof teraRaidLotteryRewardFieldNames)[number]
  );
}

function getTeraRaidEditableFieldGroup(field: NumericEditableField) {
  if (
    teraRaidSetupFieldNames.includes(
      field.field as (typeof teraRaidSetupFieldNames)[number]
    )
  ) {
    return 'Raid Setup';
  }

  if (
    teraRaidPokemonFieldNames.includes(
      field.field as (typeof teraRaidPokemonFieldNames)[number]
    )
  ) {
    return 'Pokemon';
  }

  if (
    teraRaidMoveFieldNames.includes(field.field as (typeof teraRaidMoveFieldNames)[number])
  ) {
    return 'Moves';
  }

  if (teraRaidIvFieldNames.includes(field.field as (typeof teraRaidIvFieldNames)[number])) {
    return 'Stats - IVs';
  }

  if (
    teraRaidSizeFieldNames.includes(field.field as (typeof teraRaidSizeFieldNames)[number])
  ) {
    return 'Size';
  }

  if (
    teraRaidBossBehaviorFieldNames.includes(
      field.field as (typeof teraRaidBossBehaviorFieldNames)[number]
    )
  ) {
    return 'Boss Behavior';
  }

  if (
    teraRaidRewardTableFieldNames.includes(
      field.field as (typeof teraRaidRewardTableFieldNames)[number]
    )
  ) {
    return 'Rewards';
  }

  return 'Reward Data';
}

function findTeraRaidRewardTableByHash(
  tables: readonly TeraRaidRewardTable[],
  tableHash: string
) {
  return tables.find((table) => table.tableHash === tableHash) ?? null;
}

function createTeraRaidFormOptionContext(
  raid: TeraRaidRecord,
  fields: readonly NumericEditableField[],
  drafts: Record<string, string> | undefined
): SpeciesFormOptionContext {
  const speciesField = fields.find((field) => field.field === giftSpeciesFieldName);
  const draftedSpeciesId = parseOptionalInteger(drafts?.[giftSpeciesFieldName]);
  const speciesId = draftedSpeciesId ?? raid.speciesId;
  const speciesOption = speciesField?.options.find((option) => option.value === speciesId);
  const species = speciesOption?.label.replace(/^\d+\s+/, '') ?? raid.species;

  return {
    abilityOptions: raid.abilityOptions,
    gameFamily: 'sv',
    species,
    speciesId
  };
}

function getEditableTeraRaidFieldValue(
  raid: TeraRaidRecord,
  field: string,
  fixedRewardTables: readonly TeraRaidRewardTable[],
  lotteryRewardTables: readonly TeraRaidRewardTable[]
) {
  switch (field) {
    case 'version':
      return raid.version;
    case 'difficulty':
      return raid.difficulty;
    case 'deliveryGroupId':
      return raid.deliveryGroupId;
    case 'spawnRate':
      return raid.spawnRate;
    case 'captureRate':
      return raid.captureRate;
    case 'captureLevel':
      return raid.captureLevel;
    case 'species':
      return raid.speciesId;
    case 'form':
      return raid.form;
    case 'level':
      return raid.level;
    case 'heldItemId':
      return raid.heldItemId;
    case 'ballItemId':
      return raid.ballItemId;
    case 'ability':
      return raid.ability;
    case 'nature':
      return raid.nature;
    case 'gender':
      return raid.gender;
    case 'shinyLock':
      return raid.shinyLock;
    case 'teraType':
      return raid.teraType;
    case 'moveMode':
      return raid.moveMode;
    case 'move1Id':
      return raid.moves[0]?.moveId ?? 0;
    case 'move2Id':
      return raid.moves[1]?.moveId ?? 0;
    case 'move3Id':
      return raid.moves[2]?.moveId ?? 0;
    case 'move4Id':
      return raid.moves[3]?.moveId ?? 0;
    case 'flawlessIvCount':
      return raid.flawlessIvCount;
    case 'ivHp':
      return raid.ivs.hp;
    case 'ivAttack':
      return raid.ivs.attack;
    case 'ivDefense':
      return raid.ivs.defense;
    case 'ivSpeed':
      return raid.ivs.speed;
    case 'ivSpecialAttack':
      return raid.ivs.specialAttack;
    case 'ivSpecialDefense':
      return raid.ivs.specialDefense;
    case 'scaleMode':
      return raid.scaleMode;
    case 'scaleValue':
      return raid.scaleValue;
    case 'heightMode':
      return raid.heightMode;
    case 'heightValue':
      return raid.heightValue;
    case 'weightMode':
      return raid.weightMode;
    case 'weightValue':
      return raid.weightValue;
    case 'hpMultiplier':
      return raid.hpMultiplier;
    case 'shieldTriggerHp':
      return raid.shieldTriggerHp;
    case 'shieldTriggerTime':
      return raid.shieldTriggerTime;
    case 'doubleActionHp':
      return raid.doubleActionHp;
    case 'doubleActionTime':
      return raid.doubleActionTime;
    case 'doubleActionRate':
      return raid.doubleActionRate;
    case 'fixedRewardTable':
      return findTeraRaidRewardTableByHash(fixedRewardTables, raid.fixedRewardTableHash)
        ?.tableIndex ?? null;
    case 'lotteryRewardTable':
      return findTeraRaidRewardTableByHash(lotteryRewardTables, raid.lotteryRewardTableHash)
        ?.tableIndex ?? null;
    default:
      return null;
  }
}

function getEditableTeraRaidRewardFieldValue(reward: TeraRaidRewardItem, field: string) {
  switch (field) {
    case 'fixedCategory':
    case 'lotteryCategory':
      return reward.category;
    case 'fixedSubject':
      return reward.subjectType ?? 0;
    case 'fixedItemId':
    case 'lotteryItemId':
      return reward.itemId;
    case 'fixedCount':
    case 'lotteryCount':
      return reward.count;
    case 'lotteryRate':
      return reward.rate ?? 0;
    case 'lotteryRareFlag':
      return reward.rareItemFlag ? 1 : 0;
    default:
      return null;
  }
}

function isEmptyTeraRaidReward(reward: TeraRaidRewardItem) {
  if (reward.category !== 0 || reward.itemId !== 0 || reward.count !== 0) {
    return false;
  }

  if (reward.rewardKind === 'fixed') {
    return reward.subjectType === 0;
  }

  return reward.rewardKind === 'lottery' && reward.rate === 0 && reward.rareItemFlag === false;
}

function getEditableRaidRewardFieldValue(reward: RaidRewardItemRecord, field: string) {
  if (field === raidRewardItemIdFieldName) {
    return reward.itemId;
  }

  const valueIndex = raidRewardValueFieldNames.findIndex((fieldName) => fieldName === field);
  return valueIndex >= 0 ? (reward.values[valueIndex] ?? 0) : null;
}

function hasRaidBattleDraftFieldChanged(
  battleSlot: RaidBattleSlotRecord | null,
  drafts: Record<string, string> | undefined,
  field: string
) {
  if (!battleSlot || !drafts || drafts[field] === undefined) {
    return false;
  }

  return drafts[field] !== (getEditableRaidBattleFieldValue(battleSlot, field) ?? '').toString();
}

function createRaidBattleDraftFields(
  editableFields: RaidBattleEditableField[],
  battleSlot: RaidBattleSlotRecord,
  drafts?: Record<string, string>
) {
  const speciesChanged = hasRaidBattleDraftFieldChanged(
    battleSlot,
    drafts,
    raidBattleSpeciesFieldName
  );
  const formChanged = hasRaidBattleDraftFieldChanged(
    battleSlot,
    drafts,
    raidBattleFormFieldName
  );
  const context: SpeciesFormOptionContext = {
    abilityOptions: battleSlot.abilityOptions,
    formOptions: battleSlot.formOptions,
    gameFamily: 'swsh',
    species: battleSlot.species,
    speciesId: battleSlot.speciesId
  };

  return editableFields.map((field) => {
    const shouldUseSourceOptions =
      !(field.field === raidBattleFormFieldName && speciesChanged) &&
      !(
        field.field === raidBattleAbilityFieldName &&
        (speciesChanged || formChanged)
      );
    return toNumericEditableControlField(
      field,
      shouldUseSourceOptions ? getContextualFieldOptions(field, context) : field.options
    );
  });
}

function getEditableRaidBattleFieldValue(battleSlot: RaidBattleSlotRecord, field: string) {
  switch (field) {
    case raidBattleSpeciesFieldName:
      return battleSlot.speciesId;
    case raidBattleFormFieldName:
      return battleSlot.form;
    case raidBattleAbilityFieldName:
      return battleSlot.ability;
    case raidBattleIsGigantamaxFieldName:
      return battleSlot.isGigantamax ? 1 : 0;
    case raidBattleGenderFieldName:
      return battleSlot.gender;
    case raidBattleFlawlessIvsFieldName:
      return battleSlot.flawlessIvs;
    default: {
      const probabilityIndex = raidBattleProbabilityFieldNames.findIndex(
        (fieldName) => fieldName === field
      );
      return probabilityIndex >= 0 ? (battleSlot.probabilities[probabilityIndex] ?? 0) : null;
    }
  }
}

function getPlacementDraftState(
  draftValue: string,
  currentValue: string | null,
  field: PlacementFieldControl
) {
  const normalizedValue = draftValue.trim();
  if (
    !normalizedValue &&
    field.valueKind !== 'text' &&
    field.valueKind !== 'string' &&
    field.valueKind !== 'hash'
  ) {
    return {
      canSubmit: false,
      isValid: false,
      normalizedValue: null
    };
  }

  if (field.isReadOnly) {
    return {
      canSubmit: false,
      isValid: true,
      normalizedValue: normalizedValue
    };
  }

  if (field.valueKind === 'text' || field.valueKind === 'string') {
    const byteLength = new TextEncoder().encode(normalizedValue).length;
    const isValid = field.maximumValue <= 0 || byteLength <= field.maximumValue;

    return {
      canSubmit: isValid && normalizedValue !== (currentValue ?? ''),
      isValid,
      normalizedValue: isValid ? normalizedValue : null
    };
  }

  if (field.valueKind === 'boolean') {
    const parsedValue = parsePlacementBooleanDraft(normalizedValue);
    const currentBoolean = parsePlacementBooleanDraft(currentValue ?? '');
    const isChanged =
      parsedValue !== null &&
      (currentBoolean === null || parsedValue !== currentBoolean);

    return {
      canSubmit: isChanged,
      isValid: parsedValue !== null,
      normalizedValue: parsedValue === null ? null : parsedValue ? 'true' : 'false'
    };
  }

  if (field.valueKind === 'hash') {
    const isValid = isPlacementHashDraft(normalizedValue);
    return {
      canSubmit: isValid && normalizedValue !== (currentValue ?? ''),
      isValid,
      normalizedValue: isValid ? normalizedValue : null
    };
  }

  const parsedValue =
    field.valueKind === 'integer'
      ? parseEditableIntegerDraft(normalizedValue, field.options) ?? Number.NaN
      : Number(normalizedValue);
  const isValidNumber = Number.isFinite(parsedValue);
  const inRange =
    isValidNumber &&
    parsedValue >= field.minimumValue &&
    parsedValue <= field.maximumValue &&
    (field.valueKind !== 'integer' || Number.isInteger(parsedValue));
  const nextValue =
    field.valueKind === 'integer'
      ? parsedValue.toString()
      : parsedValue.toString();
  const canSubmit =
    inRange &&
    (currentValue === null || Math.abs(parsedValue - Number(currentValue)) > Number.EPSILON);

  return {
    canSubmit,
    isValid: inRange,
    normalizedValue: inRange ? nextValue : null
  };
}

function parsePlacementBooleanDraft(value: string) {
  const normalizedValue = value.trim().toLocaleLowerCase();
  if (['true', '1', 'yes'].includes(normalizedValue)) return true;
  if (['false', '0', 'no'].includes(normalizedValue)) return false;
  return null;
}

function isPlacementHashDraft(value: string) {
  const normalizedValue = value.trim();
  if (normalizedValue.length === 0) return true;
  if (['none', 'empty'].includes(normalizedValue.toLocaleLowerCase())) return true;
  if (/^0x[0-9a-f]+$/i.test(normalizedValue)) return normalizedValue.length <= 18;
  return /^\d+$/.test(normalizedValue);
}

function getPlacementFieldErrorText(field: PlacementFieldControl) {
  if (field.valueKind === 'boolean') return 'Use true/false or 1/0.';
  if (field.valueKind === 'hash') return 'Use None, decimal, or a 0x-prefixed 64-bit hash.';
  if (field.valueKind === 'text' || field.valueKind === 'string') {
    return field.maximumValue > 0
      ? `Maximum length: ${field.maximumValue} UTF-8 bytes.`
      : 'Text does not fit this placement field.';
  }

  return `Allowed range: ${field.minimumValue}-${field.maximumValue}.`;
}

function getPlacementDraftSummary(
  fields: PlacementFieldControl[],
  drafts: Record<string, string>,
  getValue: ((field: string) => string | null) | null
): { changedFields: TrainerDraftChange[]; dirtyFieldCount: number; invalidFields: TrainerDraftChange[] } {
  const changedFields: TrainerDraftChange[] = [];
  const invalidFields: TrainerDraftChange[] = [];
  let dirtyFieldCount = 0;

  if (!getValue) {
    return { changedFields, dirtyFieldCount, invalidFields };
  }

  for (const field of fields) {
    if (field.isReadOnly) {
      continue;
    }

    const currentValue = getValue(field.field);
    const draftValue = drafts[field.field] ?? '';
    const draftState = getPlacementDraftState(draftValue, currentValue, field);
    const isChanged = draftState.canSubmit;
    const isInvalid = draftValue.trim() !== '' && draftState.isValid === false;

    if (isChanged || isInvalid) {
      dirtyFieldCount += 1;
    }

    if (isInvalid) {
      invalidFields.push({ field: field.field, label: field.label, value: draftValue });
      continue;
    }

    const normalizedValue = draftState.normalizedValue;

    if (isChanged && normalizedValue !== null) {
      changedFields.push({
        field: field.field,
        label: field.label,
        value: normalizedValue
      });
    }
  }

  return { changedFields, dirtyFieldCount, invalidFields };
}

function formatPokemonTypes(pokemon: PokemonRecord) {
  return pokemon.type1 === pokemon.type2
    ? pokemon.type1
    : `${pokemon.type1} / ${pokemon.type2}`;
}

function formatPokemonDexPresence(pokemon: PokemonRecord) {
  if (!pokemon.dexPresence.isPresentInGame) {
    return 'Not present';
  }

  if (!pokemon.dexPresence.isInAnyDex) {
    return 'Present, no dex index';
  }

  return [
    pokemon.dexPresence.regionalDexIndex > 0
      ? `Regional ${pokemon.dexPresence.regionalDexIndex}`
      : null,
    pokemon.dexPresence.armorDexIndex > 0 ? `Armor ${pokemon.dexPresence.armorDexIndex}` : null,
    pokemon.dexPresence.crownDexIndex > 0 ? `Crown ${pokemon.dexPresence.crownDexIndex}` : null
  ]
    .filter((value): value is string => value !== null)
    .join(', ');
}

function formatGiftPokemonIvs(gift: GiftPokemonRecord) {
  return [
    `HP ${formatGiftPokemonIvValue(gift.ivs.hp)}`,
    `Atk ${formatGiftPokemonIvValue(gift.ivs.attack)}`,
    `Def ${formatGiftPokemonIvValue(gift.ivs.defense)}`,
    `SpA ${formatGiftPokemonIvValue(gift.ivs.specialAttack)}`,
    `SpD ${formatGiftPokemonIvValue(gift.ivs.specialDefense)}`,
    `Spe ${formatGiftPokemonIvValue(gift.ivs.speed)}`
  ].join(' / ');
}

function formatGiftPokemonMoves(gift: GiftPokemonRecord) {
  const moves = [...gift.moves]
    .sort((left, right) => left.slot - right.slot)
    .filter((move) => move.moveId > 0)
    .map((move) => move.move ?? `Move ${move.moveId}`);

  if (moves.length > 0) {
    return moves.join(' / ');
  }

  return gift.moves.some((move) => move.moveId < 0) ? 'Game default / none' : 'None';
}

function formatGiftPokemonLevel(gift: GiftPokemonRecord, editorFamily: EditorUiFamily) {
  return editorFamily === 'za' && gift.level === 0 ? 'Game default' : gift.level.toString();
}

function formatGiftPokemonLevelSummary(gift: GiftPokemonRecord, editorFamily: EditorUiFamily) {
  return editorFamily === 'za' && gift.level === 0 ? 'Game default level' : `Lv. ${gift.level}`;
}

function formatGiftPokemonScale(gift: GiftPokemonRecord) {
  if (gift.scaleModeLabel === null) {
    return 'Default';
  }

  if (gift.scaleValue === null || gift.scaleValue === 0 || gift.scaleModeLabel !== 'Fixed value') {
    return gift.scaleModeLabel;
  }

  return `${gift.scaleModeLabel}: ${gift.scaleValue}`;
}

function formatGiftPokemonIvValue(value: number) {
  switch (value) {
    case -4:
      return '3 perfect';
    case -1:
      return 'Random';
    default:
      return value.toString();
  }
}

function formatTradePokemonIvs(trade: TradePokemonRecord) {
  return [
    `HP ${formatGiftPokemonIvValue(trade.ivs.hp)}`,
    `Atk ${formatGiftPokemonIvValue(trade.ivs.attack)}`,
    `Def ${formatGiftPokemonIvValue(trade.ivs.defense)}`,
    `SpA ${formatGiftPokemonIvValue(trade.ivs.specialAttack)}`,
    `SpD ${formatGiftPokemonIvValue(trade.ivs.specialDefense)}`,
    `Spe ${formatGiftPokemonIvValue(trade.ivs.speed)}`
  ].join(' / ');
}

function formatTradePokemonRelearnMoves(trade: TradePokemonRecord) {
  const sourceMoves = trade.moves.length > 0 ? trade.moves : trade.relearnMoves;
  const moves = [...sourceMoves]
    .sort((left, right) => left.slot - right.slot)
    .filter((move) => move.moveId > 0)
    .map((move) => move.move ?? `Move ${move.moveId}`);

  return moves.length > 0 ? moves.join(' / ') : 'None';
}

function formatTradePokemonScale(trade: TradePokemonRecord) {
  if (trade.scaleModeLabel === null) {
    return 'Default';
  }

  if (trade.scaleValue === null || trade.scaleValue === 0 || trade.scaleModeLabel !== 'Fixed value') {
    return trade.scaleModeLabel;
  }

  return `${trade.scaleModeLabel}: ${trade.scaleValue}`;
}

function formatTradePokemonMemory(trade: TradePokemonRecord) {
  return [
    `Trainer ${trade.trainerId}`,
    `OT ${trade.otGenderLabel}`,
    `Memory ${trade.memoryCode}`,
    `Text ${trade.memoryTextVariable}`,
    `Feeling ${trade.memoryFeel}`,
    `Intensity ${trade.memoryIntensity}`
  ].join(' / ');
}

