export function formatSpeciesFormLabel(
  species: string,
  form: number,
  speciesId?: number,
  gameFamily?: EditorUiFamily
) {
  if (form < 0) {
    return species;
  }

  const formLabel = resolveSpeciesFormLabel(species, form, speciesId, gameFamily);
  if (form > 0 && formLabel === undefined && speciesHasNonGenericFormSuffix(species)) {
    return species;
  }

  const displaySpecies =
    formLabel === undefined ? species : stripTrailingGenericFormLabel(species, form);
  if (form === 0) {
    return formLabel === undefined || speciesAlreadyIncludesFormLabel(displaySpecies, formLabel)
      ? displaySpecies
      : `${displaySpecies} (${formLabel})`;
  }

  const displayLabel =
    formLabel ??
    `Form ${form}`;

  return speciesAlreadyIncludesFormLabel(displaySpecies, displayLabel)
    ? displaySpecies
    : `${displaySpecies} (${displayLabel})`;
}

function stripTrailingGenericFormLabel(species: string, form: number) {
  if (form < 0) {
    return species;
  }

  return species.replace(new RegExp(`\\s*\\(Form\\s+${form}\\)\\s*$`, 'i'), '').trim();
}

function formatSpeciesFormOptionLabel(form: number, context: SpeciesFormOptionContext) {
  return (
    resolveSpeciesFormLabel(context.species, form, context.speciesId, context.gameFamily) ??
    (form === 0 ? resolveBaseSpeciesFormLabel(context) ?? 'Base' : `Form ${form}`)
  );
}

function resolveBaseSpeciesFormLabel(context: SpeciesFormOptionContext) {
  const formLabels = getSpeciesFormLabelData(context.gameFamily);
  return (
    (context.speciesId !== undefined
      ? formLabels.baseLabelsBySpeciesId.get(context.speciesId)
      : undefined) ??
    formLabels.baseLabelsBySpeciesName.get(normalizeSpeciesName(context.species))
  );
}

function resolveSpeciesFormLabel(
  species: string,
  form: number,
  speciesId?: number,
  gameFamily?: EditorUiFamily
) {
  const formLabels = getSpeciesFormLabelData(gameFamily);
  return (
    (speciesId !== undefined
      ? formLabels.labelsBySpeciesId.get(`${speciesId}:${form}`)
      : undefined) ??
    formLabels.labelsBySpeciesName.get(`${normalizeSpeciesName(species)}:${form}`)
  );
}

function speciesAlreadyIncludesFormLabel(species: string, formLabel: string) {
  const match = species.trim().match(/\(([^()]*)\)\s*$/);
  return match ? normalizeSpeciesName(match[1] ?? '') === normalizeSpeciesName(formLabel) : false;
}

function speciesHasNonGenericFormSuffix(species: string) {
  const match = species.trim().match(/\(([^()]*)\)\s*$/);
  return match ? !/^form\s+\d+$/i.test(match[1] ?? '') : false;
}

function normalizeSpeciesName(species: string) {
  return species
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-zA-Z0-9]/g, '')
    .toLocaleLowerCase();
}

function formatStaticEncounterIvs(encounter: StaticEncounterRecord) {
  return [
    `HP ${formatGiftPokemonIvValue(encounter.ivs.hp)}`,
    `Atk ${formatGiftPokemonIvValue(encounter.ivs.attack)}`,
    `Def ${formatGiftPokemonIvValue(encounter.ivs.defense)}`,
    `SpA ${formatGiftPokemonIvValue(encounter.ivs.specialAttack)}`,
    `SpD ${formatGiftPokemonIvValue(encounter.ivs.specialDefense)}`,
    `Spe ${formatGiftPokemonIvValue(encounter.ivs.speed)}`
  ].join(' / ');
}

function formatStaticEncounterStats(stats: StaticEncounterRecord['evs']) {
  return [
    `HP ${stats.hp}`,
    `Atk ${stats.attack}`,
    `Def ${stats.defense}`,
    `SpA ${stats.specialAttack}`,
    `SpD ${stats.specialDefense}`,
    `Spe ${stats.speed}`
  ].join(' / ');
}

function formatStaticEncounterMoves(encounter: StaticEncounterRecord) {
  const moves = encounter.moves
    .filter((move) => move.moveId > 0)
    .map((move) => move.move ?? `Move ${move.moveId}`);

  return moves.length > 0 ? moves.join(' / ') : 'None';
}

function getStaticEncounterDisplayValue(encounter: StaticEncounterRecord, field: string) {
  return encounter.fieldDisplayValues[field] ?? encounter.fieldValues[field] ?? 'None';
}

function formatStaticEncounterScale(encounter: StaticEncounterRecord) {
  const mode = getStaticEncounterDisplayValue(encounter, giftScaleModeFieldName);
  const value = encounter.fieldValues[giftScaleValueFieldName];

  if (!value || value === '0') {
    return mode;
  }

  return `${mode}: ${value}`;
}

function formatRentalPokemonIvs(rental: RentalPokemonRecord) {
  return [
    `HP ${rental.ivs.hp}`,
    `Atk ${rental.ivs.attack}`,
    `Def ${rental.ivs.defense}`,
    `SpA ${rental.ivs.specialAttack}`,
    `SpD ${rental.ivs.specialDefense}`,
    `Spe ${rental.ivs.speed}`
  ].join(' / ');
}

function formatRentalPokemonStats(stats: RentalPokemonRecord['evs']) {
  return [
    `HP ${stats.hp}`,
    `Atk ${stats.attack}`,
    `Def ${stats.defense}`,
    `SpA ${stats.specialAttack}`,
    `SpD ${stats.specialDefense}`,
    `Spe ${stats.speed}`
  ].join(' / ');
}

function formatRentalPokemonMoves(rental: RentalPokemonRecord) {
  const moves = [...rental.moves]
    .sort((left, right) => left.slot - right.slot)
    .filter((move) => move.moveId > 0)
    .map((move) => move.move ?? `Move ${move.moveId}`);

  return moves.length > 0 ? moves.join(' / ') : 'None';
}

function formatDynamaxAdventureIvs(encounter: DynamaxAdventureRecord) {
  const hpValue =
    encounter.guaranteedPerfectIvs > 0
      ? `${encounter.guaranteedPerfectIvs} guaranteed perfect`
      : formatDynamaxAdventureIvValue(encounter.ivs.hp);

  return [
    `HP ${hpValue}`,
    `Atk ${formatDynamaxAdventureIvValue(encounter.ivs.attack)}`,
    `Def ${formatDynamaxAdventureIvValue(encounter.ivs.defense)}`,
    `SpA ${formatDynamaxAdventureIvValue(encounter.ivs.specialAttack)}`,
    `SpD ${formatDynamaxAdventureIvValue(encounter.ivs.specialDefense)}`,
    `Spe ${formatDynamaxAdventureIvValue(encounter.ivs.speed)}`
  ].join(' / ');
}

function formatDynamaxAdventureIvValue(value: number) {
  return value === -1 ? 'Random' : value.toString();
}

function formatDynamaxAdventureMoves(encounter: DynamaxAdventureRecord) {
  const moves = [...encounter.moves]
    .sort((left, right) => left.slot - right.slot)
    .filter((move) => move.moveId > 0)
    .map((move) => move.move ?? `Move ${move.moveId}`);

  return moves.length > 0 ? moves.join(' / ') : 'None';
}

function getFixedRentalPokemonIvPreset(rental: RentalPokemonRecord) {
  const values = [
    rental.ivs.hp,
    rental.ivs.attack,
    rental.ivs.defense,
    rental.ivs.specialAttack,
    rental.ivs.specialDefense,
    rental.ivs.speed
  ];
  const firstValue = values[0] ?? null;

  return firstValue !== null && values.every((value) => value === firstValue)
    ? firstValue
    : null;
}

function formatMovePower(power: number) {
  return power === 0 ? '-' : power.toString();
}

function formatMoveInflictDuration(rawInflictCount: number) {
  const labels: Record<number, string> = {
    0: 'None',
    1: 'Permanent',
    2: 'Turn Count + Switch',
    3: 'Permanent + Switch',
    4: 'Turn Count + No Switch'
  };

  return labels[rawInflictCount] ?? `Raw ${rawInflictCount}`;
}

function formatMoveActiveFlags(move: MoveRecord) {
  const activeFlags = move.flags.filter((flag) => flag.enabled);

  if (activeFlags.length === 0) {
    return '-';
  }

  return activeFlags
    .slice(0, 3)
    .map((flag) => flag.label)
    .join(', ');
}

function formatProjectFileLayer(layer: ChangePlan['writes'][number]['sources'][number]['layer']) {
  return {
    base: 'Base',
    generated: 'Generated',
    layered: 'LayeredFS',
    pending: 'Pending'
  }[layer];
}

function getPathStatusClassName(pathValidation: ProjectPathValidation | undefined) {
  if (!pathValidation) {
    return 'path-status path-status-muted';
  }

  return `path-status path-status-${pathValidation.status}`;
}

async function fetchAvailableUpdate(currentVersion: string): Promise<ReleasePageUpdate | null> {
  const response = await fetch(githubReleasesApiUrl, {
    headers: {
      Accept: 'application/vnd.github+json'
    }
  });

  if (!response.ok) {
    throw new Error(`GitHub update check failed (${response.status}).`);
  }

  const payload: unknown = await response.json();
  if (!Array.isArray(payload)) {
    throw new Error('GitHub update response was not a release list.');
  }

  return resolveAvailableUpdate(payload as GithubRelease[], currentVersion);
}

function resolveAvailableUpdate(
  releases: GithubRelease[],
  currentVersionText: string
): ReleasePageUpdate | null {
  const currentVersion = parseVersionTag(currentVersionText);
  if (!currentVersion) {
    return null;
  }

  const updateCandidates = releases
    .map((release) => {
      const version = parseVersionTag(release.tag_name ?? '');
      return version ? { release, version } : null;
    })
    .filter((candidate): candidate is { release: GithubRelease; version: ParsedVersion } => {
      if (!candidate) {
        return false;
      }

      return (
        candidate.release.draft !== true &&
        candidate.release.prerelease !== true &&
        compareVersions(candidate.version, currentVersion) > 0
      );
    })
    .sort((left, right) => compareVersions(right.version, left.version));

  const update = updateCandidates[0];
  if (!update) {
    return null;
  }

  const releaseUrl = update.release.html_url ?? githubLatestReleaseUrl;

  return {
    kind: 'releasePage',
    releaseName: update.release.name?.trim() || update.release.tag_name || 'GitHub release',
    releaseUrl,
    version: formatParsedVersion(update.version)
  };
}

function parseVersionTag(versionText: string): ParsedVersion | null {
  const match = versionText.trim().match(/^v?(\d+)\.(\d+)\.(\d+)(?:-([0-9A-Za-z.-]+))?$/);
  if (!match) {
    return null;
  }

  return {
    major: Number.parseInt(match[1], 10),
    minor: Number.parseInt(match[2], 10),
    patch: Number.parseInt(match[3], 10),
    prerelease: match[4] ?? null
  };
}

function compareVersions(left: ParsedVersion, right: ParsedVersion) {
  const majorDelta = left.major - right.major;
  if (majorDelta !== 0) {
    return majorDelta;
  }

  const minorDelta = left.minor - right.minor;
  if (minorDelta !== 0) {
    return minorDelta;
  }

  const patchDelta = left.patch - right.patch;
  if (patchDelta !== 0) {
    return patchDelta;
  }

  if (left.prerelease === right.prerelease) {
    return 0;
  }

  if (left.prerelease === null) {
    return 1;
  }

  if (right.prerelease === null) {
    return -1;
  }

  return left.prerelease.localeCompare(right.prerelease, undefined, {
    numeric: true,
    sensitivity: 'base'
  });
}

function formatParsedVersion(version: ParsedVersion) {
  return `${version.major}.${version.minor}.${version.patch}${
    version.prerelease ? `-${version.prerelease}` : ''
  }`;
}

function getProjectStateLabel(
  health: ProjectHealth | null,
  projectStatus: 'idle' | 'validating' | 'opening' | 'open',
  activeSection: WorkbenchSection
) {
  if (projectStatus === 'opening') {
    return 'Opening project';
  }

  if (projectStatus === 'validating') {
    return 'Validating paths';
  }

  if (health && readOnlyViewerSectionIds.has(activeSection)) {
    return 'View Only';
  }

  return health ? healthLabels[health.state] : 'No project open';
}

function getRoyalCandyDependencyWarning(
  workflow: RoyalCandyWorkflow | null,
  workflowId: string
): DependencyWarningState | null {
  if (
    !workflow ||
    workflow.summary.availability !== 'available' ||
    workflowId === 'royal-candy-uninstall'
  ) {
    return null;
  }

  const selectedWorkflow = workflow.workflows.find(
    (candidate) => candidate.workflowId === workflowId
  );
  const bagHookCheck = workflow.checks.find(
    (check) =>
      check.workflowId === 'royal-candy-preflight' &&
      check.checkId.endsWith(':bag-hook-installed')
  );
  if (selectedWorkflow?.status !== 'blocked' && bagHookCheck?.status !== 'Fail') {
    return null;
  }

  if (bagHookCheck?.status !== 'Fail') {
    return null;
  }

  return {
    title: 'Bag Hook Required',
    message: 'Royal Candy cannot be staged until Bag Hook V2 is installed.',
    fix:
      'Open Hooks > Bag Hook, stage and save the Bag Hook install, then return to Royal Candy.'
  };
}

function getStartingItemsDependencyWarning(
  workflow: StartingItemsWorkflow | null
): DependencyWarningState | null {
  if (
    !workflow ||
    workflow.summary.availability !== 'available' ||
    workflow.blockerKind !== 'bagHookMissing'
  ) {
    return null;
  }

  return {
    title: 'Bag Hook Required',
    message: 'Starting Items cannot be staged until Bag Hook V2 is installed.',
    fix:
      'Open Hooks > Bag Hook, stage and save the Bag Hook install, then return to Starting Items.'
  };
}

function parseCanonicalPositiveInteger(value: string) {
  const normalizedValue = value.trim();
  if (!/^[1-9]\d*$/.test(normalizedValue)) {
    return null;
  }

  const parsedValue = Number(normalizedValue);
  return Number.isSafeInteger(parsedValue) && parsedValue.toString() === normalizedValue
    ? parsedValue
    : null;
}

function toProjectPaths(draftPaths: ProjectPathDraft, gameTextLanguage: LanguageCode) {
  return {
    baseExeFsPath: normalizeDraftPath(draftPaths.baseExeFsPath),
    baseRomFsPath: normalizeDraftPath(draftPaths.baseRomFsPath),
    gameTextLanguage,
    outputRootPath: normalizeDraftPath(draftPaths.outputRootPath),
    pokemonLegendsZASupportFolderPath: isPokemonLegendsZAGame(draftPaths.selectedGame)
      ? normalizeDraftPath(draftPaths.pokemonLegendsZASupportFolderPath)
      : null,
    saveFilePath: normalizeDraftPath(draftPaths.saveFilePath),
    scarletVioletSupportFolderPath: isScarletVioletGame(draftPaths.selectedGame)
      ? normalizeDraftPath(draftPaths.scarletVioletSupportFolderPath)
      : null,
    selectedGame: draftPaths.selectedGame
  };
}

function resolveOutputRootCreationPath(
  draftPaths: ProjectPathDraft,
  selectedGame: ProjectGame
) {
  const baseRomFsPath = trimTrailingPathSeparators(draftPaths.baseRomFsPath);
  const baseExeFsPath = trimTrailingPathSeparators(draftPaths.baseExeFsPath);

  if (!baseRomFsPath || !baseExeFsPath) {
    return null;
  }

  const romFsParentPath = getParentDirectoryPath(baseRomFsPath);
  const exeFsParentPath = getParentDirectoryPath(baseExeFsPath);

  if (
    !romFsParentPath ||
    !exeFsParentPath ||
    !pathsEqual(romFsParentPath, exeFsParentPath)
  ) {
    return null;
  }

  return joinDirectoryPath(romFsParentPath, gameDefinitions[selectedGame].titleId);
}

function formatByteCount(value: number) {
  return `${value.toLocaleString()} bytes`;
}

function formatByteSize(value: number) {
  const absoluteValue = Math.max(0, value);
  if (absoluteValue < 1024) {
    return `${absoluteValue.toLocaleString()} B`;
  }

  const units = ['KB', 'MB', 'GB', 'TB'] as const;
  let size = absoluteValue / 1024;
  let unitIndex = 0;
  while (size >= 1024 && unitIndex < units.length - 1) {
    size /= 1024;
    unitIndex += 1;
  }

  const maximumFractionDigits = size >= 10 || unitIndex === 0 ? 0 : 1;
  return `${size.toLocaleString(undefined, { maximumFractionDigits })} ${units[unitIndex]}`;
}

function formatSvCacheModeLabel(mode: TrinityCacheMode) {
  return svCacheModeOptions.find((option) => option.id === mode)?.label ?? mode;
}

function hasValidScarletVioletSupportFolder(health: ProjectHealth) {
  return health.paths.some(
    (path) => path.role === 'scarletVioletSupportFolder' && path.status === 'valid'
  );
}

function hasValidPokemonLegendsZASupportFolder(health: ProjectHealth) {
  return health.paths.some(
    (path) => path.role === 'pokemonLegendsZASupportFolder' && path.status === 'valid'
  );
}

function hasValidTrinitySupportFolder(
  game: ProjectGame | null | undefined,
  health: ProjectHealth
) {
  return isPokemonLegendsZAGame(game)
    ? hasValidPokemonLegendsZASupportFolder(health)
    : hasValidScarletVioletSupportFolder(health);
}

function getTrinityCacheTitle(game: ProjectGame | null | undefined) {
  return isPokemonLegendsZAGame(game)
    ? 'Z-A Data Cache'
    : 'S/V Data Cache';
}

function normalizeDraftPath(path: string) {
  const trimmedPath = path.trim();

  return trimmedPath.length > 0 ? trimmedPath : null;
}

function trimTrailingPathSeparators(path: string) {
  return path.trim().replace(/[\\/]+$/, '');
}

function getParentDirectoryPath(path: string) {
  const separatorIndex = Math.max(path.lastIndexOf('\\'), path.lastIndexOf('/'));

  if (separatorIndex <= 0) {
    return null;
  }

  return path.slice(0, separatorIndex);
}

function joinDirectoryPath(parentPath: string, childName: string) {
  const separator = parentPath.includes('\\') ? '\\' : '/';
  return `${trimTrailingPathSeparators(parentPath)}${separator}${childName}`;
}

function pathsEqual(left: string, right: string) {
  return normalizePathForComparison(left) === normalizePathForComparison(right);
}

function normalizePathForComparison(path: string) {
  return trimTrailingPathSeparators(path).replaceAll('\\', '/').toLowerCase();
}

function getEditSessionSignature(editSession: EditSession | null) {
  if (!editSession) {
    return null;
  }

  return JSON.stringify({
    edits: editSession.pendingEdits.map((edit) => ({
      domain: edit.domain,
      field: edit.field,
      newValue: edit.newValue,
      recordId: edit.recordId,
      summary: edit.summary,
      sources: edit.sources.map((source) => ({
        layer: source.layer,
        relativePath: source.relativePath
      }))
    })),
    sessionId: editSession.sessionId
  });
}

function delay(milliseconds: number) {
  return new Promise<void>((resolve) => {
    window.setTimeout(resolve, milliseconds);
  });
}

function toBridgeDiagnostics(error: unknown): ApiDiagnostic[] {
  if (isStaleProjectScopeError(error)) {
    return [];
  }

  if (error instanceof ProjectBridgeError) {
    if (error.apiError.diagnostics.length > 0) {
      return error.apiError.diagnostics;
    }

    return [
      {
        domain: 'bridge',
        message: formatReportableErrorMessage(
          createReportableError(error, {
            fallbackMessage: error.apiError.message,
            kind: 'bridge',
            seed: error.apiError.code,
            title: 'KM Editor hit an unexpected bridge error.'
          })
        ),
        severity: 'error'
      }
    ];
  }

  return [
    {
      domain: 'bridge',
      message: formatReportableErrorMessage(
        createReportableError(error, {
          fallbackMessage: 'Project bridge request failed.',
          kind: 'bridge',
          title: 'KM Editor hit an unexpected bridge error.'
        })
      ),
      severity: 'error'
    }
  ];
}

function toDesktopDiagnostics(error: unknown, fallbackMessage: string): ApiDiagnostic[] {
  const detail =
    error instanceof Error
      ? error.message
      : typeof error === 'string'
        ? error
        : fallbackMessage;
  const message = detail === fallbackMessage ? fallbackMessage : `${fallbackMessage} ${detail}`;

  return [
    {
      domain: 'desktop',
      message,
      severity: 'error'
    }
  ];
}

function isSupportFileSearchCancellation(error: unknown) {
  const message =
    error instanceof Error ? error.message : typeof error === 'string' ? error : '';
  return message === 'Support file search was canceled.';
}

function toErrorMessage(error: unknown) {
  if (error instanceof Error) {
    return error.message;
  }

  if (typeof error === 'string') {
    return error;
  }

  return 'Update check failed.';
}
